def _beets_config_discogs_token() -> str:
    cfg_path = Path(os.environ.get("BEETS_CONFIG", "/config/config.yaml"))
    try:
        in_discogs = False
        discogs_indent = 0
        for raw in cfg_path.read_text(encoding="utf-8", errors="ignore").splitlines():
            stripped = raw.strip()
            if not stripped or stripped.startswith("#"):
                continue
            indent = len(raw) - len(raw.lstrip(" "))
            if indent == 0 and stripped.endswith(":"):
                in_discogs = stripped[:-1].strip() == "discogs"
                discogs_indent = indent
                continue
            if in_discogs and indent <= discogs_indent:
                in_discogs = False
            if in_discogs and stripped.startswith("user_token:"):
                return stripped.split(":", 1)[1].strip().strip("\"'")
    except Exception:
        pass
    return ""


def _slskd_api_key_from_file() -> str:
    key_path = Path(os.environ.get("SLSKD_API_KEY_FILE", "/config/slskd_api_key"))
    try:
        value = key_path.read_text(encoding="utf-8", errors="ignore").strip()
        return value.splitlines()[0].strip() if value else ""
    except Exception:
        return ""


def _config_file_first_line(env_name: str, default_path: str) -> str:
    key_path = Path(os.environ.get(env_name, default_path))
    try:
        value = key_path.read_text(encoding="utf-8", errors="ignore").strip()
        return value.splitlines()[0].strip() if value else ""
    except Exception:
        return ""


def _env_flag(name: str, default: bool = False) -> bool:
    raw = os.environ.get(name)
    if raw is None:
        return default
    return raw.strip().lower() in {"1", "true", "yes", "on"}

def _env_int(name: str, default: int, *, minimum: Optional[int] = None, maximum: Optional[int] = None) -> int:
    try:
        value = int(os.environ.get(name, str(default)) or default)
    except Exception:
        value = default
    if minimum is not None:
        value = max(minimum, value)
    if maximum is not None:
        value = min(maximum, value)
    return value

def _env_float(name: str, default: float, *, minimum: Optional[float] = None, maximum: Optional[float] = None) -> float:
    try:
        value = float(os.environ.get(name, str(default)) or default)
    except Exception:
        value = default
    if minimum is not None:
        value = max(minimum, value)
    if maximum is not None:
        value = min(maximum, value)
    return value

