_MB_TRACK_PREFLIGHT_MATCH_THRESHOLD = 0.82
_MB_TRACK_REPAIR_MATCH_THRESHOLD = 0.72
_UNRESOLVED_TEMPLATE_TOKEN_RE = re.compile(
    r'%\w+\{[^}]+\}'
    r'|\$(?:disc_subfolder|albumartist|album|artist|title|track|disc|year|'
    r'mb_[A-Za-z0-9_]+)'
    r'|\{[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12},\}'
    # Literal text placeholders that should have been replaced with a real UUID:
    r'|\{(?:Album\s+MbId|Track\s+ArtistMbId)\}',
    re.IGNORECASE,
)
# Matches {Album MbId} / {Album Mbid} / {Track ArtistMbId} — literal text placeholders in
# folder/file names where a real UUID was never substituted.
_LITERAL_PLACEHOLDER_RE = re.compile(
    r'\{(?:Album\s+MbId|Track\s+ArtistMbId)\}',
    re.IGNORECASE,
)
_MALFORMED_RELEASE_GROUP_STAMP_RE = re.compile(
    r'\{([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}),\}',
    re.IGNORECASE,
)
# AI confidence thresholds for automated import decisions (use these instead of magic strings)
# Downloads batch import: "high" auto-imports; "medium" auto-imports only when preflight is strong
_AI_BATCH_MIN_CONF        = "high"   # minimum confidence for unconditional auto-import
_AI_BATCH_MEDIUM_RATIO    = 0.80     # preflight match ratio needed to auto-import at medium confidence
# Library repair (light-confirm / missing-track): lower bar once a release is already validated
_AI_REPAIR_MIN_CONF       = "medium" # minimum confidence for auto-repair of existing library albums
_AI_MISSING_MIN_CONF      = "medium" # minimum confidence for missing-track gap-fill repair
_AI_CONF_ORDER            = {"low": 0, "medium": 1, "high": 2}
_AI_USE_CASE_THRESHOLDS   = {
    "fresh_import": {
        "auto_confidence": _AI_BATCH_MIN_CONF,
        "review_confidence": "medium",
        "medium_preflight_ratio": _AI_BATCH_MEDIUM_RATIO,
        "requires_mb_release": True,
    },
    "light_confirm": {
        "auto_confidence": _AI_REPAIR_MIN_CONF,
        "preflight_ratio": 0.60,
        "requires_mb_release": True,
    },
    "missing_track": {
        "auto_confidence": _AI_MISSING_MIN_CONF,
        "preflight_ratio": 0.60,
        "requires_mb_release": True,
    },
}


def _extract_mb_uuid(value: str) -> str:
    """Return the first MusicBrainz UUID from a raw UUID or MB URL."""
    match = re.search(
        r"[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}",
        _s(value),
        re.I,
    )
    return match.group(0).lower() if match else ""
_MISSING_TRACK_FILE_MATCH_SCORE = 0.86
_MISSING_TRACK_TITLE_FUZZY_SCORE = 0.88


def _ai_conf_at_least(confidence: str, required: str) -> bool:
    """Return whether an AI confidence label satisfies a named threshold."""
    return _AI_CONF_ORDER.get(_s(confidence).lower(), -1) >= _AI_CONF_ORDER.get(_s(required).lower(), 99)


def _ai_thresholds_for(use_case: str) -> Dict[str, Any]:
    """Return a copy of the threshold settings used for this decision type."""
    return dict(_AI_USE_CASE_THRESHOLDS.get(use_case) or _AI_USE_CASE_THRESHOLDS["fresh_import"])


def _preflight_match_ratio(preflight: Optional[Dict[str, Any]]) -> float:
    if not preflight:
        return 0.0
    return float(preflight.get("matches") or 0) / max(1, int(preflight.get("expected") or 0))


def _preflight_oversized_subset_complete(preflight: Dict[str, Any]) -> bool:
    """True when a small source folder cleanly matches part of an oversized MB release."""
    audio_count = int((preflight or {}).get("audio_count") or 0)
    expected = int((preflight or {}).get("expected") or 0)
    matches = int((preflight or {}).get("matches") or 0)
    if audio_count < 6 or expected <= audio_count + max(3, audio_count // 2):
        return False
    if not bool((preflight or {}).get("artist_ok", True)):
        return False
    return matches >= min(audio_count, max(6, int(math.ceil(audio_count * 0.90))))


def _preflight_oversized_subset_summary(preflight: Optional[Dict[str, Any]]) -> str:
    preflight = preflight or {}
    audio_count = int(preflight.get("audio_count") or 0)
    expected = int(preflight.get("expected") or 0)
    matches = int(preflight.get("matches") or 0)
    release_title = _s(preflight.get("release_title")).strip()
    release_artist = _s(preflight.get("release_artist")).strip()
    release_name = " - ".join([v for v in (release_artist, release_title) if v])
    label = f" ({release_name})" if release_name else ""
    return (
        f"MusicBrainz release{label} looks like an oversized edition: "
        f"{matches}/{audio_count or '?'} local source track(s) matched, "
        f"but the release has {expected or '?'} track(s)."
    )


def _preflight_tracklist_gate_ok(matches: int, min_required: int,
                                 artist_gate: bool, too_many_extras: bool,
                                 oversized_subset: bool) -> bool:
    """Shared pass/fail gate for selected MusicBrainz release preflight."""
    if not artist_gate or too_many_extras:
        return False
    return bool(oversized_subset) or int(matches or 0) >= int(min_required or 0)


def _ai_auto_import_allowed(use_case: str, confidence: str,
                            preflight: Optional[Dict[str, Any]],
                            mb_valid: bool, mb_id: str) -> bool:
    """Central gate for automated import/repair decisions."""
    thresholds = _ai_thresholds_for(use_case)
    if thresholds.get("requires_mb_release", True) and (not mb_valid or not mb_id):
        return False
    if not preflight or not preflight.get("ok"):
        return False
    if _ai_conf_at_least(confidence, thresholds.get("auto_confidence", "high")):
        return True
    review_conf = thresholds.get("review_confidence")
    medium_ratio = float(thresholds.get("medium_preflight_ratio") or 0)
    if review_conf and _ai_conf_at_least(confidence, review_conf):
        return _preflight_match_ratio(preflight) >= medium_ratio
    return False


def _beet_env() -> dict:
    """Return os.environ plus BEETSDIR for beet subprocesses."""
    env = {**os.environ, "BEETSDIR": "/config"}
    py_path = _s(env.get("PYTHONPATH", "")).strip()
    paths = ["/config"]
    if py_path:
        paths.append(py_path)
    env["PYTHONPATH"] = ":".join(paths)
    return env


def _beet_import_timeout(source_path: str, minimum: int = 300, maximum: int = 1200) -> int:
    """Scale beet import timeout with album size while keeping a hard cap."""
    count = 0
    try:
        root = Path(source_path)
        if root.is_file():
            count = 1 if root.suffix.lower() in AUDIO_EXT else 0
        elif root.exists():
            count = sum(1 for p in root.rglob("*") if p.is_file() and p.suffix.lower() in AUDIO_EXT)
    except Exception:
        count = 0
    return max(minimum, min(maximum, 180 + (count * 20)))


def _read_beets_plugin_list(config_path: str = "/config/config.yaml") -> List[str]:
    """Read the configured plugin names without requiring PyYAML."""
    plugins: List[str] = []
    in_plugins = False
    try:
        with open(config_path, encoding="utf-8") as f:
            for raw in f:
                stripped = raw.strip()
                if not stripped or stripped.startswith("#"):
                    continue
                if in_plugins and raw[:1].isspace():
                    if stripped.startswith("-"):
                        plugins.extend(p for p in stripped[1:].strip().split() if p)
                    continue
                in_plugins = False
                if stripped.startswith("plugins:"):
                    plugins.extend(p for p in stripped.split(":", 1)[1].strip().split() if p)
                    in_plugins = True
    except Exception:
        pass
    return plugins


def _beet_plugins() -> str:
    """Return the main config's plugin list for temp config overrides."""
    plugins = _read_beets_plugin_list()
    return _filter_job_plugins(plugins)


def _write_plugin_job_beets_config(temp_path: str, command: str) -> str:
    """Write a temp config for explicit plugin command jobs."""
    try:
        plugins = [
            p for p in _read_beets_plugin_list()
            if p and p not in _JOB_PLUGIN_EXCLUDED
        ]
        if command not in plugins:
            plugins.append(command)
        Path(temp_path).write_text(
            "include:\n  - /config/config.yaml\n"
            "pluginpath: /config/beetsplug\n"
            + (f"plugins: {' '.join(plugins)}\n" if plugins else "")
            + "lyrics:\n  auto: no\n"
            "replaygain:\n  auto: no\n"
        )
        return temp_path
    except Exception:
        return "/config/config.yaml"


