_DEFAULT_ALBUM_PATH_TEMPLATE = _ARTIST_FOLDER_PATH_TEMPLATE + "/$album (%left{$year,4})%if{$mb_releasegroupid, {$mb_releasegroupid$}}/$albumartist - $album - %right{00$track,2} - $title"
_ALBUMTYPE_SINGLE_PATH_TEMPLATE = _ARTIST_FOLDER_PATH_TEMPLATE + "/%if{$year,%left{$year,4} - }$album [Single]/%right{00$track,2} - $title"
_SINGLE_TRACK_PATH_TEMPLATE = _ARTIST_FOLDER_PATH_TEMPLATE + "/$album (%left{$year,4})%if{$mb_releasegroupid, {$mb_releasegroupid$}}/$artist - $album - %right{00$track,2} - $title ($disc)%if{$mb_artistid,{$mb_artistid$}}"
_JOB_PATHS_CONFIG_BLOCK = (
    "paths:\n"
    f'  default: "{_DEFAULT_ALBUM_PATH_TEMPLATE}"\n'
    f'  singleton: "{_SINGLE_TRACK_PATH_TEMPLATE}"\n'
    f'  comp: "{_DEFAULT_ALBUM_PATH_TEMPLATE}"\n'
    "  albumtype_soundtrack: Soundtracks/$album (%left{$year,4})/$albumartist - $album - %right{00$track,2} - $title\n"
    f'  albumtype_single: "{_ALBUMTYPE_SINGLE_PATH_TEMPLATE}"\n'
)


def _write_job_beets_config(temp_path: str, extra: str = "") -> str:
    """Write a temp beets config for jobs that should not load slow/fragile plugins."""
    try:
        plugins = _beet_plugins()
        extra_block = extra or ""
        if extra_block and not extra_block.endswith("\n"):
            extra_block += "\n"
        Path(temp_path).write_text(
            "include:\n  - /config/config.yaml\n"
            "pluginpath: /config/beetsplug\n"
            + (f"plugins: {plugins}\n" if plugins else "")
            + _JOB_PATHS_CONFIG_BLOCK
            + extra_block
            + "lyrics:\n  auto: no\n"
            "replaygain:\n  auto: no\n"
        )
        return temp_path
    except Exception:
        return "/config/config.yaml"


def _write_playlist_import_beets_config(temp_path: str) -> str:
    """Use the project single-track path format for playlist download imports."""
    return _write_job_beets_config(temp_path)


def _sqlite_timeout_seconds() -> float:
    try:
        return max(1.0, float(os.environ.get("BEETS_SQLITE_TIMEOUT", "30") or "30"))
    except Exception:
        return 30.0


_SQLITE_WAL_CONFIGURED: set = set()
_SQLITE_WAL_LOCK = threading.Lock()


def _sqlite_is_locked_error(exc: BaseException) -> bool:
    return isinstance(exc, sqlite3.OperationalError) and (
        "database is locked" in str(exc).lower()
        or "database is busy" in str(exc).lower()
    )


def _sqlite_write_retry(label: str, fn, *, log=None, attempts: int = 5):
    for attempt in range(1, max(1, attempts) + 1):
        try:
            return fn()
        except sqlite3.OperationalError as exc:
            if not _sqlite_is_locked_error(exc) or attempt >= attempts:
                raise
            message = f"database locked while {label}; retrying {attempt + 1}/{attempts}"
            if isinstance(log, list) and message not in log[-5:]:
                log.append(message)
            time.sleep(min(2.0, 0.2 * (2 ** (attempt - 1))))


@contextmanager
def _db(path=None, *, text_factory=None, row_factory=None):
    """Context manager: yield a SQLite connection that is always closed."""
    timeout = _sqlite_timeout_seconds()
    db_path = path or LIB_PATH
    con = sqlite3.connect(db_path, timeout=timeout)
    try:
        con.execute(f"PRAGMA busy_timeout = {int(timeout * 1000)}")
    except Exception:
        pass
    try:
        resolved_db_path = str(Path(db_path).resolve(strict=False))
    except Exception:
        resolved_db_path = _s(db_path)
    if resolved_db_path:
        with _SQLITE_WAL_LOCK:
            if resolved_db_path not in _SQLITE_WAL_CONFIGURED:
                try:
                    con.execute("PRAGMA journal_mode=WAL")
                    con.execute("PRAGMA synchronous=NORMAL")
                    _SQLITE_WAL_CONFIGURED.add(resolved_db_path)
                except Exception:
                    pass
    if text_factory is not None:
        con.text_factory = text_factory
    if row_factory is not None:
        con.row_factory = row_factory
    try:
        yield con
    finally:
        con.close()


def _stamp_album_release_id(album_id: int, mb_albumid: str,
                            log: Optional[List[str]] = None) -> int:
    """Persist the selected MB release ID on the album and all its item rows."""
    try:
        aid = int(album_id or 0)
    except Exception:
        aid = 0
    mbid = _s(mb_albumid).strip().lower()
    if aid <= 0 or not _MB_UUID_RE.match(mbid):
        return 0
    try:
        with _db() as con:
            con.execute("UPDATE albums SET mb_albumid=? WHERE id=?", (mbid, aid))
            cur = con.execute(
                "UPDATE items SET mb_albumid=? WHERE album_id=? "
                "AND (mb_albumid IS NULL OR mb_albumid='' OR lower(mb_albumid)<>?)",
                (mbid, aid, mbid),
            )
            con.commit()
            changed = int(cur.rowcount or 0)
        if log is not None and changed:
            log.append(f"  Stamped mb_albumid on {changed} item row(s).")
        return changed
    except Exception as ex:
        if log is not None:
            log.append(f"  WARN stamping mb_albumid: {ex}")
        return 0


def _repair_album_mbid_sticking_once(album_id: int, mb_albumid: str,
                                     log: Optional[List[str]] = None, *,
                                     repair_tracks: bool = True,
                                     write_tags: bool = False,
                                     cancel_event=None) -> Dict[str, Any]:
    """Repair MB release/recording IDs for one already-validated album."""
    try:
        aid = int(album_id or 0)
    except Exception:
        aid = 0
    mbid = _s(mb_albumid).strip().lower()
    summary = {
        "album_id": aid,
        "changed": False,
        "release_item_rows": 0,
        "track_rows": 0,
        "write_returncode": None,
    }
    if aid <= 0 or not _MB_UUID_RE.match(mbid):
        return summary

    changed = _stamp_album_release_id(aid, mbid, log)
    summary["release_item_rows"] = int(changed or 0)
    album_changed = changed > 0

    if repair_tracks:
        try:
            data = _album_mb_completeness(aid, mbid, [])
            track_updates: List[tuple] = []
            for expected in data.get("tracks") or []:
                item = expected.get("item") or {}
                try:
                    item_id = int(item.get("id") or 0)
                except Exception:
                    item_id = 0
                if item_id <= 0:
                    continue
                current_mbid = _s(item.get("mb_trackid") or "").strip().lower()
                target_mbid = _s(expected.get("mb_trackid") or "").strip()
                if not target_mbid or current_mbid == target_mbid.lower():
                    continue
                track_updates.append((
                    target_mbid,
                    int(expected.get("track") or 0),
                    int(expected.get("disc") or 1),
                    _s(expected.get("title") or ""),
                    mbid,
                    item_id,
                ))
            if track_updates:
                with _db() as con:
                    con.executemany(
                        "UPDATE items SET mb_trackid=?, track=?, disc=?, title=?, mb_albumid=? "
                        "WHERE id=?",
                        track_updates,
                    )
                    con.execute("UPDATE albums SET mb_albumid=? WHERE id=?", (mbid, aid))
                    con.commit()
                summary["track_rows"] = len(track_updates)
                album_changed = True
                if log is not None:
                    log.append(
                        f"  [mbid] Auto-repaired {len(track_updates)} recording ID(s) "
                        f"for album_id {aid}."
                    )
        except Exception as ex:
            if log is not None:
                log.append(f"  [mbid] WARN auto recording-ID repair skipped for album_id {aid}: {ex}")

    summary["changed"] = bool(album_changed)
    if album_changed and write_tags:
        job_cfg = f"/tmp/beets-auto-mbid-sticking-{aid}-{uuid.uuid4().hex}.yaml"
        base = [BEET_BIN, "-c", _write_job_beets_config(job_cfg)]
        proc = _beet_run(
            base + ["write", f"album_id:{aid}"],
            log if log is not None else [],
            timeout=180,
            env=_beet_env(),
            cancel=cancel_event,
        )
        summary["write_returncode"] = proc.returncode
        if proc.returncode != 0 and log is not None:
            log.append(f"  [mbid] WARN beet write failed for album_id {aid} (rc={proc.returncode})")
    return summary


