def _transaction_user_label() -> str:
    try:
        auth = request.authorization
        if auth and auth.username:
            return str(auth.username)
    except RuntimeError:
        pass
    return os.environ.get("BEETS_WEB_USERNAME", "admin").strip() or "operator"


def _transaction_operation_from_job(label: str, metadata: Dict[str, Any]) -> Optional[str]:
    text = f"{metadata.get('type', '')} {label}".strip().lower()
    if not text or any(blocked in text for blocked in _TRANSACTION_LABEL_BLOCKLIST):
        return None
    if "playlist" in text:
        if any(word in text for word in ("import", "place", "repair", "sync", "quality")):
            return "Playlist Import"
    if "music-format" in text or "replace" in text or "replacement" in text:
        return "Replace"
    if "fetchart" in text or "art" in text or "artwork" in text:
        return "Artwork Update"
    if "dedup" in text or "duplicate" in text:
        return "Duplicate Removal"
    if "merge artist" in text or "artist-folder-merge" in text or "merge-artist" in text:
        return "Merge Artist"
    if "merge album" in text or "merge-split" in text or "release group merge" in text:
        return "Merge Album"
    if "split" in text:
        return "Split Album"
    if "import" in text or "tag+import" in text or "import+tag" in text:
        return "Import"
    if "mbsync" in text or "mbid" in text or "musicbrainz" in text or "mbsubmit" in text:
        return "MusicBrainz Match"
    if "acoustid" in text or "fingerprint" in text:
        return "AcoustID Match"
    if "ai" in text or "suggest" in text:
        return "AI Suggestion"
    if "move" in text:
        return "Move"
    if "rename" in text or "normalize" in text or "stamp" in text:
        return "Rename"
    if "delete" in text or "remove" in text or "cleanup" in text or "clean" in text:
        return "Library Cleanup"
    if "repair" in text or "fix" in text:
        return "Repair"
    if "scan" in text or "rescan" in text:
        return "Rescan"
    if text.startswith("beet "):
        return "Repair"
    return None


def _transaction_create_for_job(label: str, metadata: Optional[Dict[str, Any]], command: Optional[List[str]] = None) -> Optional[Dict[str, Any]]:
    metadata = dict(metadata or {})
    explicit = metadata.get("transaction")
    if explicit is False:
        return None
    explicit_payload = explicit if isinstance(explicit, dict) else {}
    operation_type = (
        explicit_payload.get("operation_type")
        or metadata.get("transaction_operation")
        or metadata.get("operation_type")
        or _transaction_operation_from_job(label, metadata)
    )
    if not operation_type:
        return None
    text = f"{metadata.get('type', '')} {label}".lower()
    dry_run = bool(
        explicit_payload.get("dry_run")
        or metadata.get("dry_run")
        or metadata.get("preview")
        or "dry run" in text
        or "preview" in text
    )
    summary = str(explicit_payload.get("summary") or label or operation_type)
    reason = str(explicit_payload.get("reason") or "Created from the existing job workflow before library changes are applied.")
    source = str(explicit_payload.get("source") or metadata.get("type") or "job")
    tx_metadata = {k: v for k, v in metadata.items() if k != "transaction"}
    if command:
        tx_metadata["command"] = [str(part) for part in command]
    return transactions.create(
        operation_type=str(operation_type),
        initiating_user=_transaction_user_label(),
        status="Running",
        dry_run=dry_run,
        summary=summary,
        reason=reason,
        source=source,
        confidence=explicit_payload.get("confidence") if isinstance(explicit_payload.get("confidence"), dict) else None,
        rollback_available=bool(explicit_payload.get("rollback_available", False)),
        rollback_reason=str(explicit_payload.get("rollback_reason") or "Rollback data has not been captured for this workflow yet."),
        metadata=tx_metadata,
    )


def _call_job_fn(fn, log, cancel=None, update_state=None):
    import inspect as _inspect
    sig = _inspect.signature(fn)
    if len(sig.parameters) >= 3:
        return fn(log, cancel, update_state)
    if len(sig.parameters) >= 2:
        return fn(log, cancel)
    return fn(log)


def _install_transaction_job_hooks() -> None:
    if getattr(jobs, "_transaction_hooks_installed", False):
        return
    original_start = jobs.start
    original_start_python = jobs.start_python

    def start_python_with_transaction(fn, label="", metadata=None):
        metadata_payload = dict(metadata or {})
        tx = _transaction_create_for_job(label, metadata_payload)
        tx_id = tx.get("id") if tx else ""
        if tx_id:
            metadata_payload["transaction_id"] = tx_id

            def wrapped(log, cancel=None, update_state=None):
                transactions.update(tx_id, status="Running")
                try:
                    result = _call_job_fn(fn, log, cancel, update_state)
                except Exception as ex:
                    transactions.update(tx_id, status="Failed")
                    transactions.append_log(tx_id, f"ERROR: {ex}")
                    raise
                next_status = "Preview" if metadata_payload.get("dry_run") or metadata_payload.get("preview") else "Completed"
                transactions.update(tx_id, status=next_status)
                return result
        else:
            wrapped = fn
        job = original_start_python(wrapped, label=label, metadata=metadata_payload)
        if tx_id:
            transactions.attach_job(tx_id, job.job_id)
        return job

    def start_with_transaction(command, label=""):
        tx = _transaction_create_for_job(label or "beet command", {"type": "beet-command"}, command=list(command or []))
        job = original_start(command, label=label)
        if tx:
            metadata_payload = {"type": "beet-command", "transaction_id": tx["id"]}
            setattr(job, "metadata", metadata_payload)
            transactions.attach_job(tx["id"], job.job_id)
        return job

    jobs.start_python = start_python_with_transaction
    jobs.start = start_with_transaction
    jobs._transaction_hooks_installed = True


def _sync_transactions_from_jobs() -> None:
    for job in jobs.all():
        metadata = getattr(job, "metadata", {}) or {}
        tx_id = metadata.get("transaction_id")
        if not tx_id:
            continue
        try:
            transactions.update_from_job(str(tx_id), job)
        except Exception as ex:
            app.logger.debug("transaction sync failed for %s: %s", tx_id, ex)


_install_transaction_job_hooks()
_AUTH_RATE_LIMITS: Dict[str, Dict[str, Any]] = {}
_AUTH_RATE_LIMIT_LOCK = threading.Lock()


def _first_config_secret(*names: str) -> str:
    for name in names:
        value = os.environ.get(name, "").strip()
        if value:
            return value
    return ""


def _security_auth_token() -> str:
    return _first_config_secret("BEETS_WEB_AUTH_TOKEN", "BEETS_WEB_TOKEN")


def _security_auth_password() -> str:
    value = _first_config_secret("BEETS_WEB_PASSWORD")
    if value:
        return value
    path = os.environ.get("BEETS_WEB_PASSWORD_FILE", "").strip()
    if not path:
        return ""
    try:
        return Path(path).read_text(encoding="utf-8", errors="ignore").splitlines()[0].strip()
    except Exception:
        return ""


def _security_auth_username() -> str:
    return os.environ.get("BEETS_WEB_USERNAME", "admin").strip() or "admin"


def _auth_secret_is_usable(value: str) -> bool:
    secret = (value or "").strip()
    if len(secret) < _MIN_AUTH_SECRET_LENGTH:
        return False
    lowered = secret.lower()
    compact = re.sub(r"[^a-z0-9]+", "", lowered)
    if "${" in secret or "?" in secret:
        return False
    if compact in _PLACEHOLDER_AUTH_SECRETS:
        return False
    if any(marker in compact for marker in ("changeme", "placeholder", "example", "setinenv")):
        return False
    return True


def _security_auth_configured() -> bool:
    return _auth_secret_is_usable(_security_auth_token()) or _auth_secret_is_usable(_security_auth_password())


def _security_auth_disabled() -> bool:
    return os.environ.get("BEETS_WEB_AUTH_DISABLED", "").strip().lower() in {"1", "true", "yes", "on"}


_GENERATED_AUTH_TOKEN_FILE = Path(
    os.environ.get("BEETS_WEB_AUTH_TOKEN_FILE", "/config/.auth_token")
)


def generate_secure_auth_token() -> str:
    """256-bit-entropy URL-safe token, well above _MIN_AUTH_SECRET_LENGTH and
    never a placeholder string -- suitable for signing/bearer authentication."""
    return secrets.token_urlsafe(32)


def _persist_generated_auth_token(token: str) -> None:
    """Best-effort: the in-process env var already works for this run even if
    writing to disk fails (e.g. read-only /config in some environment)."""
    try:
        _GENERATED_AUTH_TOKEN_FILE.parent.mkdir(parents=True, exist_ok=True)
        _GENERATED_AUTH_TOKEN_FILE.write_text(token, encoding="utf-8")
        try:
            os.chmod(_GENERATED_AUTH_TOKEN_FILE, 0o600)
        except Exception:
            pass
    except Exception:
        pass


def _bootstrap_auth_token_if_missing() -> None:
    """First-run safety net: with neither a usable BEETS_WEB_AUTH_TOKEN nor
    BEETS_WEB_PASSWORD configured, _enforce_security_boundary 503s every
    route including the setup wizard itself -- an operator with no shell
    access has no way in. Never require inventing a token manually: generate
    one automatically instead, persist it so a plain process restart reuses
    the same value, and print it once to the startup log (the only channel
    available before any credential exists). Never runs once a real secret
    (auto-generated or operator-set) is already configured.
    """
    if _security_auth_configured():
        return
    existing = ""
    try:
        existing = _GENERATED_AUTH_TOKEN_FILE.read_text(encoding="utf-8").strip()
    except Exception:
        existing = ""
    if _auth_secret_is_usable(existing):
        os.environ["BEETS_WEB_AUTH_TOKEN"] = existing
        return
    token = generate_secure_auth_token()
    os.environ["BEETS_WEB_AUTH_TOKEN"] = token
    _persist_generated_auth_token(token)
    print(
        "\n" + "=" * 72 +
        "\nNo BEETS_WEB_AUTH_TOKEN or BEETS_WEB_PASSWORD was configured."
        "\nGenerated a secure API token automatically so the app is not"
        "\nlocked out on first run:\n"
        f"\n  BEETS_WEB_AUTH_TOKEN={token}\n"
        "\nSave this now -- it will not be printed again. Use it as a Bearer"
        "\ntoken for API clients, or set BEETS_WEB_PASSWORD (any authenticated"
        "\nclient can do this via POST /api/setup/env) for browser access."
        "\nRegenerate anytime with POST /api/setup/auth-token/regenerate."
        "\n" + "=" * 72 + "\n",
        flush=True,
    )


_bootstrap_auth_token_if_missing()


def _constant_time_equal(left: str, right: str) -> bool:
    return hmac.compare_digest((left or "").encode("utf-8"), (right or "").encode("utf-8"))


def _bearer_authorized(header: str) -> bool:
    token = _security_auth_token()
    if not _auth_secret_is_usable(token) or not header.lower().startswith("bearer "):
        return False
    return _constant_time_equal(header.split(" ", 1)[1].strip(), token)


def _basic_authorized(header: str) -> bool:
    password = _security_auth_password()
    if not _auth_secret_is_usable(password) or not header.lower().startswith("basic "):
        return False
    try:
        raw = base64.b64decode(header.split(" ", 1)[1].strip(), validate=True).decode("utf-8")
    except Exception:
        return False
    username, sep, supplied_password = raw.partition(":")
    if not sep:
        return False
    return (
        _constant_time_equal(username, _security_auth_username())
        and _constant_time_equal(supplied_password, password)
    )


def _request_authorized() -> bool:
    header = request.headers.get("Authorization", "")
    return _bearer_authorized(header) or _basic_authorized(header)


def _trusted_proxy_cidrs() -> List[str]:
    raw = os.environ.get("BEETS_TRUSTED_PROXIES", "")
    return [part.strip() for part in raw.split(",") if part.strip()]


def _valid_client_ip(value: str) -> bool:
    try:
        import ipaddress as _ipaddress
        _ipaddress.ip_address((value or "").strip())
        return True
    except Exception:
        return False


def _request_client_identity() -> str:
    peer = (request.remote_addr or "").strip()
    if direct_peer_is_trusted(peer, _trusted_proxy_cidrs()):
        candidates = [
            request.headers.get("X-Forwarded-For", "").split(",", 1)[0].strip(),
            request.headers.get("X-Real-IP", "").strip(),
        ]
        for candidate in candidates:
            if _valid_client_ip(candidate):
                return candidate
    return peer or "unknown"


def _client_ip_is_lan() -> bool:
    try:
        import ipaddress as _ipaddress
        ip = _ipaddress.ip_address(_request_client_identity())
        return bool(ip.is_private or ip.is_loopback)
    except Exception:
        return False


def _rate_limit_subject(include_auth: bool = False) -> str:
    base = _request_client_identity()
    if not include_auth:
        return base
    header = request.headers.get("Authorization", "")
    digest = hashlib.sha256(header.encode("utf-8", errors="ignore")).hexdigest()[:16] if header else "noauth"
    return f"{base}:{digest}"


def _rate_limit_profile_for_request() -> Tuple[str, int, int]:
    path = (request.path or "").lower()
    endpoint = (request.endpoint or "").lower()
    method = request.method.upper()
    scope = f"{path} {endpoint}"
    if "ytdlp" in scope or "youtube" in scope:
        return "ytdlp", 10, 300
    if "ai" in scope or "openai" in scope or "genre" in scope:
        return "ai", 12, 300
    if "fingerprint" in scope or "acoustid" in scope:
        return "fingerprint", 12, 300
    if "replace" in scope or "replacement" in scope:
        return "replacement", 6, 300
    if "cleanup" in scope or "clean" in scope or "delete" in scope or "merge" in scope or "move" in scope:
        return "cleanup", 8, 300
    if "scan" in scope or request.args.get("refresh") == "1":
        return "scan", 12, 300
    if "playlist" in scope and method not in {"GET", "HEAD", "OPTIONS"}:
        return "playlist-write", 20, 300
    if "search" in scope:
        return "search", 60, 60
    if method not in {"GET", "HEAD", "OPTIONS"}:
        return "write", 120, 60
    return "read", 600, 60


def _rate_limited(bucket: str, subject: str, limit: int, window_seconds: int) -> Tuple[bool, int]:
    now = time.time()
    key = f"{bucket}:{hashlib.sha256(subject.encode('utf-8', errors='ignore')).hexdigest()[:32]}"
    with _AUTH_RATE_LIMIT_LOCK:
        bounded_rate_key_store_sweep(_AUTH_RATE_LIMITS, now=now, max_age=3600, max_keys=8192)
        entry = _AUTH_RATE_LIMITS.setdefault(key, {"events": [], "updated": now})
        events = [float(ts) for ts in entry.get("events", []) if now - float(ts) < window_seconds]
        entry["updated"] = now
        if len(events) >= limit:
            retry_after = max(1, int(window_seconds - (now - min(events))))
            entry["events"] = events
            return True, retry_after
        events.append(now)
        entry["events"] = events[-limit:]
        return False, 0


def _rate_limit_response(retry_after: int):
    response = jsonify({"ok": False, "error": "Rate limit exceeded; retry later"})
    response.status_code = 429
    response.headers["Retry-After"] = str(max(1, int(retry_after or 1)))
    return response


def _same_origin_url(value: str) -> bool:
    if not value:
        return False
    try:
        parsed = urllib.parse.urlparse(value)
    except Exception:
        return False
    host = request.host.split("@")[-1].lower()
    return bool(parsed.scheme in {"http", "https"} and parsed.netloc.lower() == host)


def _explicit_authorization_header_present() -> bool:
    header = request.headers.get("Authorization", "").strip().lower()
    return header.startswith("bearer ") or header.startswith("basic ")


def _csrf_request_allowed() -> bool:
    if request.method in {"GET", "HEAD", "OPTIONS"}:
        return True

    browser_same_origin = False
    origin = request.headers.get("Origin", "")
    if origin:
        if origin.strip().lower() == "null" or not _same_origin_url(origin):
            return False
        browser_same_origin = True

    referer = request.headers.get("Referer", "")
    if referer:
        if not _same_origin_url(referer):
            return False
        browser_same_origin = True

    fetch_site = request.headers.get("Sec-Fetch-Site", "").lower()
    if fetch_site:
        if fetch_site not in {"same-origin", "same-site", "none"}:
            return False
        browser_same_origin = True

    if _explicit_authorization_header_present():
        return True

    return browser_same_origin and request.headers.get("X-Beets-CSRF") == "1"

def _json_security_error(status: int, message: str):
    response = jsonify({"ok": False, "error": message})
    response.status_code = status
    if status == 401:
        response.headers["WWW-Authenticate"] = 'Basic realm="Beets Web Control", charset="UTF-8"'
    return response


def _redact_security_text(value: Any) -> str:
    text = _s(value)
    text = _CONTROL_CHAR_RE.sub("?", text)
    return _SECRET_ASSIGNMENT_RE.sub(lambda m: f"{m.group(1)}{m.group(2)}{_REDACTED_SECRET}", text)


def _is_public_endpoint() -> bool:
    endpoint = request.endpoint or ""
    method = request.method
    return (method, endpoint) in _AUTH_PUBLIC_ENDPOINTS


def _auth_failure_rate_limit_response():
    auth_limited, auth_retry = _rate_limited(
        "auth",
        _rate_limit_subject(include_auth=False),
        _env_int("BEETS_AUTH_RATE_LIMIT", 30, minimum=5, maximum=1000),
        _env_int("BEETS_AUTH_RATE_WINDOW", 60, minimum=10, maximum=3600),
    )
    if auth_limited:
        return _rate_limit_response(auth_retry)
    return None


@app.before_request
def _enforce_security_boundary():
    if _is_public_endpoint() or _security_auth_disabled():
        return None

    if not _security_auth_configured():
        return _json_security_error(
            503,
            "Authentication is required. Set a strong BEETS_WEB_AUTH_TOKEN or BEETS_WEB_PASSWORD.",
        )
    if not _request_authorized():
        limited = _auth_failure_rate_limit_response()
        if limited is not None:
            return limited
        return _json_security_error(401, "Authentication required")
    if not _csrf_request_allowed():
        return _json_security_error(403, "CSRF check failed")

    if _client_ip_is_lan():
        return None

    bucket, limit, window_seconds = _rate_limit_profile_for_request()
    action_limited, action_retry = _rate_limited(
        bucket,
        _rate_limit_subject(include_auth=True),
        limit,
        window_seconds,
    )
    if action_limited:
        return _rate_limit_response(action_retry)
    return None


_INLINE_SCRIPT_RE = re.compile(r"<script(?![^>]*\bsrc=)[^>]*>(.*?)</script>", re.IGNORECASE | re.DOTALL)


def _inline_script_csp_hashes(html: Optional[str]) -> List[str]:
    if not html:
        return []
    hashes: List[str] = []
    for match in _INLINE_SCRIPT_RE.finditer(html):
        script_body = match.group(1)
        if not script_body.strip():
            continue
        digest = base64.b64encode(hashlib.sha256(script_body.encode("utf-8")).digest()).decode("ascii")
        hashes.append(f"'sha256-{digest}'")
    return list(dict.fromkeys(hashes))


def _content_security_policy(html: Optional[str] = None) -> str:
    script_src = " ".join(["'self'", *_inline_script_csp_hashes(html)])
    return (
        "default-src 'self'; "
        f"script-src {script_src}; "
        "style-src 'self' 'unsafe-inline'; "
        "img-src 'self' data: blob:; "
        "connect-src 'self'; "
        "font-src 'self' data:; "
        "object-src 'none'; "
        "base-uri 'none'; "
        "form-action 'self'; "
        "frame-ancestors 'self'"
    )


_COMPRESSIBLE_MIMETYPE_PREFIXES = ("application/json", "text/")
_COMPRESS_MIN_BYTES = 1024  # skip tiny responses; gzip overhead isn't worth it below this


@app.after_request
def _compress_response(response):
    """Gzip-compress JSON/text responses when the client accepts it.

    Registered before _set_security_headers below, so (per Flask's
    reverse-registration-order execution) it runs AFTER that hook --
    compression must happen last, once CSP header computation has already
    read the plaintext HTML body via get_data(as_text=True); compressing
    first would hand it undecodable gzip bytes.

    Added 2026-07-20: /api/library's summary response was measured at
    ~28.7MB uncompressed for a 545-artist library, sent with no
    Content-Encoding at all -- confirmed via curl that Accept-Encoding: gzip
    from the client was simply never honored. JSON compresses very well
    (typically 5-10x), so this targets the actual "page feels slow" residual
    once the server-side cache-warming fix (see _refresh_library_cache)
    eliminated the synchronous rebuild. Applies to every JSON/text response,
    not just /api/library -- general-purpose, zero risk to response content
    (bytes in, same bytes out after decompression), skips anything already
    encoded or served via direct_passthrough (file downloads, static assets
    with their own streaming).
    """
    try:
        if response.direct_passthrough:
            return response
        if response.headers.get("Content-Encoding"):
            return response
        accept_encoding = request.headers.get("Accept-Encoding", "")
        if "gzip" not in accept_encoding.lower():
            return response
        mimetype = (response.mimetype or "").lower()
        if not mimetype.startswith(_COMPRESSIBLE_MIMETYPE_PREFIXES):
            return response
        data = response.get_data()
        if len(data) < _COMPRESS_MIN_BYTES:
            return response
        compressed = gzip.compress(data, compresslevel=6)
        if len(compressed) >= len(data):
            return response
        response.set_data(compressed)
        response.headers["Content-Encoding"] = "gzip"
        response.headers["Content-Length"] = str(len(compressed))
        existing_vary = response.headers.get("Vary", "")
        if "Accept-Encoding" not in existing_vary:
            response.headers["Vary"] = (
                f"{existing_vary}, Accept-Encoding" if existing_vary else "Accept-Encoding"
            )
    except Exception:
        pass
    return response


@app.after_request
def _set_security_headers(response):
    html_for_csp = None
    try:
        if response.mimetype == "text/html" and not response.direct_passthrough:
            html_for_csp = response.get_data(as_text=True)
    except Exception:
        html_for_csp = None
    response.headers.setdefault("X-Content-Type-Options", "nosniff")
    response.headers.setdefault("X-Frame-Options", "SAMEORIGIN")
    response.headers.setdefault("Referrer-Policy", "same-origin")
    response.headers.setdefault("Permissions-Policy", "camera=(), microphone=(), geolocation=()")
    response.headers.setdefault("Content-Security-Policy", _content_security_policy(html_for_csp))
    if request.path.startswith("/api/"):
        response.headers.setdefault("Cache-Control", "no-store")
    return response


def _safe_static_file(base: Path, filename: str) -> Optional[Path]:
    raw = _s(filename)
    if "\x00" in raw or "\\" in raw:
        return None
    candidate = Path(raw)
    if candidate.is_absolute() or ".." in candidate.parts:
        return None
    try:
        root = base.resolve(strict=True)
    except Exception:
        return None
    target = (root / candidate).resolve(strict=False)
    try:
        target.relative_to(root)
    except ValueError:
        return None
    return target if target.exists() and target.is_file() else None

from werkzeug.exceptions import HTTPException as _WerkzeugHTTPException

@app.errorhandler(_WerkzeugHTTPException)
def _handle_http_error(exc):
    return jsonify({"ok": False, "error": exc.description, "status": exc.code}), exc.code

@app.errorhandler(Exception)
def _handle_unexpected_error(exc):
    import traceback as _tb
    app.logger.error(
        "Unhandled exception in route: %s\n%s",
        _redact_security_text(exc),
        _redact_security_text(_tb.format_exc()),
    )
    return jsonify({"ok": False, "error": "Unexpected server error"}), 500


