@app.post("/api/albums/<int:aid>/add-mbids")
def album_add_mbids(aid: int):
    """Attach real MusicBrainz IDs to an album and move it to the MBID-stamped path."""
    payload = request.get_json(silent=True) or {}
    mb_albumartistid = _s(payload.get("mb_albumartistid") or "").strip().lower()
    mb_releasegroupid = _s(payload.get("mb_releasegroupid") or "").strip().lower()
    mb_albumid = _s(payload.get("mb_albumid") or "").strip().lower()
    if not mb_albumartistid or not mb_releasegroupid:
        return jsonify({"ok": False, "error": "mb_albumartistid and mb_releasegroupid are required"}), 400
    if not _MB_UUID_RE.match(mb_albumartistid) or not _MB_UUID_RE.match(mb_releasegroupid):
        return jsonify({"ok": False, "error": "Invalid MusicBrainz UUID format"}), 400

    def _do(log, cancel_event=None):
        cfg = _write_job_beets_config("/tmp/beets_add_mbids.yaml")
        query = f"album_id:{aid}"
        modify_args = [f"mb_albumartistid={mb_albumartistid}",
                       f"mb_releasegroupid={mb_releasegroupid}"]
        if mb_albumid and _MB_UUID_RE.match(mb_albumid):
            modify_args.append(f"mb_albumid={mb_albumid}")
        r = _beet_run([BEET_BIN, "-c", cfg, "modify", "--yes", "--nowrite", query] + modify_args,
                      log, timeout=120, env=_beet_env(), cancel=cancel_event)
        if r.returncode not in (0, -9, 124):
            raise RuntimeError(f"beet modify failed rc={r.returncode}")
        r = _beet_run([BEET_BIN, "-c", cfg, "write", "--yes", query],
                      log, timeout=120, env=_beet_env(), cancel=cancel_event)
        if r.returncode not in (0, -9, 124):
            log.append(f"  WARN beet write rc={r.returncode}")
        r = _beet_run([BEET_BIN, "-c", cfg, "move", query],
                      log, timeout=120, env=_beet_env(), cancel=cancel_event)
        if r.returncode not in (0, -9, 124):
            log.append(f"  WARN beet move rc={r.returncode}")
        _invalidate_lib_cache()
        _trigger_plex_refresh(log)
        log.append(f"MBIDs applied and album moved to MBID-stamped path.")

    job = jobs.start_python(_do, label=f"Add MBIDs: album {aid}")
    return jsonify({"ok": True, "job_id": job.job_id})


@app.post("/api/items/<int:iid>/attach-recording")
def item_attach_recording(iid: int):
    """Attach a MusicBrainz recording ID to a singleton item (no album_id)
    and sync/move it, mirroring album_add_mbids's direct modify+write+move
    pattern at item level. Meant for recording IDs a user picked from
    /api/items/<iid>/ai-suggest candidates."""
    item = lib.get_item(iid)
    if not item:
        return jsonify({"ok": False, "error": "Item not found"}), 404
    payload = request.get_json(silent=True) or {}
    mb_trackid = _s(payload.get("mb_trackid") or "").strip().lower()
    if not mb_trackid:
        return jsonify({"ok": False, "error": "mb_trackid is required"}), 400
    if not _MB_UUID_RE.match(mb_trackid):
        return jsonify({"ok": False, "error": "Invalid MusicBrainz UUID format"}), 400
    confirmed_conflicts = bool(payload.get("confirmed_conflicts"))
    candidate_context = payload.get("candidate") if isinstance(payload.get("candidate"), dict) else {}
    def _do(log, cancel_event=None):
        cfg = _write_job_beets_config(f"/tmp/beets_attach_recording_{iid}.yaml")
        base = [BEET_BIN, "-c", cfg]
        query = f"id:{iid}"
        r = _beet_run(base + ["modify", "--yes", "--nowrite", f"mb_trackid={mb_trackid}", query],
                      log, timeout=120, env=_beet_env(), cancel=cancel_event)
        if r.returncode not in (0, -9, 124):
            raise RuntimeError(f"beet modify failed rc={r.returncode}")
        r = _beet_run(base + ["mbsync", query], log, timeout=60, env=_beet_env(), cancel=cancel_event)
        if r.returncode not in (0, -9, 124):
            log.append(f"  WARN beet mbsync rc={r.returncode}")
        r = _beet_run(base + ["write", "--yes", query], log, timeout=120, env=_beet_env(), cancel=cancel_event)
        if r.returncode not in (0, -9, 124):
            log.append(f"  WARN beet write rc={r.returncode}")
        r = _beet_run(base + ["move", query], log, timeout=120, env=_beet_env(), cancel=cancel_event)
        if r.returncode not in (0, -9, 124):
            log.append(f"  WARN beet move rc={r.returncode}")
        log.append("Revalidating MusicBrainz recording details after attach.")
        details = _fetch_mb_recording_details(mb_trackid)
        linked_count = len(details.get("linked_releases") or []) if isinstance(details, dict) else 0
        selected_release = (details.get("selected_release") or {}) if isinstance(details, dict) else {}
        if confirmed_conflicts:
            log.append("User confirmed visible candidate conflicts before attaching the Recording ID.")
        if candidate_context:
            log.append(f"Attached candidate safety result: {_s(candidate_context.get('safety_result') or 'unknown')}.")
        if linked_count:
            rel_title = _s(selected_release.get("album") or details.get("album") or "")
            rel_year = _s(selected_release.get("year") or details.get("year") or "")
            rgid = _s(selected_release.get("mb_releasegroupid") or details.get("mb_releasegroupid") or "")
            log.append(f"MusicBrainz recording lookup returned {linked_count} linked release(s); selected release context: {rel_title or '(unknown release)'} {rel_year or ''} {rgid or ''}".strip())
            if not rgid:
                log.append("Album/release identity remains under review; no Release Group ID was attached from the recording candidate.")
        else:
            log.append("MusicBrainz recording lookup returned no linked releases; album identity remains under review.")
        _invalidate_lib_cache()
        log.append("Review eligibility will be recalculated from the refreshed library state.")
        _trigger_plex_refresh(log)
        log.append("Recording ID attached and item synced/moved.")
    job = jobs.start_python(_do, label=f"Attach recording ID: item {iid}")
    return jsonify({"ok": True, "job_id": job.job_id})


def _format_duration(seconds: Any) -> str:
    try:
        total = int(round(float(seconds or 0)))
    except Exception:
        total = 0
    if total <= 0:
        return ""
    hours, rem = divmod(total, 3600)
    minutes, secs = divmod(rem, 60)
    if hours:
        return f"{hours}:{minutes:02d}:{secs:02d}"
    return f"{minutes}:{secs:02d}"

def _item_ai_abs_path(item) -> str:
    path_text = _s(getattr(item, "path", "")).strip()
    if path_text and not Path(path_text).is_absolute():
        path_text = str(MUSIC_ROOT / path_text)
    return path_text


def _track_ai_norm(value: str) -> str:
    import unicodedata

    text = unicodedata.normalize("NFKD", _s(value).casefold())
    text = "".join(ch for ch in text if not unicodedata.combining(ch))
    text = text.replace("&", " and ")
    text = re.sub(r"\b(?:feat|ft|featuring)\.?\s+.*$", "", text, flags=re.I)
    text = re.sub(r"[^a-z0-9]+", " ", text)
    return " ".join(text.split())


def _track_ai_similarity(left: str, right: str) -> float:
    from difflib import SequenceMatcher

    a = _track_ai_norm(left)
    b = _track_ai_norm(right)
    if not a or not b:
        return 0.0
    score = SequenceMatcher(None, a, b).ratio()
    if set(a.split()) & set(b.split()):
        score = max(score, 0.70)
    return score


def _score_track_ai_candidate(current: Dict[str, Any], search_title: str,
                              search_artist: str, filename: str,
                              candidate: Dict[str, Any]) -> Dict[str, Any]:
    try:
        title_variants = _album_track_title_variants(
            current.get("title") or search_title or filename,
            filename,
        )
    except Exception:
        title_variants = [_track_ai_norm(current.get("title") or search_title or filename)]
    cand_title = _s(candidate.get("title", ""))
    cand_artist = _s(candidate.get("artist", ""))
    cand_album = _s(candidate.get("album", ""))

    title_score = max(
        (_track_ai_similarity(v, cand_title) for v in title_variants if v),
        default=_track_ai_similarity(search_title, cand_title),
    )
    artist_score = _track_ai_similarity(search_artist or current.get("artist", ""), cand_artist)
    album_score = _track_ai_similarity(current.get("album", ""), cand_album)

    year_score = 0.5
    cur_year = _s(current.get("year", ""))
    cand_year = _s(candidate.get("year", ""))
    if cur_year[:4].isdigit() and cand_year[:4].isdigit():
        delta = abs(int(cur_year[:4]) - int(cand_year[:4]))
        year_score = 1.0 if delta == 0 else (0.80 if delta == 1 else (0.55 if delta <= 3 else 0.0))

    mb_score = max(0.0, min(1.0, float(candidate.get("score") or 0) / 100.0))
    source = _s(candidate.get("source") or "mb").lower()
    acoustid_bonus = 0.22 if source == "acoustid" else 0.0
    total = (
        title_score * 0.38
        + artist_score * 0.27
        + album_score * 0.10
        + year_score * 0.05
        + mb_score * 0.10
        + acoustid_bonus
    )
    return {
        "title_score": round(title_score, 3),
        "artist_score": round(artist_score, 3),
        "album_score": round(album_score, 3),
        "year_score": round(year_score, 3),
        "mb_score": round(mb_score, 3),
        "source": source,
        "acoustid_bonus": acoustid_bonus,
        "total": round(min(1.0, max(0.0, total)), 4),
    }


def _track_ai_year(value: Any) -> str:
    text = _s(value).strip()
    m = re.match(r"^((?:19|20)\d{2})", text)
    return m.group(1) if m else ""


def _track_ai_parse_duration_seconds(value: Any) -> Optional[float]:
    if value in (None, ""):
        return None
    try:
        number = float(value)
        if number <= 0:
            return None
        return number / 1000.0 if number > 10000 else number
    except Exception:
        pass
    text = _s(value).strip()
    if not text:
        return None
    parts = text.split(":")
    try:
        if len(parts) == 2:
            return float(parts[0]) * 60.0 + float(parts[1])
        if len(parts) == 3:
            return float(parts[0]) * 3600.0 + float(parts[1]) * 60.0 + float(parts[2])
    except Exception:
        return None
    return None


def _track_ai_duration_seconds(current: Dict[str, Any]) -> Optional[float]:
    return _track_ai_parse_duration_seconds(
        current.get("duration_seconds")
        or current.get("duration")
        or current.get("length")
    )


def _track_ai_candidate_duration_seconds(candidate: Dict[str, Any], details: Dict[str, Any]) -> Optional[float]:
    release = candidate.get("selected_release") or details.get("selected_release") or {}
    return _track_ai_parse_duration_seconds(
        release.get("duration_ms")
        or candidate.get("duration_ms")
        or details.get("recording_length_ms")
        or candidate.get("duration")
    )


def _track_ai_release_match_score(current: Dict[str, Any], release: Dict[str, Any]) -> Dict[str, Any]:
    local_album = _s(current.get("album") or "")
    local_artist = _s(current.get("albumartist") or current.get("artist") or "")
    local_year = _track_ai_year(current.get("year"))
    release_album = _s(release.get("album") or "")
    release_artist = _s(release.get("artist") or "")
    release_year = _track_ai_year(release.get("year") or release.get("date"))
    album_score = _track_ai_similarity(local_album, release_album) if local_album and release_album else 0.0
    artist_score = _track_ai_similarity(local_artist, release_artist) if local_artist and release_artist else 0.0
    year_match = bool(local_year and release_year and local_year == release_year)
    year_delta = 99
    if local_year and release_year:
        try:
            year_delta = abs(int(local_year) - int(release_year))
        except Exception:
            year_delta = 99
    year_score = 1.0 if year_match else (0.75 if year_delta == 1 else (0.45 if year_delta <= 3 else 0.0))
    total = album_score * 0.48 + artist_score * 0.24 + year_score * 0.28
    return {
        "album_score": round(album_score, 3),
        "artist_score": round(artist_score, 3),
        "year_score": round(year_score, 3),
        "year_match": year_match,
        "year_delta": year_delta if year_delta != 99 else None,
        "total": round(total, 4),
    }


def _track_ai_best_linked_release(current: Dict[str, Any], candidate: Dict[str, Any], details: Dict[str, Any]) -> Optional[Dict[str, Any]]:
    linked = details.get("linked_releases") or candidate.get("linked_releases") or []
    if not linked:
        selected = details.get("selected_release") or candidate.get("selected_release") or {}
        return selected if isinstance(selected, dict) and selected else None
    preferred_albumid = _s(candidate.get("mb_albumid") or details.get("mb_albumid") or "").strip().lower()

    def _sort_key(release: Dict[str, Any]):
        match = _track_ai_release_match_score(current, release)
        preferred = 1 if preferred_albumid and _s(release.get("mb_albumid")).strip().lower() == preferred_albumid else 0
        primary = _s(release.get("release_group_primary_type")).casefold()
        albumish = 1 if primary == "album" else (0.5 if primary == "ep" else 0)
        country = _s(release.get("country")).upper()
        country_rank = 1 if country in {"US", "XW"} else 0
        return (match["total"], match["album_score"], 1 if match["year_match"] else 0, preferred, albumish, country_rank)

    ranked = sorted((r for r in linked if isinstance(r, dict)), key=_sort_key, reverse=True)
    candidate["linked_releases"] = ranked
    for release in ranked:
        release["local_match"] = _track_ai_release_match_score(current, release)
    return ranked[0] if ranked else None


def _track_ai_match_status(score: float, strong: float = 0.82, fuzzy: float = 0.68) -> str:
    if score >= strong:
        return "yes"
    if score >= fuzzy:
        return "fuzzy"
    return "no"


def _enrich_track_ai_candidate(current: Dict[str, Any], candidate: Dict[str, Any], details: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    details = details or {}
    mb_trackid = _s(candidate.get("mb_trackid") or details.get("recording_id") or "").strip().lower()
    if mb_trackid and not details:
        preferred_albumid = _s(candidate.get("mb_albumid") or next(iter(candidate.get("mb_albumids") or []), "")).strip()
        details = _fetch_mb_recording_details(mb_trackid, preferred_albumid)
    selected_release = _track_ai_best_linked_release(current, candidate, details) or {}
    recording_title = _s(details.get("recording_title") or candidate.get("recording_title") or candidate.get("title") or "")
    recording_artist = _s(details.get("recording_artist") or details.get("artist") or candidate.get("recording_artist") or candidate.get("artist") or "")
    release_title = _s(selected_release.get("album") or details.get("album") or candidate.get("album") or "")
    release_artist = _s(selected_release.get("artist") or details.get("albumartist") or candidate.get("release_artist") or "")
    release_year = _track_ai_year(selected_release.get("year") or selected_release.get("date") or details.get("year") or candidate.get("year"))
    local_title = _s(current.get("title") or "")
    local_artist = _s(current.get("artist") or current.get("albumartist") or "")
    local_album = _s(current.get("album") or "")
    local_year = _track_ai_year(current.get("year"))
    title_score = _track_ai_similarity(local_title, recording_title) if local_title and recording_title else 0.0
    artist_score = max(
        _track_ai_similarity(local_artist, recording_artist) if local_artist and recording_artist else 0.0,
        _track_ai_similarity(_s(current.get("albumartist") or ""), recording_artist) if current.get("albumartist") and recording_artist else 0.0,
    )
    album_score = _track_ai_similarity(local_album, release_title) if local_album and release_title else 0.0
    local_duration = _track_ai_duration_seconds(current)
    suggested_duration = _track_ai_candidate_duration_seconds(candidate, {**details, "selected_release": selected_release})
    duration_delta = None
    duration_status = "unknown"
    if local_duration and suggested_duration:
        duration_delta = abs(local_duration - suggested_duration)
        duration_status = "yes" if duration_delta <= 4 else ("tolerance" if duration_delta <= 10 else "conflict")
    year_status = "unknown"
    if local_year and release_year:
        year_status = "yes" if local_year == release_year else "conflict"
    release_group_id = _s(selected_release.get("mb_releasegroupid") or details.get("mb_releasegroupid") or candidate.get("mb_releasegroupid") or "").strip().lower()
    local_release_group_id = _s(current.get("mb_releasegroupid") or "").strip().lower()
    release_group_status = "unknown"
    if local_release_group_id and release_group_id:
        release_group_status = "yes" if local_release_group_id == release_group_id else "conflict"
    linked_releases = candidate.get("linked_releases") or details.get("linked_releases") or []
    matching_local_release = bool(
        linked_releases
        and any(
            (_track_ai_similarity(local_album, _s(r.get("album") or "")) >= 0.78 if local_album else False)
            and (not local_year or _track_ai_year(r.get("year") or r.get("date")) == local_year)
            for r in linked_releases
            if isinstance(r, dict)
        )
    )
    conflicts: List[str] = []
    if title_score and title_score < 0.68:
        conflicts.append("title_conflict")
    if artist_score and artist_score < 0.68:
        conflicts.append("artist_conflict")
    if local_album and release_title and album_score < 0.55:
        conflicts.append("album_conflict")
    if year_status == "conflict":
        conflicts.append("year_conflict")
    if duration_status == "conflict":
        conflicts.append("duration_conflict")
    if release_group_status == "conflict":
        conflicts.append("release_group_conflict")
    source = _s(candidate.get("source") or (candidate.get("_match_score") or {}).get("source") or "mb").lower()
    acoustid_score = _audio_identity_score(candidate) if source == "acoustid" else 0.0
    match_score = float((candidate.get("_match_score") or {}).get("total") or 0.0)
    evidence_supported = source == "acoustid" or match_score >= 0.78 or float(candidate.get("score") or 0) >= 90
    hard_conflict = "title_conflict" in conflicts or "artist_conflict" in conflicts
    needs_confirmation = bool(conflicts and not hard_conflict)
    if not mb_trackid:
        safety_result = "No verified match"
        safety_key = "none"
        recommended_action = "Search MusicBrainz manually"
    elif hard_conflict:
        safety_result = "Conflict"
        safety_key = "conflict"
        recommended_action = "Reject candidate"
    elif evidence_supported and not conflicts and title_score >= 0.82 and artist_score >= 0.72:
        safety_result = "Safe to attach"
        safety_key = "safe"
        recommended_action = "Attach Recording ID"
    else:
        safety_result = "Needs review"
        safety_key = "review"
        recommended_action = "Confirm conflicts, then attach Recording ID" if conflicts else "Use this candidate after review"
        needs_confirmation = True
    reason = _s(candidate.get("reason") or "")
    if not reason:
        if source == "acoustid":
            reason = "AcoustID fingerprint matched this recording; linked release context is ranked against local tags."
        else:
            reason = "MusicBrainz recording search matched the local title and artist clues."
    if matching_local_release and len(linked_releases) > 1:
        reason = f"{reason} Same recording appears on multiple releases; local album/year evidence selected the best linked release."
    decision = {
        "title_match": {"status": _track_ai_match_status(title_score), "score": round(title_score, 3), "local": local_title, "suggested": recording_title},
        "artist_match": {"status": _track_ai_match_status(artist_score), "score": round(artist_score, 3), "local": local_artist, "suggested": recording_artist},
        "album_match": {"status": _track_ai_match_status(album_score), "score": round(album_score, 3), "local": local_album, "suggested": release_title},
        "year_match": {"status": year_status, "local": local_year, "suggested": release_year},
        "duration_match": {"status": duration_status, "delta_seconds": round(duration_delta, 1) if duration_delta is not None else None},
        "release_group_match": {"status": release_group_status, "local": local_release_group_id, "suggested": release_group_id},
        "confidence_score": round(match_score or acoustid_score, 3),
        "safety_result": safety_result,
    }
    candidate.update({
        "candidate_type": "recording",
        "match_method": source,
        "source": source,
        "mb_trackid": mb_trackid,
        "mb_url": candidate.get("mb_url") or (f"https://musicbrainz.org/recording/{mb_trackid}" if mb_trackid else ""),
        "musicbrainz_url": candidate.get("mb_url") or (f"https://musicbrainz.org/recording/{mb_trackid}" if mb_trackid else ""),
        "recording_title": recording_title,
        "recording_artist": recording_artist,
        "title": recording_title or candidate.get("title", ""),
        "artist": recording_artist or candidate.get("artist", ""),
        "selected_release": selected_release,
        "linked_releases": linked_releases,
        "same_recording_release_count": len(linked_releases),
        "matching_local_release_found": matching_local_release,
        "release_title": release_title,
        "release_artist": release_artist,
        "release_date": _s(selected_release.get("date") or details.get("date") or ""),
        "release_year": release_year,
        "album": release_title or candidate.get("album", ""),
        "year": release_year or candidate.get("year", ""),
        "mb_albumid": _s(selected_release.get("mb_albumid") or details.get("mb_albumid") or candidate.get("mb_albumid") or "").strip().lower(),
        "mb_releasegroupid": release_group_id,
        "mb_releasegroupurl": _s(selected_release.get("mb_releasegroupurl") or details.get("mb_releasegroupurl") or ""),
        "track_number": _s(selected_release.get("track_number") or selected_release.get("track") or ""),
        "medium_position": selected_release.get("medium_position"),
        "country": _s(selected_release.get("country") or candidate.get("country") or ""),
        "medium_format": _s(selected_release.get("medium_format") or selected_release.get("media_format") or candidate.get("medium_format") or ""),
        "acoustid_score": round(acoustid_score, 3),
        "confidence": "high" if safety_key == "safe" else ("low" if safety_key in {"conflict", "none"} else "medium"),
        "confidence_score": round(match_score or acoustid_score, 3),
        "reason": reason,
        "conflicts": conflicts,
        "recommended_action": recommended_action,
        "requires_confirmation": needs_confirmation,
        "safety_result": safety_result,
        "safety_key": safety_key,
        "decision": decision,
    })
    return candidate


def _compact_track_ai_candidate(candidate: Optional[Dict[str, Any]]) -> Dict[str, Any]:
    c = candidate or {}
    score = c.get("_match_score") or {}
    try:
        candidate_index = int(c.get("candidate_index", -1))
    except Exception:
        candidate_index = -1
    selected_release = c.get("selected_release") or {}
    return {
        "candidate_index": candidate_index,
        "candidate_type": _s(c.get("candidate_type") or "recording"),
        "mb_trackid": _s(c.get("mb_trackid", "")),
        "mb_url": _s(c.get("mb_url") or c.get("musicbrainz_url") or ""),
        "musicbrainz_url": _s(c.get("musicbrainz_url") or c.get("mb_url") or ""),
        "title": _s(c.get("title", "")),
        "artist": _s(c.get("artist", "")),
        "recording_title": _s(c.get("recording_title") or c.get("title") or ""),
        "recording_artist": _s(c.get("recording_artist") or c.get("artist") or ""),
        "album": _s(c.get("album", "")),
        "year": _s(c.get("year", "")),
        "release_title": _s(c.get("release_title") or c.get("album") or ""),
        "release_artist": _s(c.get("release_artist") or selected_release.get("artist") or ""),
        "release_date": _s(c.get("release_date") or selected_release.get("date") or ""),
        "release_year": _s(c.get("release_year") or c.get("year") or ""),
        "country": _s(c.get("country", "")),
        "medium_format": _s(c.get("medium_format") or c.get("media_format") or ""),
        "track_number": _s(c.get("track_number") or c.get("track") or ""),
        "medium_position": c.get("medium_position"),
        "duration": _s(c.get("duration", "")),
        "source": _s(c.get("source") or score.get("source") or "mb"),
        "match_method": _s(c.get("match_method") or c.get("source") or score.get("source") or "mb"),
        "score": c.get("score") or 0,
        "match_total": round(float(score.get("total") or c.get("confidence_score") or 0), 3),
        "confidence": _s(c.get("confidence") or ""),
        "confidence_score": c.get("confidence_score"),
        "score_breakdown": score,
        "decision": c.get("decision") or {},
        "conflicts": c.get("conflicts") or [],
        "recommended_action": _s(c.get("recommended_action") or ""),
        "requires_confirmation": bool(c.get("requires_confirmation")),
        "safety_result": _s(c.get("safety_result") or ""),
        "safety_key": _s(c.get("safety_key") or ""),
        "reason": _s(c.get("reason") or ""),
        "acoustid_score": c.get("acoustid_score"),
        "mb_albumid": _s(c.get("mb_albumid", "")),
        "mb_albumids": c.get("mb_albumids", []) or [],
        "mb_releasegroupid": _s(c.get("mb_releasegroupid", "")),
        "mb_releasegroupurl": _s(c.get("mb_releasegroupurl", "")),
        "selected_release": selected_release,
        "linked_releases": (c.get("linked_releases") or [])[:12],
        "same_recording_release_count": c.get("same_recording_release_count") or len(c.get("linked_releases") or []),
        "matching_local_release_found": bool(c.get("matching_local_release_found")),
    }


def _track_ai_evidence_packet(iid: int, *, filename: str,
                              current: Dict[str, Any],
                              search_title: str,
                              search_artist: str,
                              suggestions: Dict[str, Any],
                              selected_candidate: Optional[Dict[str, Any]],
                              candidates: List[Dict[str, Any]],
                              acoustid_candidates: List[Dict[str, Any]],
                              discogs_candidates: List[Dict[str, Any]]) -> Dict[str, Any]:
    mb_trackid = _s(suggestions.get("mb_trackid", "")).strip().lower()
    try:
        selected_index = int((selected_candidate or {}).get("candidate_index", -1))
    except Exception:
        selected_index = -1
    top_acoustid = acoustid_candidates[0] if acoustid_candidates else {}
    fingerprint_status = "matched" if acoustid_candidates else "no_result"
    return {
        "use_case": "track_retag",
        "created_at": int(time.time()),
        "item_id": int(iid),
        "filename": filename,
        "current": dict(current),
        "search": {
            "title": search_title,
            "artist": search_artist,
        },
        "confidence": suggestions.get("confidence", ""),
        "reason": suggestions.get("reason", ""),
        "mb_trackid": mb_trackid,
        "mb_albumid": _s(suggestions.get("mb_albumid", "")).strip().lower(),
        "mb_valid": bool(suggestions.get("mb_valid")),
        "mb_candidate_valid": bool(selected_candidate),
        "candidate_index": selected_index,
        "selected_candidate": (
            _compact_track_ai_candidate(selected_candidate) if selected_candidate else {}
        ),
        "selected_recording_candidate": (
            _compact_track_ai_candidate(selected_candidate) if selected_candidate else {}
        ),
        "top_candidates": [_compact_track_ai_candidate(c) for c in candidates[:8]],
        "recording_candidates": [_compact_track_ai_candidate(c) for c in candidates[:8]],
        "missing_id_type": "Recording ID",
        "source_counts": {
            "acoustid": len(acoustid_candidates),
            "musicbrainz": max(0, len(candidates) - len(acoustid_candidates)),
            "discogs": len(discogs_candidates),
        },
        "fingerprint": {
            "status": fingerprint_status,
            "acoustid_status": "candidate" if acoustid_candidates else "no_result",
            "score": _audio_identity_score(top_acoustid) if top_acoustid else 0.0,
            "acoustid_id": _s(top_acoustid.get("acoustid_id") or "") if top_acoustid else "",
            "mb_trackid": _s(top_acoustid.get("mb_trackid") or "") if top_acoustid else "",
            "mb_releasegroupid": _s(top_acoustid.get("mb_releasegroupid") or "") if top_acoustid else "",
        },
        "validation": {
            "returned_track_in_candidates": bool(selected_candidate) if mb_trackid else False,
            "acoustid_available": bool(acoustid_candidates),
            "fingerprint_status": fingerprint_status,
            "trusted_for_apply": bool(selected_candidate),
        },
    }


@app.post("/api/items/<int:iid>/ai-suggest")
def ai_suggest(iid):
    item = lib.get_item(iid)
    if not item:
        return jsonify({"ok": False, "error": "Not found"})
    # AI is optional: gathering AcoustID/MusicBrainz/Discogs candidates below
    # runs unconditionally, so a missing/invalid key still yields a match.
    api_key = os.environ.get("OPENAI_API_KEY", "")
    ai_available = bool(api_key)

    item_path = _item_ai_abs_path(item)
    filename = Path(item_path or _s(item.path)).name
    raw_year  = str(item.year or "")
    # Normalise year: "20120923" → "2012", "2012-09-23" → "2012"
    clean_year = re.match(r'^((?:19|20)\d{2})', raw_year)
    clean_year = clean_year.group(1) if clean_year else raw_year

    current = {
        "title":       item.title       or "",
        "artist":      item.artist      or "",
        "album":       item.album       or "",
        "albumartist": item.albumartist or "",
        "year":        clean_year,
        "genre":       _s(getattr(item, "genre", "")) or "",
        "track":       item.track       or "",
        "label":       _s(getattr(item, "label", "")) or "",
        "mb_trackid":  _s(getattr(item, "mb_trackid", "")) or "",
        "mb_albumid":  _s(getattr(item, "mb_albumid", "")) or "",
        "mb_releasegroupid": _s(getattr(item, "mb_releasegroupid", "")) or "",
        "filename": filename,
        "source_path": item_path,
        "duration_seconds": float(getattr(item, "length", 0) or 0),
        "duration": _format_duration(float(getattr(item, "length", 0) or 0)),
    }

    # ── Pre-process: extract artist/title from "Artist - Title" filenames ──────
    # When the title tag contains "Artist - Title" or the filename does, split it.
    stem = Path(filename).stem
    # Strip leading track numbers: "01 - Title" → "Title"
    stem_clean = re.sub(r'^\d+\s*[-_.]\s*', '', stem).strip()

    search_title  = current["title"] or stem_clean
    search_artist = current["artist"] or current["albumartist"] or ""

    # If title looks like "Artist - Title" (and artist seems wrong/missing), split it
    _SPLIT_SCORE_THRESH = 0.4
    if " - " in search_title:
        parts = search_title.split(" - ", 1)
        candidate_artist, candidate_title = parts[0].strip(), parts[1].strip()
        # Use the split if the existing artist looks like station/label noise or is absent
        _junk_patterns = re.compile(
            r'radio|station|channel|network|records|music|media|official|vevo|'
            r'entertainment|group|label|^various',
            re.I)
        if (not search_artist or _junk_patterns.search(search_artist)
                or len(search_artist) > 30):
            search_title  = candidate_title
            search_artist = candidate_artist

    _mb_t, _mb_a = _clean_for_mb(search_title, search_artist)

    # ── 1. AcoustID fingerprint (most reliable) ───────────────────────────────
    acoustid_cands = _acoustid_lookup_cached(item_path) if item_path else []

    # ── 2. MusicBrainz text search ────────────────────────────────────────────
    mb_text_cands = _mb_recording_search(_mb_t, _mb_a, limit=6)
    # Broaden if nothing found
    if not mb_text_cands and _mb_a:
        mb_text_cands = _mb_recording_search(_mb_t, "", limit=6)

    # ── 3. Discogs (supplemental genre / label info) ──────────────────────────
    discogs_cands = _discogs_track_search(_mb_t, _mb_a, limit=3)

    # Merge AcoustID + MB, deduplicate by mb_trackid
    seen_ids: set = set()
    mb_candidates: List[Dict[str, Any]] = []
    for c in acoustid_cands + mb_text_cands:
        mid = c.get("mb_trackid", "")
        if mid and mid not in seen_ids:
            seen_ids.add(mid)
            c["source"] = c.get("source") or ("acoustid" if c in acoustid_cands else "mb")
            c["_match_score"] = _score_track_ai_candidate(
                current,
                _mb_t,
                _mb_a,
                filename,
                c,
            )
            mb_candidates.append(c)
    mb_candidates.sort(key=lambda c: c.get("_match_score", {}).get("total", 0), reverse=True)
    mb_candidates = mb_candidates[:8]
    for c in mb_candidates:
        try:
            _enrich_track_ai_candidate(current, c)
        except Exception as exc:
            c["enrichment_error"] = _s(exc)
    mb_candidates.sort(key=lambda c: c.get("_match_score", {}).get("total", 0), reverse=True)
    for idx, c in enumerate(mb_candidates):
        c["candidate_index"] = idx

    mb_section = ""
    if mb_candidates:
        lines = ["MusicBrainz/AcoustID candidates "
                 "(idx / match / score / title / artist / album / year / country / mb_trackid / source):"]
        for c in mb_candidates:
            ms = c.get("_match_score", {})
            lines.append(
                f"  [{c.get('candidate_index', -1)}] match={ms.get('total', 0):.2f} "
                f"mb={c['score']:3d} {c['title']} — {c['artist']} / "
                f"{c['album']} ({c['year']}) {c.get('country','')} "
                f"[{c['mb_trackid']}] via {c.get('source','mb')}")
        mb_section = "\n\n" + "\n".join(lines)

    discogs_section = ""
    if discogs_cands:
        dlines = ["Discogs candidates (artist / album / year / genre / format):"]
        for d in discogs_cands:
            dlines.append(f"  {d['artist']} — {d['album']} ({d['year']}) "
                          f"[{d['genre']}] {d['format']}")
        discogs_section = "\n\n" + "\n".join(dlines)

    prompt = (
        "You are a music metadata expert. A file was imported with incorrect or incomplete tags.\n\n"
        f"Filename: {filename}\n"
        "Current (possibly wrong) tags:\n" +
        "\n".join(f"  {k}: {v or '(empty)'}" for k, v in current.items()) +
        mb_section + discogs_section +
        "\n\n"
        "RULES — apply strictly:\n"
        "1. If AcoustID fingerprint candidates are available, prefer them over text-only matches and only use MB recordings from that candidate list.\n"
        "   Do not silently override strong contradictory fingerprint evidence; return low confidence and explain the conflict.\n"
        "2. If no AcoustID candidates are found, fall back to MusicBrainz text search results.\n"
        "   If choosing a MusicBrainz candidate, copy its mb_trackid exactly; do not invent a recording ID.\n"
        "3. FILENAME is the next most reliable clue. Filenames often follow 'Artist - Title' or "
        "'NN - Artist - Title' patterns — extract the correct title and artist from it.\n"
        "4. YEAR: output only a 4-digit year (e.g. 2012, not 20120923 or 2012-09-23).\n"
        "5. ARTIST: use the correct performing artist, not a radio station, label, or 'Various Artists'.\n"
        "6. ALBUM: if the file belongs to a known album, fill it in. Otherwise leave empty.\n"
        "7. RELEASE PREFERENCE: prefer US releases (country=US). If no equally strong US match exists, use Worldwide (country=XW) before other countries.\n"
        "8. FORMAT: prefer CD or Digital Media recordings. Avoid vinyl if a digital version exists.\n"
        "9. CONFIDENCE — set one of:\n"
        "   high:   certain of artist, title, year, and album\n"
        "   medium: reasonably sure but one field is uncertain\n"
        "   low:    guessing based on limited info\n\n"
        "Return ONLY a valid JSON object with these keys "
        "(include only what you are confident about):\n"
        "  title — clean track title only (no artist prefix)\n"
        "  artist — performing artist using feat. notation: e.g. 'Young Money feat. Lil Wayne & Curren$y'\n"
        "  album, albumartist, year (4-digit integer), genre, track (integer), tracktotal (integer),\n"
        "  disc (integer), disctotal (integer), label,\n"
        "  mb_trackid (recording UUID), mb_albumid (release UUID), mb_artistid (artist UUID),\n"
        "  confidence (high|medium|low), reason (one sentence)\n\n"
        'Example: {"title":"Poppin\' Them Bottles","artist":"Young Money feat. Lil Wayne, Curren$y & Mack Maine",'
        '"album":"Dedication 2","albumartist":"Lil Wayne","year":2006,"genre":"Hip-Hop","track":4,'
        '"mb_trackid":"b5316c12-b617-4086-a107-312eccfd12e7",'
        '"confidence":"high","reason":"AcoustID fingerprint matches Lil Wayne Dedication 2 mixtape"}'
    )
    payload = json.dumps({
        "model": "gpt-4o",
        "messages": [{"role": "user", "content": prompt}],
        "temperature": 0.1,
        "response_format": {"type": "json_object"},
    }).encode()
    ai_unavailable_reason = "" if ai_available else "OPENAI_API_KEY not configured"
    suggestions: Optional[Dict[str, Any]] = None
    if ai_available:
        req = urllib.request.Request(
            "https://api.openai.com/v1/chat/completions",
            data=payload,
            headers={"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"},
        )
        try:
            with urllib.request.urlopen(req, timeout=30) as resp:
                data = json.loads(resp.read())
            suggestions = json.loads(data["choices"][0]["message"]["content"])
        except Exception as exc:
            ai_available = False
            ai_unavailable_reason = _classify_openai_error(exc)

    if suggestions is None:
        # AI unavailable/failed -- fall back to the top-ranked AcoustID/
        # MusicBrainz candidate (already gathered above) instead of
        # returning ok=False.
        if mb_candidates:
            top = mb_candidates[0]
            top_score = float((top.get("_match_score") or {}).get("total", 0) or 0)
            suggestions = {
                "title": top.get("title", "") or current["title"],
                "artist": top.get("artist", "") or current["artist"],
                "album": top.get("album", "") or current["album"],
                "year": str(top.get("year") or current["year"] or ""),
                "genre": top.get("genre", "") or current["genre"],
                "label": top.get("label", "") or current["label"],
                "mb_trackid": top.get("mb_trackid", ""),
                "mb_albumid": top.get("mb_albumid", ""),
                "confidence": "medium" if top_score >= 0.75 else "low",
                "reason": f"Matched using MusicBrainz and AcoustID (AI unavailable: {ai_unavailable_reason}).",
            }
        else:
            suggestions = {
                "confidence": "low",
                "reason": f"No MusicBrainz/AcoustID candidates found, and AI is unavailable ({ai_unavailable_reason}).",
            }

    try:
        # Coerce numeric fields
        for f in ("year", "track", "tracktotal", "disc", "disctotal"):
            if f in suggestions:
                suggestions[f] = str(suggestions[f])
        # Clamp year to 4 digits
        if suggestions.get("year"):
            _ym = re.match(r'^((?:19|20)\d{2})', str(suggestions["year"]))
            if _ym:
                suggestions["year"] = _ym.group(1)
        # Ensure confidence and reason are always present
        if not suggestions.get("confidence"):
            suggestions["confidence"] = "medium"
        if not suggestions.get("reason"):
            suggestions["reason"] = ""
        # Validate mb_trackid
        _MB_RE = r"^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$"
        mb_trackid  = (suggestions.get("mb_trackid")  or "").strip()
        mb_albumid  = (suggestions.get("mb_albumid")  or "").strip()
        mb_artistid = (suggestions.get("mb_artistid") or "").strip()
        selected_candidate = None
        candidate_index = -1
        if mb_trackid:
            target_trackid = mb_trackid.strip().lower()
            for c in mb_candidates:
                if _s(c.get("mb_trackid", "")).strip().lower() == target_trackid:
                    selected_candidate = c
                    try:
                        candidate_index = int(c.get("candidate_index", -1))
                    except Exception:
                        candidate_index = -1
                    break
        suggestions["candidate_index"] = candidate_index
        suggestions["mb_candidate_valid"] = bool(selected_candidate)
        suggestions["mb_trusted"] = bool(selected_candidate)
        if mb_trackid and mb_candidates and not selected_candidate:
            if _s(suggestions.get("confidence")).lower() == "high":
                suggestions["confidence"] = "low"
            reason = _s(suggestions.get("reason")).strip()
            guard = "AI returned a MusicBrainz recording ID that was not in the AcoustID/MusicBrainz candidate list; review before applying."
            suggestions["reason"] = f"{guard} {reason}".strip()
        suggestions["mb_valid"] = bool(re.match(_MB_RE, mb_trackid, re.I))
        if not suggestions["mb_valid"]:
            suggestions["mb_trusted"] = False
            suggestions["mb_apply_warning"] = (
                "No validated MusicBrainz recording ID was returned; review text tags manually before applying."
            )
            if _s(suggestions.get("confidence")).lower() == "high":
                suggestions["confidence"] = "medium"
            reason = _s(suggestions.get("reason")).strip()
            guard = suggestions["mb_apply_warning"]
            if guard not in reason:
                suggestions["reason"] = f"{guard} {reason}".strip()
        if suggestions["mb_valid"]:
            suggestions["mb_url"] = f"https://musicbrainz.org/recording/{mb_trackid}"
            # Fetch full recording details from MB to fill remaining fields
            if selected_candidate:
                try:
                    preferred_albumid = (
                        mb_albumid
                        or _s(selected_candidate.get("mb_albumid", "")).strip()
                        or next(iter(selected_candidate.get("mb_albumids") or []), "")
                    )
                    details = _fetch_mb_recording_details(mb_trackid, preferred_albumid)
                    _enrich_track_ai_candidate(current, selected_candidate, details)
                    # Fields MB fills authoritatively (override AI guesses)
                    _mb_authoritative = {"artist", "mb_albumid", "mb_artistid",
                                         "track", "tracktotal", "disc", "disctotal",
                                         "label", "genre", "album", "year"}
                    for k, v in details.items():
                        if v and (k in _mb_authoritative or not suggestions.get(k)):
                            suggestions[k] = v
                    # Re-read possibly-updated mb_albumid
                    mb_albumid = (suggestions.get("mb_albumid") or "").strip()
                except Exception:
                    pass
        if selected_candidate:
            selected_packet = _compact_track_ai_candidate(selected_candidate)
            suggestions["candidate_type"] = "recording"
            suggestions["candidate_evidence"] = selected_packet
            suggestions["selected_recording_candidate"] = selected_packet
            suggestions["selected_release"] = selected_packet.get("selected_release") or {}
            suggestions["linked_releases"] = selected_packet.get("linked_releases") or []
            suggestions["conflicts"] = selected_packet.get("conflicts") or []
            suggestions["recommended_action"] = selected_packet.get("recommended_action") or ""
            suggestions["requires_confirmation"] = bool(selected_packet.get("requires_confirmation"))
            suggestions["safety_result"] = selected_packet.get("safety_result") or ""
            suggestions["confidence_score"] = selected_packet.get("confidence_score")
            suggestions["match_method"] = selected_packet.get("match_method") or selected_packet.get("source")
        suggestions["recording_candidates"] = [_compact_track_ai_candidate(c) for c in mb_candidates[:8]]
        suggestions["missing_id_type"] = "Recording ID"
        if re.match(_MB_RE, (suggestions.get("mb_albumid") or ""), re.I):
            suggestions["mb_album_url"] = (
                f"https://musicbrainz.org/release/{suggestions['mb_albumid']}")
        evidence = _track_ai_evidence_packet(
            iid,
            filename=filename,
            current=current,
            search_title=_mb_t,
            search_artist=_mb_a,
            suggestions=suggestions,
            selected_candidate=selected_candidate,
            candidates=mb_candidates,
            acoustid_candidates=acoustid_cands,
            discogs_candidates=discogs_cands,
        )
        suggestions["ai_available"] = ai_available
        suggestions["ai_unavailable_reason"] = ai_unavailable_reason
        suggestions["evidence"] = evidence
        return jsonify({"ok": True, "suggestions": suggestions,
                        "mb_candidates": mb_candidates,
                        "selected_candidate": _compact_track_ai_candidate(selected_candidate) if selected_candidate else {},
                        "evidence": evidence,
                        "acoustid_candidates": acoustid_cands,
                        "discogs_candidates": discogs_cands})
    except Exception as exc:
        return jsonify({"ok": False, "error": str(exc)})


def _discogs_track_search(title: str, artist: str, limit: int = 5) -> List[Dict[str, Any]]:
    """Search Discogs for track/release candidates. Returns list of candidate dicts."""

    if not DISCOGS_TOKEN or not (title or artist):
        return []
    params = _up.urlencode({
        "q":      f"{artist} {title}".strip(),
        "type":   "release",
        "per_page": limit,
        "page":   1,
        "token":  DISCOGS_TOKEN,
    })
    headers = {
        "User-Agent": "BeetsWebControl/1.0",
        "Authorization": f"Discogs token={DISCOGS_TOKEN}",
    }
    try:
        req = _ur.Request(f"https://api.discogs.com/database/search?{params}", headers=headers)
        with _ur.urlopen(req, timeout=12) as r:
            data = json.loads(r.read())
    except Exception:
        return []
    out = []
    for rel in (data.get("results") or [])[:limit]:
        rel_title = rel.get("title", "")          # "Artist - Album" format
        year      = str(rel.get("year") or "")
        country   = rel.get("country") or ""
        format_   = ", ".join(rel.get("format") or [])
        genres    = ", ".join(rel.get("genre") or [])
        discogs_id = rel.get("id")
        discogs_url = f"https://www.discogs.com/release/{discogs_id}" if discogs_id else ""
        # title is "Artist - Album"; extract if possible
        if " - " in rel_title:
            parts = rel_title.split(" - ", 1)
            d_artist, d_album = parts[0].strip(), parts[1].strip()
        else:
            d_artist, d_album = "", rel_title
        out.append({
            "score":       85,   # Discogs doesn't give a relevance score; use fixed
            "discogs_id":  discogs_id,
            "discogs_url": discogs_url,
            "artist":      d_artist,
            "album":       d_album,
            "year":        year,
            "country":     country,
            "format":      format_,
            "genre":       genres,
            "source":      "discogs",
        })
    return out


def _discogs_release_fallback_candidate(artist: str, album: str) -> Dict[str, Any]:
    """Best-effort Discogs release match for when MusicBrainz search finds
    nothing at all. Discogs' catalog is far larger than MusicBrainz's for a
    lot of regional/independent/reissue releases, so a Discogs hit here is
    useful two ways: its cleaner artist/album text can succeed at a retry
    MusicBrainz search that the raw folder-name guess couldn't, and even
    when MusicBrainz still has nothing, surfacing the Discogs match gives a
    reviewer something concrete to submit to MusicBrainz instead of a bare
    "no candidates found". Returns {} if Discogs isn't configured, nothing
    was found, or the top result's artist looks unrelated to the query.
    """
    if not DISCOGS_TOKEN or not (artist or album):
        return {}
    results = _discogs_track_search(album, artist, limit=5)
    if not results:
        return {}
    best = results[0]
    if artist and best.get("artist"):
        from difflib import SequenceMatcher
        similarity = SequenceMatcher(None, _s(best.get("artist")).lower(), _s(artist).lower()).ratio()
        if similarity < 0.55:
            return {}
    return best


def _discogs_artist_discography(artist_name: str) -> Dict[str, Any]:
    """Fetch artist releases from Discogs and compare against disk. Returns same shape as _fetch_discography."""

    if not DISCOGS_TOKEN:
        return {"ok": False, "error": "DISCOGS_TOKEN not set"}
    # Step 1: find artist
    q = _up.urlencode({"q": artist_name, "type": "artist", "per_page": 5, "page": 1, "token": DISCOGS_TOKEN})
    headers = {"User-Agent": "BeetsWebControl/1.0", "Authorization": f"Discogs token={DISCOGS_TOKEN}"}
    try:
        req = _ur.Request(f"https://api.discogs.com/database/search?{q}", headers=headers)
        with _ur.urlopen(req, timeout=15) as r:
            results = json.loads(r.read()).get("results") or []
    except Exception as exc:
        return {"ok": False, "error": str(exc)}
    if not results:
        return {"ok": False, "error": f"Artist '{artist_name}' not found on Discogs"}
    artist_hit = max(results, key=lambda r: _discogs_artist_score(r, artist_name))
    artist_id   = artist_hit["id"]
    artist_name_d = re.sub(r'\s+\(\d+\)\s*$', '', artist_hit.get("title") or artist_name)
    # Step 2: fetch releases (master releases = albums)
    releases: List[Dict] = []
    page = 1
    while page <= 5:
        time.sleep(1.1)   # Discogs: 60 req/min
        q2 = _up.urlencode({"sort": "year", "sort_order": "asc", "per_page": 100, "page": page, "token": DISCOGS_TOKEN})
        try:
            req2 = _ur.Request(f"https://api.discogs.com/artists/{artist_id}/releases?{q2}", headers=headers)
            with _ur.urlopen(req2, timeout=15) as r2:
                page_data = json.loads(r2.read())
        except Exception:
            break
        items = page_data.get("releases") or []
        if not items:
            break
        # Keep only albums and masters (skip singles, compilations)
        for rel in items:
            rtype = (rel.get("type") or "").lower()
            role  = (rel.get("role")  or "").lower()
            # Include all master releases (canonical album entries on Discogs)
            # AND all releases where the artist has a main/primary role
            if rtype == "master" or role == "main":
                releases.append(rel)
        pagination = page_data.get("pagination") or {}
        if page >= (pagination.get("pages") or 1):
            break
        page += 1
    # Step 3: compare against disk
    # (MUSIC_ROOT is a module-level constant)
    album_index = _artist_album_index(artist_name)
    have: List[Dict]    = []
    missing: List[Dict] = []
    seen_titles: set    = set()
    for rel in releases:
        title = (rel.get("title") or "").strip()
        year  = str(rel.get("year") or "")
        if not title:
            continue
        norm = _normalize_album(title)
        if norm in seen_titles:
            continue
        seen_titles.add(norm)
        discogs_id  = rel.get("main_release") or rel.get("id")
        discogs_url = f"https://www.discogs.com/release/{discogs_id}" if discogs_id else f"https://www.discogs.com/artist/{artist_id}"
        matched, match_reason = _album_title_match(title, album_index)
        entry = {
            "album": title, "year": year, "discogs_url": discogs_url,
            "discogs_id": discogs_id, "role": rel.get("role", ""),
            "release_type": rel.get("type", ""), "match_reason": match_reason,
        }
        if matched:
            have.append(entry)
        else:
            missing.append(entry)
    missing.sort(key=lambda r: r["year"] or "9999")
    have.sort(key=lambda r: r["year"] or "9999")
    return {"ok": True, "source": "discogs", "artist": artist_name_d,
            "discogs_artist_id": artist_id, "have": have, "missing": missing,
            "total": len(have) + len(missing)}


@app.get("/api/items/<int:iid>/mb-candidates")
def item_mb_candidates(iid):
    """Search MusicBrainz for recording candidates for a library track."""
    item = lib.get_item(iid)
    if not item:
        return jsonify({"ok": False, "error": "Not found"})
    raw_title  = item.title or ""
    raw_artist = item.artist or item.albumartist or ""
    title, artist = _clean_for_mb(raw_title, raw_artist)
    candidates = _mb_recording_search(title, artist)
    return jsonify({"ok": True, "candidates": candidates, "query": {"title": title, "artist": artist}})


@app.get("/api/albums/<int:aid>/mb-candidates")
def album_mb_candidates(aid):
    """Search MusicBrainz for release candidates for a library album."""
    album = lib.get_album(aid)
    if not album:
        return jsonify({"ok": False, "error": "Not found"})
    candidates = _mb_release_search(album.album or "", album.albumartist or "")
    current_mbid = _s(getattr(album, "mb_albumid", "") or "").strip().lower()
    if current_mbid:
        for candidate in candidates:
            candidate["is_current"] = (
                _s(candidate.get("mb_albumid", "")).strip().lower() == current_mbid)
            for alt in candidate.get("edition_alternates") or []:
                if isinstance(alt, dict):
                    alt["is_current"] = (
                        _s(alt.get("mb_albumid", "")).strip().lower() == current_mbid)
    return jsonify({"ok": True, "candidates": candidates})


# ── Discography / Wanted ──────────────────────────────────────────────────────

def _normalize_album(s: str) -> str:
    """Normalise album title for fuzzy disk-vs-discography comparison."""
    s = _restore_time_colon_title(s or "").lower()
    s = s.replace("&", " and ")
    # Strip common edition suffixes
    s = re.sub(r'\s*[\(\[](deluxe|remaster(?:ed)?|expanded|anniversary|super|special|bonus|explicit|clean|edition|version|mono|stereo)[^\)\]]*[\)\]]', '', s, flags=re.I)
    s = re.sub(r'\s*-\s*(deluxe|remaster(?:ed)?|expanded|anniversary|super|special|bonus|explicit|clean|mono|stereo)\s*(edition|version)?\s*$', '', s, flags=re.I)
    s = re.sub(r'\s*\(\d{4}\)\s*$', '', s)       # strip trailing year
    s = re.sub(r'[^\w\s]', ' ', s)               # punct → space
    s = re.sub(r'\s+', ' ', s).strip()
    return s


def _album_key(s: str) -> str:
    """Compact album key used for fuzzy cross-source title matching."""
    key = re.sub(r'[^a-z0-9]', '', _normalize_album(s))
    if key:
        return key
    # Punctuation-only album titles like "+", "=", "÷", and "-" are real
    # releases. Preserve a symbol key so discography/Lidarr matching does not
    # collapse them all into an empty string.
    raw = (s or "").lower().replace("&", " and ")
    raw = re.sub(r'\s*[\(\[]\d{4,8}[\)\]]\s*$', '', raw).strip()
    raw = re.sub(r'\s+', '', raw)
    return ("sym_" + urllib.parse.quote(raw, safe="")) if raw else ""


def _artist_name_key(s: str) -> str:
    return re.sub(r'[^a-z0-9]', '', (s or "").lower().replace("&", "and"))


def _split_mbid_values(value: str) -> List[str]:
    try:
        parts = _split_beets_multi(value)
    except NameError:
        parts = re.split(r'[\0;,]', str(value or ""))
    ids = []
    for part in parts:
        part = (part or "").strip().lower()
        if _MB_UUID_RE.match(part):
            ids.append(part)
    return ids


def _artist_library_mbid(artist_name: str) -> str:
    """Prefer the MusicBrainz artist ID already stamped in the Beets library."""
    target = _artist_name_key(artist_name)
    if not target:
        return ""
    counts: Counter = Counter()
    try:
        for ba in lib.albums([]):
            names = [
                _s(getattr(ba, "albumartist", "") or ""),
                _s(getattr(ba, "albumartist_credit", "") or ""),
            ]
            names += _split_beets_multi(_s(getattr(ba, "albumartists", "") or ""))
            names += _split_beets_multi(_s(getattr(ba, "albumartists_credit", "") or ""))
            if target not in {_artist_name_key(n) for n in names if n}:
                continue
            ids = (_split_mbid_values(_s(getattr(ba, "mb_albumartistids", "") or ""))
                   or _split_mbid_values(_s(getattr(ba, "mb_albumartistid", "") or "")))
            counts.update(ids)
    except Exception:
        pass
    return counts.most_common(1)[0][0] if counts else ""


def _artist_album_index(artist_name: str, mb_artistid: str = "") -> Dict[str, set]:
    """Return title/release-group keys known locally for an artist."""
    title_norms: set = set()
    title_keys: set = set()
    rgids: set = set()

    def add_title(title: str):
        norm = _normalize_album(title)
        key = _album_key(title)
        if norm:
            title_norms.add(norm)
        if key:
            title_keys.add(key)

    target_key = _artist_name_key(artist_name)
    candidate_dirs: List[Path] = []
    try:
        if MUSIC_ROOT.exists():
            exact = MUSIC_ROOT / artist_name
            if exact.exists() and exact.is_dir():
                candidate_dirs.append(exact)
            for d in MUSIC_ROOT.iterdir():
                if d.is_dir() and _artist_name_key(d.name) == target_key and d not in candidate_dirs:
                    candidate_dirs.append(d)
    except Exception:
        pass

    for adir in candidate_dirs:
        try:
            for d in adir.iterdir():
                if d.is_dir():
                    add_title(re.sub(r'\s*[\(\[]\d{4,8}[\)\]]\s*$', '', d.name).strip())
        except Exception:
            pass

    try:
        for ba in lib.albums([]):
            names = [
                _s(getattr(ba, "albumartist", "") or ""),
                _s(getattr(ba, "albumartist_credit", "") or ""),
            ]
            ids = (_split_mbid_values(_s(getattr(ba, "mb_albumartistids", "") or ""))
                   or _split_mbid_values(_s(getattr(ba, "mb_albumartistid", "") or "")))
            name_match = target_key in {_artist_name_key(n) for n in names if n}
            id_match = bool(mb_artistid and mb_artistid.lower() in ids)
            if not (name_match or id_match):
                continue
            add_title(_s(getattr(ba, "album", "") or ""))
            rgid = _s(getattr(ba, "mb_releasegroupid", "") or "").strip().lower()
            if _MB_UUID_RE.match(rgid):
                rgids.add(rgid)
    except Exception:
        pass

    return {"norms": title_norms, "keys": title_keys, "rgids": rgids}


def _album_title_match(title: str, index: Dict[str, set], *, rgid: str = "") -> tuple:
    """Return (matched, reason) for a remote release title against local albums."""
    if rgid and rgid.lower() in index.get("rgids", set()):
        return True, "release-group-id"
    norm = _normalize_album(title)
    key = _album_key(title)
    if norm and norm in index.get("norms", set()):
        return True, "title"
    if key and key in index.get("keys", set()):
        return True, "title"
    if key:
        for other in index.get("keys", set()):
            if len(key) >= 8 and len(other) >= 8 and (key in other or other in key):
                return True, "fuzzy-title"
            if len(key) >= 8 and len(other) >= 8 and difflib.SequenceMatcher(None, key, other).ratio() >= 0.92:
                return True, "fuzzy-title"
    return False, ""


def _discogs_artist_score(result: Dict[str, Any], artist_name: str) -> int:
    """Score Discogs artist search results so aliases do not always pick the first hit."""
    raw = (result.get("title") or "").strip()
    title = re.sub(r'\s+\(\d+\)\s*$', '', raw)
    want = _artist_name_key(artist_name)
    got = _artist_name_key(title)
    if got == want:
        return 100
    if want and (want in got or got in want):
        return 75
    return 0


# ── slskd + yt-dlp Album Download ─────────────────────────────────────────────

def _slskd_req(method: str, path: str, body=None) -> Any:
    """Thin wrapper for slskd REST API using the API key."""
    if not SLSKD_API_KEY:
        raise RuntimeError(
            "slskd API key is not configured; set SLSKD_API_KEY or /config/slskd_api_key"
        )
    url  = f"{SLSKD_URL}/api/v0/{path.lstrip('/')}"
    hdrs = {"X-API-Key": SLSKD_API_KEY, "Accept": "application/json"}
    data = None
    if body is not None:
        hdrs["Content-Type"] = "application/json"
        data = json.dumps(body).encode()
    req = _ur.Request(url, data=data, headers=hdrs, method=method)
    try:
        with _ur.urlopen(req, timeout=20) as r:
            raw = r.read()
            return json.loads(raw) if raw.strip() else {}
    except urllib.error.HTTPError as e:
        raise RuntimeError(
            f"slskd {method} /{path} → HTTP {e.code}: "
            f"{e.read()[:300].decode('utf-8', 'replace')}")


def _normalise_wanted_tracks(raw) -> List[Dict[str, Any]]:
    """Return a compact list of wanted MB tracks from UI/API payloads."""
    if not raw:
        return []
    if isinstance(raw, str):
        try:
            raw = json.loads(raw)
        except Exception:
            return []
    if isinstance(raw, dict):
        raw = raw.get("missing") or raw.get("tracks") or raw.get("wanted") or []
    if not isinstance(raw, list):
        return []

    tracks: List[Dict[str, Any]] = []
    seen: set = set()
    for item in raw:
        if not isinstance(item, dict):
            continue
        try:
            disc = int(item.get("disc") or item.get("medium") or 1)
        except Exception:
            disc = 1
        try:
            track = int(item.get("track") or item.get("position") or item.get("number") or 0)
        except Exception:
            track = 0
        title = _s(item.get("title") or item.get("name") or "").strip()
        mb_trackid = _s(item.get("mb_trackid") or item.get("recording_id") or "").strip().lower()
        if not track and not title and not mb_trackid:
            continue
        key = (disc, track, _slskd_title_norm(title), mb_trackid)
        if key in seen:
            continue
        seen.add(key)
        tracks.append({
            "disc": max(disc, 1),
            "track": max(track, 0),
            "title": title,
            "mb_trackid": mb_trackid,
        })
    tracks.sort(key=lambda t: (int(t.get("disc") or 1), int(t.get("track") or 0), t.get("title", "")))
    return tracks


def _slskd_title_norm(value: str) -> str:
    text = _strip_track_filename_id_suffix(value).casefold().replace("&", " and ")
    text = re.sub(r"\b(?:feat|ft)\.?\s+.*$", "", text, flags=re.IGNORECASE)
    text = re.sub(r"\s*[\(\[]\s*(?:feat\.?|ft\.?|with|prod\.?|produced\s+by|remix|edit|version|bonus|clean|explicit).*?[\)\]]\s*", " ", text, flags=re.IGNORECASE)
    text = re.sub(r"[^a-z0-9]+", " ", text)
    return " ".join(text.split())


def _slskd_track_numbers_from_name(name: str) -> List[tuple]:
    stem = _strip_track_filename_id_suffix(Path(_s(name).replace("\\", "/")).stem)
    nums: List[tuple] = []

    def _add(disc: int, track: int) -> None:
        if track <= 0:
            return
        val = (max(disc, 0), track)
        if val not in nums:
            nums.append(val)

    m = re.match(r"^\s*(\d{1,2})[\s._-]+(\d{1,3})(?=$|[\s.-])", stem)
    if m:
        _add(int(m.group(1)), int(m.group(2)))
    m = re.match(r"^\s*(\d{1,3})", stem)
    if m:
        raw_num = m.group(1)
        rest = stem[m.end(1):]
        if len(raw_num) >= 2 or not rest.strip() or re.match(r"^\s*[-_.]", rest):
            _add(0, int(raw_num))
    # Scene-style filenames often embed the track number after artist/album:
    # "2 Chainz-Based On A T.R.U. Story (Deluxe)-02-Crack".
    for m in re.finditer(r"(?:^|[\s._-])(\d{1,3})\s*[-_.]\s*(?=\D)", stem):
        if m.start(1) == 0 or len(m.group(1)) < 2:
            continue
        _add(0, int(m.group(1)))
    return nums


def _disc_number_from_path(path: str) -> int:
    try:
        parts = Path(_s(path).replace("\\", "/")).parts[:-1]
    except Exception:
        return 0
    for part in reversed(parts):
        match = re.search(
            r"(?i)(?:^|[^a-z0-9])(?:cd|disc|disk)\s*0*(\d{1,2})(?:[^a-z0-9]|$)",
            _s(part),
        )
        if match:
            try:
                return int(match.group(1))
            except Exception:
                return 0
    return 0


def _audio_position_from_path(path: str) -> tuple:
    nums = _slskd_track_numbers_from_name(Path(_s(path).replace("\\", "/")).name)
    disc, track = (nums[0] if nums else (0, 0))
    path_disc = _disc_number_from_path(path)
    if path_disc and (not disc or disc == 1):
        disc = path_disc
    return max(int(disc or 1), 1), max(int(track or 0), 0)


def _album_item_position_hints(item: Dict[str, Any]) -> tuple:
    try:
        disc = int(item.get("disc") or 1)
    except Exception:
        disc = 1
    try:
        track = int(item.get("track") or 0)
    except Exception:
        track = 0
    path = _s(item.get("path", ""))
    if path:
        path_disc, path_track = _audio_position_from_path(path)
        if path_track and (not track or track == path_track):
            track = path_track
        if path_disc and (disc <= 1 or path_disc != 1):
            disc = path_disc
    return max(disc, 1), max(track, 0)


def _slskd_title_guess_from_name(name: str) -> str:
    stem = _strip_track_filename_id_suffix(Path(_s(name).replace("\\", "/")).stem)
    scene_matches = [
        m for m in re.finditer(r"(?:^|[\s._-])(\d{1,3})\s*[-_.]\s*(?=\D)", stem)
        if m.start(1) > 0 and len(m.group(1)) >= 2
    ]
    filtered_scene_matches = []
    for m in scene_matches:
        prefix = stem[:m.start(1)]
        suffix = stem[m.end(1):]
        numeric_artist_alias = (
            re.match(r"^\s*\d{1,3}\s*[-_.]\s*$", prefix)
            and re.match(r"^[_.][A-Za-z][A-Za-z0-9_.]*[-–—]", suffix)
        )
        if not numeric_artist_alias:
            filtered_scene_matches.append(m)
    scene_matches = filtered_scene_matches
    if scene_matches:
        title = stem[scene_matches[-1].end():].strip(" -_.")
        if title:
            return title
    # Strip leading track/disc numbers without eating artist names like
    # "01-2_chainz-intro": that should become "2_chainz-intro" first, then
    # the scene artist prefix is removed below.
    stem = re.sub(r"^\s*\d{1,2}[\s._-]+\d{2,3}(?=[\s.-])[\s._-]+", "", stem)
    stem = re.sub(r"^\s*\d{1,3}\s*[\s._-]+\s*", "", stem)
    parts = [p.strip() for p in re.split(r"\s+-\s+", stem) if p.strip()]
    if len(parts) >= 2:
        stem = parts[-1]
    else:
        compact = stem.strip()
        m = re.match(r"^([a-z0-9]+(?:[_\.][a-z0-9]+){1,5})-(.+)$", compact, flags=re.IGNORECASE)
        if m:
            stem = m.group(2).strip()
        else:
            m = re.match(r"^([a-z0-9]+(?:[\s_\.]+[a-z0-9]+){1,5})-(.+)$", compact, flags=re.IGNORECASE)
            if m:
                stem = m.group(2).strip()
    return _strip_track_filename_id_suffix(stem)


def _wanted_track_key(track: Dict[str, Any]) -> tuple:
    mbid = _s(track.get("mb_trackid", "")).strip().lower()
    if mbid:
        return ("mbid", mbid)
    disc = int(track.get("disc") or 1)
    num = int(track.get("track") or 0)
    if num:
        return ("pos", disc, num)
    title = _slskd_title_norm(track.get("title", ""))
    return ("title", title) if title else ("unknown", "")


def _wanted_track_label(track: Dict[str, Any]) -> str:
    disc = int(track.get("disc") or 1)
    num = int(track.get("track") or 0)
    title = _s(track.get("title", "")).strip() or "Untitled"
    return f"{disc}.{num:02d} {title}" if num else title


def _slskd_file_wanted_match_score(remote_name: str,
                                   wanted_tracks: List[Dict[str, Any]]) -> Dict[str, Any]:
    """Score how strongly a remote Soulseek file matches the requested missing tracks."""
    wanted_tracks = _normalise_wanted_tracks(wanted_tracks)
    if not wanted_tracks:
        return {
            "ok": True,
            "score": 1.0,
            "reason": "no wanted-track filter",
            "track": {},
            "key": ("all", ""),
        }

    best: Dict[str, Any] = {
        "ok": False,
        "score": 0.0,
        "reason": "no wanted-track match",
        "track": {},
        "key": ("none", ""),
    }

    def _consider(score: float, reason: str, track: Dict[str, Any]) -> None:
        nonlocal best
        if score > float(best.get("score") or 0.0):
            best = {
                "ok": score >= _MISSING_TRACK_FILE_MATCH_SCORE,
                "score": round(score, 3),
                "reason": reason,
                "track": track,
                "key": _wanted_track_key(track),
            }

    file_title = _slskd_title_norm(_slskd_title_guess_from_name(remote_name))

    def _title_score(want_title: str) -> tuple:
        want_title = _slskd_title_norm(want_title)
        if not file_title or not want_title:
            return 0.0, "no title check"
        if file_title == want_title:
            return 0.98, "exact title"
        ratio = difflib.SequenceMatcher(None, file_title, want_title).ratio()
        if ratio >= _MISSING_TRACK_TITLE_FUZZY_SCORE:
            return ratio, f"title similarity {ratio:.0%}"
        shorter, longer = sorted((file_title, want_title), key=len)
        if len(shorter) >= 5 and shorter in longer:
            coverage = len(shorter) / max(1, len(longer))
            return max(0.86, min(0.93, coverage)), "title containment"
        return ratio, f"title mismatch {ratio:.0%}"

    nums = _slskd_track_numbers_from_name(remote_name)
    for disc, track_num in nums:
        for track in wanted_tracks:
            want_disc = int(track.get("disc") or 1)
            want_num = int(track.get("track") or 0)
            if not want_num or track_num != want_num:
                continue
            want_title = _slskd_title_norm(track.get("title", ""))
            title_score, title_reason = _title_score(want_title)
            if file_title and want_title and title_score < 0.70:
                continue
            if disc and disc == want_disc:
                score = 1.0 if not file_title or not want_title else max(0.92, min(1.0, title_score + 0.04))
                _consider(score, f"exact disc/track {want_disc}.{want_num:02d}, {title_reason}", track)
            elif not disc:
                score = 0.90 if not file_title or not want_title else max(0.86, min(0.94, title_score))
                _consider(score, f"track number {want_num:02d}, {title_reason}", track)

    if file_title:
        for track in wanted_tracks:
            want_title = _slskd_title_norm(track.get("title", ""))
            if not want_title:
                continue
            score, reason = _title_score(want_title)
            if score >= _MISSING_TRACK_TITLE_FUZZY_SCORE:
                _consider(score, reason, track)

    best["ok"] = float(best.get("score") or 0.0) >= _MISSING_TRACK_FILE_MATCH_SCORE
    return best


def _slskd_file_matches_wanted(remote_name: str, wanted_tracks: List[Dict[str, Any]]) -> bool:
    return bool(_slskd_file_wanted_match_score(remote_name, wanted_tracks).get("ok"))


def _wanted_tracks_satisfied_by_names(names: List[Any],
                                     wanted_tracks: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    wanted_tracks = _normalise_wanted_tracks(wanted_tracks)
    if not names or not wanted_tracks:
        return []
    best_by_key: Dict[tuple, Dict[str, Any]] = {}
    for raw in names:
        match = _slskd_file_wanted_match_score(_s(raw), wanted_tracks)
        if not match.get("ok"):
            continue
        track = match.get("track") or {}
        key = match.get("key") or _wanted_track_key(track)
        current = best_by_key.get(key)
        if current and float(current.get("score") or 0) >= float(match.get("score") or 0):
            continue
        best_by_key[key] = {
            "track": track,
            "score": float(match.get("score") or 0),
        }
    wanted_keys = {_wanted_track_key(t): t for t in wanted_tracks}
    return [
        wanted_keys[key]
        for key in wanted_keys
        if key in best_by_key
    ]


def _wanted_tracks_remaining_after_satisfied(
    wanted_tracks: List[Dict[str, Any]],
    satisfied_tracks: List[Dict[str, Any]],
) -> List[Dict[str, Any]]:
    wanted_tracks = _normalise_wanted_tracks(wanted_tracks)
    satisfied_keys = {_wanted_track_key(t) for t in _normalise_wanted_tracks(satisfied_tracks)}
    if not satisfied_keys:
        return wanted_tracks
    return [t for t in wanted_tracks if _wanted_track_key(t) not in satisfied_keys]


def _wanted_tracks_not_in_album(existing_album_id: int, mb_albumid: str,
                                wanted_tracks: List[Dict[str, Any]],
                                log: list) -> List[Dict[str, Any]]:
    """Filter a requested track list against the current library state."""
    if not existing_album_id or not mb_albumid:
        return wanted_tracks
    try:
        comp = _album_mb_completeness(existing_album_id, mb_albumid, log)
    except Exception as ex:
        log.append(f"  [import] WARN: could not refresh missing-track list: {ex}")
        return wanted_tracks

    missing_now = _normalise_wanted_tracks(comp.get("missing") or [])
    extra_count = int(comp.get("extra_count") or 0)
    if extra_count and not missing_now:
        log.append(
            f"  [import] Selected MusicBrainz release is complete, but album has "
            f"{extra_count} extra track(s) not on that release. Verify the edition or "
            "run Album Track Cleanup."
        )
    if not wanted_tracks:
        return missing_now
    filtered = _guard_filter_wanted_tracks_against_missing(
        wanted_tracks,
        missing_now,
        title_norm_fn=_slskd_title_norm,
    )
    skipped = len(wanted_tracks) - len(filtered)
    if skipped:
        log.append(f"  [import] Skipping {skipped} requested track(s) that are already in the library")
    return filtered


def _album_folder_for_album_id(album_id: int) -> str:
    """Return a best-effort library folder path for an album row."""
    if not album_id:
        return ""
    try:
        with _db(text_factory=bytes) as con:
            row = con.execute(
                "SELECT path FROM items WHERE album_id=? AND path IS NOT NULL "
                "ORDER BY disc, track, id LIMIT 1",
                (int(album_id),),
            ).fetchone()
    except Exception:
        row = None
    if not row:
        return ""
    raw = _s(row[0])
    if not raw:
        return ""
    fpath = Path(raw)
    if not fpath.is_absolute():
        fpath = MUSIC_ROOT / raw
    folder = fpath.parent
    if re.match(r'^(?:disc|cd|disk)\s*\d+$', folder.name, re.I):
        folder = folder.parent
    return str(folder)


def _source_audio_missing_track_scan(folder_path: str, existing_album_id: int,
                                     mb_albumid: str, log: list) -> Dict[str, Any]:
    """Classify source audio files against the still-missing MB tracks."""
    result: Dict[str, Any] = {
        "ok": False,
        "existing_album_id": int(existing_album_id or 0),
        "artist": "",
        "album": "",
        "audio_count": 0,
        "expected_count": 0,
        "in_library": 0,
        "missing_count": 0,
        "useful_files": [],
        "duplicate_files": [],
        "unknown_files": [],
        "wanted_tracks": [],
    }
    if not existing_album_id or not mb_albumid:
        return result
    source = Path(folder_path)
    if not source.exists() or not source.is_dir():
        return result

    try:
        comp = _album_mb_completeness(existing_album_id, mb_albumid, log)
    except Exception as ex:
        log.append(f"  [import] Existing-album scan warning: {ex}")
        return result
    missing = _normalise_wanted_tracks(comp.get("missing") or [])
    result["artist"] = _s(comp.get("artist", ""))
    result["album"] = _s(comp.get("album", ""))
    result["expected_count"] = int(comp.get("expected_count") or 0)
    result["in_library"] = int(comp.get("in_library") or 0)
    result["missing_count"] = len(missing)

    try:
        audio_files = sorted(
            [p for p in source.rglob("*") if p.is_file() and p.suffix.lower() in AUDIO_EXT],
            key=lambda p: str(p).lower(),
        )
    except Exception as ex:
        log.append(f"  [import] Source scan warning: {ex}")
        return result
    result["audio_count"] = len(audio_files)
    if not audio_files:
        result["ok"] = True
        return result

    mb = _fetch_mb_release_tracklist(mb_albumid, log)
    mb_tracks = mb.get("tracks") or []
    if not mb_tracks:
        return result

    release_title_counts: Dict[str, int] = {}
    for mbt in mb_tracks:
        title_norm = _album_track_norm(mbt.get("title", ""))
        if title_norm:
            release_title_counts[title_norm] = release_title_counts.get(title_norm, 0) + 1

    missing_mb_tracks = [
        t for t in mb_tracks
        if _guard_release_track_matches_missing_target(
            t,
            missing,
            title_norm_fn=_album_track_norm,
            release_title_counts=release_title_counts,
        )
    ]
    if not missing_mb_tracks:
        missing_mb_tracks = [
            {
                "disc": int(t.get("disc") or 1),
                "track": int(t.get("track") or 0),
                "title": _s(t.get("title", "")),
                "title_norm": _album_track_norm(t.get("title", "")),
                "mb_trackid": _s(t.get("mb_trackid", "")).strip().lower(),
                "duration_ms": int(t.get("duration_ms") or 0),
            }
            for t in missing
        ]

    selected_by_key: Dict[tuple, Dict[str, Any]] = {}
    for fpath in audio_files:
        disc, track = _audio_position_from_path(str(fpath))
        item = {
            "title": _slskd_title_guess_from_name(fpath.name) or fpath.stem,
            "path": str(fpath),
            "track": int(track or 0),
            "disc": int(disc or 1),
            "mb_trackid": "",
            "length": 0,
        }
        best_missing = _best_album_track_match(item, missing_mb_tracks)
        missing_idx = int(best_missing.get("idx", -1))
        missing_score = float(best_missing.get("score") or 0.0)
        if missing_idx >= 0 and missing_score >= _MB_TRACK_REPAIR_MATCH_THRESHOLD:
            mbt = best_missing.get("track") or {}
            key = (
                int(mbt.get("disc") or 1),
                int(mbt.get("track") or 0),
                _s(mbt.get("mb_trackid", "")).strip().lower(),
            )
            if key in selected_by_key:
                result["duplicate_files"].append(str(fpath))
                continue
            selected_by_key[key] = {
                "path": str(fpath),
                "disc": int(mbt.get("disc") or 1),
                "track": int(mbt.get("track") or 0),
                "title": _s(mbt.get("title", "")),
                "mb_trackid": _s(mbt.get("mb_trackid", "")).strip().lower(),
                "score": round(missing_score, 3),
            }
            continue

        best = _best_album_track_match(item, mb_tracks)
        idx = int(best.get("idx", -1))
        score = float(best.get("score") or 0.0)
        if idx >= 0 and score >= _MB_TRACK_REPAIR_MATCH_THRESHOLD:
            result["duplicate_files"].append(str(fpath))
        else:
            result["unknown_files"].append(str(fpath))

    selected = list(selected_by_key.values())
    selected.sort(key=lambda t: (int(t.get("disc") or 1), int(t.get("track") or 0), t.get("title", "")))
    result["useful_files"] = [t["path"] for t in selected]
    result["wanted_tracks"] = [
        {
            "disc": t["disc"],
            "track": t["track"],
            "title": t["title"],
            "mb_trackid": t["mb_trackid"],
        }
        for t in selected
    ]
    result["ok"] = True
    return result


def _folder_release_preflight(folder_path: str, mb_albumid: str,
                              existing_album_id: int = 0,
                              log: Optional[list] = None) -> Dict[str, Any]:
    """Check a folder/current album against an MB release before destructive repair."""
    result: Dict[str, Any] = {
        "ok": False,
        "matches": 0,
        "expected": 0,
        "audio_count": 0,
        "examples": [],
        "release_title": "",
        "release_artist": "",
        "release_group": "",
        "folder_artist": "",
        "artist_score": 0.0,
        "artist_ok": True,
        "acoustid_release_hits": {},
        "acoustid_target_hits": 0,
        "acoustid_top_release": "",
        "acoustid_top_hits": 0,
        "acoustid_mismatch": False,
        "error": "",
    }
    mb = _fetch_mb_release_tracklist(mb_albumid, log)
    if not mb.get("ok"):
        result["error"] = mb.get("error") or "MusicBrainz release lookup failed"
        return result
    mb_tracks = mb.get("tracks") or []
    result["expected"] = len(mb_tracks)
    result["release_title"] = mb.get("release_title", "")
    result["release_artist"] = mb.get("release_artist", "")
    result["release_group"] = mb.get("release_group", "")
    if not mb_tracks:
        result["error"] = "MusicBrainz release has no tracks"
        return result

    source = Path(folder_path)
    folder_artist = _artist_folder_name_without_mbid(
        source.parent.name if source.parent else ""
    )
    result["folder_artist"] = folder_artist
    try:
        import unicodedata
        from difflib import SequenceMatcher

        def _artist_key(value: str) -> str:
            value = unicodedata.normalize("NFKC", _s(value).casefold())
            value = value.replace("&", " and ")
            chars = [c if c.isalnum() else " " for c in value]
            return " ".join("".join(chars).split())

        folder_key = _artist_key(folder_artist)
        release_key = _artist_key(result["release_artist"])
        if folder_key and release_key:
            folder_tokens = set(folder_key.split())
            release_tokens = set(release_key.split())
            score = SequenceMatcher(None, folder_key, release_key).ratio()
            result["artist_score"] = round(score, 3)
            result["artist_ok"] = bool(folder_tokens & release_tokens) or score >= 0.48
    except Exception:
        result["artist_ok"] = True

    audio_files: List[Path] = []
    try:
        if source.is_dir():
            audio_files = sorted(
                [p for p in source.rglob("*")
                 if p.is_file() and p.suffix.lower() in AUDIO_EXT],
                key=lambda p: str(p).lower(),
            )
    except Exception as ex:
        result["error"] = f"Could not scan source folder: {ex}"
        return result
    result["audio_count"] = len(audio_files)

    acoustid_release_hits: Dict[str, int] = {}
    try:
        if audio_files:
            acoustid_release_hits = _acoustid_multi_file([str(p) for p in audio_files])
    except Exception as ex:
        if log is not None:
            log.append(f"  [preflight] AcoustID warning: {ex}")
    if acoustid_release_hits:
        target_mbid = _s(mb_albumid).strip().lower()
        target_hits = sum(
            int(hits or 0)
            for rid, hits in acoustid_release_hits.items()
            if _s(rid).strip().lower() == target_mbid
        )
        top_release, top_hits = max(
            acoustid_release_hits.items(),
            key=lambda item: int(item[1] or 0),
        )
        result.update({
            "acoustid_release_hits": acoustid_release_hits,
            "acoustid_target_hits": int(target_hits or 0),
            "acoustid_top_release": top_release,
            "acoustid_top_hits": int(top_hits or 0),
            "acoustid_mismatch": bool(
                target_mbid
                and top_release
                and _s(top_release).strip().lower() != target_mbid
                and int(target_hits or 0) == 0
            ),
        })

    candidates: List[Dict[str, Any]] = []
    seen_keys: set = set()

    def _add_candidate(title: str, path: str = "", track: int = 0,
                       disc: int = 1, mb_trackid: str = "",
                       length: float = 0.0) -> None:
        key = (_album_track_norm(title), _s(path), int(track or 0), int(disc or 1))
        if key in seen_keys:
            return
        seen_keys.add(key)
        candidates.append({
            "title": _s(title) or Path(_s(path)).stem,
            "path": _s(path),
            "track": int(track or 0),
            "disc": int(disc or 1),
            "mb_trackid": _s(mb_trackid).strip().lower(),
            "length": float(length or 0),
        })

    for fpath in audio_files:
        disc, track = _audio_position_from_path(str(fpath))
        _add_candidate(
            _slskd_title_guess_from_name(fpath.name) or fpath.stem,
            str(fpath),
            track=track,
            disc=disc or 1,
        )

    if existing_album_id:
        try:
            with _db(text_factory=bytes, row_factory=sqlite3.Row) as con:
                rows = con.execute(
                    "SELECT title, track, disc, path, mb_trackid, length "
                    "FROM items WHERE album_id=? ORDER BY disc, track, title, id",
                    (existing_album_id,),
                ).fetchall()
            for row in rows:
                _add_candidate(
                    _s(row["title"]),
                    _s(row["path"]),
                    track=int(row["track"] or 0),
                    disc=int(row["disc"] or 1),
                    mb_trackid=_s(row["mb_trackid"]),
                    length=float(row["length"] or 0),
                )
        except Exception as ex:
            if log is not None:
                log.append(f"  [preflight] Existing DB read warning: {ex}")

    matched_indices: set = set()
    best_lines: List[str] = []
    for item in candidates:
        best = _best_album_track_match(item, mb_tracks)
        idx = int(best.get("idx", -1))
        score = float(best.get("score") or 0.0)
        title_score = float(best.get("title_score") or 0.0)
        if idx >= 0 and (
            (best.get("exact_mbid") and title_score >= _MB_TRACK_REPAIR_MATCH_THRESHOLD)
            or (not best.get("exact_mbid") and score >= _MB_TRACK_PREFLIGHT_MATCH_THRESHOLD)
        ):
            matched_indices.add(idx)
        if len(best_lines) < 5:
            mbt = best.get("track") or {}
            best_lines.append(
                f"    {item.get('title','')!r} -> {mbt.get('title','?')!r} ({score:.0%})"
            )

    matches = len(matched_indices)
    expected = len(mb_tracks)
    min_required = max(1, min(expected, int(expected * 0.60)))
    # Do not demand 60% when importing a small missing subset into an existing album.
    if existing_album_id and audio_files and len(audio_files) < expected:
        min_required = max(1, min(len(audio_files), int(len(audio_files) * 0.60)))
    max_audio_allowed = expected + max(1, expected // 4)
    too_many_extras = (
        bool(audio_files)
        and len(audio_files) > max_audio_allowed
        and matches < max(1, int(len(audio_files) * 0.80))
    )
    if too_many_extras:
        result["error"] = (
            f"Folder has {len(audio_files)} audio file(s) but release has "
            f"{expected} track(s)"
        )
    match_ratio = matches / max(1, expected)
    source_match_ratio = matches / max(1, len(audio_files))
    # High track-match confidence overrides a failed artist check (handles artist renames, e.g. Kanye → Ye)
    artist_gate = bool(result.get("artist_ok", True)) or match_ratio >= 0.80
    oversized_subset = _preflight_oversized_subset_complete({
        **result,
        "matches": matches,
        "expected": expected,
        "audio_count": len(audio_files),
    })
    gate_ok = _preflight_tracklist_gate_ok(
        matches,
        min_required,
        artist_gate,
        too_many_extras,
        oversized_subset,
    )
    if (
        not gate_ok
        and not too_many_extras
        and audio_files
        and len(audio_files) <= 3
        and matches >= 1
        and source_match_ratio >= 1.0
    ):
        gate_ok = True
    result.update({
        "ok": gate_ok,
        "matches": matches,
        "min_required": min_required,
        "max_audio_allowed": max_audio_allowed,
        "too_many_extras": too_many_extras,
        "match_ratio": round(match_ratio, 3),
        "source_match_ratio": round(source_match_ratio, 3),
        "oversized_subset_complete": bool(oversized_subset),
        "examples": best_lines,
    })
    return result


def _preflight_review_reason(preflight: Optional[Dict[str, Any]],
                             default_reason: str) -> str:
    if not preflight:
        return default_reason

    matches = int(preflight.get("matches") or 0)
    expected = int(preflight.get("expected") or 0)
    audio_count = int(preflight.get("audio_count") or 0)
    min_required = int(preflight.get("min_required") or 0)
    release_title = _s(preflight.get("release_title")).strip()
    release_artist = _s(preflight.get("release_artist")).strip()
    folder_artist = _s(preflight.get("folder_artist")).strip()
    error = _s(preflight.get("error")).strip()

    release_label = "selected MusicBrainz release"
    if release_title or release_artist:
        release_name = " - ".join([v for v in (release_artist, release_title) if v])
        release_label = f"selected MusicBrainz release ({release_name})"

    parts: List[str] = []
    if preflight.get("oversized_subset_complete"):
        parts.append(_preflight_oversized_subset_summary(preflight))
    if expected or audio_count:
        parts.append(
            f"Rejected {release_label}: only {matches}/{expected or '?'} "
            f"release track(s) matched {audio_count} folder audio file(s)."
        )
    if min_required:
        parts.append(f"At least {min_required} matching track(s) were required.")
    if error:
        parts.append(error)
    if preflight.get("artist_ok") is False:
        artist_label = " / ".join([v for v in (folder_artist, release_artist) if v])
        if artist_label:
            parts.append(f"Artist check also failed ({artist_label}).")
        else:
            parts.append("Artist check also failed.")
    if preflight.get("acoustid_mismatch"):
        top_release = _s(preflight.get("acoustid_top_release")).strip()
        top_hits = int(preflight.get("acoustid_top_hits") or 0)
        target_hits = int(preflight.get("acoustid_target_hits") or 0)
        if top_release:
            parts.append(
                "AcoustID fingerprint mismatch: "
                f"selected release had {target_hits} hit(s), while release "
                f"{top_release} had {top_hits} hit(s)."
            )
        else:
            parts.append("AcoustID fingerprint mismatch against the selected release.")
    parts.append(
        "This looks like a mixed, mislabeled, or wrong-release folder. "
        "Choose a release whose tracklist matches the folder before retagging."
    )
    return " ".join(parts) if parts else default_reason


def _queue_folder_for_manual_review(folder_path: str, suggestion: Optional[dict],
                                    reason: str, log: Optional[list] = None,
                                    allow_existing: bool = False,
                                    evidence: Optional[Dict[str, Any]] = None,
                                    origin: Optional[Any] = None) -> bool:
    """Put a folder back in Import Review without failing the current job."""
    existing_ids = _library_album_ids_for_folder(folder_path)
    if existing_ids and not allow_existing:
        if log is not None:
            log.append(
                "  Skipped Pending Review: folder already belongs to "
                f"Beets album_id(s) {existing_ids}."
            )
        return False
    sug = dict(suggestion or {})
    sug["confidence"] = "low"
    sug["reason"] = reason
    if allow_existing:
        sug["allow_existing_review"] = True
        sug["existing_album_ids"] = existing_ids
    if sug.get("mb_albumid"):
        sug["rejected_mb_albumid"] = sug.get("mb_albumid")
    sug["mb_albumid"] = ""
    sug.pop("mb_url", None)
    # Force the user to verify the release instead of treating the bad match as importable.
    sug["mb_valid"] = False
    evidence = evidence or sug.get("review_evidence")
    if evidence:
        sug["review_evidence"] = evidence
    try:
        _add_to_pending(folder_path, sug, allow_existing=allow_existing, evidence=evidence, origin=origin)
        if log is not None:
            log.append("  Queued folder for manual Review; no library files were changed.")
        return True
    except Exception as ex:
        if log is not None:
            log.append(f"  WARN could not queue manual Review item: {ex}")
    return False


def _stage_selected_audio_files(aldir: str, audio_files: List[Path],
                                artist: str, album: str, log: list,
                                force_stage: bool = False,
                                target_tracks: Optional[List[Dict[str, Any]]] = None) -> str:
    """Copy a selected subset to a clean import folder when the source has extras."""
    return _stage_selected_audio_files_impl(
        DOWNLOADS_ROOT, AUDIO_EXT, aldir, audio_files, artist, album, log,
        force_stage=force_stage,
        target_tracks=target_tracks,
    )


def _db_item_file_exists(raw_path: str) -> bool:
    if not raw_path:
        return False
    fpath = Path(raw_path)
    if not fpath.is_absolute():
        fpath = MUSIC_ROOT / raw_path
    try:
        return fpath.exists() and fpath.is_file()
    except Exception:
        return False


def _prune_stale_wanted_rows_before_import(existing_album_id: int, mb_albumid: str,
                                           wanted_tracks: List[Dict[str, Any]],
                                           log: list) -> int:
    """Remove missing-file rows that would make Beets reject a downloaded replacement."""
    wanted = _normalise_wanted_tracks(wanted_tracks)
    if not existing_album_id or not wanted:
        return 0
    wanted_pairs = {
        (int(t.get("disc") or 1), int(t.get("track") or 0))
        for t in wanted if int(t.get("track") or 0)
    }
    wanted_mbids = {
        _s(t.get("mb_trackid", "")).strip().lower()
        for t in wanted if t.get("mb_trackid")
    }
    if not wanted_pairs and not wanted_mbids:
        return 0

    def _row_matches_wanted(row: sqlite3.Row) -> bool:
        pair = (int(row["disc"] or 1), int(row["track"] or 0))
        row_mbid = _s(row["mb_trackid"]) if "mb_trackid" in row.keys() else ""
        row_mbid = row_mbid.strip().lower()
        if pair[1] and pair in wanted_pairs:
            return True
        if row_mbid and row_mbid in wanted_mbids:
            return True
        item = {
            "title": _s(row["title"]) if "title" in row.keys() else "",
            "path": "",
            "disc": pair[0],
            "track": pair[1],
            "mb_trackid": row_mbid,
            "length": float(row["length"] or 0) if "length" in row.keys() else 0.0,
        }
        return any(
            _album_track_score(item, target) >= _MB_TRACK_REPAIR_MATCH_THRESHOLD
            for target in wanted
        )

    try:
        with _db(text_factory=bytes, row_factory=sqlite3.Row) as con:
            rows = con.execute(
                "SELECT id, title, disc, track, path, mb_trackid, length "
                "FROM items WHERE album_id=? ORDER BY disc, track, id",
                (int(existing_album_id),),
            ).fetchall()
            delete_ids: List[int] = []
            labels: List[str] = []
            for row in rows:
                raw_path = _s(row["path"]) if "path" in row.keys() else ""
                if _db_item_file_exists(raw_path):
                    continue
                if not _row_matches_wanted(row):
                    continue
                delete_ids.append(int(row["id"]))
                labels.append(
                    f"{int(row['disc'] or 1)}.{int(row['track'] or 0):02d} "
                    f"{_s(row['title'])}"
                )
            if not delete_ids:
                return 0
            con.execute(
                f"DELETE FROM items WHERE id IN ({','.join('?' * len(delete_ids))})",
                delete_ids,
            )
            con.commit()
        label_text = ", ".join(labels[:5])
        log.append(
            "  [import] Removed "
            f"{len(delete_ids)} stale missing DB row(s) before duplicate check"
            + (f": {label_text}" if label_text else "")
        )
        return len(delete_ids)
    except Exception as ex:
        log.append(f"  [import] WARN stale wanted-row cleanup skipped: {ex}")
        return 0


def _merge_imported_album_into_existing(imported_album_id: int, existing_album_id: int,
                                        source_folder: str, log: list,
                                        mb_albumid: str = "",
                                        replace_existing_item_ids: Optional[Iterable[int]] = None) -> int:
    """Move newly imported missing items onto an existing album row."""
    if not imported_album_id or not existing_album_id or imported_album_id == existing_album_id:
        return imported_album_id
    forced_replace_ids = {int(v) for v in (replace_existing_item_ids or []) if int(v or 0)}
    try:
        mb_tracks: List[Dict[str, Any]] = []
        target_by_key: Dict[tuple, Dict[str, Any]] = {}
        if mb_albumid:
            mb = _fetch_mb_release_tracklist(mb_albumid, log)
            if mb.get("ok"):
                mb_tracks = mb.get("tracks") or []
                target_by_key = {
                    (int(t.get("disc") or 1), int(t.get("track") or 0)): t
                    for t in mb_tracks
                    if int(t.get("track") or 0)
                }

        def _row_item(row: sqlite3.Row) -> Dict[str, Any]:
            return {
                "title": _s(row["title"]) if "title" in row.keys() else "",
                "path": _s(row["path"]) if "path" in row.keys() else "",
                "disc": int(row["disc"] or 1),
                "track": int(row["track"] or 0),
                "mb_trackid": _s(row["mb_trackid"]) if "mb_trackid" in row.keys() else "",
                "length": float(row["length"] or 0) if "length" in row.keys() else 0.0,
            }

        def _row_file_exists(row: sqlite3.Row) -> bool:
            raw_path = _s(row["path"]) if "path" in row.keys() else ""
            if not raw_path:
                return False
            fpath = Path(raw_path)
            if not fpath.is_absolute():
                fpath = MUSIC_ROOT / raw_path
            try:
                return fpath.exists() and fpath.is_file()
            except Exception:
                return False

        def _row_matches_target(row: sqlite3.Row, target: Dict[str, Any]) -> bool:
            if not target:
                return False
            item = _row_item(row)
            fp = _album_track_fingerprint_check(item, [target])
            fingerprint_status = _s(fp.get("status", ""))
            target_id = _s(target.get("mb_trackid", "")).strip().lower()
            item_id = _s(item.get("mb_trackid", "")).strip().lower()
            title_only_score = _album_track_score({**item, "path": ""}, target)
            return _guard_existing_track_can_block_downloaded_replacement(
                file_exists=_row_file_exists(row),
                fingerprint_status=fingerprint_status,
                exact_mbid=bool(item_id and target_id and item_id == target_id),
                title_score=title_only_score,
                repair_threshold=_MB_TRACK_REPAIR_MATCH_THRESHOLD,
            )

        def _delete_row_file(row: sqlite3.Row, reason: str) -> None:
            raw_path = _s(row["path"]) if "path" in row.keys() else ""
            if not raw_path:
                return
            fpath = Path(raw_path)
            if not fpath.is_absolute():
                fpath = MUSIC_ROOT / raw_path
            try:
                resolved = fpath.resolve(strict=False)
                if _path_is_under(resolved, MUSIC_ROOT):
                    resolved.unlink(missing_ok=True)
                    log.append(
                        f"  [merge] Removed {reason} track "
                        f"{int(row['track'] or 0):02d}: {resolved.name}"
                    )
            except Exception as ex:
                log.append(f"  [merge] WARN removing conflicting file: {ex}")

        with _db(text_factory=bytes, row_factory=sqlite3.Row) as con:
            existing = con.execute(
                "SELECT id, album, albumartist, mb_albumid, year FROM albums WHERE id=?",
                (existing_album_id,),
            ).fetchone()
            if not existing:
                log.append(f"  [merge] Existing album_id {existing_album_id} not found; keeping imported album_id {imported_album_id}")
                return imported_album_id
            existing_rows = con.execute(
                "SELECT id, title, disc, track, path, mb_trackid, length "
                "FROM items WHERE album_id=? ORDER BY disc, track, id",
                (existing_album_id,),
            ).fetchall()
            existing_by_key: Dict[tuple, List[sqlite3.Row]] = {}
            for row in existing_rows:
                key = (int(row["disc"] or 1), int(row["track"] or 0))
                if key[1]:
                    existing_by_key.setdefault(key, []).append(row)
            imported_rows = con.execute(
                "SELECT id, title, disc, track, path, mb_trackid, length "
                "FROM items WHERE album_id=? ORDER BY disc, track, id",
                (imported_album_id,),
            ).fetchall()
            move_ids: List[int] = []
            dup_rows: List[sqlite3.Row] = []
            replace_rows: List[sqlite3.Row] = []
            for row in imported_rows:
                key = (int(row["disc"] or 1), int(row["track"] or 0))
                if key[1] and key in existing_by_key:
                    target = target_by_key.get(key, {})
                    existing_rows_for_key = existing_by_key.get(key, [])
                    forced_replace_rows = [
                        ex for ex in existing_rows_for_key
                        if int(ex["id"] or 0) in forced_replace_ids
                    ]
                    if forced_replace_rows:
                        existing_by_key[key] = [
                            ex for ex in existing_rows_for_key
                            if int(ex["id"] or 0) not in forced_replace_ids
                        ]
                    else:
                        existing_matches = [
                            ex for ex in existing_rows_for_key
                            if _row_matches_target(ex, target)
                        ]
                        if existing_matches:
                            dup_rows.append(row)
                            continue
                        replace_rows.extend(existing_rows_for_key)
                        existing_by_key[key] = []
                move_ids.append(int(row["id"]))
                if key[1]:
                    existing_by_key.setdefault(key, []).append(row)

            if replace_rows:
                replace_ids = sorted({int(r["id"]) for r in replace_rows})
                for row in replace_rows:
                    _delete_row_file(row, "wrong existing")
                con.execute(
                    f"DELETE FROM items WHERE id IN ({','.join('?' * len(replace_ids))})",
                    replace_ids,
                )
                log.append(
                    f"  [merge] Removed {len(replace_ids)} conflicting existing DB row(s) "
                    "before merging downloaded replacements."
                )

            if dup_rows:
                source_root = Path(source_folder).resolve(strict=False)
                for row in dup_rows:
                    raw_path = _s(row["path"])
                    fpath = Path(raw_path)
                    if not fpath.is_absolute():
                        fpath = MUSIC_ROOT / raw_path
                    try:
                        resolved = fpath.resolve(strict=False)
                        resolved.relative_to(source_root)
                        resolved.unlink(missing_ok=True)
                        log.append(f"  [merge] Removed duplicate downloaded track {int(row['track'] or 0):02d}: {resolved.name}")
                    except Exception:
                        pass
                con.execute(
                    f"DELETE FROM items WHERE id IN ({','.join('?' * len(dup_rows))})",
                    [int(r["id"]) for r in dup_rows],
                )

            if move_ids:
                album_name = _s(existing["album"])
                albumartist = _s(existing["albumartist"])
                con.execute(
                    f"UPDATE items SET album_id=?, album=?, albumartist=? "
                    f"WHERE id IN ({','.join('?' * len(move_ids))})",
                    [existing_album_id, album_name, albumartist, *move_ids],
                )
                log.append(f"  [merge] Merged {len(move_ids)} missing track(s) into existing album_id {existing_album_id}")

            left = con.execute(
                "SELECT COUNT(*) FROM items WHERE album_id=?",
                (imported_album_id,),
            ).fetchone()[0]
            if int(left or 0) == 0:
                con.execute("DELETE FROM albums WHERE id=?", (imported_album_id,))
            con.commit()
            return existing_album_id if move_ids or dup_rows or replace_rows else imported_album_id
    except Exception as ex:
        log.append(f"  [merge] Warning: {ex}")
        return imported_album_id


def _slskd_search_and_queue(artist: str, album: str, year: str,
                             log: list, track_count: int = 0,
                             wanted_tracks: Optional[List[Dict[str, Any]]] = None,
                             skip_candidates: Optional[set] = None,
                             busy_retries: int = 24):
    """
    Search slskd for artist/album, pick best response, queue downloads.
    Returns (username, [queued_remote_filenames], expected_local_dir).
    Raises RuntimeError on failure.
    """
    wanted_tracks = _normalise_wanted_tracks(wanted_tracks)
    skip_candidates = skip_candidates or set()
    search_text = f"{artist} {album}"
    search_id   = str(uuid.uuid4())
    log.append(f"  [slskd] Searching: {search_text!r}")

    # 1. Start search
    search_body = {
        "id": search_id,
        "searchText": search_text,
        "fileLimit": 500,
        # Do not let slskd's UI/search filters hide MP3 folders from the app.
        # The app validates track count and file type itself below.
        "filterResponses": False,
        "minimumResponseFileCount": 1,
    }
    for attempt in range(1, busy_retries + 1):
        try:
            _slskd_req("POST", "searches", search_body)
            break
        except RuntimeError as ex:
            msg = str(ex)
            busy = "HTTP 429" in msg and "Only one concurrent operation" in msg
            if not busy:
                raise
            if attempt >= busy_retries:
                raise RuntimeError(
                    f"slskd stayed busy and would not start a new search after "
                    f"{busy_retries} retry attempt(s). Wait for the current SLSKD operation to "
                    "finish, then retry."
                ) from ex
            if attempt == 1:
                log.append("  [slskd] Search is busy; waiting for the current SLSKD operation to finish...")
            elif attempt % 3 == 0:
                log.append(f"  [slskd] Still waiting for SLSKD search slot ({attempt}/{busy_retries})...")
            time.sleep(10)

    # 2. Poll until we have real response rows, not just a response count.
    #    slskd can expose responseCount before the response objects are
    #    available, then clear the response list when the search finalises.
    #    Cache rows from both includeResponses=true and /responses while the
    #    search is still alive.
    resp_count = 0
    _inline_responses: list = []

    def _normalise_search_responses(raw: Any) -> list:
        if isinstance(raw, list):
            return raw
        if isinstance(raw, dict):
            for key in ("responses", "results", "items"):
                rows = raw.get(key)
                if isinstance(rows, list):
                    return rows
        return []

    def _cache_responses(raw: Any) -> None:
        nonlocal _inline_responses
        rows = _normalise_search_responses(raw)
        if rows:
            _inline_responses = rows

    missing_rows_logged = False
    for _ in range(45):
        time.sleep(1)
        try:
            st = _slskd_req("GET", f"searches/{search_id}?includeResponses=true")
            resp_count = max(resp_count, int(st.get("responseCount") or 0))
            state = st.get("state", "").lower()
            _cache_responses(st)

            if resp_count and not _inline_responses:
                try:
                    _cache_responses(_slskd_req("GET", f"searches/{search_id}/responses") or [])
                except Exception:
                    pass
                if not _inline_responses and not missing_rows_logged:
                    log.append("  [slskd] Response count is available; waiting for response details...")
                    missing_rows_logged = True

            if _inline_responses and (state in ("completed", "stopped") or resp_count >= 5):
                break
        except Exception:
            break
    log.append(f"  [slskd] {resp_count} response(s) returned")
    if not resp_count:
        raise RuntimeError(f"No Soulseek results for '{search_text}'")

    # 3. Get responses — prefer dedicated endpoint, fall back to cached rows.
    responses = []
    for _ in range(8):
        try:
            responses = _normalise_search_responses(
                _slskd_req("GET", f"searches/{search_id}/responses") or []
            )
        except Exception:
            responses = []
        if responses or _inline_responses:
            break
        time.sleep(1)
    if not responses and _inline_responses:
        log.append(f"  [slskd] Using {len(_inline_responses)} cached inline responses")
        responses = _inline_responses
    if not responses:
        raise RuntimeError(
            f"Got {resp_count} matches but responses list is empty "
            "(search may have expired — try again)")

    # 4. Score every album-like directory in every response. Track-count
    # completeness dominates format: a complete 320 kbps MP3 album is valid.
    candidates, skipped = _slskd_build_album_candidates(
        responses, artist, album, year, track_count, AUDIO_EXT, skip_candidates
    )

    if not candidates:
        if skipped:
            log.append(f"  [slskd] Skipped {skipped} previously failed candidate(s)")
            raise RuntimeError("No remaining Soulseek candidates after previous failed attempts")
        raise RuntimeError("No audio files in Soulseek results")
    if skipped:
        log.append(f"  [slskd] Skipped {skipped} previously failed candidate(s)")

    for cand in candidates[:5]:
        slot = "free" if cand["resp"].get("hasFreeUploadSlot") else "locked"
        log.append(
            f"  [slskd] Candidate @{cand['username'] or '?'} — "
            f"{len(cand['files'])} file(s), {slot}, score {cand['score']}: {cand['dir']}"
        )

    best = candidates[0]
    best_score = best["score"]
    best_dir_remote = best["dir"]
    best_afiles = best["files"]
    best_resp = best["resp"]
    if best_score < 0:
        raise RuntimeError("No audio files in Soulseek results")
    if track_count and not wanted_tracks:
        min_files = max(1, min(track_count, int(track_count * 0.70)))
        if len(best_afiles) < min_files:
            counts = ", ".join(
                f"@{c['username'] or '?'}:{len(c['files'])}" for c in candidates[:5]
            )
            raise RuntimeError(
                f"Best Soulseek candidate only has {len(best_afiles)}/{track_count} "
                f"audio file(s); refusing incomplete album candidate"
                + (f" (top counts: {counts})" if counts else "")
            )

    username = best_resp.get("username", "")
    log.append(f"  [slskd] Best peer: @{username} — {len(best_afiles)} file(s) from '{best_dir_remote}' (score {best_score})")

    queue_afiles = best_afiles
    if wanted_tracks:
        wanted_desc = ", ".join(
            f"{int(t.get('disc') or 1)}.{int(t.get('track') or 0):02d}"
            for t in wanted_tracks if int(t.get("track") or 0)
        ) or f"{len(wanted_tracks)} track(s)"

        def _wanted_matches_for_candidate(cand: Dict[str, Any]) -> List[Dict[str, Any]]:
            chosen: Dict[tuple, Dict[str, Any]] = {}
            resp = cand["resp"]
            for f in cand["files"]:
                remote_name = _slskd_file_remote_name(f, resp)
                match = _slskd_file_wanted_match_score(remote_name, wanted_tracks)
                if not match.get("ok"):
                    continue
                key = match.get("key") or ("file", remote_name)
                current = chosen.get(key)
                if current and float(current["match"].get("score") or 0) >= float(match.get("score") or 0):
                    continue
                chosen[key] = {"file": f, "remote_name": remote_name, "match": match}
            selected = list(chosen.values())
            selected.sort(key=lambda row: (
                int((row["match"].get("track") or {}).get("disc") or 1),
                int((row["match"].get("track") or {}).get("track") or 0),
                -float(row["match"].get("score") or 0),
                Path(row["remote_name"]).name.lower(),
            ))
            return selected

        wanted_ranked: List[tuple] = []
        for cand in candidates:
            matches = _wanted_matches_for_candidate(cand)
            avg_score = (
                sum(float(m["match"].get("score") or 0) for m in matches) / len(matches)
                if matches else 0.0
            )
            has_free_slot = 1 if (cand.get("resp") or {}).get("hasFreeUploadSlot") else 0
            wanted_ranked.append((len(matches), has_free_slot, avg_score, cand["score"], cand, matches))
        wanted_ranked.sort(key=lambda item: (item[0], item[1], item[2], item[3]), reverse=True)

        best_wanted_count, _free_slot, best_wanted_avg, _cand_score, wanted_cand, wanted_matches = wanted_ranked[0]
        if best_wanted_count < 1:
            found = ", ".join(Path(m["remote_name"]).name for m in wanted_matches[:8])
            top_counts = ", ".join(
                f"@{row[4]['username'] or '?'}:{row[0]} match(es)"
                for row in wanted_ranked[:5]
            )
            raise RuntimeError(
                f"Best Soulseek candidate only matched {best_wanted_count}/{len(wanted_tracks)} "
                f"requested missing track(s) ({wanted_desc})"
                + (f": {found}" if found else "")
                + (f" (top wanted matches: {top_counts})" if top_counts else "")
            )

        matched_tracks = [m["match"].get("track") or {} for m in wanted_matches]
        remaining_tracks = _wanted_tracks_remaining_after_satisfied(wanted_tracks, matched_tracks)

        if wanted_cand is not best:
            best = wanted_cand
            best_score = best["score"]
            best_dir_remote = best["dir"]
            best_afiles = best["files"]
            best_resp = best["resp"]
            username = best_resp.get("username", "")
            log.append(
                f"  [slskd] Switched to @{username or '?'} for missing-track score: "
                f"{best_wanted_count}/{len(wanted_tracks)} requested track(s), "
                f"avg match {best_wanted_avg:.2f}"
            )

        queue_afiles = [m["file"] for m in wanted_matches]
        matched_desc = ", ".join(_wanted_track_label(t) for t in matched_tracks[:8])
        log.append(
            f"  [slskd] Filtering candidate to {len(queue_afiles)}/"
            f"{len(wanted_tracks)} requested missing track(s)"
            + (f": {matched_desc}" if matched_desc else f": {wanted_desc}")
        )
        if remaining_tracks:
            remaining_desc = ", ".join(_wanted_track_label(t) for t in remaining_tracks[:8])
            log.append(
                "  [slskd] Candidate is partial; unresolved requested track(s) "
                f"will remain eligible for fallback: {remaining_desc}"
            )
        for row in wanted_matches[:5]:
            mt = row["match"].get("track") or {}
            log.append(
                f"    [slskd] {int(mt.get('disc') or 1)}.{int(mt.get('track') or 0):02d} "
                f"{mt.get('title','') or Path(row['remote_name']).name} "
                f"({float(row['match'].get('score') or 0):.2f}, {row['match'].get('reason','')})"
            )

    # 5. Queue downloads — API expects an array of QueueDownloadRequest objects
    queued = []
    for f in queue_afiles:
        remote_name = _slskd_file_remote_name(f, best_resp)
        try:
            _slskd_req("POST",
                       f"transfers/downloads/{_up.quote(username, safe='')}",
                       [{"filename": remote_name, "size": _slskd_file_size(f)}])
            queued.append(remote_name)
        except Exception as ex:
            log.append(f"  [slskd] WARN: queue failed for {remote_name or '?'}: {ex}")
    if not queued:
        raise RuntimeError("Failed to queue any downloads from slskd")
    log.append(f"  [slskd] Queued {len(queued)} file(s)")

    # Compute expected local directory from the remote best_dir path
    # slskd saves to: DOWNLOADS_ROOT / username / remote_dir (with drive letter stripped)
    rdir = best_dir_remote.replace("\\", "/")
    if len(rdir) > 2 and rdir[1] == ":":
        rdir = rdir[2:]
    rdir = rdir.lstrip("/")
    expected_dir = str(DOWNLOADS_ROOT / username / rdir)
    return username, queued, expected_dir, best_dir_remote


def _slskd_download_candidate_roots(username: str, remote_files: list) -> List[Path]:
    """Return likely local roots for queued SLSKD remote files."""
    return _slskd_download_candidate_roots_impl(DOWNLOADS_ROOT, username, remote_files)


def _slskd_cancel_queued_downloads(username: str, remote_files: list, log: list) -> None:
    """Best-effort cancellation for a failed candidate before retrying another peer."""
    if not username or not remote_files:
        return
    cancelled = 0
    failed = 0
    for remote in remote_files:
        try:
            _slskd_req(
                "DELETE",
                f"transfers/downloads/{_up.quote(username, safe='')}/"
                f"{_up.quote(_s(remote), safe='')}?remove=true",
            )
            cancelled += 1
        except Exception:
            failed += 1
    if cancelled:
        log.append(f"  [slskd] Cancelled {cancelled} queued transfer(s) from failed candidate.")
    if failed:
        log.append(f"  [slskd] WARN: could not cancel {failed} queued transfer(s); continuing cleanup.")


def _slskd_cleanup_failed_candidate_files(username: str, remote_files: list, log: list) -> None:
    """Remove only queued audio files from a failed SLSKD candidate under downloads."""
    _slskd_cleanup_failed_candidate_files_impl(
        DOWNLOADS_ROOT, username, remote_files, AUDIO_EXT, log
    )


def _find_slskd_downloaded_files(username: str, remote_files: list,
                                 expected_dir: str, log: list,
                                 artist: str = "", album: str = "",
                                 track_count: int = 0,
                                 transfer_hints: Optional[List[Any]] = None,
                                 wanted_tracks: Optional[List[Dict[str, Any]]] = None) -> tuple:
    """Find downloaded SLSKD files by exact queued filenames.

    Never falls back to arbitrary recent files because that can import an
    unrelated failed_imports folder when slskd uses an unexpected layout.
    Returns (album_dir, audio_files).
    """
    audio_exts = {
        '.mp3', '.flac', '.m4a', '.ogg', '.opus', '.wav', '.ape', '.wv',
        '.aac', '.alac', '.aif', '.aiff',
    }
    expected = Path(expected_dir)

    queued_names = {
        Path(str(p).replace("\\", "/")).name.lower()
        for p in remote_files if str(p).strip()
    }
    queued_remote_lowers = {
        str(p).replace("\\", "/").lower()
        for p in remote_files if str(p).strip()
    }
    if not queued_names:
        return str(expected), []
    wanted_filter = _normalise_wanted_tracks(wanted_tracks)

    def _root_add(roots: List[Path], raw) -> None:
        if not raw:
            return
        try:
            p = Path(str(raw))
        except Exception:
            return
        if p not in roots:
            roots.append(p)

    def _dirs_from_transfer_result(result: Any) -> list:
        dirs: list = []
        if isinstance(result, list):
            for user_obj in result:
                if (user_obj.get("username") or "").lower() == username.lower():
                    dirs = user_obj.get("directories", [])
                    break
        elif isinstance(result, dict):
            dirs = result.get("directories", [])
        return dirs

    local_file_keys = (
            "localFilename", "localFileName", "localPath", "filePath",
            "downloadPath", "destination", "path",
    )
    local_dir_keys = (
            "localDirectory", "localDir", "downloadDirectory",
            "destinationDirectory", "path",
    )

    def _paths_from_transfer_dirs(dirs: list) -> List[Path]:
        hints: List[Path] = []
        for d in dirs:
            dvals = [_s(d.get(k, "")).strip() for k in local_dir_keys]
            for f in d.get("files", []) or []:
                fname = _s(f.get("filename", "")).replace("\\", "/")
                if Path(fname).name.lower() not in queued_names and fname.lower() not in queued_remote_lowers:
                    continue
                for key in local_file_keys:
                    raw = _s(f.get(key, "")).strip()
                    if raw:
                        hints.append(Path(raw))
                base = Path(fname).name
                for raw_dir in dvals:
                    if raw_dir:
                        hints.append(Path(raw_dir) / base)
        return hints

    def _transfer_hint_paths() -> List[Path]:
        hints: List[Path] = []
        for snapshot in transfer_hints or []:
            hints.extend(_paths_from_transfer_dirs(_dirs_from_transfer_result(snapshot)))
        try:
            result = _slskd_req(
                "GET", f"transfers/downloads/{_up.quote(username, safe='')}")
            hints.extend(_paths_from_transfer_dirs(_dirs_from_transfer_result(result)))
        except Exception as ex:
            log.append(f"  [slskd] WARN: transfer-path lookup failed: {ex}")
        return hints

    def _scan_exact(roots: List[Path]) -> tuple:
        for root in roots:
            try:
                if root.is_file() and root.suffix.lower() in audio_exts and root.name.lower() in queued_names:
                    return str(root.parent), [root]
                if root.is_dir():
                    matches = [
                        f for f in root.rglob("*")
                        if f.is_file()
                        and f.suffix.lower() in audio_exts
                        and f.name.lower() in queued_names
                    ]
                else:
                    continue
            except Exception as ex:
                log.append(f"  [slskd] WARN: queued-file search failed under {root}: {ex}")
                continue
            if not matches:
                continue
            by_parent = Counter(str(f.parent) for f in matches)
            best_parent, count = by_parent.most_common(1)[0]
            files = sorted([f for f in matches if str(f.parent) == best_parent], key=lambda p: p.name.lower())
            filtered = _wanted_filtered_files(best_parent, files, "queued-file match")
            if not filtered:
                continue
            log.append(f"  [slskd] Located {len(filtered)}/{len(queued_names)} queued file(s) at {best_parent}")
            return best_parent, filtered
        return "", []

    def _track_num(name: str) -> int:
        m = re.match(r'^\s*(\d{1,3})[\s._-]+', Path(name).name)
        return int(m.group(1)) if m else 0

    expected_nums = {n for n in (_track_num(x) for x in queued_names) if n}
    album_norm = re.sub(r'[^a-z0-9]', '', album.lower())
    artist_norm = re.sub(r'[^a-z0-9]', '', artist.lower())
    queued_stem_norms = {
        re.sub(r'[^a-z0-9]', '', Path(name).stem.lower())
        for name in queued_names
        if name
    }

    def _safe_dir_name(value: str) -> str:
        return re.sub(r'[\\/:*?"<>|]', '_', str(value or "")).strip()

    def _min_expected_files() -> int:
        base = track_count or len(queued_names)
        return max(1, min(base, int(base * 0.70)))

    def _wanted_filtered_files(folder: Any, files: List[Path], context: str) -> List[Path]:
        if not wanted_filter:
            return files
        selected: Dict[tuple, Dict[str, Any]] = {}
        rejected: List[str] = []
        for fpath in files:
            match = _slskd_file_wanted_match_score(fpath.name, wanted_filter)
            if not match.get("ok"):
                rejected.append(fpath.name)
                continue
            key = match.get("key") or ("file", str(fpath).lower())
            current = selected.get(key)
            if current and float(current["match"].get("score") or 0) >= float(match.get("score") or 0):
                rejected.append(fpath.name)
                continue
            selected[key] = {"file": fpath, "match": match}
        min_wanted = max(1, min(len(wanted_filter), int(math.ceil(len(wanted_filter) * 0.70))))
        if len(selected) < min_wanted:
            sample = ", ".join(rejected[:3])
            log.append(
                f"  [slskd] Ignored {context} at {folder}: "
                f"{len(selected)}/{len(wanted_filter)} file(s) matched requested missing track(s)"
                + (f" ({sample})" if sample else "")
            )
            return []
        filtered = [
            row["file"]
            for row in sorted(
                selected.values(),
                key=lambda row: (
                    int((row["match"].get("track") or {}).get("disc") or 1),
                    int((row["match"].get("track") or {}).get("track") or 0),
                    row["file"].name.lower(),
                ),
            )
        ]
        if len(filtered) != len(files):
            log.append(
                f"  [slskd] Filtered located files to {len(filtered)} requested missing track(s)."
            )
        return filtered

    def _folder_audio_files(folder: Path) -> List[Path]:
        try:
            return sorted(
                [f for f in folder.rglob("*")
                 if f.is_file() and f.suffix.lower() in audio_exts],
                key=lambda p: p.name.lower(),
            )
        except Exception:
            return []

    def _scan_direct_album_dirs() -> tuple:
        guesses: List[Path] = []
        artist_album = f"{artist} - {album}".strip(" -")
        for name in (
            artist_album,
            f"{_safe_dir_name(artist)} - {_safe_dir_name(album)}".strip(" -"),
            album,
            _safe_dir_name(album),
        ):
            if name:
                _root_add(guesses, DOWNLOADS_ROOT / name)
        for folder in guesses:
            if not folder.is_dir():
                continue
            files = _folder_audio_files(folder)
            queued_matches = [f for f in files if f.name.lower() in queued_names]
            if len(queued_matches) >= _min_expected_files():
                filtered = _wanted_filtered_files(folder, queued_matches, "direct album folder")
                if not filtered:
                    continue
                log.append(
                    f"  [slskd] Located direct album folder: "
                    f"{len(filtered)}/{len(queued_names)} queued file(s) at {folder}"
                )
                return str(folder), filtered
            if len(files) < _min_expected_files():
                continue
            nums = {n for n in (_track_num(f.name) for f in files) if n}
            overlap = len(nums & expected_nums) if expected_nums else len(files)
            if expected_nums and overlap < min(len(expected_nums), _min_expected_files()):
                continue
            filtered = _wanted_filtered_files(folder, files, "direct album folder")
            if not filtered:
                continue
            log.append(f"  [slskd] Located direct album folder: {len(filtered)} file(s) at {folder}")
            return str(folder), filtered
        return "", []

    def _scan_album_folder_fallback(roots: List[Path]) -> tuple:
        if not album_norm:
            return "", []
        min_files = _min_expected_files()
        best = None
        for root in roots:
            try:
                if not root.is_dir():
                    continue
                for folder in [root] + [p for p in root.rglob("*") if p.is_dir()]:
                    f_norm = re.sub(r'[^a-z0-9]', '', str(folder).lower())
                    if album_norm not in f_norm:
                        continue
                    if artist_norm and artist_norm not in f_norm:
                        # Album title alone is often enough, but prefer artist hits.
                        artist_hit = False
                    else:
                        artist_hit = True
                    files = _folder_audio_files(folder)
                    queued_matches = [f for f in files if f.name.lower() in queued_names]
                    if len(queued_matches) >= min_files:
                        candidate_files = sorted(queued_matches, key=lambda p: p.name.lower())
                    else:
                        candidate_files = files
                    if len(files) < min_files:
                        continue
                    nums = {n for n in (_track_num(f.name) for f in files) if n}
                    overlap = len(nums & expected_nums) if expected_nums else 0
                    if expected_nums and overlap < min(len(expected_nums), min_files):
                        continue
                    score = (1000 if artist_hit else 0) + len(candidate_files) * 10 + overlap
                    if best is None or score > best[0]:
                        best = (score, folder, candidate_files)
            except Exception as ex:
                log.append(f"  [slskd] WARN: album-folder search failed under {root}: {ex}")
                continue
        if best:
            _, folder, files = best
            filtered = _wanted_filtered_files(folder, files, "album folder fallback")
            if not filtered:
                return "", []
            log.append(f"  [slskd] Located album folder fallback: {len(filtered)} queued file(s) at {folder}")
            return str(folder), filtered
        return "", []

    def _scan_single_track_fallback(roots: List[Path]) -> tuple:
        if len(queued_names) != 1 or (track_count and track_count != 1):
            return "", []
        if not album_norm and not queued_stem_norms:
            return "", []
        newest_allowed = time.time() - (2 * 60 * 60)
        best = None
        for root in roots:
            try:
                if not root.is_dir():
                    continue
                files = [
                    f for f in root.rglob("*")
                    if f.is_file() and f.suffix.lower() in audio_exts
                ]
            except Exception as ex:
                log.append(f"  [slskd] WARN: single-track search failed under {root}: {ex}")
                continue
            for f in files:
                try:
                    if f.stat().st_mtime < newest_allowed:
                        continue
                except Exception:
                    continue
                hay = re.sub(r'[^a-z0-9]', '', f"{f.parent} {f.stem}".lower())
                title_hit = bool(album_norm and album_norm in hay)
                if not title_hit:
                    title_hit = any(stem and (stem in hay or hay in stem) for stem in queued_stem_norms)
                if not title_hit:
                    continue
                artist_hit = bool(artist_norm and artist_norm in hay)
                if artist_norm and not artist_hit and not any(stem and artist_norm in stem for stem in queued_stem_norms):
                    continue
                score = (1000 if artist_hit else 0) + int(f.stat().st_mtime - newest_allowed)
                if best is None or score > best[0]:
                    best = (score, f)
        if best:
            f = best[1]
            filtered = _wanted_filtered_files(f.parent, [f], "single-track fallback")
            if not filtered:
                return "", []
            log.append(f"  [slskd] Located recent single-track fallback at {f.parent}: {f.name}")
            return str(f.parent), filtered
        return "", []

    roots: List[Path] = []
    user_root = DOWNLOADS_ROOT / username
    for raw in (
        expected,
        user_root,
        DOWNLOADS_ROOT,
        DOWNLOADS_ROOT.parent,
        "/data/downloads",
        "/downloads",
        "/download",
        "/tmp",
    ):
        _root_add(roots, raw)

    folder, files = _scan_direct_album_dirs()
    if files:
        return folder, files

    # slskd can mark transfers completed before its final move is visible in
    # the shared volume. Poll briefly for exact queued filenames before falling
    # back to a guarded album-folder search.
    deadline = time.time() + 90
    logged_wait = False
    static_hint_logged = False
    while True:
        hint_paths = _transfer_hint_paths()
        if hint_paths and not static_hint_logged:
            preview = ", ".join(str(p) for p in hint_paths[:3])
            extra = "..." if len(hint_paths) > 3 else ""
            log.append(f"  [slskd] Transfer path hint(s): {preview}{extra}")
            static_hint_logged = True
        hint_roots = roots[:]
        for hp in hint_paths:
            _root_add(hint_roots, hp)
            _root_add(hint_roots, hp.parent)
        folder, files = _scan_exact(hint_roots)
        if files:
            return folder, files
        if not logged_wait:
            log.append("  [slskd] Completed transfers not visible yet; waiting for final file move...")
            logged_wait = True
        time.sleep(3)

    folder, files = _scan_album_folder_fallback(roots)
    if files:
        return folder, files

    folder, files = _scan_single_track_fallback(roots)
    if files:
        return folder, files

    log.append(
        "  [slskd] Could not locate completed queued files. "
        "Checked transfer hints, expected dir, /data/torrents/music, /data/downloads, /downloads, /download, /tmp."
    )
    return str(expected), []


def _slskd_wait_downloads(username: str, remote_files: list, log: list,
                           timeout: int = 600) -> tuple:
    """Poll slskd until all queued files are Completed. Returns local dir."""
    deadline = time.time() + timeout
    pending  = set(remote_files)
    completed_snapshots: List[Any] = []
    rejected_logged: set = set()
    disk_seen_logged: set = set()
    last_progress_at = time.time()
    last_done = 0
    last_transfer_marker = 0
    poll_error_count = 0
    stall_timeout = min(240, max(90, int(timeout * 0.30)))
    # Minimum new bytes required to reset the stall timer. Prevents tiny
    # SLSKD API jitter (handshake overhead, <64KB) from indefinitely deferring
    # stall detection when a peer has queued files but never actually transfers.
    _STALL_BYTE_THRESHOLD = 65536

    def _num(value: Any) -> int:
        try:
            return int(value or 0)
        except Exception:
            return 0

    def _remote_parent(remote_name: str) -> Path:
        raw = _s(remote_name).replace("\\", "/")
        if len(raw) > 2 and raw[1] == ":":
            raw = raw[2:]
        raw = raw.lstrip("/")
        return Path(raw).parent

    def _download_roots_for_pending() -> List[Path]:
        roots: List[Path] = []

        def _add(raw) -> None:
            if not raw:
                return
            try:
                p = Path(str(raw))
            except Exception:
                return
            if p not in roots:
                roots.append(p)

        for remote in remote_files:
            parent = _remote_parent(remote)
            if str(parent) in ("", "."):
                continue
            _add(DOWNLOADS_ROOT / username / parent)
            _add(DOWNLOADS_ROOT / username / parent.name)
            _add(DOWNLOADS_ROOT / parent)
            _add(DOWNLOADS_ROOT / parent.name)
        return roots

    def _already_on_disk() -> set:
        if not pending:
            return set()
        by_name: Dict[str, List[str]] = defaultdict(list)
        for remote in pending:
            by_name[Path(_s(remote).replace("\\", "/")).name.lower()].append(remote)
        if not by_name:
            return set()

        found: set = set()
        for root in _download_roots_for_pending():
            try:
                if root.is_file():
                    files = [root]
                elif root.is_dir():
                    files = [
                        f for f in root.rglob("*")
                        if f.is_file() and f.suffix.lower() in AUDIO_EXT
                    ]
                else:
                    continue
            except Exception:
                continue
            for f in files:
                matches = by_name.get(f.name.lower())
                if not matches:
                    continue
                for remote in matches:
                    if remote in pending and remote not in found:
                        found.add(remote)
                        break
            if len(found) >= len(by_name):
                break
        return found

    while time.time() < deadline and pending:
        time.sleep(10)
        try:
            result = _slskd_req(
                "GET", f"transfers/downloads/{_up.quote(username, safe='')}")
            poll_error_count = 0
            # Response is either a dict with "directories" or a list
            dirs: list = []
            if isinstance(result, list):
                for user_obj in result:
                    if (user_obj.get("username") or "").lower() == username.lower():
                        dirs = user_obj.get("directories", [])
                        break
            elif isinstance(result, dict):
                dirs = result.get("directories", [])

            newly_done: set = set()
            rejected: Dict[str, str] = {}
            transfer_marker = 0
            for d in dirs:
                for f in d.get("files", []):
                    fname = f.get("filename", "")
                    if fname not in pending:
                        continue
                    state = f"{f.get('state', '')} {f.get('stateDescription', '')}".lower()
                    exception = _s(f.get("exception", "")).strip()
                    exception_l = exception.lower()
                    if "rejected" in state or "file not shared" in exception_l:
                        rejected[fname] = exception or f.get("stateDescription") or f.get("state") or "Rejected"
                        continue
                    size = _num(f.get("size"))
                    transferred = _num(f.get("bytesTransferred"))
                    remaining = _num(f.get("bytesRemaining"))
                    pct = _num(f.get("percentComplete"))
                    if transferred > 0:
                        transfer_marker += transferred
                    elif pct > 0 and size > 0:
                        transfer_marker += int(size * min(pct, 100) / 100)
                    complete_enough = (
                        remaining == 0
                        or pct >= 100
                        or (size > 0 and transferred >= size)
                    )
                    if "completed" in state and complete_enough:
                        newly_done.add(fname)
            if newly_done:
                completed_snapshots.append(result)
            disk_done = _already_on_disk()
            if disk_done:
                newly_visible = disk_done - disk_seen_logged
                if newly_visible:
                    disk_seen_logged.update(newly_visible)
                    sample = ", ".join(
                        Path(_s(name).replace("\\", "/")).name
                        for name in sorted(newly_visible)[:3]
                    )
                    log.append(
                        f"  [slskd] Found {len(newly_visible)} already-present "
                        f"queued file(s) on disk"
                        + (f": {sample}" if sample else "")
                    )
                newly_done |= disk_done
            pending -= newly_done
            done = len(remote_files) - len(pending)
            log.append(f"  [slskd] {done}/{len(remote_files)} file(s) downloaded")
            if newly_done or done > last_done:
                last_progress_at = time.time()
                last_done = done
                last_transfer_marker = transfer_marker
            elif transfer_marker >= last_transfer_marker + _STALL_BYTE_THRESHOLD:
                last_progress_at = time.time()
                last_transfer_marker = transfer_marker
            if rejected:
                new_rejected = [name for name in rejected if name not in rejected_logged]
                if new_rejected:
                    rejected_logged.update(new_rejected)
                    samples = "; ".join(
                        f"{Path(name).name}: {rejected[name]}" for name in new_rejected[:3]
                    )
                    log.append(
                        f"  [slskd] Rejected {len(new_rejected)} queued file(s): {samples}"
                    )
                if all(name in rejected for name in pending):
                    reason = next(iter(rejected.values()), "Rejected")
                    raise RuntimeError(
                        f"SLSKD rejected {len(rejected)}/{len(remote_files)} queued file(s) "
                        f"from @{username}: {reason}. This peer's search result is not downloadable; retry to use another source."
                    )
            if pending and time.time() - last_progress_at >= stall_timeout:
                stalled_for = int(time.time() - last_progress_at)
                samples = ", ".join(
                    Path(_s(name).replace("\\", "/")).name
                    for name in sorted(pending)[:5]
                )
                raise RuntimeError(
                    f"Download stalled for {stalled_for}s with {len(pending)}/"
                    f"{len(remote_files)} file(s) still pending from @{username}"
                    + (f": {samples}" if samples else "")
                    + ". Trying another source."
                )
        except Exception as ex:
            msg = str(ex)
            if "SLSKD rejected" in msg or "Download stalled" in msg:
                raise
            poll_error_count += 1
            if (
                poll_error_count >= 3
                and "HTTP 404" in msg
                and "transfers/downloads" in msg
            ):
                raise RuntimeError(
                    f"SLSKD transfer state disappeared while polling @{username} "
                    f"after {poll_error_count} poll error(s). Trying another source."
                ) from ex
            log.append(f"  [slskd] Poll error: {ex}")

    if pending:
        done_pct = int(100 * (len(remote_files) - len(pending)) / max(len(remote_files), 1))
        log.append(f"  [slskd] WARNING: {len(pending)} file(s) still pending at timeout "
                   f"({done_pct}% complete)")
        raise RuntimeError(
            f"Download timeout: only {done_pct}% of files completed "
            f"({len(remote_files) - len(pending)}/{len(remote_files)})"
        )

    # Re-compute local dir from first file
    first = list(remote_files)[0].replace("\\", "/")
    if len(first) > 2 and first[1] == ":":
        first = first[2:]
    first = first.lstrip("/")
    return str(DOWNLOADS_ROOT / username / Path(first).parent), completed_snapshots


_DOWNLOAD_METHOD_ALIASES = {
    "yt": "ytdlp",
    "yt-dlp": "ytdlp",
    "youtube": "ytdlp",
    "youtube-music": "ytdlp",
    "sc": "soundcloud",
    "sound-cloud": "soundcloud",
    "sp": "spotiflac",
    "spotiflac": "spotiflac",
    "spotiflac-cli": "spotiflac",
}
_YTDLP_SOURCE_METHODS = {"ytdlp", "soundcloud"}
_DOWNLOAD_METHODS = {"slskd", "spotiflac", "ytdlp", "soundcloud"}
_SPOTIFLAC_PIP_PACKAGE = os.environ.get("SPOTIFLAC_PIP_PACKAGE", "SpotiFLAC").strip() or "SpotiFLAC"
_SPOTIFLAC_AUTO_INSTALL = False
_SPOTIFLAC_INPUT_SOURCES = os.environ.get("SPOTIFLAC_INPUT_SOURCES", "soundcloud")
_SPOTIFLAC_SERVICES = os.environ.get("SPOTIFLAC_SERVICES", "tidal,qobuz,deezer,amazon,soundcloud")
_SLSKD_FALLBACK_METHODS = os.environ.get("SLSKD_FALLBACK_METHODS", "spotiflac,ytdlp,soundcloud")


def _normalise_download_method(value: Any, default: str = "slskd") -> str:
    method = _s(value or default).strip().lower()
    method = _DOWNLOAD_METHOD_ALIASES.get(method, method)
    return method or default


def _download_method_label(method: Any) -> str:
    method = _normalise_download_method(method)
    return {
        "slskd": "SLSKD",
        "ytdlp": "YouTube",
        "soundcloud": "SoundCloud",
        "spotiflac": "SpotiFLAC",
        "resume": "Resume",
    }.get(method, method)


def _download_method_job_label(method: Any) -> str:
    method = _normalise_download_method(method)
    return {
        "slskd": "Soulseek",
        "ytdlp": "YouTube",
        "soundcloud": "SoundCloud",
        "spotiflac": "SpotiFLAC",
    }.get(method, method)


def _ytdlp_source_needs_youtube_auth(source: str) -> bool:
    return _normalise_download_method(source) == "ytdlp" and YTDLP_REQUIRE_YOUTUBE_AUTH


def _ytdlp_source_requires_js(source: str) -> bool:
    return _normalise_download_method(source) == "ytdlp"


def _ytdlp_client_profiles_for_source(source: str) -> List[tuple]:
    if _normalise_download_method(source) == "soundcloud":
        return [("default", None)]
    return _ytdlp_youtube_client_profiles()


def _ytdlp_cookie_auths_for_source(source: str, log: Optional[list] = None) -> List[Optional[Dict[str, Any]]]:
    if not _ytdlp_source_needs_youtube_auth(source):
        return [None]
    all_cookie_auths = _configured_ytdlp_cookie_auths(log)
    cookie_auths = _usable_ytdlp_cookie_auths(log)
    if not all_cookie_auths:
        raise RuntimeError(_ytdlp_cookie_help())
    if not cookie_auths:
        raise RuntimeError(
            "yt-dlp auth sources are unavailable: "
            + ", ".join(_describe_ytdlp_cookie_auths(all_cookie_auths))
        )
    return cookie_auths


def _ytdlp_album_queries(source: str, artist: str, album: str, max_tracks: int) -> List[str]:
    source = _normalise_download_method(source, "ytdlp")
    if source == "soundcloud":
        return [
            f"scsearch{max_tracks}:{artist} {album}",
            f"scsearch{max_tracks}:{artist} {album} full album",
        ]
    return [
        f"ytsearch{max_tracks}:{artist} {album}",
        f"ytsearch:{artist} {album} full album",
    ]


def _ytdlp_track_queries(source: str, artist: str, album: str, title: str, year: str = "") -> List[str]:
    source = _normalise_download_method(source, "ytdlp")
    prefix = "scsearch1" if source == "soundcloud" else "ytsearch1"
    queries = [f"{prefix}:{artist} {album} {title}"]
    if year:
        queries.append(f"{prefix}:{artist} {album} {title} {year}")
    queries.append(f"{prefix}:{artist} {title}")
    return queries


def _ytdlp_apply_cookie_auth_if_needed(ydl_opts: Dict[str, Any],
                                       cookie_auth: Optional[Dict[str, Any]],
                                       log: Optional[list] = None) -> None:
    if cookie_auth:
        _apply_ytdlp_cookie_auth(ydl_opts, cookie_auth, log)


def _ytdlp_apply_source_auth(ydl_opts: Dict[str, Any], source: str,
                             cookie_auth: Optional[Dict[str, Any]],
                             log: Optional[list] = None) -> None:
    _ytdlp_apply_cookie_auth_if_needed(ydl_opts, cookie_auth, log)
    if _normalise_download_method(source) == "soundcloud":
        _apply_ytdlp_netrc(ydl_opts, log)


def _merge_ytdlp_extractor_args(*groups: Optional[Dict[str, Any]]) -> Dict[str, Any]:
    merged: Dict[str, Any] = {}
    for group in groups:
        if not group:
            continue
        for extractor, values in group.items():
            current = merged.setdefault(extractor, {})
            if isinstance(values, dict):
                for key, value in values.items():
                    current[key] = value
    return merged


def _ytdlp_base_extractor_args_for_source(source: str) -> Dict[str, Any]:
    if _normalise_download_method(source) != "ytdlp" or not YTDLP_PO_PROVIDER_URL:
        return {}
    try:
        validate_outbound_url(YTDLP_PO_PROVIDER_URL)
    except OutboundPolicyError as ex:
        raise RuntimeError("Configured yt-dlp PO provider URL is blocked by outbound policy") from ex
    return {"youtubepot-bgutilhttp": {"base_url": [YTDLP_PO_PROVIDER_URL]}}


def _ytdlp_source_extractor_args(source: str,
                                 client_args: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    return _merge_ytdlp_extractor_args(_ytdlp_base_extractor_args_for_source(source), client_args)


def _ytdlp_audio_format_for_source(source: str) -> str:
    if _normalise_download_method(source) == "ytdlp":
        return "bestaudio[acodec!=none][vcodec=none]/bestaudio[acodec!=none]/bestaudio/best"
    return "bestaudio[ext=m4a]/bestaudio/best"


def _ytdlp_audio_codec_for_source(source: str) -> str:
    return "flac" if _normalise_download_method(source) == "ytdlp" else "mp3"


def _ytdlp_postprocessors_for_source(source: str) -> List[Dict[str, Any]]:
    codec = _ytdlp_audio_codec_for_source(source)
    audio_pp: Dict[str, Any] = {"key": "FFmpegExtractAudio", "preferredcodec": codec}
    if codec == "mp3":
        audio_pp["preferredquality"] = "320"
    return [audio_pp, {"key": "FFmpegMetadata"}]


def _ytdlp_youtube_impersonate_target(log: Optional[list] = None):
    raw = os.environ.get("YTDLP_YOUTUBE_IMPERSONATE", "chrome").strip().lower()
    if raw in {"", "0", "false", "no", "off", "none"}:
        return None
    try:
        from yt_dlp.networking.impersonate import ImpersonateTarget
        return ImpersonateTarget.from_str(raw)
    except Exception as ex:
        if log is not None:
            log.append(f"  [yt-dlp] WARN: browser impersonation unavailable for {raw}: {ex}")
        return None


def _ytdlp_apply_source_network_options(ydl_opts: Dict[str, Any], source: str,
                                        log: Optional[list] = None) -> None:
    if _normalise_download_method(source) != "ytdlp":
        return
    target = _ytdlp_youtube_impersonate_target(log)
    if target is not None:
        ydl_opts["impersonate"] = target


def _spotiflac_list_from_env(value: str) -> List[str]:
    return [
        item.strip().lower()
        for item in re.split(r"[\s,]+", _s(value))
        if item.strip()
    ]


def _download_method_list(value: str) -> List[str]:
    methods: List[str] = []
    for item in re.split(r"[\s,]+", _s(value)):
        method = _normalise_download_method(item, "")
        if method and method not in methods:
            methods.append(method)
    return methods


def _slskd_fallback_methods(requested: str = "") -> List[str]:
    methods: List[str] = []
    for method in [requested] + _download_method_list(_SLSKD_FALLBACK_METHODS):
        method = _normalise_download_method(method, "")
        if method in {"spotiflac", "ytdlp", "soundcloud"} and method not in methods:
            methods.append(method)
    if methods and "ytdlp" not in methods:
        insert_at = methods.index("soundcloud") if "soundcloud" in methods else len(methods)
        methods.insert(insert_at, "ytdlp")
    return methods or ["spotiflac", "ytdlp", "soundcloud"]


def _spotiflac_input_sources() -> List[str]:
    sources = []
    for item in _download_method_list(_SPOTIFLAC_INPUT_SOURCES):
        method = _normalise_download_method(item, "soundcloud")
        if method == "soundcloud" and method not in sources:
            sources.append(method)
    return sources or ["soundcloud"]


def _spotiflac_services() -> List[str]:
    return _spotiflac_list_from_env(_SPOTIFLAC_SERVICES) or [
        "tidal", "qobuz", "deezer", "amazon", "soundcloud"
    ]


def _spotiflac_command(log: Optional[list] = None) -> List[str]:
    configured = os.environ.get("SPOTIFLAC_CMD", "").strip()
    if configured:
        parts = shlex.split(configured)
        if parts:
            first = shutil.which(parts[0]) or parts[0]
            try:
                if Path(first).exists():
                    return [first] + parts[1:]
            except Exception:
                pass
    candidates = [configured] if configured else []
    found = shutil.which("spotiflac")
    if found:
        candidates.append(found)
    candidates.extend([
        str(Path(sys.executable).with_name("spotiflac")),
        "/usr/local/bin/spotiflac",
        "/lsiopy/bin/spotiflac",
    ])
    for candidate in candidates:
        if not candidate:
            continue
        try:
            if Path(candidate).exists():
                return [candidate]
        except Exception:
            continue
    if log is not None:
        log.append("  [spotiflac] runtime CLI installation is disabled; preinstall a pinned SpotiFLAC CLI in the image build")
    raise RuntimeError(
        "SpotiFLAC is not available. Install the pinned SpotiFLAC CLI during the container image build."
    )


def _audio_files_in_dir(dest_dir: str) -> set:
    try:
        return {
            str(p)
            for p in Path(dest_dir).rglob("*")
            if p.is_file() and p.suffix.lower() in AUDIO_EXT
        }
    except Exception:
        return set()


def _audio_duration_seconds(path_value: str) -> float:
    ffprobe = shutil.which("ffprobe") or "/usr/bin/ffprobe"
    try:
        r = subprocess.run(
            [
                ffprobe,
                "-v", "error",
                "-show_entries", "format=duration",
                "-of", "default=noprint_wrappers=1:nokey=1",
                path_value,
            ],
            timeout=15,
            capture_output=True,
            text=True,
        )
        if r.returncode == 0:
            return float((r.stdout or "").strip() or 0)
    except Exception:
        pass
    return 0.0


def _playlist_filter_preview_downloads(paths: Iterable[str], log) -> List[str]:
    valid: List[str] = []
    minimum = int(PLAYLIST_MIN_DOWNLOAD_SECONDS or 0)
    for path_value in paths:
        duration = _audio_duration_seconds(path_value)
        if minimum > 0 and duration > 0 and duration < minimum:
            try:
                Path(path_value).unlink()
            except Exception:
                pass
            log(
                f"  rejected preview-length download "
                f"({duration:.1f}s < {minimum}s): {Path(path_value).name}"
            )
            continue
        valid.append(path_value)
    return valid



def _ytdlp_find_first_url(source: str, queries: List[str], log: list) -> str:
    if not _ytdlp_ready.wait(timeout=30):
        raise RuntimeError("yt-dlp not ready — still installing")
    try:
        import yt_dlp
    except ImportError:
        raise RuntimeError("yt-dlp not installed")

    js_runtime = None
    if _ytdlp_source_requires_js(source):
        js_runtime = _require_ytdlp_js_runtime()
    base_opts = {
        "quiet": True,
        "no_warnings": False,
        "skip_download": True,
        "ignoreerrors": False,
        "socket_timeout": 30,
        "noplaylist": True,
        "extract_flat": "in_playlist",
        "js_runtimes": _ytdlp_js_runtime_options(),
        "remote_components": _ytdlp_remote_components(),
    }
    _ytdlp_apply_source_network_options(base_opts, source, log)
    if js_runtime and js_runtime.get("runtimes"):
        runtime = js_runtime["runtimes"][0]
        log.append(
            f"  [yt-dlp] JS runtime: {runtime['name']} {runtime.get('version') or ''}".rstrip()
        )

    for cookie_auth in _ytdlp_cookie_auths_for_source(source, log):
        auth_opts = dict(base_opts)
        _ytdlp_apply_cookie_auth_if_needed(auth_opts, cookie_auth, log)
        _ytdlp_apply_source_auth(auth_opts, source, cookie_auth, log)
        for query in queries:
            for client_label, extractor_args in _ytdlp_client_profiles_for_source(source):
                opts = dict(auth_opts)
                merged_extractor_args = _ytdlp_source_extractor_args(source, extractor_args)
                if merged_extractor_args:
                    opts["extractor_args"] = merged_extractor_args
                log.append(f"  [yt-dlp] Resolving source URL: {query!r} (client {client_label})")
                try:
                    with yt_dlp.YoutubeDL(opts) as ydl:
                        info = ydl.extract_info(query, download=False)
                except Exception as ex:
                    log.append(f"  [yt-dlp] URL resolve error: {ex}")
                    continue
                entries = info.get("entries") if isinstance(info, dict) else None
                candidates = entries if entries else [info]
                for entry in candidates or []:
                    if not entry:
                        continue
                    url = _s(entry.get("webpage_url") or entry.get("original_url") or entry.get("url")).strip()
                    if not url:
                        continue
                    if not url.startswith(("http://", "https://")):
                        if _normalise_download_method(source) == "ytdlp":
                            url = f"https://www.youtube.com/watch?v={url}"
                        else:
                            continue
                    log.append(f"  [yt-dlp] Source URL: {url}")
                    return url
    return ""


def _spotiflac_download_url(url: str, dest_dir: str, log: list, label: str = "") -> int:
    os.makedirs(dest_dir, exist_ok=True)
    before = _audio_files_in_dir(dest_dir)
    cmd = _spotiflac_command(log) + [url, dest_dir]
    services = _spotiflac_services()
    if services:
        cmd += ["--service"] + services
    cmd += [
        "--filename-format", "{title} - {artist}",
        "--use-track-numbers",
        "--use-album-track-numbers",
    ]
    log.append(
        "  [spotiflac] Downloading"
        + (f" {label}" if label else "")
        + f" via {url}"
    )
    try:
        proc = subprocess.run(
            cmd,
            timeout=int(os.environ.get("SPOTIFLAC_TIMEOUT", "1200") or "1200"),
            capture_output=True,
            text=True,
        )
    except subprocess.TimeoutExpired as ex:
        raise RuntimeError(f"SpotiFLAC timed out: {label or url}") from ex
    output = "\n".join([proc.stdout or "", proc.stderr or ""]).strip()
    for line in output.splitlines()[-25:]:
        text = line.strip()
        if text:
            log.append(f"  [spotiflac] {text[:240]}")
    if proc.returncode != 0:
        raise RuntimeError(f"SpotiFLAC failed with exit code {proc.returncode}")
    after = _audio_files_in_dir(dest_dir)
    return max(0, len(after - before))


def _spotiflac_missing_tracks_download(artist: str, album: str, year: str,
                                       dest_dir: str, log: list,
                                       wanted_tracks: List[Dict[str, Any]]) -> int:
    wanted_tracks = _normalise_wanted_tracks(wanted_tracks)
    if not wanted_tracks:
        return _spotiflac_album_download(artist, album, year, dest_dir, log)
    downloaded = 0
    failed: List[str] = []
    log.append(
        f"  [spotiflac] Missing-track mode: resolving URLs for "
        f"{len(wanted_tracks)} requested track(s)"
    )
    for idx, track in enumerate(wanted_tracks, start=1):
        title = _s(track.get("title", "")).strip()
        label = _wanted_track_label(track)
        if not title:
            failed.append(label)
            continue
        log.append(f"  [spotiflac] [{idx}/{len(wanted_tracks)}] {label}")
        source_url = ""
        for source in _spotiflac_input_sources():
            source_url = _ytdlp_find_first_url(
                source,
                _ytdlp_track_queries(source, artist, album, title, year),
                log,
            )
            if source_url:
                break
        if not source_url:
            failed.append(label)
            log.append(f"  [spotiflac] No source URL found for {label}")
            continue
        try:
            n_new = _spotiflac_download_url(source_url, dest_dir, log, label)
        except Exception as ex:
            failed.append(label)
            log.append(f"  [spotiflac] Failed {label}: {ex}")
            continue
        if n_new > 0:
            downloaded += n_new
        else:
            failed.append(label)
            log.append(
                f"  [spotiflac] No output file produced for {label} "
                "(SpotiFLAC exited successfully but no audio was saved)"
            )
    if downloaded:
        log.append(f"  [spotiflac] Downloaded {downloaded} file(s) to {dest_dir}")
        if failed:
            log.append(
                "  [spotiflac] Still not downloaded: "
                + ", ".join(failed[:8])
                + ("..." if len(failed) > 8 else "")
            )
        return downloaded
    raise RuntimeError("SpotiFLAC: no files downloaded")


def _spotiflac_album_download(artist: str, album: str, year: str,
                              dest_dir: str, log: list,
                              track_count: int = 0,
                              mb_albumid: str = "") -> int:
    mb_tracks: List[Dict[str, Any]] = []
    if mb_albumid:
        mb = _fetch_mb_release_tracklist(mb_albumid, log)
        if mb.get("ok"):
            mb_tracks = _normalise_wanted_tracks(mb.get("tracks") or [])
    if mb_tracks:
        log.append(
            f"  [spotiflac] Album mode: downloading {len(mb_tracks)} "
            "MusicBrainz track URL(s)"
        )
        return _spotiflac_missing_tracks_download(artist, album, year, dest_dir, log, mb_tracks)

    max_tracks = max(track_count + 2, 3) if track_count else 25
    queries_by_source = [
        (source, _ytdlp_album_queries(source, artist, album, max_tracks))
        for source in _spotiflac_input_sources()
    ]
    for source, queries in queries_by_source:
        source_url = _ytdlp_find_first_url(source, queries, log)
        if not source_url:
            continue
        n_new = _spotiflac_download_url(source_url, dest_dir, log, f"{artist} - {album}")
        if n_new:
            return n_new
    raise RuntimeError("SpotiFLAC: no album source URL found")


def _ytdlp_album_download(artist: str, album: str, year: str,
                           dest_dir: str, log: list,
                           track_count: int = 0,
                           source: str = "ytdlp") -> int:
    """Download album tracks from a yt-dlp-backed source.
    Returns number of audio files downloaded to dest_dir."""
    source = _normalise_download_method(source, "ytdlp")
    if not _ytdlp_ready.wait(timeout=30):
        raise RuntimeError("yt-dlp not ready — still installing")
    try:
        import yt_dlp
    except ImportError:
        raise RuntimeError("yt-dlp not installed")

    cookie_auths = _ytdlp_cookie_auths_for_source(source, log)
    js_runtime = _require_ytdlp_js_runtime() if _ytdlp_source_requires_js(source) else {}

    os.makedirs(dest_dir, exist_ok=True)
    if track_count:
        max_tracks = max(track_count + 2, 3)
    else:
        max_tracks = 25
    bot_check_seen = {"count": 0}

    # Custom logger so yt-dlp errors/warnings appear in the job log
    _ytlog = log
    class _YdlLogger:
        def debug(self, msg):
            if not msg.startswith('[debug]'):
                _ytlog.append(f"  [yt-dlp] {msg[:200]}")
        def warning(self, msg):
            _ytlog.append(f"  [yt-dlp] WARN: {msg[:200]}")
        def error(self, msg):
            _ytlog.append(f"  [yt-dlp] ERR: {msg[:200]}")
            if _yt_bot_check_message(msg):
                bot_check_seen["count"] += 1

    # outtmpl: %(title)s avoids the %(playlist_index)02d silent-failure bug
    # (playlist_index is None for non-playlist downloads, causing ignoreerrors
    # to silently discard the file when using the %02d format spec).
    ydl_opts = {
        'format': _ytdlp_audio_format_for_source(source),
        'postprocessors': _ytdlp_postprocessors_for_source(source),
        'outtmpl': os.path.join(dest_dir, '%(title)s.%(ext)s'),
        'logger': _YdlLogger(),
        'quiet': True,
        'no_warnings': False,
        'ignoreerrors': False,
        'socket_timeout': 30,
        'playlistend': max_tracks,
        'noplaylist': False,
        'js_runtimes': _ytdlp_js_runtime_options(),
        'remote_components': _ytdlp_remote_components(),
    }
    _ytdlp_apply_source_network_options(ydl_opts, source, log)

    if js_runtime.get("runtimes"):
        runtime = js_runtime["runtimes"][0]
        log.append(
            f"  [yt-dlp] JS runtime: {runtime['name']} {runtime.get('version') or ''}".rstrip()
        )
    if ydl_opts.get("remote_components"):
        log.append(
            "  [yt-dlp] Remote components: "
            + ", ".join(ydl_opts["remote_components"])
        )

    log.append(f"  [yt-dlp] Source: {_download_method_label(source)}")
    queries = _ytdlp_album_queries(source, artist, album, max_tracks)
    client_profiles = _ytdlp_client_profiles_for_source(source)
    last_auth_error = ""
    for cookie_auth in cookie_auths:
        cookie_auth_key = _ytdlp_cookie_auth_rejection_key(cookie_auth) if cookie_auth else ""
        bot_check_seen["count"] = 0
        auth_opts = dict(ydl_opts)
        _ytdlp_apply_cookie_auth_if_needed(auth_opts, cookie_auth, log)
        _ytdlp_apply_source_auth(auth_opts, source, cookie_auth, log)
        auth_failed = False
        for query in queries:
            for client_label, extractor_args in client_profiles:
                log.append(f"  [yt-dlp] Trying: {query!r} (client {client_label})")
                n_before = len([f for f in os.listdir(dest_dir)
                                if os.path.splitext(f)[1].lower() in AUDIO_EXT])
                opts = dict(auth_opts)
                merged_extractor_args = _ytdlp_source_extractor_args(source, extractor_args)
                if merged_extractor_args:
                    opts["extractor_args"] = merged_extractor_args
                try:
                    with yt_dlp.YoutubeDL(opts) as ydl:
                        ydl.download([query])
                    if cookie_auth and bot_check_seen["count"]:
                        last_auth_error = _mark_ytdlp_auth_rejected(cookie_auth)
                        auth_failed = True
                        log.append(
                            f"  [yt-dlp] Auth source failed: {cookie_auth.get('label')}; "
                            "trying next auth source..."
                        )
                        break
                except Exception as ex:
                    if cookie_auth and (_yt_auth_source_failed_message(str(ex)) or bot_check_seen["count"]):
                        last_auth_error = _mark_ytdlp_auth_rejected(cookie_auth, str(ex))
                        auth_failed = True
                        log.append(
                            f"  [yt-dlp] Auth source failed: {cookie_auth.get('label')}; "
                            "trying next auth source..."
                        )
                        break
                    log.append(f"  [yt-dlp] Error: {ex}")
                    continue
                files = [f for f in os.listdir(dest_dir)
                         if os.path.splitext(f)[1].lower() in AUDIO_EXT]
                n_new = len(files) - n_before
                if n_new > 0:
                    log.append(f"  [yt-dlp] Downloaded {n_new} new file(s) to {dest_dir}")
                    if n_new >= max(track_count // 2, 1):
                        return len(files)
                    log.append(f"  [yt-dlp] Only {n_new}/{track_count or '?'} tracks, trying next...")
            if auth_failed:
                break

    files = [f for f in os.listdir(dest_dir)
             if os.path.splitext(f)[1].lower() in AUDIO_EXT]
    if files:
        log.append(f"  [yt-dlp] {len(files)} total file(s) in {dest_dir}")
        return len(files)
    if last_auth_error:
        raise RuntimeError(last_auth_error)
    raise RuntimeError("yt-dlp: no audio files downloaded")


def _ytdlp_missing_tracks_download(artist: str, album: str, year: str,
                                   dest_dir: str, log: list,
                                   wanted_tracks: List[Dict[str, Any]],
                                   source: str = "ytdlp") -> int:
    """Download one yt-dlp result per requested missing MusicBrainz track."""
    source = _normalise_download_method(source, "ytdlp")
    wanted_tracks = _normalise_wanted_tracks(wanted_tracks)
    if not wanted_tracks:
        return _ytdlp_album_download(artist, album, year, dest_dir, log, source=source)
    if not _ytdlp_ready.wait(timeout=30):
        raise RuntimeError("yt-dlp not ready — still installing")
    try:
        import yt_dlp
    except ImportError:
        raise RuntimeError("yt-dlp not installed")

    cookie_auths = _ytdlp_cookie_auths_for_source(source, log)
    js_runtime = _require_ytdlp_js_runtime() if _ytdlp_source_requires_js(source) else {}

    os.makedirs(dest_dir, exist_ok=True)
    bot_check_seen = {"count": 0}
    _ytlog = log

    class _YdlLogger:
        def debug(self, msg):
            if not msg.startswith('[debug]'):
                _ytlog.append(f"  [yt-dlp] {msg[:200]}")

        def warning(self, msg):
            _ytlog.append(f"  [yt-dlp] WARN: {msg[:200]}")

        def error(self, msg):
            _ytlog.append(f"  [yt-dlp] ERR: {msg[:200]}")
            if _yt_bot_check_message(msg):
                bot_check_seen["count"] += 1

    def _audio_files() -> set[str]:
        try:
            return {
                str(p)
                for p in Path(dest_dir).iterdir()
                if p.is_file() and p.suffix.lower() in AUDIO_EXT
            }
        except Exception:
            return set()

    def _safe_name(value: str, fallback: str) -> str:
        cleaned = re.sub(r'[\\/:*?"<>|]+', "_", _s(value)).strip()
        cleaned = re.sub(r"\s+", " ", cleaned)
        return (cleaned or fallback)[:90]

    base_opts = {
        'format': _ytdlp_audio_format_for_source(source),
        'postprocessors': _ytdlp_postprocessors_for_source(source),
        'logger': _YdlLogger(),
        'quiet': True,
        'no_warnings': False,
        'ignoreerrors': False,
        'socket_timeout': 30,
        'noplaylist': True,
        'js_runtimes': _ytdlp_js_runtime_options(),
        'remote_components': _ytdlp_remote_components(),
    }
    _ytdlp_apply_source_network_options(base_opts, source, log)
    if js_runtime.get("runtimes"):
        runtime = js_runtime["runtimes"][0]
        log.append(
            f"  [yt-dlp] JS runtime: {runtime['name']} {runtime.get('version') or ''}".rstrip()
        )
    if base_opts.get("remote_components"):
        log.append(
            "  [yt-dlp] Remote components: "
            + ", ".join(base_opts["remote_components"])
        )
    log.append(
        f"  [yt-dlp] Missing-track mode: searching {_download_method_label(source)} for "
        f"{len(wanted_tracks)} requested track(s)"
    )

    client_profiles = _ytdlp_client_profiles_for_source(source)
    downloaded = 0
    failed: List[str] = []
    last_auth_error = ""
    for idx, track in enumerate(wanted_tracks, start=1):
        title = _s(track.get("title", "")).strip()
        if not title:
            failed.append(_wanted_track_label(track))
            log.append(f"  [yt-dlp] Skipping track {idx}: missing title")
            continue
        disc = int(track.get("disc") or 1)
        track_num = int(track.get("track") or 0)
        label = _wanted_track_label(track)
        prefix = (
            f"{disc:02d}-{track_num:02d} {_safe_name(title, f'track-{idx}')}"
            if track_num else
            f"{idx:03d} {_safe_name(title, f'track-{idx}')}"
        )
        outtmpl = os.path.join(dest_dir, f"{prefix} - %(title).120s.%(ext)s")
        queries = _ytdlp_track_queries(source, artist, album, title, year)

        log.append(f"  [yt-dlp] [{idx}/{len(wanted_tracks)}] {label}")
        track_downloaded = False
        for cookie_auth in cookie_auths:
            cookie_auth_key = _ytdlp_cookie_auth_rejection_key(cookie_auth) if cookie_auth else ""
            if cookie_auth_key and _ytdlp_cookie_rejection_state(cookie_auth_key):
                continue
            bot_check_seen["count"] = 0
            auth_opts = dict(base_opts)
            _ytdlp_apply_cookie_auth_if_needed(auth_opts, cookie_auth, log)
            _ytdlp_apply_source_auth(auth_opts, source, cookie_auth, log)
            auth_failed = False
            for query in queries:
                for client_label, extractor_args in client_profiles:
                    before = _audio_files()
                    log.append(f"  [yt-dlp] Trying: {query!r} (client {client_label})")
                    ydl_opts = dict(auth_opts)
                    ydl_opts["outtmpl"] = outtmpl
                    merged_extractor_args = _ytdlp_source_extractor_args(source, extractor_args)
                    if merged_extractor_args:
                        ydl_opts["extractor_args"] = merged_extractor_args
                    try:
                        with yt_dlp.YoutubeDL(ydl_opts) as ydl:
                            ydl.download([query])
                        if cookie_auth and bot_check_seen["count"]:
                            last_auth_error = _mark_ytdlp_auth_rejected(cookie_auth)
                            auth_failed = True
                            log.append(
                                f"  [yt-dlp] Auth source failed: {cookie_auth.get('label')}; "
                                "trying next auth source..."
                            )
                            break
                    except Exception as ex:
                        if cookie_auth and (_yt_auth_source_failed_message(str(ex)) or bot_check_seen["count"]):
                            last_auth_error = _mark_ytdlp_auth_rejected(cookie_auth, str(ex))
                            auth_failed = True
                            log.append(
                                f"  [yt-dlp] Auth source failed: {cookie_auth.get('label')}; "
                                "trying next auth source..."
                            )
                            break
                        log.append(f"  [yt-dlp] Error: {ex}")
                        continue
                    after = _audio_files()
                    new_files = sorted(after - before)
                    if new_files:
                        downloaded += len(new_files)
                        track_downloaded = True
                        log.append(
                            f"  [yt-dlp] Downloaded {Path(new_files[0]).name}"
                        )
                        break
                if track_downloaded or auth_failed:
                    break
            if track_downloaded:
                break
        if not track_downloaded:
            failed.append(label)
            log.append(f"  [yt-dlp] No {_download_method_label(source)} result downloaded for {label}")

    if downloaded:
        log.append(f"  [yt-dlp] Downloaded {downloaded} missing-track file(s) to {dest_dir}")
        if failed:
            log.append(
                "  [yt-dlp] Still not downloaded: "
                + ", ".join(failed[:8])
                + ("..." if len(failed) > 8 else "")
        )
        return downloaded
    if last_auth_error:
        raise RuntimeError(last_auth_error)
    raise RuntimeError("yt-dlp: no missing tracks downloaded")


def _mb_release_track_count(mb_releaseid: str, log: list = None) -> int:
    """Return MusicBrainz release track count, or 0 if unavailable."""
    if not _MB_UUID_RE.match((mb_releaseid or "").strip()):
        return 0
    mb = _fetch_mb_release_tracklist(mb_releaseid, log)
    if mb.get("ok"):
        return len(mb.get("tracks") or [])
    if log is not None:
        ex = mb.get("error") or "unknown MusicBrainz lookup error"
        log.append(f"  WARN: release track-count lookup failed: {ex}")
    return 0


def _mb_release_has_tracks(mb_releaseid: str) -> bool:
    """Return True when a UUID resolves as a MusicBrainz release with media."""
    return _mb_release_track_count(mb_releaseid) > 0



def _folder_import_track_count(source_folder: str, existing_album_id: int = 0) -> int:
    """Best known track count for a source folder before selecting an MB release."""
    if existing_album_id:
        try:
            with _db() as con:
                count = int(con.execute(
                    "SELECT COUNT(*) FROM items WHERE album_id=?",
                    (existing_album_id,),
                ).fetchone()[0] or 0)
            if count:
                return count
        except Exception:
            pass
    try:
        source = Path(source_folder)
        if source.is_dir():
            return sum(
                1 for p in source.rglob("*")
                if p.is_file() and p.suffix.lower() in AUDIO_EXT
            )
    except Exception:
        pass
    return 0


def _folder_track_search_titles(source_folder: str, existing_album_id: int = 0,
                                limit: int = 12) -> List[str]:
    """Return cleaned track titles from DB/files for tracklist-based MB lookup."""
    raw_entries: List[tuple] = []
    if existing_album_id:
        try:
            with _db(text_factory=bytes, row_factory=sqlite3.Row) as con:
                rows = con.execute(
                    "SELECT title, path FROM items WHERE album_id=? "
                    "ORDER BY disc, track, title, id",
                    (existing_album_id,),
                ).fetchall()
            raw_entries.extend((_s(row["title"]), _s(row["path"])) for row in rows)
        except Exception:
            pass
    try:
        source = Path(source_folder)
        if source.is_dir():
            files = sorted(
                [p for p in source.rglob("*")
                 if p.is_file() and p.suffix.lower() in AUDIO_EXT],
                key=lambda p: str(p).lower(),
            )
            raw_entries.extend(
                (_slskd_title_guess_from_name(p.name) or p.stem, str(p))
                for p in files
            )
    except Exception:
        pass

    titles: List[str] = []
    seen: set = set()
    for raw, path in raw_entries:
        # Strip MBID stamp artifacts from track names before MB search
        raw = re.sub(r"\{[^{}]*\}", "", raw).strip(" -_.")
        variants = _album_track_title_variants(raw, path)
        if variants:
            term = sorted(
                variants,
                key=lambda v: (
                    1 if re.match(r"^\d+\b", v) else 0,
                    len(v.split()),
                    len(v),
                ),
            )[0]
        else:
            term = _album_track_norm(raw)
        term = re.sub(r"^(?:bonus\s+track\s*)+", "", term, flags=re.IGNORECASE).strip()
        if not term or len(term) < 3 or term in seen:
            continue
        seen.add(term)
        titles.append(term)
        if len(titles) >= limit:
            break
    return titles


def _musicbrainz_transient_error(ex: Exception) -> bool:
    code = getattr(ex, "code", None)
    if code in {429, 500, 502, 503, 504}:
        return True
    reason = getattr(ex, "reason", "")
    details = " ".join(
        str(part)
        for part in (
            ex,
            reason,
            getattr(reason, "reason", ""),
            getattr(reason, "strerror", ""),
        )
        if part
    ).lower()
    return any(marker in details for marker in (
        "timed out",
        "temporarily",
        "unexpected_eof",
        "eof occurred in violation of protocol",
        "connection reset",
        "connection aborted",
        "remote end closed connection",
        "remote disconnected",
        "server disconnected",
    ))


def _mb_release_search_by_folder_tracks(source_folder: str,
                                        existing_album_id: int = 0,
                                        artist: str = "",
                                        log: Optional[list] = None,
                                        limit: int = 8) -> List[Dict[str, Any]]:
    """Find release candidates by aggregating MB recording search release hits."""
    titles = _folder_track_search_titles(source_folder, existing_album_id, limit=12)
    if not titles:
        return []
    if log is not None:
        log.append(
            "  Searching MusicBrainz by folder track titles: "
            + ", ".join(titles[:5])
            + ("…" if len(titles) > 5 else "")
            + (f" (artist scoped to {artist})" if artist else "")
        )

    release_hits: Dict[str, Dict[str, Any]] = {}
    used_title_only_fallback = False
    for pos, title in enumerate(titles, start=1):
        data: Dict[str, Any] = {}
        query_terms: List[tuple] = []
        if artist:
            query_terms.append(("artist", f'artist:"{artist}" AND recording:"{title}"'))
        query_terms.append(("title", f'recording:"{title}"'))
        for query_scope, query in query_terms:
            params = _up.urlencode({
                "query": query,
                "limit": 50,
                "fmt": "json",
            })
            req = _ur.Request(
                f"https://musicbrainz.org/ws/2/recording?{params}",
                headers={"User-Agent": "BeetsWebControl/1.0 (beets-webcontrol)"},
            )
            data = {}
            for attempt in range(1, 4):
                try:
                    with _ur.urlopen(req, timeout=25) as resp:
                        data = json.loads(resp.read())
                    break
                except Exception as ex:
                    transient = _musicbrainz_transient_error(ex)
                    if transient and attempt < 3:
                        if log is not None:
                            log.append(
                                f"  MB recording search transient error for {title!r}; retrying ({attempt}/3)"
                            )
                        time.sleep(1.5)
                        continue
                    if log is not None:
                        log.append(f"  WARN: MB recording search failed for {title!r}: {ex}")
                    break
            if data.get("recordings") or query_scope == "title":
                if query_scope == "title" and artist:
                    used_title_only_fallback = True
                break
        for rec in data.get("recordings", []) or []:
            artist_credit = " / ".join(
                x.get("artist", {}).get("name", "")
                for x in rec.get("artist-credit", [])
                if isinstance(x, dict)
            )
            for rel in rec.get("releases") or []:
                rid = _s(rel.get("id", "")).strip().lower()
                if not rid:
                    continue
                entry = release_hits.setdefault(rid, {
                    "score": 0,
                    "mb_albumid": rid,
                    "mb_url": f"https://musicbrainz.org/release/{rid}",
                    "album": _s(rel.get("title", "")),
                    "artist": artist_credit,
                    "year": _s(rel.get("date", ""))[:4],
                    "label": "",
                    "country": _s(rel.get("country", "")),
                    "tracks": 0,
                    "formats": [],
                    "is_vinyl": False,
                    "_hit_titles": set(),
                })
                entry["_hit_titles"].add(title)
                entry["score"] = len(entry["_hit_titles"])
        if pos < len(titles):
            time.sleep(1.0)

    if used_title_only_fallback and log is not None:
        log.append("  Artist-scoped recording search had gaps; used title-only fallback for some tracks.")

    cands = list(release_hits.values())
    for cand in cands:
        cand["score"] = int(cand.get("score") or 0) * 10
        cand.pop("_hit_titles", None)
    cands.sort(key=lambda c: c.get("score", 0), reverse=True)
    return cands[:limit]


def _resolve_album_release_for_import(mb_input: str, artist: str, album: str,
                                      year: str, track_count: int, log: list,
                                      source_folder: str = "",
                                      existing_album_id: int = 0,
                                      allow_provided_release_override: bool = False,
                                      allow_oversized_partial: bool = True) -> str:
    """Resolve or discover a concrete MB release UUID suitable for beet import."""
    mb_input = (mb_input or "").strip()
    source_track_count = (
        _folder_import_track_count(source_folder, existing_album_id)
        if source_folder else 0
    )
    rank_track_count = track_count or source_track_count

    def _oversized_release_subset_complete(pre: Dict[str, Any]) -> bool:
        return _preflight_oversized_subset_complete(pre)

    def _same_group_source_sized_release(pre: Dict[str, Any], label: str) -> str:
        if not _oversized_release_subset_complete(pre):
            return ""
        rgid = _s(pre.get("release_group", "") or "").strip().lower()
        if not rgid:
            return ""
        audio_count = int(pre.get("audio_count") or 0)
        log.append(
            f"  {label} matches {pre.get('matches', 0)}/{audio_count} source track(s) "
            f"but the MB release has {pre.get('expected', 0)} tracks; "
            f"checking release group for a {audio_count}-track release…"
        )
        replacement = _resolve_release_group_to_release(
            rgid, log, year=year, track_count=audio_count or rank_track_count)
        if not replacement:
            return ""
        replacement_pre = _folder_release_preflight(
            source_folder,
            replacement,
            existing_album_id=existing_album_id,
            log=None,
        )
        if replacement_pre.get("ok"):
            log.append(
                f"  {label} switched to same-release-group track-count match: "
                f"{replacement} ({replacement_pre.get('matches', 0)}/"
                f"{replacement_pre.get('expected', 0)} track(s))"
            )
            return replacement
        log.append(
            f"  Same-release-group candidate rejected by folder tracklist: "
            f"{replacement_pre.get('matches', 0)}/"
            f"{replacement_pre.get('expected', 0)} track(s) matched"
        )
        return ""

    def _source_accepts_release(rel_id: str, label: str) -> str:
        if not source_folder:
            return rel_id
        pre = _folder_release_preflight(
            source_folder,
            rel_id,
            existing_album_id=existing_album_id,
            log=None,
        )
        replacement = _same_group_source_sized_release(pre, label)
        if replacement:
            return replacement
        if _oversized_release_subset_complete(pre):
            audio_count = int(pre.get("audio_count") or 0)
            if not allow_oversized_partial:
                log.append(
                    f"  {label} rejected by strict edition guard: "
                    f"{pre.get('matches', 0)}/{audio_count} source track(s) match "
                    f"the {pre.get('expected', 0)}-track MusicBrainz release. "
                    "Queueing Review instead of auto-repairing an oversized edition."
                )
                return ""
            log.append(
                f"  {label} accepted as a clean partial match: "
                f"{pre.get('matches', 0)}/{audio_count} source track(s) match "
                f"the {pre.get('expected', 0)}-track MusicBrainz release. "
                "Remaining tracks will stay missing/downloadable."
            )
            return rel_id
        if pre.get("ok"):
            log.append(
                f"  {label} passed folder tracklist check: "
                f"{pre.get('matches', 0)}/{pre.get('expected', 0)} track(s)"
            )
            return rel_id
        log.append(
            f"  {label} rejected by folder tracklist: "
            f"{pre.get('matches', 0)}/{pre.get('expected', 0)} track(s) matched"
            + (f" ({pre.get('release_title')})" if pre.get("release_title") else "")
        )
        for line in (pre.get("examples") or [])[:3]:
            log.append(line)
        return ""

    if mb_input:
        input_uuid_match = re.search(
            r"[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}",
            mb_input,
            re.I,
        )
        if input_uuid_match and "release-group" in mb_input.casefold():
            rg_resolved = _resolve_release_group_to_release(
                input_uuid_match.group(0).lower(),
                log,
                year=year,
                track_count=rank_track_count,
            )
            if rg_resolved:
                accepted = _source_accepts_release(
                    rg_resolved, "Resolved release-group candidate")
                if accepted:
                    return accepted
                if allow_provided_release_override:
                    log.append(
                        "  Manual MusicBrainz release-group override requested; using "
                        "the resolved release despite the folder tracklist mismatch."
                    )
                    return rg_resolved
                log.append("  Searching for a replacement MusicBrainz release from folder tracks…")
            else:
                log.append(
                    f"  WARN: release-group {input_uuid_match.group(0).lower()} "
                    "did not resolve to a release with tracks"
                )

        resolved = _resolve_mb_release_id(mb_input, log) or ""
        if resolved and _mb_release_has_tracks(resolved):
            accepted = _source_accepts_release(resolved, "Provided MusicBrainz release")
            if accepted:
                return accepted
            if allow_provided_release_override:
                log.append(
                    "  Manual MusicBrainz release override requested; using the "
                    "provided release ID despite the folder tracklist mismatch."
                )
                return resolved
            log.append("  Searching for a replacement MusicBrainz release from folder tracks…")
        elif resolved and _MB_UUID_RE.match(resolved):
            rg_resolved = _resolve_release_group_to_release(
                resolved, log, year=year, track_count=track_count)
            if rg_resolved:
                accepted = _source_accepts_release(rg_resolved, "Resolved release-group candidate")
                if accepted:
                    return accepted
                if allow_provided_release_override:
                    log.append(
                        "  Manual MusicBrainz release-group override requested; using "
                        "the resolved release despite the folder tracklist mismatch."
                    )
                    return rg_resolved
                log.append("  Searching for a replacement MusicBrainz release from folder tracks…")
            log.append(f"  WARN: {resolved} did not resolve to a release with tracks")

    log.append("  Searching MusicBrainz for a release ID…")
    album_only_pool_loaded = False
    cands = _mb_release_search(album, artist, limit=6, year=year,
                               track_count=rank_track_count, log=log)
    if not cands and source_folder and artist:
        log.append(
            "  No artist-scoped MusicBrainz candidates found; "
            "trying album title without artist…"
        )
        cands = _mb_release_search(album, "", limit=12, year=year,
                                   track_count=rank_track_count, log=log)
        album_only_pool_loaded = True
    if not cands and not source_folder:
        return ""

    if source_folder:
        scored_cands: List[tuple] = []
        rejected: List[str] = []
        seen_mbids: set = set()

        def _score_candidate_pool(candidates: List[Dict[str, Any]]) -> None:
            for cand in candidates:
                cand_mbid = (cand.get("mb_albumid") or "").strip().lower()
                if not cand_mbid or cand_mbid in seen_mbids:
                    continue
                seen_mbids.add(cand_mbid)
                pre = _folder_release_preflight(
                    source_folder,
                    cand_mbid,
                    existing_album_id=existing_album_id,
                    log=None,
                )
                matches = int(pre.get("matches") or 0)
                expected = int(pre.get("expected") or cand.get("tracks") or 0)
                replacement = _same_group_source_sized_release(
                    pre,
                    f"MusicBrainz candidate {cand.get('artist','?')} – {cand.get('album','?')}",
                )
                if replacement:
                    replacement_cand = dict(cand)
                    replacement_cand["mb_albumid"] = replacement
                    if source_track_count:
                        replacement_cand["tracks"] = source_track_count
                    scored_cands.append((
                        matches,
                        -abs((replacement_cand.get("tracks") or expected) - rank_track_count)
                        if rank_track_count else 0,
                        replacement_cand,
                    ))
                    continue
                if _oversized_release_subset_complete(pre):
                    if not allow_oversized_partial:
                        rejected.append(
                            f"{cand.get('artist','?')} – {cand.get('album','?')} "
                            f"{cand.get('year','')} [{cand_mbid}] "
                            f"(oversized partial: {matches}/{int(pre.get('audio_count') or 0)} "
                            f"source track matches, release has {expected} tracks)"
                        )
                        continue
                    scored_cands.append((
                        matches,
                        -abs((cand.get("tracks") or expected) - rank_track_count)
                        if rank_track_count else 0,
                        cand,
                    ))
                    continue
                if pre.get("ok"):
                    scored_cands.append((
                        matches,
                        -abs((cand.get("tracks") or expected) - rank_track_count)
                        if rank_track_count else 0,
                        cand,
                    ))
                    continue
                rejected.append(
                    f"{cand.get('artist','?')} – {cand.get('album','?')} "
                    f"{cand.get('year','')} [{cand_mbid}] ({matches}/{expected} track matches)"
                )

        _score_candidate_pool(cands)
        if not scored_cands and artist and not album_only_pool_loaded:
            log.append(
                "  No artist-scoped MusicBrainz candidate matched the folder; "
                "trying album title without artist…"
            )
            _score_candidate_pool(
                _mb_release_search(album, "", limit=12, year=year,
                                   track_count=rank_track_count, log=log)
            )
        if not scored_cands:
            track_cands = _mb_release_search_by_folder_tracks(
                source_folder, existing_album_id=existing_album_id,
                artist=artist, log=log, limit=12)
            if track_cands:
                log.append(
                    f"  Found {len(track_cands)} MusicBrainz candidate(s) "
                    "from folder track titles."
                )
                _score_candidate_pool(track_cands)

        if scored_cands:
            scored_cands.sort(key=lambda item: (item[0], item[1]), reverse=True)
            best = scored_cands[0][2]
            mbid = (best.get("mb_albumid") or "").strip().lower()
            log.append(
                f"  MusicBrainz release selected after tracklist check: "
                f"{best.get('artist','?')} – {best.get('album','?')} "
                f"{best.get('year','')} [{mbid}]"
            )
            return mbid

        for line in rejected[:3]:
            log.append(f"  MusicBrainz candidate rejected: {line}")
        log.append(
            "  No MusicBrainz search candidate matched the folder tracklist; "
            "manual Review is required."
        )
        return ""

    best = cands[0]
    mbid = (best.get("mb_albumid") or "").strip().lower()
    if mbid:
        log.append(f"  MusicBrainz release selected: {best.get('artist','?')} – "
                   f"{best.get('album','?')} {best.get('year','')} [{mbid}]")
    return mbid


def _json_from_flask_response(resp) -> Dict[str, Any]:
    """Extract JSON from Flask Response or (Response, status) tuples."""
    if isinstance(resp, tuple):
        resp = resp[0]
    try:
        return resp.get_json(silent=True) or {}
    except Exception:
        return {}


def _start_reimport_disk_job_internal(aldir: str, mb_albumid: str,
                                      albumartist: str = "",
                                      existing_album_id: int = 0,
                                      wanted_tracks: Optional[List[Dict[str, Any]]] = None,
                                      strict_edition_guard: bool = False,
                                      replace_existing_item_ids: Optional[List[int]] = None,
                                      skip_import_lock: bool = False) -> str:
    """Start the existing reimport-disk job without making an HTTP request."""
    payload = {"aldir": aldir, "mb_albumid": mb_albumid}
    if albumartist:
        payload["albumartist"] = albumartist
    if existing_album_id:
        payload["existing_album_id"] = existing_album_id
    if wanted_tracks:
        payload["wanted_tracks"] = _normalise_wanted_tracks(wanted_tracks)
    if replace_existing_item_ids:
        payload["replace_existing_item_ids"] = [int(v) for v in replace_existing_item_ids if int(v or 0)]
        payload["replace_existing"] = True
    if strict_edition_guard:
        payload["strict_edition_guard"] = True
    if skip_import_lock:
        payload["skip_import_lock"] = True
    with app.test_request_context("/api/albums/reimport-disk",
                                  method="POST", json=payload):
        resp = reimport_disk()
    data = _json_from_flask_response(resp)
    if not data.get("ok") or not data.get("job_id"):
        raise RuntimeError(data.get("error") or "failed to start import job")
    return data["job_id"]


def _wait_for_child_job(job_id: str, log: list, cancel_event=None,
                        prefix: str = "import", timeout: int = 900,
                        idle_timeout: int = 0, progress: Optional[Any] = None) -> Any:
    """Mirror a child job and fail on failure, wall timeout, or idle stall."""
    started = time.time()
    deadline = started + timeout if timeout and timeout > 0 else None
    last_activity = started
    last_state_key: Optional[Tuple[Any, ...]] = None
    timeout_notice_logged = False
    seen = 0
    mirrored_lines: List[str] = []

    def _mirrored_log_indicates_success() -> bool:
        text = "\n".join(_s(line) for line in mirrored_lines[-120:])
        if re.search(r'(^|\n)\s*ERROR:|Traceback|job failed', text, re.IGNORECASE):
            return False
        success_markers = (
            "Updated ",
            "track(s) matched and numbered from MB",
            "Final file names",
            "Existing album already matches",
            "Existing album repair completed",
        )
        return any(marker in text for marker in success_markers)

    def _child_failure_detail() -> str:
        for line in reversed(mirrored_lines[-120:]):
            text = _s(line).strip()
            if not text:
                continue
            if (
                "youtube rejected the configured yt-dlp cookies" in text.lower()
                or text.startswith("ERROR:")
                or "Traceback" in text
                or _yt_bot_check_message(text)
            ):
                return text[:500]
        return ""

    def _should_mirror_child_line(line: Any) -> bool:
        if prefix == "metadata-repair":
            text = _s(line).strip()
            if not text:
                return False
            lower = text.lower()
            if "error" in lower or "traceback" in lower or "failed" in lower or "warn" in lower:
                return True
            if text.startswith(("Scanning for albums", "Done -")):
                return True
            return False
        if prefix != "duplicates":
            return True
        text = _s(line).strip()
        if not text:
            return False
        lower = text.lower()
        if "error" in lower or "traceback" in lower or "failed" in lower:
            return True
        if text.startswith("Found ") and "audio file" in lower:
            return True
        if text.startswith(("Scanning ", "Comparing ", "Done")):
            return True
        if re.match(r"^\[\d+/\d+\]", text):
            return False
        if "DUPLICATE [" in text or "REJECTED [" in text:
            return False
        if text.startswith(("skipped stale path:", "skipped unreadable path:")):
            return False
        return True

    while True:
        now = time.time()
        if cancel_event is not None and cancel_event.is_set():
            child = jobs.get(job_id)
            if child:
                child.kill()
            raise RuntimeError("cancelled")
        child = jobs.get(job_id)
        if not child:
            if _mirrored_log_indicates_success():
                log.append(
                    f"  [{prefix}] Child job record was already cleaned up after a successful import; continuing."
                )
                return {"job_id": job_id, "status": "success", "result_inferred_from_log": True}
            raise RuntimeError(f"child job not found: {job_id}")
        new_lines = child.log[seen:]
        for line in new_lines:
            if _should_mirror_child_line(line):
                log.append(f"  [{prefix}] {line}")
        mirrored_lines.extend(new_lines)
        seen += len(new_lines)
        child_state = dict(getattr(child, "state", {}) or {})
        state_key = (
            child.status,
            len(child.log),
            child_state.get("scanned_count"),
            child_state.get("found_count"),
            child_state.get("total_count"),
            child_state.get("remaining_count"),
            child_state.get("current_path"),
            child_state.get("current_task"),
            child_state.get("current_result"),
            child_state.get("duplicate_type"),
            child_state.get("progress_percent"),
        )
        if new_lines or state_key != last_state_key:
            last_activity = now
            last_state_key = state_key
            if progress and child_state:
                progress(child_state)
        if child.status != "running":
            if child.status != "success":
                detail = _child_failure_detail()
                raise RuntimeError(
                    f"{prefix} job failed: {detail}" if detail else f"{prefix} job failed"
                )
            return getattr(child, "result", None)
        if deadline is not None and now >= deadline:
            if idle_timeout and (now - last_activity) < idle_timeout:
                if not timeout_notice_logged:
                    log.append(
                        f"  [{prefix}] Still making progress after {timeout}s; "
                        f"continuing unless idle for {idle_timeout}s."
                    )
                    timeout_notice_logged = True
            else:
                child.kill()
                raise RuntimeError(f"{prefix} job timed out")
        if idle_timeout and (now - last_activity) >= idle_timeout:
            child.kill()
            raise RuntimeError(f"{prefix} job stalled with no progress for {idle_timeout}s")
        time.sleep(2)


@app.post("/api/download/album")
def api_download_album():
    """Start a background job to download an album via slskd (primary)
    or yt-dlp (fallback), then import/tag/move it unless auto_import=false."""
    data        = request.get_json(silent=True) or {}
    artist      = (data.get("artist")      or "").strip()
    album       = (data.get("album")       or "").strip()
    year        = str(data.get("year")     or "").strip()
    track_count = int(data.get("track_count") or 0)
    mb_albumid  = (data.get("mb_albumid")  or "").strip()
    method      = _normalise_download_method(data.get("method") or "slskd")
    auto_import = bool(data.get("auto_import", True))
    forced_albumartist = _artist_folder_name_without_mbid(data.get("albumartist") or artist).strip()
    raw_fallback_method = data.get("fallback_method")
    fallback_method = _normalise_download_method(raw_fallback_method or "spotiflac", "spotiflac")
    source_fallback_methods = _slskd_fallback_methods(fallback_method)
    try_source_fallback = (
        (raw_fallback_method is not None and fallback_method in {"soundcloud", "spotiflac"})
        or bool(data.get("try_ytdlp_fallback"))
        or bool(data.get("ytdlp_fallback"))
        or bool(data.get("try_source_fallback"))
    )
    wanted_tracks = _normalise_wanted_tracks(
        data.get("missing_tracks") or data.get("wanted_tracks") or [])
    replace_existing_item_ids = []
    for raw_id in (data.get("replace_existing_item_ids") or []):
        try:
            item_id = int(raw_id or 0)
            if item_id > 0:
                replace_existing_item_ids.append(item_id)
        except Exception:
            pass
    replace_existing = bool(data.get("replace_existing") or replace_existing_item_ids)
    try:
        existing_album_id = int(data.get("existing_album_id") or data.get("album_id") or 0)
    except Exception:
        existing_album_id = 0
    # method: "slskd" | "soundcloud" | "spotiflac";
    # slskd can optionally fall back through non-YouTube direct sources.

    if not artist or not album:
        return jsonify({"ok": False, "error": "artist and album required"})
    if method not in _DOWNLOAD_METHODS:
        return jsonify({
            "ok": False,
            "error": (
                f"Unknown method {method!r}; use 'slskd', 'spotiflac', "
                "'ytdlp', or 'soundcloud'"
            ),
        })

    def _do(log, cancel_event=None):
        _safe = lambda s: re.sub(r'[\\/:*?"<>|]', '_', str(s)).strip()
        yr_sfx   = f" ({year})" if year else ""
        dest_dir = str(DOWNLOADS_ROOT / _safe(artist) / (_safe(album) + yr_sfx))
        download_result: Dict[str, Any]
        resolved_mbid = mb_albumid
        effective_track_count = track_count
        job_wanted_tracks = list(wanted_tracks)
        supplied_mbid_match = re.search(
            r"[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}",
            mb_albumid,
            re.I,
        )
        supplied_mbid = supplied_mbid_match.group(0).lower() if supplied_mbid_match else ""
        release_group_requested = "release-group" in _s(mb_albumid).casefold()
        resolved_release_group_id = ""
        if auto_import or mb_albumid:
            log.append("[import] Resolving MusicBrainz release before download…")
            resolved_mbid = _resolve_album_release_for_import(
                mb_albumid, artist, album, year, track_count, log)
            if resolved_mbid:
                if supplied_mbid and supplied_mbid != _s(resolved_mbid).strip().lower():
                    release_group_requested = True
                    resolved_release_group_id = supplied_mbid
                mb_release = _fetch_mb_release_tracklist(resolved_mbid, log)
                mb_tracks = len(mb_release.get("tracks") or []) if mb_release.get("ok") else 0
                if mb_release.get("release_group"):
                    resolved_release_group_id = _s(mb_release.get("release_group")).strip().lower()
                if mb_tracks and (not effective_track_count or effective_track_count != mb_tracks):
                    log.append(f"  MusicBrainz track count: {mb_tracks}")
                    effective_track_count = mb_tracks
            elif auto_import:
                raise RuntimeError("Could not resolve a MusicBrainz release ID before download")

        if existing_album_id and resolved_mbid:
            if replace_existing and job_wanted_tracks:
                log.append(
                    f"[import] Replacement mode: {len(job_wanted_tracks)} track(s) "
                    f"will be downloaded for existing album_id {existing_album_id}"
                )
            else:
                job_wanted_tracks = _wanted_tracks_not_in_album(
                    existing_album_id, resolved_mbid, job_wanted_tracks, log)
            if job_wanted_tracks:
                log.append(
                    f"[import] Missing-track mode: {len(job_wanted_tracks)} track(s) "
                    f"will be downloaded for existing album_id {existing_album_id}"
                )
            elif existing_album_id:
                review_reason = (
                    "Requested missing track(s) are not missing for the selected "
                    "MusicBrainz release. Verify the release edition before downloading."
                )
                log.append(
                    "[import] No requested tracks are still missing for this selected "
                    "MusicBrainz release; skipping download"
                )
                album_folder = _album_folder_for_album_id(existing_album_id)
                if album_folder:
                    try:
                        comp = _album_mb_completeness(existing_album_id, resolved_mbid, log)
                    except Exception:
                        comp = {}
                    requested = _normalise_wanted_tracks(wanted_tracks)
                    currently_missing = _normalise_wanted_tracks((comp or {}).get("missing") or [])
                    suggestion = {
                        "albumartist": artist,
                        "album": album,
                        "year": year,
                        "mb_albumid": resolved_mbid,
                        "mb_url": f"https://musicbrainz.org/release/{resolved_mbid}",
                        "mb_valid": bool(_MB_UUID_RE.match(_s(resolved_mbid).strip().lower())),
                        "confidence": "low",
                        "reason": review_reason,
                    }
                    evidence = _ai_match_evidence_packet(
                        "missing_track",
                        folder_path=album_folder,
                        suggestion=suggestion,
                        folder_evidence=_build_folder_evidence(album_folder),
                        preflight=_folder_release_preflight(
                            album_folder,
                            resolved_mbid,
                            existing_album_id=existing_album_id,
                            log=None,
                        ),
                        wanted_tracks=requested,
                        reason=review_reason,
                    )
                    evidence["requested_tracks"] = requested
                    evidence["currently_missing_tracks"] = currently_missing
                    if _queue_folder_for_manual_review(
                        album_folder,
                        suggestion,
                        review_reason,
                        log,
                        allow_existing=True,
                        evidence=evidence,
                    ):
                        log.append(
                            "[import] Queued existing album for Review with requested-track evidence."
                        )
                return {
                    "aldir": "",
                    "method": method,
                    "files": 0,
                    "mb_albumid": resolved_mbid,
                    "imported": True,
                    "already_complete": True,
                    "existing_album_id": existing_album_id,
                }

        expected_download_count = len(job_wanted_tracks) if job_wanted_tracks else effective_track_count

        def _maybe_switch_release_for_slskd_candidate(candidate_dir: str,
                                                      candidate_count: int) -> int:
            nonlocal resolved_mbid, effective_track_count, expected_download_count
            if (
                job_wanted_tracks
                or not release_group_requested
                or not resolved_release_group_id
                or not candidate_count
                or candidate_count == effective_track_count
            ):
                return 0
            if effective_track_count:
                min_viable = max(1, min(effective_track_count, int(effective_track_count * 0.70)))
                if candidate_count < min_viable:
                    return 0
            replacement = _resolve_release_group_to_release(
                resolved_release_group_id,
                log,
                year=year,
                track_count=candidate_count,
            )
            replacement = _s(replacement).strip().lower()
            if not replacement or replacement == _s(resolved_mbid).strip().lower():
                return 0
            replacement_mb = _fetch_mb_release_tracklist(replacement, log)
            replacement_count = len(replacement_mb.get("tracks") or []) if replacement_mb.get("ok") else 0
            if replacement_count != candidate_count:
                log.append(
                    "  [slskd] Same-release-group candidate did not match downloaded "
                    f"file count: MB has {replacement_count or '?'} track(s), "
                    f"download has {candidate_count}."
                )
                return 0
            preflight = _folder_release_preflight(
                candidate_dir,
                replacement,
                existing_album_id=existing_album_id,
                log=None,
            )
            if not preflight.get("ok"):
                log.append(
                    "  [slskd] Same-release-group candidate rejected by downloaded "
                    f"folder tracklist: {preflight.get('matches', 0)}/"
                    f"{preflight.get('expected', 0)} track(s) matched."
                )
                return 0
            old_mbid = _s(resolved_mbid).strip().lower()
            old_count = int(effective_track_count or 0)
            resolved_mbid = replacement
            effective_track_count = replacement_count
            expected_download_count = replacement_count
            log.append(
                "  [slskd] Downloaded folder has "
                f"{candidate_count} file(s); switched MusicBrainz release within "
                f"release-group {resolved_release_group_id}: "
                f"{old_mbid or '?'} ({old_count or '?'} tracks) -> "
                f"{replacement} ({replacement_count} tracks)."
            )
            return replacement_count

        def _import_downloaded_album(
            import_dir: str,
            import_wanted_tracks: Optional[List[Dict[str, Any]]] = None,
        ) -> Dict[str, Any]:
            if not resolved_mbid:
                raise RuntimeError("Could not resolve a MusicBrainz release ID for import")
            active_wanted_tracks = (
                _normalise_wanted_tracks(import_wanted_tracks)
                if import_wanted_tracks is not None
                else job_wanted_tracks
            )
            if active_wanted_tracks:
                _validate_wanted_download_identity_before_import(
                    import_dir,
                    active_wanted_tracks,
                    log,
                    fallback_artist=forced_albumartist or artist,
                )
            _validate_import_source_audio(import_dir, log, reject_downloads=True)
            log.append(f"[import] Starting Beets import/tag/move for {import_dir}")
            import_job_id = _start_reimport_disk_job_internal(
                import_dir, resolved_mbid, albumartist=forced_albumartist,
                existing_album_id=existing_album_id,
                wanted_tracks=active_wanted_tracks,
                replace_existing_item_ids=replace_existing_item_ids)
            log.append(f"[import] Job {import_job_id} started; waiting for completion...")
            import_result = _wait_for_child_job(import_job_id, log, cancel_event,
                                                prefix="import", timeout=1200)
            log.append("[import] Complete — files imported, tagged, and moved into the music folder")
            return {
                "imported": True,
                "import_job_id": import_job_id,
                "import_result": import_result,
                "existing_album_id": existing_album_id,
                "missing_track_count": len(active_wanted_tracks),
            }

        def _direct_dest_dir(selection_tracks: Optional[List[Dict[str, Any]]] = None,
                             direct_method: Optional[str] = None) -> str:
            source_method = _normalise_download_method(direct_method or method, "ytdlp")
            active_tracks = (
                _normalise_wanted_tracks(selection_tracks)
                if selection_tracks is not None
                else job_wanted_tracks
            )
            if active_tracks:
                suffix = str(int(time.time() * 1000))
                source_slug = re.sub(r"[^a-z0-9]+", "", source_method) or "download"
                return str(
                    DOWNLOADS_ROOT
                    / _safe(artist)
                    / f"{_safe(album)}{yr_sfx} - {source_slug} missing {suffix}"
                )
            return dest_dir

        def _download_ytdlp_selection(
            selection_tracks: Optional[List[Dict[str, Any]]] = None,
            direct_method: Optional[str] = None,
        ) -> Dict[str, Any]:
            source_method = _normalise_download_method(direct_method or method, "ytdlp")
            active_tracks = (
                _normalise_wanted_tracks(selection_tracks)
                if selection_tracks is not None
                else job_wanted_tracks
            )
            yt_dir = _direct_dest_dir(active_tracks, source_method)
            log.append(f"  Downloading via {_download_method_label(source_method)} → {yt_dir}")
            if active_tracks:
                if source_method == "spotiflac":
                    n = _spotiflac_missing_tracks_download(
                        artist, album, year, yt_dir, log, active_tracks)
                else:
                    n = _ytdlp_missing_tracks_download(
                        artist, album, year, yt_dir, log, active_tracks,
                        source=source_method)
            else:
                if source_method == "spotiflac":
                    n = _spotiflac_album_download(
                        artist, album, year, yt_dir, log,
                        track_count=effective_track_count,
                        mb_albumid=resolved_mbid)
                else:
                    n = _ytdlp_album_download(
                        artist, album, year, yt_dir, log,
                        track_count=effective_track_count,
                        source=source_method)
            return {
                "aldir": yt_dir,
                "method": source_method,
                "files": n,
                "mb_albumid": resolved_mbid,
            }

        def _try_direct_sources_after_slskd(slskd_error: Exception,
                                            selection_tracks: Optional[List[Dict[str, Any]]] = None,
                                            fallback_from: str = "slskd") -> Dict[str, Any]:
            active_tracks = (
                _normalise_wanted_tracks(selection_tracks)
                if selection_tracks is not None
                else job_wanted_tracks
            )
            if not try_source_fallback:
                raise slskd_error
            fallback_tracks = active_tracks or None
            fallback_scope = (
                f"{len(active_tracks)} missing track(s)"
                if active_tracks
                else "the full album"
            )
            methods = list(source_fallback_methods)
            failures: List[str] = []
            log.append(
                f"[fallback] SLSKD could not provide a valid candidate for "
                f"{fallback_scope}; trying direct sources: "
                + ", ".join(_download_method_label(method) for method in methods)
            )
            for fallback_source in methods:
                fallback_result = None
                try:
                    log.append(
                        f"[fallback] Trying {_download_method_label(fallback_source)} "
                        f"for {fallback_scope}."
                    )
                    fallback_result = _download_ytdlp_selection(
                        fallback_tracks, direct_method=fallback_source)
                    fallback_result["fallback_from"] = fallback_from
                    fallback_result["slskd_error"] = str(slskd_error)
                    if auto_import:
                        fallback_result.update(
                            _import_downloaded_album(
                                fallback_result["aldir"], fallback_tracks))
                    return fallback_result
                except Exception as direct_ex:
                    failures.append(
                        f"{_download_method_label(fallback_source)}: {direct_ex}"
                    )
                    log.append(
                        f"[fallback] {_download_method_label(fallback_source)} failed: "
                        f"{direct_ex}"
                    )
                    if fallback_result:
                        _delete_staged_import_folder(
                            fallback_result.get("aldir", ""), log
                        )
            raise RuntimeError(
                "SLSKD download failed; direct-source fallback also failed: "
                + "; ".join(failures)
            ) from slskd_error

        if method == "slskd":
            # ── Soulseek via slskd ───────────────────────────────────────────
            max_slskd_attempts = 12

            def _skip_key(username: str, remote_dir: str) -> tuple:
                return (
                    _s(username).strip().lower(),
                    _s(remote_dir).replace("\\", "/").strip().lower(),
                )

            def _download_slskd_selection(
                selection_tracks: List[Dict[str, Any]],
                expected_count: int,
                skip_candidates: Optional[set] = None,
            ) -> Dict[str, Any]:
                slskd_skip_candidates = skip_candidates if skip_candidates is not None else set()
                last_slskd_error: Optional[Exception] = None
                for attempt in range(1, max_slskd_attempts + 1):
                    username = ""
                    remote_dir = ""
                    queued: List[str] = []
                    try:
                        if attempt > 1:
                            log.append(
                                f"  [slskd] Trying another Soulseek candidate "
                                f"({attempt}/{max_slskd_attempts})..."
                            )
                        username, queued, expected, remote_dir = _slskd_search_and_queue(
                            artist, album, year, log, track_count=effective_track_count,
                            wanted_tracks=selection_tracks,
                            skip_candidates=slskd_skip_candidates)
                        matched_tracks = _wanted_tracks_satisfied_by_names(
                            queued, selection_tracks)
                        download_target_tracks = (
                            matched_tracks if selection_tracks and matched_tracks
                            else _normalise_wanted_tracks(selection_tracks)
                        )
                        download_expected_count = (
                            len(download_target_tracks)
                            if selection_tracks and download_target_tracks
                            else expected_count
                        )
                        aldir, transfer_hints = _slskd_wait_downloads(username, queued, log, timeout=600)
                        time.sleep(3)
                        aldir, afiles = _find_slskd_downloaded_files(
                            username, queued, expected or aldir, log,
                            artist=artist, album=album, track_count=download_expected_count,
                            transfer_hints=transfer_hints,
                            wanted_tracks=download_target_tracks)
                        if not afiles:
                            raise RuntimeError(
                                f"No queued Soulseek files found at {aldir} after download; "
                                "refusing unrelated fallback folders"
                            )
                        if (
                            not selection_tracks
                            and download_expected_count
                            and len(afiles) != download_expected_count
                        ):
                            switched_count = _maybe_switch_release_for_slskd_candidate(
                                aldir,
                                len(afiles),
                            )
                            if switched_count:
                                download_expected_count = switched_count
                        if download_expected_count:
                            required_files = max(1, download_expected_count)
                            if len(afiles) < required_files:
                                raise RuntimeError(
                                    f"Downloaded candidate has only {len(afiles)}/{download_expected_count} "
                                    "expected files; refusing incomplete import"
                                )
                        log.append(f"  [slskd] OK {len(afiles)} file(s) in {aldir}")
                        log.append(
                            "  [slskd] Download phase complete for this candidate; "
                            "no additional Soulseek sources will be queued unless "
                            "import validation fails."
                        )
                        return {
                            "aldir": aldir,
                            "files": afiles,
                            "queued": queued,
                            "username": username,
                            "remote_dir": remote_dir,
                            "wanted_tracks": download_target_tracks,
                        }
                    except Exception as ex:
                        last_slskd_error = ex
                        if username or remote_dir:
                            if queued:
                                log.append("  [slskd] Candidate failed after queueing; cancelling it before retrying.")
                                _slskd_cancel_queued_downloads(username, queued, log)
                                _slskd_cleanup_failed_candidate_files(username, queued, log)
                            slskd_skip_candidates.add(_skip_key(username, remote_dir))
                            if attempt < max_slskd_attempts:
                                log.append(f"  [slskd] Candidate failed: {ex}")
                                log.append(
                                    "  [slskd] Skipping that peer/folder and continuing automatically."
                                )
                                continue
                        if slskd_skip_candidates:
                            raise RuntimeError(
                                f"SLSKD could not find a usable candidate after "
                                f"{len(slskd_skip_candidates)} failed candidate(s): {ex}"
                            ) from ex
                        raise
                raise RuntimeError(
                    f"SLSKD could not find a usable candidate after {max_slskd_attempts} attempts"
                    + (f": {last_slskd_error}" if last_slskd_error else "")
                )

            if job_wanted_tracks:
                log.append(
                    f"[import] SLSKD batch mode: {len(job_wanted_tracks)} "
                    "requested missing track(s) will be queued together"
                )
            else:
                log.append("[import] SLSKD batch mode: album tracks will be queued together")
            slskd_skip_candidates: set = set()
            if auto_import:
                last_import_error: Optional[Exception] = None
                for import_attempt in range(1, max_slskd_attempts + 1):
                    try:
                        dl = _download_slskd_selection(
                            job_wanted_tracks,
                            expected_download_count,
                            skip_candidates=slskd_skip_candidates,
                        )
                    except Exception as ex:
                        return _try_direct_sources_after_slskd(ex)
                    aldir = dl["aldir"]
                    afiles = dl["files"]
                    dl_wanted_tracks = _normalise_wanted_tracks(
                        dl.get("wanted_tracks") or job_wanted_tracks)
                    import_dir = _stage_selected_audio_files(
                        aldir, afiles, artist, album, log,
                        target_tracks=dl_wanted_tracks or None,
                    )
                    try:
                        download_result = {
                            "aldir": import_dir,
                            "method": "slskd",
                            "files": len(afiles),
                            "mb_albumid": resolved_mbid,
                            "username": dl.get("username", ""),
                            "remote_dir": dl.get("remote_dir", ""),
                        }
                        download_result.update(
                            _import_downloaded_album(import_dir, dl_wanted_tracks))
                    except Exception as ex:
                        last_import_error = ex
                        username = _s(dl.get("username", ""))
                        queued = list(dl.get("queued") or [])
                        remote_dir = _s(dl.get("remote_dir", ""))
                        log.append(
                            "  [slskd] Downloaded candidate failed import validation: "
                            f"{ex}"
                        )
                        if queued:
                            log.append(
                                "  [slskd] Cleaning failed candidate before trying another source."
                            )
                            _slskd_cancel_queued_downloads(username, queued, log)
                            _slskd_cleanup_failed_candidate_files(username, queued, log)
                        _delete_staged_import_folder(import_dir, log)
                        if username or remote_dir:
                            slskd_skip_candidates.add(_skip_key(username, remote_dir))
                        if import_attempt < max_slskd_attempts:
                            log.append(
                                "  [slskd] Trying the next peer/folder because the "
                                "downloaded files did not validate."
                            )
                            continue
                        break
                    if job_wanted_tracks and dl_wanted_tracks and len(dl_wanted_tracks) < len(job_wanted_tracks):
                        remaining_after_slskd = _wanted_tracks_not_in_album(
                            existing_album_id, resolved_mbid, job_wanted_tracks, log)
                        if remaining_after_slskd:
                            remaining_desc = ", ".join(
                                _wanted_track_label(t) for t in remaining_after_slskd[:8]
                            )
                            if not try_source_fallback:
                                raise RuntimeError(
                                    "SLSKD imported "
                                    f"{len(dl_wanted_tracks)}/{len(job_wanted_tracks)} "
                                    "requested missing track(s), but these remain: "
                                    f"{remaining_desc}"
                                )
                            log.append(
                                "[fallback] SLSKD satisfied "
                                f"{len(dl_wanted_tracks)}/{len(job_wanted_tracks)} "
                                "requested missing track(s); trying direct sources for remaining: "
                                f"{remaining_desc}"
                            )
                            try:
                                fallback_result = _try_direct_sources_after_slskd(
                                    RuntimeError(
                                        "partial SLSKD candidate left unresolved track(s): "
                                        f"{remaining_desc}"
                                    ),
                                    remaining_after_slskd,
                                    fallback_from="partial_slskd",
                                )
                            except Exception as direct_ex:
                                raise RuntimeError(
                                    "SLSKD imported "
                                    f"{len(dl_wanted_tracks)}/{len(job_wanted_tracks)} "
                                    "requested missing track(s), but direct-source fallback for the "
                                    f"remaining track(s) failed: {direct_ex}"
                                ) from direct_ex
                            combined = dict(download_result)
                            combined["method"] = f"slskd+{fallback_result.get('method') or 'fallback'}"
                            combined["files"] = int(download_result.get("files") or 0) + int(fallback_result.get("files") or 0)
                            combined["fallback_result"] = fallback_result
                            return combined
                    return download_result
                slskd_error = RuntimeError(
                    f"SLSKD could not import a valid candidate after "
                    f"{len(slskd_skip_candidates)} failed candidate(s)"
                    + (f": {last_import_error}" if last_import_error else "")
                )
                return _try_direct_sources_after_slskd(slskd_error)

            try:
                dl = _download_slskd_selection(
                    job_wanted_tracks,
                    expected_download_count,
                    skip_candidates=slskd_skip_candidates,
                )
            except Exception as ex:
                return _try_direct_sources_after_slskd(ex)
            aldir = dl["aldir"]
            afiles = dl["files"]
            download_result = {"aldir": aldir, "method": "slskd",
                               "files": len(afiles), "mb_albumid": resolved_mbid}

        else:
            # ── Direct non-SLSKD source ──────────────────────────────────────
            download_result = _download_ytdlp_selection(direct_method=method)

        if not auto_import:
            return download_result

        aldir = download_result["aldir"]
        download_result["mb_albumid"] = resolved_mbid
        download_result.update(_import_downloaded_album(aldir))
        return download_result

    label = f"{_download_method_job_label(method)} Import: {artist} – {album}"
    job = jobs.start_python(_do, label=label,
                            metadata={"type": "download-import", "artist": artist,
                                      "album": album, "year": year,
                                      "track_count": track_count,
                                      "mb_albumid": mb_albumid, "method": method,
                                      "albumartist": forced_albumartist,
                                      "existing_album_id": existing_album_id,
                                      "missing_track_count": len(wanted_tracks),
                                      "try_source_fallback": try_source_fallback,
                                      "try_ytdlp_fallback": try_source_fallback,
                                      "fallback_methods": source_fallback_methods})
    return jsonify({"ok": True, "job_id": job.job_id})


_disc_cache: Dict[str, Any] = {}        # artist_name → MB discography result
_disc_cache_lock = threading.Lock()

def _fetch_discography(artist_name: str) -> Dict[str, Any]:
    """Fetch + compare discography synchronously (runs in a thread). Returns result dict."""


    # --- Step 1: artist search ---
    mbid = _artist_library_mbid(artist_name)
    mb_artist = artist_name
    if mbid:
        req = _ur.Request(f"https://musicbrainz.org/ws/2/artist/{mbid}?fmt=json",
                          headers={"User-Agent": "BeetsWebControl/1.0"})
        try:
            with _ur.urlopen(req, timeout=20) as r:
                adata = json.loads(r.read())
            mb_artist = adata.get("name") or artist_name
        except Exception:
            mbid = ""
    if not mbid:
        q = _up.urlencode({"query": f'artist:"{artist_name}"', "limit": 8, "fmt": "json"})
        req = _ur.Request(f"https://musicbrainz.org/ws/2/artist?{q}",
                          headers={"User-Agent": "BeetsWebControl/1.0"})
        with _ur.urlopen(req, timeout=20) as r:
            adata = json.loads(r.read())

        artists = adata.get("artists", [])
        if not artists:
            raise ValueError(f"'{artist_name}' not found on MusicBrainz")

        def _artist_score(a):
            nm = _artist_name_key(a.get("name", ""))
            sn = _artist_name_key((a.get("sort-name") or "").split(",", 1)[0])
            want = _artist_name_key(artist_name)
            if nm == want or sn == want:
                return 100
            if want and (want in nm or nm in want):
                return 75
            return int(a.get("score") or 0)

        artist_hit = max(artists, key=_artist_score)
        mbid      = artist_hit["id"]
        mb_artist = artist_hit.get("name") or artist_name

    # --- Step 2: release-groups (page through, respecting 1 req/s) ---
    rgs: list = []
    offset = 0
    while True:
        time.sleep(1.1)
        p = _up.urlencode({"artist": mbid, "limit": 100, "offset": offset, "fmt": "json"})
        req = _ur.Request(f"https://musicbrainz.org/ws/2/release-group?{p}",
                          headers={"User-Agent": "BeetsWebControl/1.0"})
        try:
            with _ur.urlopen(req, timeout=20) as r:
                rdata = json.loads(r.read())
        except Exception:
            break
        batch = rdata.get("release-groups", [])
        rgs.extend(batch)
        if len(batch) < 100:
            break
        offset += 100

    # --- Step 3: compare against disk ---
    # (MUSIC_ROOT is a module-level constant)
    album_index = _artist_album_index(artist_name, mbid)

    have, missing = [], []
    for rg in rgs:
        title     = rg.get("title", "")
        year      = (rg.get("first-release-date") or "")[:4]
        rg_type   = rg.get("primary-type", "Album")
        sec_types = rg.get("secondary-types", [])
        rg_mbid   = rg.get("id", "")
        on_disk, match_reason = _album_title_match(title, album_index, rgid=rg_mbid)
        rec = {"album": title, "year": year, "type": rg_type,
               "subtypes": sec_types, "mbid": rg_mbid,
               "mb_url": f"https://musicbrainz.org/release-group/{rg_mbid}",
               "on_disk": on_disk, "match_reason": match_reason}
        (have if on_disk else missing).append(rec)

    have.sort(   key=lambda r: r["year"] or "9999")
    missing.sort(key=lambda r: r["year"] or "9999")
    return {"ok": True, "mb_artist": mb_artist, "mbid": mbid,
            "have": have, "missing": missing, "total": len(rgs)}


@app.get("/api/artist-discography")
def artist_discography():
    """Start (or return cached) discography check. Returns job_id while running, result when done."""
    artist_name = request.args.get("artist", "").strip()
    if not artist_name:
        return jsonify({"ok": False, "error": "artist parameter required"})

    # Return cached result if fresh (same session)
    with _disc_cache_lock:
        if artist_name in _disc_cache:
            return jsonify(_disc_cache[artist_name])

    # Start background job
    result_holder: Dict[str, Any] = {}

    def _run(log):
        log.append(f"Searching MusicBrainz for '{artist_name}'…")
        try:
            res = _fetch_discography(artist_name)
            result_holder.update(res)
            log.append(f"done:{len(res.get('missing', []))} missing")
            with _disc_cache_lock:
                _disc_cache[artist_name] = res
        except Exception as exc:
            result_holder["error"] = str(exc)
            log.append(f"error:{exc}")

    job = jobs.start_python(_run, label=f"Discography: {artist_name}")
    return jsonify({"ok": True, "status": "running", "job_id": job.job_id,
                    "artist": artist_name})


_disc_cache_discogs: Dict[str, Any] = {}    # artist → Discogs discography result (TTL: _DISC_CACHE_TTL)
_disc_cache_discogs_lock = threading.Lock()

@app.get("/api/artist-discography/discogs")
def artist_discography_discogs():
    """Fetch artist discography from Discogs and compare against library."""
    artist_name = request.args.get("artist", "").strip()
    if not artist_name:
        return jsonify({"ok": False, "error": "artist parameter required"})
    with _disc_cache_discogs_lock:
        cached = _disc_cache_discogs.get(artist_name)
        if cached:
            age   = time.time() - cached.get("_cached_at", 0)
            total = cached.get("total", 0) or (
                len(cached.get("have") or []) + len(cached.get("missing") or []))
            # Serve cache if: within TTL, non-empty, or a known-error result
            if age < _DISC_CACHE_TTL and (total > 0 or not cached.get("ok")):
                return jsonify(cached)
            # Expired or empty-success → evict and re-fetch
            del _disc_cache_discogs[artist_name]

    def _run(log):
        log.append(f"Searching Discogs for '{artist_name}'…")
        try:
            res = _discogs_artist_discography(artist_name)
            if res.get("ok") and (res.get("total") or 0) == 0:
                log.append("warn:0 releases matched — check Discogs filter or artist name")
            else:
                res["_cached_at"] = time.time()
                with _disc_cache_discogs_lock:
                    _disc_cache_discogs[artist_name] = res
            log.append(f"done:{len(res.get('missing', []))} missing / {len(res.get('have', []))} have")
        except Exception as exc:
            log.append(f"error:{exc}")

    job = jobs.start_python(_run, label=f"Discogs discography: {artist_name}")
    return jsonify({"ok": True, "status": "running", "job_id": job.job_id,
                    "artist": artist_name, "source": "discogs"})


_artist_img_cache: Dict[str, str] = {}
_artist_img_cache_lock = threading.Lock()
_ARTIST_IMAGE_MAX_BYTES = 8 * 1024 * 1024
_ARTIST_IMAGE_EXT_BY_MIME = {
    "image/jpeg": ".jpg",
    "image/jpg": ".jpg",
    "image/png": ".png",
    "image/webp": ".webp",
    "image/gif": ".gif",
}


def _artist_image_cache_key(artist_name: str) -> str:
    base = re.sub(r"[^a-z0-9]+", "-", (artist_name or "").lower()).strip("-")[:80]
    digest = hashlib.sha1((artist_name or "").strip().lower().encode("utf-8")).hexdigest()[:12]
    return f"{base or 'artist'}-{digest}"


def _artist_image_cache_info(artist_name: str) -> Dict[str, Any]:
    key = _artist_image_cache_key(artist_name)
    meta_path = ARTIST_IMAGE_CACHE_DIR / f"{key}.json"
    try:
        meta = json.loads(meta_path.read_text(encoding="utf-8"))
        image_name = _s(meta.get("image_file", "") or "")
        if not image_name or Path(image_name).name != image_name:
            return {}
        image_path = ARTIST_IMAGE_CACHE_DIR / image_name
        if image_path.exists() and image_path.is_file():
            return {
                "url": f"/api/artist-image-cache/{key}?v={int(image_path.stat().st_mtime)}",
                "key": key,
                "image_file": image_name,
                "cached_at": meta.get("cached_at") or 0,
                "source_url": _s(meta.get("source_url", "") or ""),
            }
    except Exception:
        pass
    return {}


def _artist_image_cache_url(artist_name: str) -> str:
    return _s(_artist_image_cache_info(artist_name).get("url", "") or "")


def _attach_artist_image_cache_urls(artists: List[Dict[str, Any]]) -> None:
    for artist in artists:
        if not isinstance(artist, dict):
            continue
        url = _artist_image_cache_url(_s(artist.get("name", "") or ""))
        artist["image_url"] = url
        artist["artist_image_url"] = url
        artist["image_source"] = "artist_cache" if url else ""


def _artist_image_ext(url: str, content_type: str) -> str:
    ctype = (content_type or "").split(";", 1)[0].strip().lower()
    if ctype in _ARTIST_IMAGE_EXT_BY_MIME:
        return _ARTIST_IMAGE_EXT_BY_MIME[ctype]
    ext = Path(_up.urlparse(url or "").path).suffix.lower()
    return ext if ext in {".jpg", ".jpeg", ".png", ".webp", ".gif"} else ""


def _cache_artist_image(artist_name: str, url: str) -> str:
    parsed = _up.urlparse(url or "")
    if parsed.scheme not in {"http", "https"}:
        return ""
    try:
        ARTIST_IMAGE_CACHE_DIR.mkdir(parents=True, exist_ok=True)
        req = _ur.Request(url, headers={"User-Agent": "BeetsWebControl/1.0"})
        with _ur.urlopen(req, timeout=15) as r:
            content_type = r.headers.get("Content-Type", "")
            ext = _artist_image_ext(url, content_type)
            if not ext:
                return ""
            blob = r.read(_ARTIST_IMAGE_MAX_BYTES + 1)
        if not blob or len(blob) > _ARTIST_IMAGE_MAX_BYTES:
            return ""
        key = _artist_image_cache_key(artist_name)
        if ext == ".jpeg":
            ext = ".jpg"
        image_name = f"{key}{ext}"
        image_path = ARTIST_IMAGE_CACHE_DIR / image_name
        tmp_path = ARTIST_IMAGE_CACHE_DIR / f"{image_name}.tmp"
        tmp_path.write_bytes(blob)
        tmp_path.replace(image_path)
        for stale in ARTIST_IMAGE_CACHE_DIR.glob(f"{key}.*"):
            if stale.name not in {image_name, f"{key}.json"} and stale.is_file():
                try:
                    stale.unlink()
                except Exception:
                    pass
        meta = {
            "artist": artist_name,
            "source_url": url,
            "image_file": image_name,
            "mime": (content_type or mimetypes.guess_type(image_name)[0] or "image/jpeg").split(";", 1)[0],
            "cached_at": time.time(),
        }
        (ARTIST_IMAGE_CACHE_DIR / f"{key}.json").write_text(
            json.dumps(meta, ensure_ascii=False, indent=2),
            encoding="utf-8",
        )
        return f"/api/artist-image-cache/{key}?v={int(image_path.stat().st_mtime)}"
    except Exception:
        return ""


def _fetch_artist_image(artist_name: str) -> str:
    """Fetch artist image URL from Discogs search. Returns empty string if not found."""

    if not DISCOGS_TOKEN:
        return ""
    q = _up.urlencode({"q": artist_name, "type": "artist", "per_page": 3, "page": 1, "token": DISCOGS_TOKEN})
    headers = {"User-Agent": "BeetsWebControl/1.0", "Authorization": f"Discogs token={DISCOGS_TOKEN}"}
    try:
        req = _ur.Request(f"https://api.discogs.com/database/search?{q}", headers=headers)
        with _ur.urlopen(req, timeout=10) as r:
            results = json.loads(r.read()).get("results") or []
        if results:
            return results[0].get("cover_image") or results[0].get("thumb") or ""
    except Exception:
        pass
    return ""


def _artist_local_art_url(artist_name: str) -> str:
    """Use a local album cover as an artist-card fallback."""
    want = _artist_name_key(artist_name)
    fallback = ""
    try:
        for album in lib.albums():
            album_artist = _s(getattr(album, "albumartist", "") or getattr(album, "artist", ""))
            if _artist_name_key(album_artist) != want:
                continue
            aid = int(getattr(album, "id", 0) or 0)
            if not aid:
                continue
            artpath = _s(getattr(album, "artpath", "") or "")
            mbid = (_s(getattr(album, "mb_releasegroupid", "") or "")
                    or _s(getattr(album, "mb_albumid", "") or ""))
            if artpath:
                return f"/api/albums/{aid}/art"
            if not fallback or mbid:
                fallback = f"/api/albums/{aid}/art"
    except Exception:
        return fallback
    return fallback


@app.get("/api/artist-image-cache/<key>")
def artist_image_cache(key):
    if not re.match(r"^[a-z0-9][a-z0-9-]{0,120}-[0-9a-f]{12}$", key or ""):
        return ("", 404)
    meta_path = ARTIST_IMAGE_CACHE_DIR / f"{key}.json"
    try:
        meta = json.loads(meta_path.read_text(encoding="utf-8"))
        image_name = _s(meta.get("image_file", "") or "")
        if not image_name or Path(image_name).name != image_name:
            return ("", 404)
        image_path = ARTIST_IMAGE_CACHE_DIR / image_name
        if not image_path.exists() or not image_path.is_file():
            return ("", 404)
        mime = _s(meta.get("mime", "") or "") or mimetypes.guess_type(image_name)[0] or "image/jpeg"
        return send_file(str(image_path), mimetype=mime)
    except Exception:
        return ("", 404)


_RELEASE_ART_MBID_RE = re.compile(r"^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$")
_RELEASE_ART_NEGATIVE_TTL = 7 * 24 * 3600  # re-check a "no art found" release weekly, not every page load


def _release_art_cache_info(mbid: str) -> Dict[str, Any]:
    if not _RELEASE_ART_MBID_RE.match(mbid or ""):
        return {}
    meta_path = RELEASE_ART_CACHE_DIR / f"{mbid}.json"
    try:
        meta = json.loads(meta_path.read_text(encoding="utf-8"))
    except Exception:
        return {}
    if meta.get("miss"):
        if time.time() - float(meta.get("cached_at") or 0) < _RELEASE_ART_NEGATIVE_TTL:
            return {"miss": True}
        return {}
    image_name = _s(meta.get("image_file", "") or "")
    if not image_name or Path(image_name).name != image_name:
        return {}
    image_path = RELEASE_ART_CACHE_DIR / image_name
    if not image_path.exists() or not image_path.is_file():
        return {}
    return {
        "url": f"/api/release-art-cache/{mbid}?v={int(image_path.stat().st_mtime)}",
        "image_file": image_name,
    }


def _release_art_save_miss(mbid: str) -> None:
    try:
        RELEASE_ART_CACHE_DIR.mkdir(parents=True, exist_ok=True)
        (RELEASE_ART_CACHE_DIR / f"{mbid}.json").write_text(
            json.dumps({"miss": True, "cached_at": time.time()}, ensure_ascii=False, indent=2),
            encoding="utf-8",
        )
    except Exception:
        pass


def _release_art_download(mbid: str, url: str, source: str) -> str:
    try:
        RELEASE_ART_CACHE_DIR.mkdir(parents=True, exist_ok=True)
        req = _ur.Request(url, headers={"User-Agent": "BeetsWebControl/1.0"})
        with _ur.urlopen(req, timeout=15) as r:
            content_type = r.headers.get("Content-Type", "")
            ext = _artist_image_ext(url, content_type)
            if not ext:
                return ""
            blob = r.read(_ARTIST_IMAGE_MAX_BYTES + 1)
        if not blob or len(blob) > _ARTIST_IMAGE_MAX_BYTES:
            return ""
        if ext == ".jpeg":
            ext = ".jpg"
        image_name = f"{mbid}{ext}"
        image_path = RELEASE_ART_CACHE_DIR / image_name
        tmp_path = RELEASE_ART_CACHE_DIR / f"{image_name}.tmp"
        tmp_path.write_bytes(blob)
        tmp_path.replace(image_path)
        for stale in RELEASE_ART_CACHE_DIR.glob(f"{mbid}.*"):
            if stale.name not in {image_name, f"{mbid}.json"} and stale.is_file():
                try:
                    stale.unlink()
                except Exception:
                    pass
        meta = {
            "mbid": mbid,
            "source_url": url,
            "source": source,
            "image_file": image_name,
            "mime": (content_type or mimetypes.guess_type(image_name)[0] or "image/jpeg").split(";", 1)[0],
            "cached_at": time.time(),
        }
        (RELEASE_ART_CACHE_DIR / f"{mbid}.json").write_text(
            json.dumps(meta, ensure_ascii=False, indent=2),
            encoding="utf-8",
        )
        return f"/api/release-art-cache/{mbid}?v={int(image_path.stat().st_mtime)}"
    except Exception:
        return ""


def _fetch_release_group_art_discogs(artist_name: str, album_title: str) -> str:
    """Fallback source when Cover Art Archive has no art for a release group."""
    if not DISCOGS_TOKEN or not (artist_name or album_title):
        return ""
    q = _up.urlencode({
        "q": f"{artist_name} {album_title}".strip(),
        "type": "release",
        "per_page": 3,
        "page": 1,
        "token": DISCOGS_TOKEN,
    })
    headers = {"User-Agent": "BeetsWebControl/1.0", "Authorization": f"Discogs token={DISCOGS_TOKEN}"}
    try:
        req = _ur.Request(f"https://api.discogs.com/database/search?{q}", headers=headers)
        with _ur.urlopen(req, timeout=10) as r:
            results = json.loads(r.read()).get("results") or []
        if results:
            return results[0].get("cover_image") or results[0].get("thumb") or ""
    except Exception:
        pass
    return ""


def _ensure_release_group_art(mbid: str, artist_name: str = "", album_title: str = "") -> Dict[str, Any]:
    """Serve a locally-stored release-group cover, downloading+caching on first request.
    Tries Cover Art Archive first, then Discogs (if configured) so a release with no
    MusicBrainz-registered art can still get a thumbnail. Misses are cached too, so a
    release with genuinely no art anywhere isn't re-fetched on every page load."""
    if not _RELEASE_ART_MBID_RE.match(mbid or ""):
        return {"ok": False, "error": "invalid mbid"}
    cached = _release_art_cache_info(mbid)
    if cached.get("url"):
        return {"ok": True, "url": cached["url"]}
    if cached.get("miss"):
        return {"ok": False, "error": "no art found"}

    url = _release_art_download(
        mbid, f"https://coverartarchive.org/release-group/{mbid}/front-250", "coverartarchive")
    if not url and (artist_name or album_title):
        discogs_url = _fetch_release_group_art_discogs(artist_name, album_title)
        if discogs_url:
            url = _release_art_download(mbid, discogs_url, "discogs")
    if not url:
        _release_art_save_miss(mbid)
        return {"ok": False, "error": "no art found"}
    return {"ok": True, "url": url}


@app.get("/api/release-art-cache/<mbid>")
def release_art_cache(mbid):
    if not _RELEASE_ART_MBID_RE.match(mbid or ""):
        return ("", 404)
    meta_path = RELEASE_ART_CACHE_DIR / f"{mbid}.json"
