# ── Recent imports tracking ───────────────────────────────────────────────────

_RECENT_IMPORTS_FILE = Path("/config/recent_imports.json")
_recent_imports_lock = threading.Lock()

def _record_recent_import(artist: str, album: str, year: int,
                          track_count: int, mb_albumid: str, aldir: str):
    """Append an album-level entry to the recent imports log."""
    entry = {
        "artist": artist,
        "album": album,
        "year": year,
        "tracks": track_count,
        "mb_albumid": mb_albumid,
        "aldir": aldir,
        "imported_at": int(time.time()),
    }
    with _recent_imports_lock:
        try:
            existing = json.loads(_RECENT_IMPORTS_FILE.read_text()) if _RECENT_IMPORTS_FILE.exists() else []
        except Exception:
            existing = []
        existing.insert(0, entry)
        _RECENT_IMPORTS_FILE.write_text(json.dumps(existing[:100], indent=2))

@app.get("/api/recent-imports")
def get_recent_imports():
    """Return the list of recently imported albums (from reimport-disk)."""
    try:
        data = json.loads(_RECENT_IMPORTS_FILE.read_text()) if _RECENT_IMPORTS_FILE.exists() else []
    except Exception:
        data = []
    return jsonify({"imports": data})


# ── AI Match history ──────────────────────────────────────────────────────────

_AI_MATCH_HISTORY_FILE = Path("/config/ai_match_history.json")
_ai_match_history_lock = threading.Lock()
_IMPORT_JOB_LOCK = threading.Lock()

def _record_ai_match(original_path: str, suggestion: dict):
    """Persist a successful AI-matched import to the history file."""
    entry = {
        "matched_at":      int(time.time()),
        "original_path":   original_path,
        "original_folder": Path(original_path).name,
        "artist":          suggestion.get("albumartist", ""),
        "album":           suggestion.get("album", ""),
        "year":            suggestion.get("year", ""),
        "mb_albumid":      suggestion.get("mb_albumid", ""),
        "mb_url":          suggestion.get("mb_url", "") or (
            f"https://musicbrainz.org/release/{suggestion['mb_albumid']}"
            if suggestion.get("mb_albumid") else ""),
        "confidence":      suggestion.get("confidence", ""),
        "reason":          suggestion.get("reason", ""),
        "evidence":        suggestion.get("review_evidence") or {},
    }
    with _ai_match_history_lock:
        try:
            existing = json.loads(_AI_MATCH_HISTORY_FILE.read_text()) \
                       if _AI_MATCH_HISTORY_FILE.exists() else []
        except Exception:
            existing = []
        existing.insert(0, entry)
        _AI_MATCH_HISTORY_FILE.write_text(json.dumps(existing[:200], indent=2))

@app.get("/api/ai-match-history")
def get_ai_match_history():
    limit = min(int(request.args.get("limit", 50)), 200)
    try:
        data = json.loads(_AI_MATCH_HISTORY_FILE.read_text()) \
               if _AI_MATCH_HISTORY_FILE.exists() else []
    except Exception:
        data = []
    return jsonify({"ok": True, "history": data[:limit]})

@app.post("/api/recent-imports/clear")
def clear_recent_imports():
    """Clear the recent imports log."""
    _RECENT_IMPORTS_FILE.write_text("[]")
    return jsonify({"ok": True})

