# ── Clean: album track validation ────────────────────────────────────────────

_ALBUM_TRACK_PREFIX_RE = re.compile(
    r'^(?:.*?\s+[-–—]\s+)?(?:\d+|%\w+\{[^}]+\})\s*[-–—\.]\s*',
    re.IGNORECASE,
)
_ALBUM_TRACK_ANNOT_RE = re.compile(
    r'\s*[\(\[]\s*(?:ft\.|feat\.|with\b|prod\.?|produced\s+by|remix|edit|remaster|radio|live|'
    r'acoustic|album\s+version|single\s+version|original\s+version|explicit\s+album\s+version|'
    r'clean\s+version|version|bonus|instrumental|deluxe|explicit|clean|official|'
    r'lyrics?|letra\s+oficial|hq(?:\s+audio)?|hd|audio|video|mv).*?[\)\]]\s*',
    re.IGNORECASE,
)
_ALBUM_TRACK_UNCLOSED_RE = re.compile(r'\s*[\(\[](?!.*[\)\]]).*$')
_ALBUM_TRACK_TRAILING_ALIAS_RE = re.compile(r'\s*[\(\[]\s*([^\)\]]{2,})\s*[\)\]]\s*$')
_ALBUM_TRACK_VERSION_MARKER_RE = re.compile(
    r"\b(?:remix|re-?mix|edit|remaster(?:ed)?|radio|live|acoustic|acappella|"
    r"a\s*cappella|a\s*pella|instrumental|karaoke|dub|extended|club|vip|"
    r"rework|reprise|demo|sketch|outtake|version|mix|mono|stereo|explicit|"
    r"clean|bonus|deluxe|single|album\s+edit)\b",
    re.IGNORECASE,
)
_ALBUM_TRACK_FEATURE_SUFFIX_RE = re.compile(
    r'\b(?:featuring|feat|ft|with)\.?\s+.+$',
    re.IGNORECASE,
)
_ALBUM_TRACK_GLUED_FEATURE_SUFFIX_RE = re.compile(
    r'^(.{4,}?)(?:featuring|feat|ft)\.?\s+([A-Za-z0-9].*)$',
    re.IGNORECASE,
)


_TRACK_FILENAME_SOURCE_ID_SUFFIX_RE = re.compile(
    r'''(?ix)
    (?:[\s._-]+|\s*[\(\[]\s*)
    (?:
        [0-9]{10,}
        | [0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}
        | (?:lidarr|soularr|soulseek|slskd|source|import|staging|playlist)[\s._-]*[a-z0-9]{6,}
        | (?=[a-f0-9]*[a-f])[a-f0-9]{6,9}
    )
    \s*[\)\]]?\s*$
    ''',
    re.IGNORECASE,
)
_TRACK_FILENAME_SHORT_SOURCE_ID_SUFFIX_RE = re.compile(
    r'''(?ix)
    (?:[\s._-]+|\s*[\(\[]\s*)
    (?=[a-f0-9]*[a-f])[a-f0-9]{4,5}
    \s*[\)\]]?\s*$
    ''',
    re.IGNORECASE,
)


def _strip_track_filename_id_suffix(value: Any) -> str:
    text = _s(value).strip()
    for _ in range(4):
        cleaned = _TRACK_FILENAME_SOURCE_ID_SUFFIX_RE.sub("", text).strip(" -_.")
        if cleaned == text:
            short_cleaned = _TRACK_FILENAME_SHORT_SOURCE_ID_SUFFIX_RE.sub("", text).strip(" -_.")
            dirty_prefix_hint = bool(
                re.search(r"[_\(\)\[\]]", short_cleaned)
                or re.match(r"^\s*\d{1,3}[\s._-]+", short_cleaned)
            )
            if short_cleaned != text and dirty_prefix_hint:
                cleaned = short_cleaned
        if cleaned == text or not cleaned:
            break
        text = cleaned
    return text


def _track_filename_has_source_id_suffix(value: Any) -> bool:
    text = _s(value).strip()
    return bool(text and _strip_track_filename_id_suffix(text) != text)

def _album_track_norm(value: str) -> str:
    import unicodedata

    text = _strip_track_filename_id_suffix(value).casefold()
    text = unicodedata.normalize("NFKD", text)
    text = "".join(ch for ch in text if not unicodedata.combining(ch))
    text = text.replace("&", " and ")
    text = _ALBUM_TRACK_UNCLOSED_RE.sub("", _ALBUM_TRACK_ANNOT_RE.sub("", text))
    text = re.sub(r"@\w+", " ", text)
    text = re.sub(r"\b(?:feat|ft)\.?\s+.*$", "", text, flags=re.IGNORECASE)
    text = re.sub(r"[^a-z0-9]+", " ", text)
    text = re.sub(r"^(?:bonus\s+track\s*)+", "", text, flags=re.IGNORECASE)
    return " ".join(text.split())


def _album_track_feature_variants(value: str) -> List[str]:
    """Return title candidates with normal and glued feature suffixes removed."""
    text = _s(value).strip()
    if not text:
        return []
    variants = [text]
    stripped = _ALBUM_TRACK_FEATURE_SUFFIX_RE.sub("", text).strip(" -_–—:;,.")
    if stripped and stripped != text:
        variants.append(stripped)
    glued = _ALBUM_TRACK_GLUED_FEATURE_SUFFIX_RE.sub(r"\1", text).strip(" -_–—:;,.")
    if glued and glued != text:
        variants.append(glued)
    spaced = re.sub(
        r'(?i)^(.{4,}?)(featuring|feat|ft)(\.?\s+[A-Za-z0-9].*)$',
        r'\1 \2\3',
        text,
    )
    if spaced and spaced != text:
        variants.append(spaced)
        spaced_stripped = _ALBUM_TRACK_FEATURE_SUFFIX_RE.sub("", spaced).strip(" -_–—:;,.")
        if spaced_stripped and spaced_stripped != spaced:
            variants.append(spaced_stripped)
    out: List[str] = []
    seen: set = set()
    for val in variants:
        key = val.casefold()
        if val and key not in seen:
            seen.add(key)
            out.append(val)
    return out


def _album_track_parenthetical_alias_variants(value: str) -> List[str]:
    """Return conservative title aliases such as "Money (That's What I Want)" -> "Money"."""
    text = _s(value).strip()
    if not text:
        return []
    variants: List[str] = []
    match = _ALBUM_TRACK_TRAILING_ALIAS_RE.search(text)
    if match and not _ALBUM_TRACK_VERSION_MARKER_RE.search(match.group(1)):
        base = text[:match.start()].strip(" -_–—:;,.")
        if len(_album_track_norm(base)) >= 3:
            variants.append(base)
    return variants


def _album_track_path_prefixes(path: str) -> List[str]:
    """Normalized artist/album prefixes that may be embedded in track titles."""
    raw_path = _s(path).replace("\\", "/")
    if not raw_path:
        return []
    for marker in (
        "/data/media/music/",
        "/data/torrents/music/",
        "/data/downloads/music/",
        "/downloads/music/",
        "/download/music/",
    ):
        if marker in raw_path:
            raw_path = raw_path.split(marker, 1)[1]
            break
    parts = [p for p in raw_path.split("/") if p]
    prefixes: List[str] = []

    def _prefix_candidates(value: str) -> List[str]:
        text = _s(value).strip()
        if not text:
            return []
        candidates = [text]
        no_year = re.sub(r"\s*[\(\[]\d{4}[\)\]]\s*$", "", text).strip()
        if no_year and no_year != text:
            candidates.append(no_year)
        no_mbid = re.sub(
            r"\s*[\{\(\[]\s*[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}\s*[\}\)\]]\s*$",
            "",
            text,
            flags=re.I,
        ).strip()
        if no_mbid and no_mbid != text:
            candidates.append(no_mbid)
        numeric_alias_base = no_mbid or no_year or text
        no_leading_number = re.sub(r"^\s*\d+[\s._-]+", "", numeric_alias_base).strip()
        if no_leading_number and no_leading_number != numeric_alias_base:
            candidates.append(no_leading_number)
        try:
            bare_artist = _artist_folder_name_without_mbid(text)
        except Exception:
            bare_artist = ""
        if bare_artist and bare_artist != text:
            candidates.append(bare_artist)
        return candidates

    if len(parts) >= 2:
        prefixes.extend(_prefix_candidates(parts[0]))
        prefixes.extend(_prefix_candidates(parts[1]))
    if len(parts) >= 1:
        stem = Path(parts[-1]).stem
        # A path template like "Artist - Album - 00 - Artist Title" can still
        # leave the artist at the start of the title after numeric prefixes are stripped.
        file_parts = [p.strip() for p in re.split(r"\s+[-–—]\s*|\s*[-–—]\s+", stem) if p.strip()]
        if file_parts:
            prefixes.extend(_prefix_candidates(file_parts[0]))
    out: List[str] = []
    seen: set = set()
    for prefix in prefixes:
        norm = _album_track_norm(prefix)
        if norm and norm not in seen:
            seen.add(norm)
            out.append(norm)
    return out

def _album_track_title_variants(title: str, path: str = "") -> List[str]:
    raw_values = [_s(title).strip()]
    if path:
        raw_values.append(Path(_s(path)).stem)
    for raw in list(raw_values):
        cleaned = _strip_track_filename_id_suffix(raw)
        if cleaned and cleaned not in raw_values:
            raw_values.append(cleaned)
    variants: List[str] = []
    seen: set = set()
    path_prefixes = _album_track_path_prefixes(path)
    for raw in raw_values:
        if not raw:
            continue
        candidates = [raw]
        parts = [p.strip() for p in re.split(r"\s+[-–—]\s*|\s*[-–—]\s+", raw) if p.strip()]
        if len(parts) > 1:
            for idx in range(1, len(parts)):
                candidates.append(" - ".join(parts[idx:]))
            candidates.append(parts[-1])
        stripped = raw
        for _ in range(3):
            nxt = _ALBUM_TRACK_PREFIX_RE.sub("", stripped).strip()
            if nxt == stripped:
                break
            stripped = nxt
            candidates.append(stripped)
        expanded_candidates: List[str] = []
        for cand in candidates:
            expanded_candidates.append(cand)
            stripped_cand = cand
            for _ in range(3):
                nxt = _ALBUM_TRACK_PREFIX_RE.sub("", stripped_cand).strip()
                if nxt == stripped_cand:
                    break
                stripped_cand = nxt
                expanded_candidates.append(stripped_cand)
        feature_candidates: List[str] = []
        for cand in expanded_candidates:
            feature_candidates.extend(_album_track_feature_variants(cand) or [cand])
        alias_candidates: List[str] = []
        for cand in feature_candidates:
            alias_candidates.append(cand)
            alias_candidates.extend(_album_track_parenthetical_alias_variants(cand))
        for cand in alias_candidates:
            bare = _ALBUM_TRACK_UNCLOSED_RE.sub(
                "", _ALBUM_TRACK_ANNOT_RE.sub("", cand)
            ).strip()
            for val in (cand, bare):
                norm = _album_track_norm(val)
                norm_options = [norm] if norm else []
                for prefix in path_prefixes:
                    if norm == prefix:
                        continue
                    if norm.startswith(prefix + " "):
                        norm_options.append(norm[len(prefix):].strip())
                for opt in norm_options:
                    if opt and opt not in seen:
                        seen.add(opt)
                        variants.append(opt)
    return variants


def _album_item_abs_path(raw_path: str) -> str:
    p = _s(raw_path).strip()
    if p and not p.startswith("/"):
        p = str(MUSIC_ROOT / p)
    return p


def _mb_release_tracklist_cache_path(mb_albumid: str) -> Path:
    release_id = (mb_albumid or "").strip().lower()
    return _MB_RELEASE_TRACKLIST_CACHE_DIR / release_id[:2] / f"{release_id}.json"


def _mb_release_tracklist_read_disk(mb_albumid: str, now: float) -> Optional[Dict[str, Any]]:
    if _MB_RELEASE_TRACKLIST_DISK_CACHE_TTL <= 0:
        return None
    cache_path = _mb_release_tracklist_cache_path(mb_albumid)
    try:
        cached = json.loads(cache_path.read_text(encoding="utf-8"))
        payload = cached.get("payload")
        ts = float(cached.get("ts") or 0)
        if isinstance(payload, dict) and (now - ts) < _MB_RELEASE_TRACKLIST_DISK_CACHE_TTL:
            return copy.deepcopy(payload)
    except Exception:
        pass
    return None


def _mb_release_tracklist_write_disk(mb_albumid: str, payload: Dict[str, Any]) -> None:
    if _MB_RELEASE_TRACKLIST_DISK_CACHE_TTL <= 0:
        return
    cache_path = _mb_release_tracklist_cache_path(mb_albumid)
    try:
        cache_path.parent.mkdir(parents=True, exist_ok=True)
        tmp_path = cache_path.with_suffix(f".{os.getpid()}.tmp")
        tmp_path.write_text(
            json.dumps({"ts": time.time(), "payload": payload}, ensure_ascii=False),
            encoding="utf-8",
        )
        tmp_path.replace(cache_path)
    except Exception:
        pass


def _fetch_mb_release_tracklist(mb_albumid: str, log: Optional[List[str]] = None) -> Dict[str, Any]:
    mb_albumid = (mb_albumid or "").strip().lower()
    if not _MB_UUID_RE.match(mb_albumid):
        return {"ok": False, "error": "Invalid MusicBrainz release ID", "tracks": []}
    now = time.time()
    with _MB_RELEASE_TRACKLIST_CACHE_LOCK:
        cached = _MB_RELEASE_TRACKLIST_CACHE.get(mb_albumid)
        if cached and (now - float(cached.get("ts") or 0)) < _MB_RELEASE_TRACKLIST_CACHE_TTL:
            return copy.deepcopy(cached.get("payload") or {})
    disk_cached = _mb_release_tracklist_read_disk(mb_albumid, now)
    if disk_cached is not None:
        with _MB_RELEASE_TRACKLIST_CACHE_LOCK:
            _MB_RELEASE_TRACKLIST_CACHE[mb_albumid] = {
                "ts": now,
                "payload": copy.deepcopy(disk_cached),
            }
        return disk_cached
    mb_url = (f"https://musicbrainz.org/ws/2/release/{mb_albumid}"
              "?inc=recordings+release-groups&fmt=json")
    req = _ur.Request(
        mb_url,
        headers={"User-Agent": "BeetsWebControl/1.0 (beets-webcontrol)"}
    )
    mb_data: Dict[str, Any] = {}
    transient_codes = {429, 500, 502, 503, 504}
    for attempt in range(1, 4):
        try:
            with _ur.urlopen(req, timeout=30) as resp:
                mb_data = json.loads(resp.read())
            break
        except Exception as ex:
            code = getattr(ex, "code", None)
            reason = str(getattr(ex, "reason", "") or "").lower()
            transient = code in transient_codes or "timed out" in reason or "temporarily" in reason
            if transient and attempt < 3:
                if log is not None:
                    log.append(
                        f"  MB fetch transient error ({code or reason or ex}); "
                        f"retrying {attempt + 1}/3"
                    )
                time.sleep(1.5 * attempt)
                continue
            if log is not None:
                log.append(f"  MB fetch failed: {ex}")
            return {"ok": False, "error": str(ex), "tracks": []}

    release_artist_info = _playlist_artist_credit_info(mb_data.get("artist-credit") or [])
    release_artist = release_artist_info.get("albumartist", "")

    tracks: List[Dict[str, Any]] = []
    for medium in mb_data.get("media", []) or []:
        disc_num = int(medium.get("position") or 1)
        for trk in medium.get("tracks", []) or []:
            rec = trk.get("recording") or {}
            title = _s(trk.get("title") or rec.get("title") or "").strip()
            tracks.append({
                "track": int(trk.get("position") or 0),
                "disc": disc_num,
                "title": title,
                "title_norm": _album_track_norm(title),
                "mb_trackid": _s(rec.get("id", "")).strip().lower(),
                "duration_ms": int(trk.get("length") or rec.get("length") or 0),
            })
    release_group = mb_data.get("release-group") or {}
    result = {
        "ok": bool(tracks),
        "error": "" if tracks else "MusicBrainz release has no tracks",
        "tracks": tracks,
        "release_title": _s(mb_data.get("title", "")).strip(),
        "release_artist": release_artist,
        "release_artist_id": release_artist_info.get("mb_albumartistid", ""),
        "release_artistids": release_artist_info.get("mb_albumartistids", ""),
        "release_group": release_group.get("id", ""),
        "release_group_primary_type": _s(release_group.get("primary-type", "")).strip(),
        "release_group_secondary_types": [
            _s(value).strip() for value in (release_group.get("secondary-types") or []) if _s(value).strip()
        ],
        "country": _s(mb_data.get("country", "")).strip(),
        "date": _s(mb_data.get("date", "")).strip(),
    }
    if result.get("ok"):
        payload_copy = copy.deepcopy(result)
        with _MB_RELEASE_TRACKLIST_CACHE_LOCK:
            _MB_RELEASE_TRACKLIST_CACHE[mb_albumid] = {
                "ts": time.time(),
                "payload": payload_copy,
            }
        _mb_release_tracklist_write_disk(mb_albumid, payload_copy)
    return result


def _album_track_score(item: Dict[str, Any], mb_trk: Dict[str, Any]) -> float:
    from difflib import SequenceMatcher

    mb_norm = mb_trk.get("title_norm") or _album_track_norm(mb_trk.get("title", ""))
    variants = _album_track_title_variants(item.get("title", ""), item.get("path", ""))
    title_score = max(
        (SequenceMatcher(None, v, mb_norm).ratio() for v in variants if v and mb_norm),
        default=0.0,
    )
    pos_bonus = 0.0
    item_disc, item_track = _album_item_position_hints(item)
    if item_track == int(mb_trk.get("track") or 0):
        pos_bonus += 0.04
        if item_disc == int(mb_trk.get("disc") or 1):
            pos_bonus += 0.02
    dur_bonus = 0.0
    item_ms = int(float(item.get("length") or 0) * 1000)
    mb_ms = int(mb_trk.get("duration_ms") or 0)
    if item_ms and mb_ms:
        diff_s = abs(item_ms - mb_ms) / 1000.0
        dur_bonus = 0.04 if diff_s <= 4 else (0.02 if diff_s <= 10 else 0.0)
    return min(1.0, title_score + pos_bonus + dur_bonus)


def _best_album_track_match(item: Dict[str, Any], mb_tracks: List[Dict[str, Any]]) -> Dict[str, Any]:
    item_mbid = _s(item.get("mb_trackid", "")).strip().lower()
    if item_mbid:
        for idx, trk in enumerate(mb_tracks):
            if item_mbid and item_mbid == trk.get("mb_trackid"):
                title_score = _album_track_score(item, trk)
                return {"idx": idx, "track": trk, "score": max(0.98, title_score),
                        "title_score": title_score, "exact_mbid": True}

    best_idx = -1
    best_score = -1.0
    best_rank = (-1.0, -1, -1)
    item_disc, item_track = _album_item_position_hints(item)
    for idx, trk in enumerate(mb_tracks):
        score = _album_track_score(item, trk)
        exact_pos = int(
            bool(item_track and item_track == int(trk.get("track") or 0))
            and bool(item_disc == int(trk.get("disc") or 1))
        )
        track_pos = int(bool(item_track and item_track == int(trk.get("track") or 0)))
        rank = (score, exact_pos, track_pos)
        if rank > best_rank:
            best_rank = rank
            best_score = score
            best_idx = idx
    return {
        "idx": best_idx,
        "track": mb_tracks[best_idx] if best_idx >= 0 else {},
        "score": max(best_score, 0.0),
        "title_score": max(best_score, 0.0),
        "exact_mbid": False,
    }


def _album_track_fingerprint_check(item: Dict[str, Any],
                                   mb_tracks: List[Dict[str, Any]]) -> Dict[str, Any]:
    path = _album_item_abs_path(item.get("path", ""))
    if not path or not Path(path).exists():
        return {"status": "missing", "path": path}
    cands = _acoustid_lookup_cached(path)
    if not cands:
        return {"status": "none"}

    mb_ids = {t.get("mb_trackid") for t in mb_tracks if t.get("mb_trackid")}
    for cand in cands:
        cand_id = _s(cand.get("mb_trackid", "")).strip().lower()
        if cand_id and cand_id in mb_ids:
            return {"status": "match", "candidate": cand}

    from difflib import SequenceMatcher
    best_cand = cands[0]
    cand_title = _album_track_norm(best_cand.get("title", ""))
    best_title_score = max(
        (SequenceMatcher(None, cand_title, t.get("title_norm", "")).ratio()
         for t in mb_tracks if cand_title and t.get("title_norm")),
        default=0.0,
    )
    if int(best_cand.get("score") or 0) >= 70 and best_title_score < 0.72:
        return {
            "status": "mismatch",
            "candidate": best_cand,
            "best_title_score": round(best_title_score, 3),
        }
    return {
        "status": "unclear",
        "candidate": best_cand,
        "best_title_score": round(best_title_score, 3),
    }


def _validate_wanted_album_items_with_acoustid(album_id: int, mb_albumid: str,
                                               wanted_tracks: List[Dict[str, Any]],
                                               log: list) -> Dict[str, Any]:
    """Reject downloaded missing-track files when AcoustID proves they are wrong."""
    wanted = _normalise_wanted_tracks(wanted_tracks)
    if not album_id or not mb_albumid or not wanted:
        return {"ok": True, "checked": 0, "mismatches": []}
    mb = _fetch_mb_release_tracklist(mb_albumid, log)
    if not mb.get("ok"):
        return {"ok": True, "checked": 0, "mismatches": [], "warning": mb.get("error", "")}
    mb_tracks = mb.get("tracks") or []
    wanted_pairs = {
        (int(t.get("disc") or 1), int(t.get("track") or 0))
        for t in wanted
        if int(t.get("track") or 0)
    }
    wanted_mbids = {
        _s(t.get("mb_trackid", "")).strip().lower()
        for t in wanted
        if t.get("mb_trackid")
    }
    target_tracks = [
        t for t in mb_tracks
        if (
            (int(t.get("disc") or 1), int(t.get("track") or 0)) in wanted_pairs
            or _s(t.get("mb_trackid", "")).strip().lower() in wanted_mbids
        )
    ]
    target_by_pair = {
        (int(t.get("disc") or 1), int(t.get("track") or 0)): t
        for t in target_tracks
        if int(t.get("track") or 0)
    }
    target_by_mbid = {
        _s(t.get("mb_trackid", "")).strip().lower(): t
        for t in target_tracks
        if t.get("mb_trackid")
    }
    if not target_tracks:
        return {"ok": True, "checked": 0, "mismatches": []}

    try:
        with _db(text_factory=bytes, row_factory=sqlite3.Row) as con:
            rows = con.execute(
                "SELECT id, title, disc, track, path, mb_trackid, length "
                "FROM items WHERE album_id=? ORDER BY disc, track, id",
                (int(album_id),),
            ).fetchall()
    except Exception as ex:
        log.append(f"  AcoustID validation warning: {ex}")
        return {"ok": True, "checked": 0, "mismatches": [], "warning": str(ex)}

    target_release = _s(mb_albumid).strip().lower()
    checked = 0
    no_result = 0
    mismatches: List[Dict[str, Any]] = []
    for row in rows:
        item = {
            "title": _s(row["title"]),
            "path": _s(row["path"]),
            "disc": int(row["disc"] or 1),
            "track": int(row["track"] or 0),
            "mb_trackid": _s(row["mb_trackid"]),
            "length": float(row["length"] or 0),
        }
        item_mbid = _s(item.get("mb_trackid", "")).strip().lower()
        pair = (int(item.get("disc") or 1), int(item.get("track") or 0))
        target = target_by_mbid.get(item_mbid) or target_by_pair.get(pair)
        if not target:
            best = _best_album_track_match(item, target_tracks)
            if float(best.get("score") or 0) >= _MB_TRACK_PREFLIGHT_MATCH_THRESHOLD:
                target = best.get("track") or {}
        if not target:
            continue

        path = _album_item_abs_path(item.get("path", ""))
        cands = _acoustid_lookup_cached(path) if path else []
        if not cands:
            no_result += 1
            continue
        checked += 1
        target_trackid = _s(target.get("mb_trackid", "")).strip().lower()
        confirmed = False
        for cand in cands:
            cand_trackid = _s(cand.get("mb_trackid", "")).strip().lower()
            cand_releases = {
                _s(r).strip().lower()
                for r in (cand.get("mb_albumids") or [])
                if r
            }
            if (target_trackid and cand_trackid == target_trackid) or target_release in cand_releases:
                confirmed = True
                break
        top = cands[0]
        if not confirmed and int(top.get("score") or 0) >= 70:
            mismatches.append({
                "item_id": int(row["id"]),
                "title": item.get("title", ""),
                "path": path,
                "target": target,
                "candidate": top,
            })

    if checked or no_result:
        log.append(
            "  AcoustID missing-track validation: "
            f"{checked} checked, {no_result} without fingerprint result, "
            f"{len(mismatches)} mismatch(es)."
        )
    for mismatch in mismatches[:5]:
        cand = mismatch.get("candidate") or {}
        target = mismatch.get("target") or {}
        log.append(
            "  AcoustID mismatch: "
            f"{mismatch.get('title')!r} should be {target.get('title')!r}, "
            f"fingerprint points to {cand.get('artist', '')} - "
            f"{cand.get('title', '')} ({cand.get('album', '')})"
        )
    return {
        "ok": not mismatches,
        "checked": checked,
        "no_result": no_result,
        "mismatches": mismatches,
    }


def _ai_review_album_track_candidates(album_info: Dict[str, Any],
                                      mb_tracks: List[Dict[str, Any]],
                                      candidates: List[Dict[str, Any]],
                                      log: Optional[List[str]] = None) -> Dict[str, Any]:
    api_key = os.environ.get("OPENAI_API_KEY", "")
    if not api_key:
        return {"status": "skipped", "error": "OPENAI_API_KEY not configured"}
    if not candidates:
        return {"status": "skipped", "error": "No candidates"}

    mb_line_parts: List[str] = []
    for t in mb_tracks[:80]:
        disc_num = int(t.get("disc") or 1)
        track_num = int(t.get("track") or 0)
        title_text = _s(t.get("title") or "")
        mb_track_id = _s(t.get("mb_trackid") or "")
        mb_line_parts.append(f"{disc_num}.{track_num:02d} {title_text} [{mb_track_id}]")
    mb_lines = "\n".join(mb_line_parts)
    cand_lines = "\n".join(
        f'id={c["id"]} track={c.get("disc", 1)}.{int(c.get("track") or 0):02d} '
        f'title={c.get("title", "")!r} file={c.get("filename", "")!r} '
        f'best_mb={((c.get("best_mb") or {}).get("disc", 1))}.'
        f'{int((c.get("best_mb") or {}).get("track") or 0):02d} '
        f'{(c.get("best_mb") or {}).get("title", "")!r} score={c.get("score", 0)} '
        f'fingerprint={(c.get("fingerprint") or {}).get("status", "")}'
        for c in candidates
    )
    prompt = (
        "You are checking whether files in a Beets album belong to the exact "
        "MusicBrainz release. Use the MusicBrainz track list as the source of truth.\n\n"
        f"Album artist: {album_info.get('artist','')}\n"
        f"Album: {album_info.get('album','')}\n"
        f"MusicBrainz release ID: {album_info.get('mb_albumid','')}\n\n"
        f"MUSICBRAINZ TRACK LIST:\n{mb_lines}\n\n"
        f"QUESTIONABLE LIBRARY ITEMS:\n{cand_lines}\n\n"
        "For each questionable item, choose:\n"
        "- remove: clearly from another album or not on this release\n"
        "- keep: clearly a valid version of a listed MusicBrainz track\n"
        "- review: uncertain\n"
        "Do not remove only because punctuation, featured-artist text, or spelling differs.\n"
        'Return ONLY JSON: {"decisions":[{"id":123,"action":"remove|keep|review",'
        '"confidence":"high|medium|low","reason":"short reason",'
        '"matched_track":"disc.track or empty"}]}'
    )
    _track_review_schema = {
        "type": "object",
        "properties": {
            "decisions": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "id":            {"type": "integer"},
                        "action":        {"type": "string", "enum": ["remove", "keep", "review"]},
                        "confidence":    {"type": "string", "enum": ["high", "medium", "low"]},
                        "reason":        {"type": "string"},
                        "matched_track": {"type": "string"},
                    },
                    "required": ["id", "action", "confidence", "reason", "matched_track"],
                    "additionalProperties": False,
                },
            }
        },
        "required": ["decisions"],
        "additionalProperties": False,
    }
    req_body = json.dumps({
        "model": "gpt-4o-mini",
        "messages": [{"role": "user", "content": prompt}],
        "temperature": 0.0,
        "response_format": {
            "type": "json_schema",
            "json_schema": {"name": "track_review", "strict": True, "schema": _track_review_schema},
        },
    }).encode()
    try:
        req = _ur.Request(
            "https://api.openai.com/v1/chat/completions",
            data=req_body,
            headers={"Authorization": f"Bearer {api_key}",
                     "Content-Type": "application/json"},
        )
        with _ur.urlopen(req, timeout=45) as resp:
            data = json.loads(resp.read())
        msg = (data.get("choices") or [{}])[0].get("message") or {}
        if msg.get("refusal"):
            return {"status": "error", "error": f"AI refusal: {msg['refusal'][:100]}"}
        parsed = json.loads(msg["content"])
        decisions = parsed.get("decisions", []) if isinstance(parsed, dict) else []
        return {"status": "used", "decisions": decisions}
    except urllib.error.HTTPError as exc:
        body = exc.read().decode("utf-8", errors="replace")
        if log is not None:
            log.append(f"  AI review failed: OpenAI {exc.code}: {body[:180]}")
        return {"status": "error", "error": f"OpenAI {exc.code}: {body[:180]}"}
    except Exception as ex:
        if log is not None:
            log.append(f"  AI review failed: {ex}")
        return {"status": "error", "error": str(ex)}


def _scan_album_track_integrity(album_row: Dict[str, Any], *,
                                use_ai: bool,
                                use_fingerprint: bool,
                                fingerprint_limit: int,
                                log: List[str]) -> Optional[Dict[str, Any]]:
    aid = int(album_row["id"])
    album_title = _s(album_row.get("album", "")).strip()
    album_artist = _s(album_row.get("albumartist", "")).strip()
    mb_albumid = _s(album_row.get("mb_albumid", "")).strip().lower()
    mb_rg = _s(album_row.get("mb_releasegroupid", "")).strip().lower()
    if not mb_albumid and mb_rg:
        mb_albumid = _resolve_release_group_to_release(mb_rg, log)
    if not mb_albumid:
        return None

    mb = _fetch_mb_release_tracklist(mb_albumid, log)
    if not mb.get("ok"):
        return {
            "album_id": aid, "artist": album_artist, "album": album_title,
            "mb_albumid": mb_albumid, "error": mb.get("error") or "MB lookup failed",
            "remove_candidates": [], "review_candidates": [],
        }
    mb_tracks = mb["tracks"]

    try:
        with _db(text_factory=bytes, row_factory=sqlite3.Row) as con:
            rows = con.execute(
                "SELECT id, title, track, disc, path, mb_trackid, length "
                "FROM items WHERE album_id=? ORDER BY disc, track, title, id",
                (aid,),
            ).fetchall()
    except Exception as ex:
        log.append(f"  DB read failed for album_id {aid}: {ex}")
        return None

    items: List[Dict[str, Any]] = []
    for row in rows:
        path = _s(row["path"])
        items.append({
            "id": int(row["id"]),
            "title": _s(row["title"]),
            "track": int(row["track"] or 0),
            "disc": int(row["disc"] or 1),
            "path": path,
            "abs_path": _album_item_abs_path(path),
            "filename": Path(_s(path)).name,
            "mb_trackid": _s(row["mb_trackid"]).strip().lower(),
            "length": float(row["length"] or 0),
        })

    if not items:
        return None

    expected_count = len(mb_tracks)
    actual_count = len(items)
    do_fingerprint = bool(use_fingerprint and actual_count <= max(1, fingerprint_limit))
    if use_fingerprint and not do_fingerprint:
        log.append(f"  Skipping fingerprint pass: {actual_count} tracks exceeds limit {fingerprint_limit}")

    records: List[Dict[str, Any]] = []
    for item in items:
        best = _best_album_track_match(item, mb_tracks)
        mb_best = best.get("track") or {}
        score = round(float(best.get("score") or 0.0), 3)
        fp: Dict[str, Any] = {"status": "skipped"}
        decision = "keep"
        reason = "Matched MusicBrainz track list"
        if score < 0.62:
            decision = "remove"
            reason = "No MusicBrainz track title is close enough"
        elif score < 0.90:
            decision = "review"
            reason = "Fuzzy MusicBrainz match needs review"

        if do_fingerprint:
            fp = _album_track_fingerprint_check(item, mb_tracks)
            if fp.get("status") == "mismatch":
                decision = "remove"
                cand = fp.get("candidate") or {}
                reason = ("Audio fingerprint points to "
                          f"{cand.get('artist','')} - {cand.get('title','')}".strip(" -"))
            elif fp.get("status") == "unclear" and decision == "keep" and score < 0.96:
                decision = "review"
                reason = "Fingerprint did not confirm the MusicBrainz recording"

        records.append({
            **item,
            "decision": decision,
            "reason": reason,
            "score": score,
            "exact_mbid": bool(best.get("exact_mbid")),
            "best_idx": int(best.get("idx", -1)),
            "best_mb": {
                "disc": int(mb_best.get("disc") or 1),
                "track": int(mb_best.get("track") or 0),
                "title": mb_best.get("title", ""),
                "mb_trackid": mb_best.get("mb_trackid", ""),
            } if mb_best else {},
            "fingerprint": fp,
        })

    grouped: Dict[int, List[Dict[str, Any]]] = defaultdict(list)
    for rec in records:
        if rec["best_idx"] >= 0 and rec["decision"] != "remove" and rec["score"] >= 0.74:
            grouped[rec["best_idx"]].append(rec)

    def _collision_rank(path: str) -> int:
        m = re.search(r"\.(\d+)$", Path(path).stem)
        return int(m.group(1)) if m else 0

    for group in grouped.values():
        if len(group) <= 1:
            continue
        group.sort(key=lambda r: (
            0 if (r.get("fingerprint") or {}).get("status") == "match" else 1,
            0 if r.get("exact_mbid") else 1,
            -float(r.get("score") or 0),
            _collision_rank(r.get("path", "")),
            int(r.get("id") or 0),
        ))
        for extra in group[1:]:
            extra["decision"] = "remove"
            extra["reason"] = "Duplicate file mapped to the same MusicBrainz track"

    review_records = [r for r in records if r["decision"] == "review"]
    ai_status: Dict[str, Any] = {"status": "skipped", "error": ""}
    if use_ai and review_records:
        ai_status = _ai_review_album_track_candidates(
            {"artist": album_artist, "album": album_title, "mb_albumid": mb_albumid},
            mb_tracks,
            review_records[:40],
            log,
        )
        decisions = {
            int(d.get("id")): d for d in ai_status.get("decisions", [])
            if str(d.get("id", "")).isdigit()
        }
        for rec in review_records:
            d = decisions.get(rec["id"])
            if not d:
                continue
            action = _s(d.get("action", "")).lower()
            conf = _s(d.get("confidence", "")).lower()
            if action == "remove" and conf in {"high", "medium"}:
                rec["decision"] = "remove"
                rec["reason"] = "AI review: " + _s(d.get("reason", "")).strip()
            elif action == "keep" and conf == "high":
                rec["decision"] = "keep"
                rec["reason"] = "AI review kept: " + _s(d.get("reason", "")).strip()
            else:
                rec["reason"] = "AI review uncertain: " + _s(d.get("reason", "")).strip()
            rec["ai"] = d

    keep_records = [r for r in records if r["decision"] == "keep"]
    local_match_ratio = (len(keep_records) / actual_count) if actual_count else 0.0
    low_album_match = actual_count >= 3 and local_match_ratio < 0.25
    if low_album_match:
        log.append(
            f"  Low album-level MB match: {len(keep_records)}/{actual_count} "
            "local track(s) confidently match; promoting uncertain tracks to removal."
        )
        for rec in records:
            if rec["decision"] == "review":
                rec["decision"] = "remove"
                rec["reason"] = (
                    "Album-level MusicBrainz match is too low; local file does not "
                    "belong to this selected release"
                )

    remove_candidates = [r for r in records if r["decision"] == "remove"]
    review_candidates = [r for r in records if r["decision"] == "review"]
    if not remove_candidates and not review_candidates and actual_count == expected_count:
        return None

    return {
        "album_id": aid,
        "artist": album_artist,
        "album": album_title,
        "mb_albumid": mb_albumid,
        "mb_url": f"https://musicbrainz.org/release/{mb_albumid}",
        "expected_count": expected_count,
        "actual_count": actual_count,
        "keep_count": len([r for r in records if r["decision"] == "keep"]),
        "local_match_ratio": round(local_match_ratio, 3),
        "low_album_match": low_album_match,
        "remove_candidates": remove_candidates,
        "review_candidates": review_candidates,
        "ai_status": ai_status,
        "fingerprint_checked": do_fingerprint,
        "release_title": mb.get("release_title", ""),
    }


def _album_mb_match_plan(album_id: int, mb_albumid: str,
                         log: Optional[List[str]] = None) -> Dict[str, Any]:
    mb_albumid = _s(mb_albumid).strip().lower()
    mb = _fetch_mb_release_tracklist(mb_albumid, log)
    if not mb.get("ok"):
        raise RuntimeError(mb.get("error") or "MusicBrainz release lookup failed")
    mb_tracks = mb.get("tracks") or []
    if not mb_tracks:
        raise RuntimeError("MusicBrainz release has no tracks")

    try:
        with _db(text_factory=bytes, row_factory=sqlite3.Row) as con:
            rows = con.execute(
                "SELECT id, title, track, disc, path, mb_trackid, length "
                "FROM items WHERE album_id=? ORDER BY disc, track, title, id",
                (album_id,),
            ).fetchall()
    except Exception as ex:
        raise RuntimeError(f"Could not read album tracks: {ex}")

    items: List[Dict[str, Any]] = []
    for row in rows:
        path = _s(row["path"])
        items.append({
            "id": int(row["id"]),
            "title": _s(row["title"]),
            "track": int(row["track"] or 0),
            "disc": int(row["disc"] or 1),
            "path": path,
            "filename": Path(path).name,
            "mb_trackid": _s(row["mb_trackid"]).strip().lower(),
            "length": float(row["length"] or 0),
        })

    def _match_with_fingerprint_guard(item: Dict[str, Any],
                                      tracks: List[Dict[str, Any]]) -> Dict[str, Any]:
        best = _best_album_track_match(item, tracks)
        if int(best.get("idx", -1)) >= 0:
            fp = _album_track_fingerprint_check(item, tracks)
            if fp.get("status") == "match":
                return best
            if fp.get("status") == "mismatch":
                return {
                    "idx": -1,
                    "track": {},
                    "score": 0.0,
                    "title_score": 0.0,
                    "exact_mbid": False,
                }
            if (
                best.get("exact_mbid")
                and float(best.get("title_score") or 0) < _MB_TRACK_REPAIR_MATCH_THRESHOLD
            ):
                return {
                    "idx": -1,
                    "track": {},
                    "score": 0.0,
                    "title_score": 0.0,
                    "exact_mbid": False,
                }
        return best

    return build_album_match_plan(
        album_id=int(album_id),
        mb_albumid=mb_albumid,
        release_title=mb.get("release_title", ""),
        items=items,
        mb_tracks=mb_tracks,
        match_fn=_match_with_fingerprint_guard,
        file_exists_fn=lambda path: Path(_album_item_abs_path(path)).exists(),
        threshold=_MB_TRACK_PREFLIGHT_MATCH_THRESHOLD,
    )


def _album_mb_completeness(album_id: int, mb_override: str = "",
                           log: Optional[List[str]] = None) -> Dict[str, Any]:
    try:
        with _db(row_factory=sqlite3.Row) as con:
            album_row = con.execute(
                "SELECT id, album, albumartist, year, mb_albumid, mb_releasegroupid "
                "FROM albums WHERE id=?",
                (album_id,),
            ).fetchone()
    except Exception as ex:
        raise RuntimeError(f"Could not read album {album_id}: {ex}")
    if not album_row:
        raise RuntimeError(f"Album {album_id} not found")

    album_title = _s(album_row["album"]).strip()
    album_artist = _s(album_row["albumartist"]).strip()
    mb_albumid = (mb_override or _s(album_row["mb_albumid"])).strip().lower()
    mb_rg = _s(album_row["mb_releasegroupid"]).strip().lower()
    if not mb_albumid and mb_rg:
        mb_albumid = _resolve_release_group_to_release(
            mb_rg, log if log is not None else [], year=str(album_row["year"] or ""))
    if not mb_albumid:
        raise RuntimeError("Album does not have a MusicBrainz release ID")

    mb = _fetch_mb_release_tracklist(mb_albumid, log)
    if not mb.get("ok"):
        raise RuntimeError(mb.get("error") or "MusicBrainz release lookup failed")
    mb_tracks = mb["tracks"]

    try:
        with _db(text_factory=bytes, row_factory=sqlite3.Row) as con:
            rows = con.execute(
                "SELECT id, title, track, disc, path, mb_trackid, length "
                "FROM items WHERE album_id=? ORDER BY disc, track, title, id",
                (album_id,),
            ).fetchall()
    except Exception as ex:
        raise RuntimeError(f"Could not read album tracks: {ex}")

    items: List[Dict[str, Any]] = []
    for row in rows:
        path = _s(row["path"])
        items.append({
            "id": int(row["id"]),
            "title": _s(row["title"]),
            "track": int(row["track"] or 0),
            "disc": int(row["disc"] or 1),
            "path": path,
            "filename": Path(path).name,
            "mb_trackid": _s(row["mb_trackid"]).strip().lower(),
            "length": float(row["length"] or 0),
        })

    alignment = summarize_mb_track_alignment(
        items,
        mb_tracks,
        match_fn=_best_album_track_match,
        file_exists_fn=lambda item: (
            not _album_item_abs_path(item.get("path", ""))
            or Path(_album_item_abs_path(item.get("path", ""))).exists()
        ),
        threshold=_MB_TRACK_PREFLIGHT_MATCH_THRESHOLD,
        repair_threshold=_MB_TRACK_REPAIR_MATCH_THRESHOLD,
    )

    return {
        "ok": True,
        "album_id": album_id,
        "album": album_title or mb.get("release_title", ""),
        "artist": album_artist,
        "year": int(str(album_row["year"] or "0")[:4] or 0),
        "mb_albumid": mb_albumid,
        "mb_url": f"https://musicbrainz.org/release/{mb_albumid}",
        "expected_count": alignment["expected_count"],
        "actual_count": alignment["actual_count"],
        "extra_count": alignment["extra_count"],
        "extra_track_count": alignment["extra_count"],
        "extra_items": alignment["extra_items"][:25],
        "in_library": alignment["in_library"],
        "missing_count": alignment["missing_count"],
        "percent": alignment["percent"],
        "tracks": alignment["tracks"],
        "missing": alignment["missing"],
        "mb_missing_count": alignment["missing_count"],
        "mb_trackid_missing_count": alignment["mb_trackid_missing_count"],
        "mb_trackid_mismatch_count": alignment["mb_trackid_mismatch_count"],
        "mb_duplicate_recording_id_count": alignment.get("mb_duplicate_recording_id_count", 0),
        "duplicate_recording_groups": alignment.get("duplicate_recording_groups", [])[:25],
        "mb_repairable_count": alignment["mb_repairable_count"],
        "mb_health_source": "musicbrainz",
        "release_title": mb.get("release_title", ""),
    }


def _resolver_rel_path(raw_path: str) -> str:
    text = _s(raw_path).strip().replace("\\", "/")
    root = str(MUSIC_ROOT).replace("\\", "/").rstrip("/")
    if text.startswith(root + "/"):
        text = text[len(root) + 1:]
    return text.strip("/")


def _resolver_parent(raw_path: str) -> str:
    rel = _resolver_rel_path(raw_path)
    if "/" not in rel:
        return ""
    return rel.rsplit("/", 1)[0]


def _resolver_sql_like(value: str) -> str:
    return (
        value
        .replace("\\", "\\\\")
        .replace("%", "\\%")
        .replace("_", "\\_")
    )


def _resolver_compact_track(track: Dict[str, Any]) -> Dict[str, Any]:
    return {
        "disc": int(track.get("disc") or 1),
        "track": int(track.get("track") or 0),
        "title": _s(track.get("title") or ""),
        "mb_trackid": _s(track.get("mb_trackid") or "").strip().lower(),
    }


def _resolver_compact_item(item: Dict[str, Any], *,
                           selected_album_id: int,
                           selected_mbid: str,
                           matched_ids: set[int]) -> Dict[str, Any]:
    path = _s(item.get("path") or "")
    return {
        "id": int(item.get("id") or 0),
        "album_id": int(item.get("album_id") or 0),
        "album": _s(item.get("album") or ""),
        "albumartist": _s(item.get("albumartist") or ""),
        "disc": int(item.get("disc") or 1),
        "track": int(item.get("track") or 0),
        "title": _s(item.get("title") or ""),
        "path": path,
        "filename": Path(path).name,
        "mb_trackid": _s(item.get("mb_trackid") or "").strip().lower(),
        "mb_albumid": _s(item.get("mb_albumid") or "").strip().lower(),
        "length": float(item.get("length") or 0),
        "in_selected_album": int(item.get("album_id") or 0) == int(selected_album_id),
        "selected_release": _s(item.get("mb_albumid") or "").strip().lower() == selected_mbid,
        "matched_to_selected_release": int(item.get("id") or 0) in matched_ids,
    }


def _resolver_title_base(value: str) -> str:
    text = re.sub(r"\s*[\(\[].*?[\)\]]", " ", _s(value))
    return _album_track_norm(text)


def _resolver_title_score(source_title: str, target_title: str) -> float:
    source_full = _album_track_norm(source_title)
    target_full = _album_track_norm(target_title)
    source_base = _resolver_title_base(source_title)
    target_base = _resolver_title_base(target_title)
    scores = [
        difflib.SequenceMatcher(None, source_full, target_full).ratio()
        if source_full and target_full else 0.0,
        difflib.SequenceMatcher(None, source_base, target_base).ratio()
        if source_base and target_base else 0.0,
    ]
    if source_base and target_full and (
        source_base == target_full or target_full.startswith(source_base + " ")
    ):
        scores.append(0.94)
    if target_base and source_full and (
        target_base == source_full or source_full.startswith(target_base + " ")
    ):
        scores.append(0.90)
    return max(scores or [0.0])


def _resolver_retag_candidates(item: Dict[str, Any],
                               missing_tracks: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    candidates: List[Dict[str, Any]] = []
    for track in missing_tracks:
        score = _resolver_title_score(item.get("title", ""), track.get("title", ""))
        if score < 0.55:
            continue
        candidates.append({
            **_resolver_compact_track(track),
            "score": round(score, 3),
        })
    candidates.sort(key=lambda c: (-float(c.get("score") or 0), int(c.get("disc") or 1), int(c.get("track") or 0)))
    return candidates[:5]


def _album_duplicate_resolver_plan(album_id: int, mb_override: str = "",
                                   log: Optional[List[str]] = None) -> Dict[str, Any]:
    data = _album_mb_completeness(album_id, mb_override, log)
    selected_mbid = _s(data.get("mb_albumid") or mb_override).strip().lower()
    if not selected_mbid:
        raise RuntimeError("Album does not have a selected MusicBrainz release ID")

    matched_ids = {
        int((row.get("item") or {}).get("id") or 0)
        for row in data.get("tracks") or []
        if int((row.get("item") or {}).get("id") or 0) > 0
    }
    expected_by_mbid: Dict[str, List[Dict[str, Any]]] = defaultdict(list)
    for row in data.get("tracks") or []:
        mbid = _s(row.get("mb_trackid") or "").strip().lower()
        if mbid:
            expected_by_mbid[mbid].append(row)
    missing_tracks = [
        _resolver_compact_track(row)
        for row in data.get("missing") or []
        if _s(row.get("mb_trackid") or "").strip()
    ]

    try:
        with _db(text_factory=bytes, row_factory=sqlite3.Row) as con:
            selected_rows = con.execute(
                "SELECT path FROM items WHERE album_id=? ORDER BY disc, track, id",
                (int(album_id),),
            ).fetchall()
    except Exception as ex:
        raise RuntimeError(f"Could not read selected album paths: {ex}") from ex

    prefixes = sorted({
        _resolver_parent(row["path"])
        for row in selected_rows
        if _resolver_parent(row["path"])
    })
    if not prefixes:
        return {
            "ok": True,
            "album_id": int(album_id),
            "mb_albumid": selected_mbid,
            "groups": [],
            "missing_tracks": missing_tracks,
            "message": "No album folder path was available for duplicate resolution.",
        }

    clauses: List[str] = []
    params: List[str] = []
    for prefix in prefixes[:30]:
        clauses.append("replace(i.path, char(92), '/') LIKE ? ESCAPE '\\'")
        params.append(_resolver_sql_like(prefix) + "/%")

    try:
        with _db(text_factory=bytes, row_factory=sqlite3.Row) as con:
            rows = con.execute(
                "SELECT i.id, i.album_id, i.title, i.track, i.disc, i.path, "
                "i.mb_trackid, i.mb_albumid, i.length, a.album, a.albumartist "
                "FROM items i LEFT JOIN albums a ON a.id=i.album_id "
                f"WHERE {' OR '.join(clauses)} "
                "ORDER BY i.disc, i.track, i.title, i.id",
                params,
            ).fetchall()
    except Exception as ex:
        raise RuntimeError(f"Could not read album-folder items: {ex}") from ex

    folder_items: List[Dict[str, Any]] = []
    for row in rows:
        folder_items.append({
            "id": int(row["id"]),
            "album_id": int(row["album_id"] or 0),
            "title": _s(row["title"]),
            "track": int(row["track"] or 0),
            "disc": int(row["disc"] or 1),
            "path": _s(row["path"]),
            "mb_trackid": _s(row["mb_trackid"]).strip().lower(),
            "mb_albumid": _s(row["mb_albumid"]).strip().lower(),
            "length": float(row["length"] or 0),
            "album": _s(row["album"]),
            "albumartist": _s(row["albumartist"]),
        })

    by_mbid: Dict[str, List[Dict[str, Any]]] = defaultdict(list)
    for item in folder_items:
        mbid = _s(item.get("mb_trackid") or "").strip().lower()
        if mbid:
            by_mbid[mbid].append(item)

    groups: List[Dict[str, Any]] = []
    used_missing_targets: set[str] = set()
    for mbid, items in sorted(by_mbid.items()):
        expected_rows = expected_by_mbid.get(mbid, [])
        allowed_count = max(1, len(expected_rows))
        if len(items) <= allowed_count:
            continue
        sorted_items = sorted(
            items,
            key=lambda item: (
                0 if int(item.get("id") or 0) in matched_ids else 1,
                0 if _s(item.get("mb_albumid") or "").strip().lower() == selected_mbid else 1,
                int(item.get("album_id") or 0) != int(album_id),
                int(item.get("disc") or 1),
                int(item.get("track") or 0),
                int(item.get("id") or 0),
            ),
        )
        keep_ids = {
            int(item.get("id") or 0)
            for item in sorted_items
            if int(item.get("id") or 0) in matched_ids
        }
        if not keep_ids:
            selected_release_items = [
                item for item in sorted_items
                if _s(item.get("mb_albumid") or "").strip().lower() == selected_mbid
            ]
            keep_ids.add(int((selected_release_items or sorted_items)[0].get("id") or 0))

        action_items: List[Dict[str, Any]] = []
        for item in sorted_items:
            item_id = int(item.get("id") or 0)
            if item_id in keep_ids:
                continue
            compact = _resolver_compact_item(
                item,
                selected_album_id=int(album_id),
                selected_mbid=selected_mbid,
                matched_ids=matched_ids,
            )
            candidates = _resolver_retag_candidates(item, data.get("missing") or [])
            available_candidates = [
                cand for cand in candidates
                if _s(cand.get("mb_trackid") or "").strip().lower() not in used_missing_targets
            ]
            default_action = "delete"
            default_target = None
            if available_candidates and float(available_candidates[0].get("score") or 0) >= 0.78:
                default_action = "retag"
                default_target = available_candidates[0]
                used_missing_targets.add(_s(default_target.get("mb_trackid")).strip().lower())
            compact.update({
                "default_action": default_action,
                "default_target": default_target,
                "retag_candidates": candidates,
            })
            action_items.append(compact)

        groups.append({
            "key": mbid,
            "mb_trackid": mbid,
            "count": len(sorted_items),
            "duplicate_count": max(0, len(sorted_items) - allowed_count),
            "expected_count": len(expected_rows),
            "expected_tracks": [_resolver_compact_track(row) for row in expected_rows],
            "keep_items": [
                _resolver_compact_item(
                    item,
                    selected_album_id=int(album_id),
                    selected_mbid=selected_mbid,
                    matched_ids=matched_ids,
                )
                for item in sorted_items
                if int(item.get("id") or 0) in keep_ids
            ],
            "action_items": action_items,
        })

    return {
        "ok": True,
        "album_id": int(album_id),
        "mb_albumid": selected_mbid,
        "album": data.get("album", ""),
        "artist": data.get("artist", ""),
        "expected_count": data.get("expected_count", 0),
        "actual_count": len(folder_items),
        "missing_count": len(missing_tracks),
        "missing_tracks": missing_tracks,
        "groups": groups,
        "group_count": len(groups),
        "action_item_count": sum(len(group.get("action_items") or []) for group in groups),
    }


