def _remove_album_track_items(album_id: int, item_ids: List[int], *,
                              dry_run: bool,
                              delete_files: bool,
                              clean_empty_folders: bool = True,
                              log: List[str]) -> Dict[str, Any]:
    if not item_ids:
        return {"removed_db": 0, "deleted_files": 0, "folders_removed": 0,
                "dry_run": dry_run}
    clean_ids: set = set()
    for raw_id in item_ids:
        try:
            val = int(raw_id)
        except Exception:
            continue
        if val > 0:
            clean_ids.add(val)
    safe_ids = sorted(clean_ids)
    if not safe_ids:
        return {"removed_db": 0, "deleted_files": 0, "folders_removed": 0,
                "dry_run": dry_run}
    q_marks = ",".join("?" for _ in safe_ids)
    try:
        with _db(text_factory=bytes, row_factory=sqlite3.Row) as con:
            rows = con.execute(
                f"SELECT id, title, track, disc, path FROM items "
                f"WHERE album_id=? AND id IN ({q_marks})",
                [album_id] + safe_ids,
            ).fetchall()
    except Exception as ex:
        raise RuntimeError(f"Could not load selected tracks: {ex}")

    music_root_res = MUSIC_ROOT.resolve(strict=False)
    selected = []
    for row in rows:
        raw_path = _s(row["path"])
        abs_path = Path(_album_item_abs_path(raw_path))
        try:
            abs_path.resolve(strict=False).relative_to(music_root_res)
            in_music_root = True
        except Exception:
            in_music_root = False
        selected.append({
            "id": int(row["id"]),
            "title": _s(row["title"]),
            "track": int(row["track"] or 0),
            "disc": int(row["disc"] or 1),
            "path": str(abs_path),
            "filename": abs_path.name,
            "in_music_root": in_music_root,
        })

    log.append(f"{'Dry run: ' if dry_run else ''}Removing {len(selected)} selected track(s) from album_id {album_id}")
    deleted_files = 0
    parent_dirs: List[Path] = []
    for rec in selected:
        log.append(f"  [{rec['track']:02d}] {rec['filename']}")
        p = Path(rec["path"])
        if delete_files and rec["in_music_root"]:
            parent_dirs.append(p.parent)
            if dry_run:
                deleted_files += 1
                continue
            try:
                p.unlink(missing_ok=True)
                deleted_files += 1
            except Exception as ex:
                log.append(f"    WARN could not delete file: {ex}")
        elif delete_files:
            log.append("    WARN file is outside /data/media/music; DB entry only")

    folders_removed = 0
    selected_paths = set()
    for rec in selected:
        try:
            selected_paths.add(Path(rec["path"]).resolve(strict=False))
        except Exception:
            pass

    def _folder_empty(folder: Path) -> bool:
        try:
            for child in folder.iterdir():
                if child.name.startswith("."):
                    continue
                if dry_run:
                    try:
                        if child.resolve(strict=False) in selected_paths:
                            continue
                    except Exception:
                        pass
                return False
            return True
        except Exception:
            return False

    def _clean_parents(start: Path):
        nonlocal folders_removed
        folder = start
        for _ in range(8):
            try:
                folder.resolve(strict=False).relative_to(music_root_res)
            except Exception:
                break
            if folder.resolve(strict=False) == music_root_res:
                break
            if not _folder_empty(folder):
                break
            if dry_run:
                folders_removed += 1
                log.append(f"  Would remove empty folder: {folder}")
            else:
                try:
                    folder.rmdir()
                    folders_removed += 1
                    log.append(f"  Removed empty folder: {folder}")
                except Exception:
                    break
            folder = folder.parent

    if delete_files and clean_empty_folders:
        for parent in sorted(set(parent_dirs), key=lambda p: len(p.parts), reverse=True):
            _clean_parents(parent)

    removed_db = 0
    album_deleted = False
    if selected and not dry_run:
        del_ids = [r["id"] for r in selected]
        q_marks = ",".join("?" for _ in del_ids)
        try:
            with _db() as con:
                cur = con.execute(f"DELETE FROM items WHERE album_id=? AND id IN ({q_marks})",
                                  [album_id] + del_ids)
                removed_db = cur.rowcount if cur.rowcount > 0 else len(del_ids)
                remaining = con.execute(
                    "SELECT COUNT(*) FROM items WHERE album_id=?", (album_id,)
                ).fetchone()[0]
                if int(remaining or 0) == 0:
                    con.execute("DELETE FROM albums WHERE id=?", (album_id,))
                    album_deleted = True
                con.commit()
        except Exception as ex:
            raise RuntimeError(f"Could not remove DB rows: {ex}")
        _invalidate_lib_cache()
        _trigger_plex_refresh(log)
    elif dry_run:
        removed_db = len(selected)

    return {
        "removed_db": removed_db,
        "deleted_files": deleted_files,
        "folders_removed": folders_removed,
        "album_deleted": album_deleted,
        "dry_run": dry_run,
        "items": selected,
    }


@app.post("/api/clean/album-tracks/scan")
def clean_album_tracks_scan():
    payload = request.get_json(silent=True) or {}
    album_id = int(payload.get("album_id") or 0)
    limit = max(1, min(int(payload.get("limit") or 75), 500))
    use_ai = bool(payload.get("use_ai", True))
    use_fingerprint = bool(payload.get("use_fingerprint", True))
    fingerprint_limit = max(1, min(int(payload.get("fingerprint_limit") or 80), 200))

    try:
        with _db(row_factory=sqlite3.Row) as con:
            if album_id:
                rows = con.execute(
                    "SELECT id, album, albumartist, mb_albumid, mb_releasegroupid "
                    "FROM albums WHERE id=?",
                    (album_id,),
                ).fetchall()
            else:
                rows = con.execute(
                    "SELECT id, album, albumartist, mb_albumid, mb_releasegroupid "
                    "FROM albums WHERE COALESCE(mb_albumid,'') != '' "
                    "ORDER BY id DESC LIMIT ?",
                    (limit,),
                ).fetchall()
    except Exception as ex:
        return jsonify({"ok": False, "error": f"Could not read albums: {ex}"}), 500
    if album_id and not rows:
        return jsonify({"ok": False, "error": f"Album {album_id} not found"}), 404
    if not rows:
        return jsonify({"ok": False, "error": "No MusicBrainz-tagged albums found"}), 404

    album_rows = [dict(r) for r in rows]

    def _do(log, cancel_event=None):
        results = []
        remove_count = 0
        review_count = 0
        log.append(f"Scanning {len(album_rows)} MusicBrainz-tagged album(s)")
        log.append(f"AI review: {'on' if use_ai else 'off'}; audio fingerprint: {'on' if use_fingerprint else 'off'}")
        for idx, row in enumerate(album_rows, start=1):
            if cancel_event is not None and cancel_event.is_set():
                log.append("Cancelled")
                break
            log.append(f"[{idx}/{len(album_rows)}] {row.get('albumartist','')} - {row.get('album','')} (album_id {row.get('id')})")
            res = _scan_album_track_integrity(
                row,
                use_ai=use_ai,
                use_fingerprint=use_fingerprint,
                fingerprint_limit=fingerprint_limit,
                log=log,
            )
            if not res:
                log.append("  OK")
                continue
            rmc = len(res.get("remove_candidates") or [])
            rvc = len(res.get("review_candidates") or [])
            log.append(f"  Found {rmc} remove candidate(s), {rvc} review candidate(s)")
            remove_count += rmc
            review_count += rvc
            results.append(res)
        return {
            "ok": True,
            "albums_scanned": len(album_rows),
            "problem_albums": results,
            "problem_count": len(results),
            "remove_count": remove_count,
            "review_count": review_count,
        }

    label = f"Clean album tracks: album {album_id}" if album_id else "Clean album tracks scan"
    job = jobs.start_python(_do, label=label)
    return jsonify({"ok": True, "job_id": job.job_id})


@app.post("/api/clean/album-tracks/remove")
def clean_album_tracks_remove():
    payload = request.get_json(silent=True) or {}
    album_id = int(payload.get("album_id") or 0)
    item_ids = payload.get("item_ids") or []
    dry_run = bool(payload.get("dry_run", True))
    delete_files = bool(payload.get("delete_files", True))
    clean_empty_folders = bool(payload.get("clean_empty_folders", False))
    if not album_id:
        return jsonify({"ok": False, "error": "album_id required"}), 400
    if not isinstance(item_ids, list) or not item_ids:
        return jsonify({"ok": False, "error": "item_ids required"}), 400

    if dry_run:
        log: List[str] = []
        summary = _remove_album_track_items(
            album_id,
            item_ids,
            dry_run=True,
            delete_files=delete_files,
            clean_empty_folders=clean_empty_folders,
            log=log,
        )
        return jsonify({"ok": True, "dry_run": True, "summary": summary, "log": log})

    def _do(log, cancel_event=None):
        return _remove_album_track_items(
            album_id,
            item_ids,
            dry_run=False,
            delete_files=delete_files,
            clean_empty_folders=clean_empty_folders,
            log=log,
        )

    job = jobs.start_python(_do, label=f"Remove bad tracks: album {album_id}")
    return jsonify({"ok": True, "job_id": job.job_id})


@app.post("/api/clean/album-tracks/remove-batch")
def clean_album_tracks_remove_batch():
    payload = request.get_json(silent=True) or {}
    groups = payload.get("groups") or []
    dry_run = bool(payload.get("dry_run", False))
    delete_files = bool(payload.get("delete_files", True))
    clean_empty_folders = bool(payload.get("clean_empty_folders", False))
    if not isinstance(groups, list) or not groups:
        return jsonify({"ok": False, "error": "groups required"}), 400

    clean_groups: List[Dict[str, Any]] = []
    for group in groups:
        try:
            album_id = int((group or {}).get("album_id") or 0)
        except Exception:
            album_id = 0
        item_ids = (group or {}).get("item_ids") or []
        if album_id <= 0 or not isinstance(item_ids, list):
            continue
        ids = []
        for raw in item_ids:
            try:
                iid = int(raw)
            except Exception:
                continue
            if iid > 0:
                ids.append(iid)
        if ids:
            clean_groups.append({"album_id": album_id, "item_ids": sorted(set(ids))})
    if not clean_groups:
        return jsonify({"ok": False, "error": "No valid album/item groups"}), 400

    def _do(log, cancel_event=None):
        summaries = []
        totals = {
            "albums": 0,
            "removed_db": 0,
            "deleted_files": 0,
            "folders_removed": 0,
            "album_deleted": 0,
        }
        log.append(
            f"{'Dry run: ' if dry_run else ''}Removing bad tracks from "
            f"{len(clean_groups)} album(s); folders will be preserved."
        )
        for idx, group in enumerate(clean_groups, start=1):
            if cancel_event is not None and cancel_event.is_set():
                log.append("Cancelled")
                break
            album_id = int(group["album_id"])
            item_ids = group["item_ids"]
            log.append(f"[{idx}/{len(clean_groups)}] album_id {album_id}: {len(item_ids)} track(s)")
            summary = _remove_album_track_items(
                album_id,
                item_ids,
                dry_run=dry_run,
                delete_files=delete_files,
                clean_empty_folders=clean_empty_folders,
                log=log,
            )
            summaries.append({"album_id": album_id, **summary})
            totals["albums"] += 1
            totals["removed_db"] += int(summary.get("removed_db") or 0)
            totals["deleted_files"] += int(summary.get("deleted_files") or 0)
            totals["folders_removed"] += int(summary.get("folders_removed") or 0)
            if summary.get("album_deleted"):
                totals["album_deleted"] += 1
        log.append(
            "Done: "
            f"{totals['deleted_files']} file(s) deleted, "
            f"{totals['removed_db']} DB row(s) removed, "
            f"{totals['album_deleted']} empty album record(s) removed."
        )
        return {"ok": True, "dry_run": dry_run, "totals": totals, "albums": summaries}

    job = jobs.start_python(_do, label="Remove bad tracks: batch")
    return jsonify({"ok": True, "job_id": job.job_id})


# ── Clean: artist folder merge ────────────────────────────────────────────────

def _artist_folder_key(name: str) -> str:
    """Case/punctuation-insensitive key for duplicate artist folder detection."""
    text = _normalize_name(name).casefold()
    text = (
        text.replace("$", "s")
            .replace("@", "a")
            .replace("!", "i")
    )
    return re.sub(r"[^a-z0-9]+", "", text)


_mb_artist_cache: Dict[str, Dict[str, Any]] = {}


def _mb_artist_search_one(name: str) -> Dict[str, Any]:
    """Return the best MusicBrainz artist match for a name or {}.

    Used by cleanup to choose canonical spellings like Joey Bada$$.
    """
    raw = _normalize_name(name).strip()
    if not raw:
        return {}
    cache_key = raw.casefold()
    if cache_key in _mb_artist_cache:
        return _mb_artist_cache[cache_key]

    queries = [
        f'artist:"{raw}"',
        raw,
    ]
    best: Dict[str, Any] = {}
    key = _artist_folder_key(raw)
    for q in queries:
        try:
            params = _up.urlencode({"query": q, "limit": 8, "fmt": "json"})
            req = _ur.Request(
                f"https://musicbrainz.org/ws/2/artist?{params}",
                headers={"User-Agent": "BeetsWebControl/1.0 (beets-webcontrol)"}
            )
            with _ur.urlopen(req, timeout=8) as resp:
                data = json.loads(resp.read())
        except Exception:
            continue
        for artist in data.get("artists", []):
            mb_name = _s(artist.get("name", "")).strip()
            mb_id = _s(artist.get("id", "")).strip()
            if not mb_name or not _MB_UUID_RE.match(mb_id):
                continue
            score = int(artist.get("score", 0) or 0)
            mb_key = _artist_folder_key(mb_name)
            alias_match = any(
                _artist_folder_key((a or {}).get("name", "")) == key
                for a in artist.get("aliases", []) or []
                if isinstance(a, dict)
            )
            key_match = mb_key == key or alias_match
            rank = (
                0 if key_match else 1,
                -score,
                len(mb_name),
                mb_name.casefold(),
            )
            cand = {
                "id": mb_id,
                "name": mb_name,
                "score": score,
                "disambiguation": _s(artist.get("disambiguation", "")),
                "_rank": rank,
                "matched_query": q,
            }
            if not best or rank < best.get("_rank", (9, 0, 0, "")):
                best = cand
    if best:
        best.pop("_rank", None)
    _mb_artist_cache[cache_key] = best
    return best


def _mb_artist_lookup_by_id(mb_artistid: str) -> Dict[str, Any]:
    """Return MusicBrainz canonical artist details for an artist UUID."""
    mbid = _s(mb_artistid).strip().lower()
    if not _MB_UUID_RE.match(mbid):
        return {}
    cache_key = f"id:{mbid}"
    if cache_key in _mb_artist_cache:
        return _mb_artist_cache[cache_key]
    best: Dict[str, Any] = {}
    try:
        req = _ur.Request(
            f"https://musicbrainz.org/ws/2/artist/{mbid}?fmt=json",
            headers={"User-Agent": "BeetsWebControl/1.0 (beets-webcontrol)"}
        )
        with _ur.urlopen(req, timeout=8) as resp:
            data = json.loads(resp.read())
        mb_name = _s(data.get("name", "")).strip()
        if mb_name:
            best = {
                "id": mbid,
                "name": mb_name,
                "disambiguation": _s(data.get("disambiguation", "")),
                "matched_query": mbid,
            }
    except Exception:
        best = {}
    _mb_artist_cache[cache_key] = best
    return best


def _mb_canonical_for_artist_entries(entries: List[Dict[str, Any]], key: str) -> Dict[str, Any]:
    matches = []
    for e in entries:
        m = _mb_artist_search_one(e["name"])
        if not m:
            continue
        if _artist_folder_key(m.get("name", "")) != key:
            # Keep alias hits only when the search score is strong enough.
            if int(m.get("score") or 0) < 90:
                continue
        matches.append({"entry": e, "match": m})
    if not matches:
        return {}

    by_id: Dict[str, Dict[str, Any]] = {}
    for item in matches:
        m = item["match"]
        rec = by_id.setdefault(m["id"], {
            "id": m["id"],
            "name": m["name"],
            "score_total": 0,
            "count": 0,
            "entries": [],
            "disambiguation": m.get("disambiguation", ""),
        })
        rec["score_total"] += int(m.get("score") or 0)
        rec["count"] += 1
        rec["entries"].append(item["entry"]["name"])
        # Prefer the MB display spelling from the best scoring hit.
        if int(m.get("score") or 0) >= rec.get("best_score", -1):
            rec["name"] = m["name"]
            rec["best_score"] = int(m.get("score") or 0)
    best = sorted(
        by_id.values(),
        key=lambda r: (-r["count"], -r["score_total"], r["name"].casefold())
    )[0]
    return best


def _artist_folder_db_counts() -> Dict[str, Dict[str, int]]:
    counts: Dict[str, Dict[str, int]] = {}
    try:
        with _db() as con:
            rows = con.execute(
                "SELECT albumartist, COUNT(DISTINCT albums.id), COUNT(items.id) "
                "FROM albums LEFT JOIN items ON items.album_id = albums.id "
                "WHERE albumartist != '' GROUP BY albumartist"
            ).fetchall()
        for artist, album_count, track_count in rows:
            counts[_s(artist)] = {
                "albums": int(album_count or 0),
                "tracks": int(track_count or 0),
            }
    except Exception:
        pass
    return counts


def _count_audio_files(folder: Path) -> Dict[str, int]:
    audio = 0
    folders = 0
    try:
        for p in folder.rglob("*"):
            if p.is_dir():
                folders += 1
            elif p.is_file() and p.suffix.lower() in AUDIO_EXTS:
                audio += 1
    except Exception:
        pass
    return {"audio": audio, "folders": folders}


def _scan_artist_folder_groups(root: str, *, use_musicbrainz: bool = False,
                               only_keys: Optional[set] = None) -> List[Dict[str, Any]]:
    root_path = Path(root)
    db_counts = _artist_folder_db_counts()
    grouped: Dict[str, List[Dict[str, Any]]] = defaultdict(list)
    wanted = set(only_keys or [])
    for child in sorted(root_path.iterdir(), key=lambda p: p.name.casefold()):
        if not child.is_dir() or child.name.startswith("."):
            continue
        key = _artist_folder_key(child.name)
        if not key:
            continue
        if wanted and key not in wanted:
            continue
        counts = _count_audio_files(child)
        dbc = db_counts.get(child.name, {})
        grouped[key].append({
            "name": child.name,
            "path": str(child),
            "audio_files": counts["audio"],
            "subfolders": counts["folders"],
            "db_albums": dbc.get("albums", 0),
            "db_tracks": dbc.get("tracks", 0),
        })

    out = []
    for key, entries in grouped.items():
        mb_canonical = _mb_canonical_for_artist_entries(entries, key) if use_musicbrainz else {}
        canonical_name_from_mb = _s(mb_canonical.get("name", "")).strip()
        needs_mb_rename = bool(
            canonical_name_from_mb
            and not any(e["name"] == canonical_name_from_mb for e in entries)
            and any(_artist_folder_key(e["name"]) == _artist_folder_key(canonical_name_from_mb) for e in entries)
        )
        if len(entries) < 2 and not needs_mb_rename:
            continue
        def _looks_bad_upper(name: str) -> bool:
            letters = re.sub(r"[^A-Za-z]+", "", name)
            return len(letters) > 4 and letters.isupper()

        has_preferred_case = any(not _looks_bad_upper(e["name"]) for e in entries)

        def _score(e):
            return (
                1 if has_preferred_case and _looks_bad_upper(e["name"]) else 0,
                -int(e["db_tracks"] or 0),
                -int(e["audio_files"] or 0),
                len(e["name"]),
                e["name"].casefold(),
            )

        canonical = sorted(entries, key=_score)[0]
        if canonical_name_from_mb:
            existing_mb = next((e for e in entries if e["name"] == canonical_name_from_mb), None)
            if existing_mb:
                canonical = existing_mb
            elif needs_mb_rename:
                canonical = {
                    "name": canonical_name_from_mb,
                    "path": str(root_path / canonical_name_from_mb),
                    "audio_files": 0,
                    "subfolders": 0,
                    "db_albums": 0,
                    "db_tracks": 0,
                    "musicbrainz_synthetic": True,
                }
        sources = [e for e in entries if e["path"] != canonical["path"]]
        out.append({
            "key": key,
            "canonical": canonical,
            "sources": sources,
            "variants": entries,
            "musicbrainz": {
                "id": mb_canonical.get("id", ""),
                "name": canonical_name_from_mb,
                "score": mb_canonical.get("best_score", 0),
                "matched_entries": mb_canonical.get("entries", []),
                "disambiguation": mb_canonical.get("disambiguation", ""),
            } if mb_canonical else {},
            "rename_to_musicbrainz": bool(canonical_name_from_mb),
            "source_audio_files": sum(int(e["audio_files"] or 0) for e in sources),
            "source_folders": len(sources),
        })
    return sorted(out, key=lambda g: g["canonical"]["name"].casefold())


def _path_under(path: Path, root: Path) -> bool:
    try:
        path.resolve(strict=False).relative_to(root.resolve(strict=False))
        return True
    except Exception:
        return False


def _db_path_value(path: Path) -> str:
    raw = str(path)
    mroot = str(MUSIC_ROOT)
    return raw[len(mroot) + 1:] if raw.startswith(mroot + "/") else raw


def _qbit_status_payload() -> Dict[str, Any]:
    return {
        "ok": True,
        "configured": bool(QBIT_URL),
        "url": QBIT_URL,
        "username_configured": bool(QBIT_USERNAME),
        "password_configured": bool(QBIT_PASSWORD),
        "category": QBIT_CATEGORY,
        "filter": QBIT_FILTER,
        "path_aliases": QBIT_PATH_ALIASES,
        "repair_allowed_roots": [str(p) for p in QBIT_REPAIR_ALLOWED_ROOTS],
        "torrent_source_roots": [str(p) for p in TORRENT_SOURCE_ROOTS],
    }


def _qbit_login_cookie() -> str:
    if not QBIT_URL:
        raise RuntimeError(
            "qBittorrent is not configured. Set QBITTORRENT_URL or QBIT_URL "
            "in the Beets container."
        )
    if not QBIT_URL.startswith(("http://", "https://")):
        raise RuntimeError(f"qBittorrent URL must include http:// or https://: {QBIT_URL}")
    if not (QBIT_USERNAME and QBIT_PASSWORD):
        return ""
    data = urllib.parse.urlencode({
        "username": QBIT_USERNAME,
        "password": QBIT_PASSWORD,
    }).encode("utf-8")
    req = urllib.request.Request(
        f"{QBIT_URL}/api/v2/auth/login",
        data=data,
        headers={"Content-Type": "application/x-www-form-urlencoded"},
    )
    with urllib.request.urlopen(req, timeout=20) as resp:
        status = int(getattr(resp, "status", 200) or 200)
        body = resp.read().decode("utf-8", errors="replace").strip()
        cookie = resp.headers.get("Set-Cookie", "")
        if body != "Ok." and not (status == 204 and cookie):
            raise RuntimeError(f"qBittorrent login failed: {body or 'empty response'}")
    return cookie.split(";", 1)[0].strip()


def _qbit_request_json(api_path: str, params: Optional[Dict[str, Any]] = None,
                       cookie: str = "") -> Any:
    query = urllib.parse.urlencode(params or {})
    url = f"{QBIT_URL}{api_path}" + (f"?{query}" if query else "")
    headers = {"Cookie": cookie} if cookie else {}
    req = urllib.request.Request(url, headers=headers)
    with urllib.request.urlopen(req, timeout=30) as resp:
        body = resp.read().decode("utf-8", errors="replace")
    return json.loads(body) if body.strip() else None


def _qbit_post(api_path: str, data: Dict[str, Any], cookie: str = "") -> str:
    encoded = urllib.parse.urlencode(data).encode("utf-8")
    headers = {"Content-Type": "application/x-www-form-urlencoded"}
    if cookie:
        headers["Cookie"] = cookie
    req = urllib.request.Request(f"{QBIT_URL}{api_path}", data=encoded, headers=headers)
    with urllib.request.urlopen(req, timeout=30) as resp:
        return resp.read().decode("utf-8", errors="replace")


def _qbit_path_alias_pairs() -> List[Tuple[str, str]]:
    pairs: List[Tuple[str, str]] = []
    for token in QBIT_PATH_ALIASES.split(","):
        if "=" not in token:
            continue
        src, dst = token.split("=", 1)
        src = src.strip().replace("\\", "/").rstrip("/")
        dst = dst.strip().replace("\\", "/").rstrip("/")
        if src and dst:
            pairs.append((src, dst))
    return sorted(pairs, key=lambda pair: len(pair[0]), reverse=True)


def _qbit_map_path(path_value: str) -> Path:
    text = _s(path_value).strip().replace("\\", "/")
    for src, dst in _qbit_path_alias_pairs():
        if text == src or text.startswith(src + "/"):
            text = dst + text[len(src):]
            break
    return Path(text)


def _qbit_allowed_repair_path(path: Path) -> bool:
    if not QBIT_REPAIR_ALLOWED_ROOTS:
        return False
    return any(_path_is_under(path, root) for root in QBIT_REPAIR_ALLOWED_ROOTS)


def _qbit_candidate_target_paths(torrent: Dict[str, Any],
                                 file_row: Dict[str, Any]) -> List[Path]:
    rel_name = _s(file_row.get("name")).strip().replace("\\", "/").lstrip("/")
    if not rel_name:
        return []
    rel = Path(rel_name)
    content_raw = _s(torrent.get("content_path")).strip()
    save_raw = _s(torrent.get("save_path")).strip()
    content = _qbit_map_path(content_raw) if content_raw else None
    save = _qbit_map_path(save_raw) if save_raw else None
    candidates: List[Path] = []

    if content:
        if content.suffix.lower() in AUDIO_EXT:
            candidates.append(content)
        elif rel.parts and content.name.casefold() == rel.parts[0].casefold():
            if save:
                candidates.append(save / rel)
            candidates.append(content.parent / rel)
        else:
            candidates.append(content / rel)
    if save:
        candidates.append(save / rel)
    if content and content.suffix.lower() in AUDIO_EXT:
        candidates.append(content)

    out: List[Path] = []
    seen: set = set()
    for candidate in candidates:
        text = str(candidate)
        if text in seen:
            continue
        seen.add(text)
        out.append(candidate)
    return out


def _library_file_candidates_for_qbit(file_name: str, size: int) -> List[Dict[str, Any]]:
    basename = Path(file_name).name
    if not basename or size <= 0:
        return []
    rows: List[sqlite3.Row] = []
    try:
        with _db(text_factory=bytes, row_factory=sqlite3.Row) as con:
            rows = con.execute(
                "SELECT id,path,title,artist,album FROM items WHERE path LIKE ?",
                (f"%{basename}",),
            ).fetchall()
    except Exception:
        return []

    matches: List[Dict[str, Any]] = []
    seen_paths: set = set()
    for row in rows:
        raw = _s(row["path"]).strip()
        if not raw:
            continue
        path = Path(raw)
        if not path.is_absolute():
            path = MUSIC_ROOT / raw
        try:
            if not path.exists() or not path.is_file():
                continue
            if path.stat().st_size != size:
                continue
            resolved = str(path.resolve(strict=False))
        except Exception:
            continue
        if resolved in seen_paths:
            continue
        seen_paths.add(resolved)
        matches.append({
            "id": int(row["id"]),
            "path": str(path),
            "title": _s(row["title"]),
            "artist": _s(row["artist"]),
            "album": _s(row["album"]),
            "size": size,
            "match_strategy": "filename_size",
        })
    return matches


_QBIT_SCENE_META_TOKENS = {
    "16BIT", "24BIT", "320", "CD", "CDS", "DIGITAL", "FLAC", "MP3", "M4A",
    "PROPER", "REPACK", "REMASTERED", "RETAIL", "VINYL", "WEB",
}


def _qbit_scene_text(value: str) -> str:
    text = _s(value).strip()
    text = text.replace("_", " ").replace(".", " ")
    text = re.sub(r"\s+", " ", text)
    return text.strip()


def _qbit_torrent_scene_artist_slug(torrent_name: str) -> str:
    first = _s(torrent_name).split("-", 1)[0]
    return re.sub(r"[^a-z0-9]+", "_", first.casefold()).strip("_")


def _qbit_torrent_album_guess(torrent_name: str) -> str:
    parts = [_s(p).strip() for p in _s(torrent_name).split("-") if _s(p).strip()]
    if len(parts) < 2:
        return ""
    album_parts: List[str] = []
    for part in parts[1:]:
        token = re.sub(r"[^A-Za-z0-9]+", "", part).upper()
        if token in _QBIT_SCENE_META_TOKENS or re.fullmatch(r"(?:19|20)\d{2}", token or ""):
            break
        album_parts.append(part)
    return _qbit_scene_text(" ".join(album_parts))


def _qbit_track_guess_from_scene_file(file_name: str, torrent_name: str) -> Dict[str, Any]:
    stem = Path(_s(file_name).replace("\\", "/")).stem
    match = re.match(r"^\s*(?:cd\d+[-_. ]*)?0*(\d{1,3})[-_. ]+(.+)$", stem, re.I)
    if not match:
        return {"track": 0, "title": ""}
    try:
        track_no = int(match.group(1))
    except Exception:
        track_no = 0
    remainder = match.group(2).strip("-_ .")
    artist_slug = _qbit_torrent_scene_artist_slug(torrent_name)
    rem_slug = re.sub(r"[^a-z0-9]+", "_", remainder.casefold()).strip("_")
    if artist_slug and rem_slug.startswith(artist_slug + "_"):
        remainder = remainder[len(artist_slug):].lstrip("-_ .")
    elif "-" in remainder:
        # Scene files commonly use NN-artist-title.ext. If the artist slug did
        # not match exactly, the first hyphen chunk is still usually artist text.
        first, rest = remainder.split("-", 1)
        first_key = re.sub(r"[^a-z0-9]+", "", first.casefold())
        artist_key = re.sub(r"[^a-z0-9]+", "", artist_slug)
        if first_key and artist_key and (first_key in artist_key or artist_key in first_key):
            remainder = rest
    return {"track": track_no, "title": _qbit_scene_text(remainder)}


def _library_file_candidates_for_qbit_metadata(file_name: str, size: int,
                                               torrent: Dict[str, Any], *,
                                               require_size: bool = True) -> List[Dict[str, Any]]:
    if size <= 0:
        return []
    torrent_name = _s(torrent.get("name"))
    album_guess = _qbit_torrent_album_guess(torrent_name)
    track_guess = _qbit_track_guess_from_scene_file(file_name, torrent_name)
    track_no = int(track_guess.get("track") or 0)
    title_guess = _s(track_guess.get("title"))
    album_norm = _normalize_album(album_guess)
    album_key = _album_key(album_guess)
    title_norm = _album_track_norm(title_guess)
    if not album_norm and not album_key:
        return []
    if not track_no and not title_norm:
        return []

    where = ["path IS NOT NULL"]
    params: List[Any] = []
    if track_no:
        where.append("track=?")
        params.append(track_no)
    try:
        with _db(text_factory=bytes, row_factory=sqlite3.Row) as con:
            rows = con.execute(
                "SELECT id,path,title,artist,album,albumartist,track,disc "
                f"FROM items WHERE {' AND '.join(where)}",
                params,
            ).fetchall()
    except Exception:
        return []

    matches: List[Dict[str, Any]] = []
    seen_paths: set = set()
    for row in rows:
        raw = _s(row["path"]).strip()
        if not raw:
            continue
        path = Path(raw)
        if not path.is_absolute():
            path = MUSIC_ROOT / raw
        try:
            if not path.exists() or not path.is_file():
                continue
            actual_size = int(path.stat().st_size)
            if require_size and actual_size != size:
                continue
            resolved = str(path.resolve(strict=False))
        except Exception:
            continue

        row_album = _s(row["album"])
        row_album_norm = _normalize_album(row_album)
        row_album_key = _album_key(row_album)
        album_match = bool(
            (album_norm and album_norm == row_album_norm)
            or (album_key and album_key == row_album_key)
        )
        if not album_match:
            continue

        row_title_norm = _album_track_norm(_s(row["title"]))
        title_match = bool(title_norm and row_title_norm and (
            title_norm == row_title_norm
            or difflib.SequenceMatcher(None, title_norm, row_title_norm).ratio() >= 0.92
        ))
        if not track_no and not title_match:
            continue

        if resolved in seen_paths:
            continue
        seen_paths.add(resolved)
        matches.append({
            "id": int(row["id"]),
            "path": str(path),
            "title": _s(row["title"]),
            "artist": _s(row["artist"]),
            "album": row_album,
            "albumartist": _s(row["albumartist"]),
            "track": int(row["track"] or 0),
            "disc": int(row["disc"] or 0),
            "size": size,
            "actual_size": actual_size,
            "size_delta": actual_size - size,
            "match_strategy": "album_track_size" if not title_match else "album_track_title_size",
            "torrent_album_guess": album_guess,
            "torrent_title_guess": title_guess,
        })
    return matches


def _qbit_hardlink_missing_impl(*, dry_run: bool, category: str,
                                qbit_filter: str,
                                search: str,
                                hashes: List[str], limit: int,
                                recheck: bool, log: list,
                                cancel_event=None) -> Dict[str, Any]:
    cookie = _qbit_login_cookie()
    params: Dict[str, Any] = {}
    category = _s(category).strip()
    if category and category.lower() not in {"*", "all", "any"}:
        params["category"] = category
    qbit_filter = _s(qbit_filter).strip()
    if qbit_filter and qbit_filter.lower() not in {"*", "all", "any"}:
        params["filter"] = qbit_filter
    torrents = _qbit_request_json("/api/v2/torrents/info", params, cookie) or []
    wanted_hashes = {h.strip().lower() for h in hashes if h and h.strip()}
    if wanted_hashes:
        torrents = [
            t for t in torrents
            if _s(t.get("hash")).strip().lower() in wanted_hashes
        ]
    search_norm = _s(search).strip().casefold()
    if search_norm:
        torrents = [
            t for t in torrents
            if search_norm in _s(t.get("name")).casefold()
        ]
    log.append(
        f"qBittorrent scan: {len(torrents)} torrent(s), "
        f"category={category or 'all'}, filter={qbit_filter or 'all'}, "
        f"search={search or 'all'}, dry_run={dry_run}"
    )

    summary = {
        "dry_run": dry_run,
        "torrents": len(torrents),
        "category": category or "",
        "filter": qbit_filter or "",
        "search": search or "",
        "checked": 0,
        "already_present": 0,
        "linked": 0,
        "would_link": 0,
        "size_mismatch": 0,
        "skipped": 0,
        "errors": 0,
        "rechecked_hashes": 0,
        "actions": [],
    }
    touched_hashes: set = set()
    max_actions = 200

    def add_action(action: Dict[str, Any]) -> None:
        if len(summary["actions"]) < max_actions:
            summary["actions"].append(action)

    for torrent in torrents:
        if cancel_event and cancel_event.is_set():
            raise RuntimeError("cancelled")
        thash = _s(torrent.get("hash")).strip()
        if not thash:
            continue
        try:
            files = _qbit_request_json(
                "/api/v2/torrents/files",
                {"hash": thash},
                cookie,
            ) or []
        except Exception as ex:
            summary["errors"] += 1
            log.append(f"  ERROR reading files for {torrent.get('name')}: {ex}")
            continue
        for file_row in files:
            if cancel_event and cancel_event.is_set():
                raise RuntimeError("cancelled")
            if limit and summary["checked"] >= limit:
                break
            name = _s(file_row.get("name")).strip()
            if Path(name).suffix.lower() not in AUDIO_EXT:
                continue
            progress = float(file_row.get("progress") or 0)
            size = int(file_row.get("size") or 0)
            if size <= 0:
                summary["skipped"] += 1
                add_action({
                    "status": "skipped",
                    "reason": "missing file size",
                    "torrent": _s(torrent.get("name")),
                    "file": name,
                    "progress": round(progress, 3),
                    "size": size,
                })
                continue
            summary["checked"] += 1
            target_candidates = _qbit_candidate_target_paths(torrent, file_row)
            existing_target = next((p for p in target_candidates if p.exists() and p.is_file()), None)
            if existing_target:
                summary["already_present"] += 1
                add_action({
                    "status": "already_present",
                    "reason": "qBittorrent target file exists",
                    "torrent": _s(torrent.get("name")),
                    "file": name,
                    "target": str(existing_target),
                    "progress": round(progress, 3),
                    "size": size,
                })
                continue
            target = next((p for p in target_candidates if _qbit_allowed_repair_path(p)), None)
            if not target:
                summary["skipped"] += 1
                add_action({
                    "status": "skipped",
                    "reason": "no allowed qBittorrent target path",
                    "torrent": _s(torrent.get("name")),
                    "file": name,
                    "progress": round(progress, 3),
                    "size": size,
                })
                continue
            lib_matches = _library_file_candidates_for_qbit(name, size)
            if len(lib_matches) != 1:
                meta_matches = _library_file_candidates_for_qbit_metadata(name, size, torrent)
                if len(meta_matches) == 1 or not lib_matches:
                    lib_matches = meta_matches
            if len(lib_matches) != 1:
                size_mismatch_matches: List[Dict[str, Any]] = []
                if not lib_matches:
                    size_mismatch_matches = [
                        m for m in _library_file_candidates_for_qbit_metadata(
                            name, size, torrent, require_size=False)
                        if int(m.get("actual_size") or 0) != size
                    ]
                if len(size_mismatch_matches) == 1:
                    src = Path(size_mismatch_matches[0]["path"])
                    summary["skipped"] += 1
                    summary["size_mismatch"] += 1
                    add_action({
                        "status": "size_mismatch",
                        "reason": (
                            "library track matched by metadata, but size differs; "
                            "qBittorrent recheck would fail"
                        ),
                        "torrent": _s(torrent.get("name")),
                        "file": name,
                        "source": str(src),
                        "target": str(target),
                        "progress": round(progress, 3),
                        "expected_size": size,
                        "actual_size": int(size_mismatch_matches[0].get("actual_size") or 0),
                        "size_delta": int(size_mismatch_matches[0].get("size_delta") or 0),
                        "match_strategy": size_mismatch_matches[0].get("match_strategy", ""),
                    })
                    continue
                summary["skipped"] += 1
                add_action({
                    "status": "skipped",
                    "reason": "no unique library file match" if not lib_matches else "ambiguous library matches",
                    "torrent": _s(torrent.get("name")),
                    "file": name,
                    "target": str(target),
                    "progress": round(progress, 3),
                    "size": size,
                    "match_count": len(lib_matches),
                })
                continue
            src = Path(lib_matches[0]["path"])
            action = {
                "status": "would_link" if dry_run else "linked",
                "torrent": _s(torrent.get("name")),
                "file": name,
                "source": str(src),
                "target": str(target),
                "progress": round(progress, 3),
                "reason": (
                    "unique library file matched by filename and size"
                    if lib_matches[0].get("match_strategy") == "filename_size"
                    else "unique library file matched by album/track metadata and size"
                ),
                "size": size,
                "match_strategy": lib_matches[0].get("match_strategy", ""),
            }
            if dry_run:
                summary["would_link"] += 1
                add_action(action)
                log.append(f"  would link: {target.name}")
                continue
            try:
                target.parent.mkdir(parents=True, exist_ok=True)
                os.link(str(src), str(target))
                summary["linked"] += 1
                touched_hashes.add(thash)
                add_action(action)
                log.append(f"  linked: {target}")
            except Exception as ex:
                summary["errors"] += 1
                action["status"] = "error"
                action["error"] = str(ex)
                add_action(action)
                log.append(f"  ERROR linking {target}: {ex}")
        if limit and summary["checked"] >= limit:
            break

    if touched_hashes and recheck:
        try:
            _qbit_post(
                "/api/v2/torrents/recheck",
                {"hashes": "|".join(sorted(touched_hashes))},
                cookie,
            )
            summary["rechecked_hashes"] = len(touched_hashes)
            log.append(f"Triggered qBittorrent recheck for {len(touched_hashes)} torrent(s).")
        except Exception as ex:
            summary["errors"] += 1
            log.append(f"  WARN: qBittorrent recheck failed: {ex}")

    log.append(
        "qBittorrent hardlink repair complete: "
        f"{summary['linked']} linked, {summary['would_link']} would link, "
        f"{summary['already_present']} already present, {summary['skipped']} skipped, "
        f"{summary['errors']} error(s)."
    )
    return summary


@app.get("/api/qbittorrent/status")
def qbit_status():
    return jsonify(_qbit_status_payload())


@app.post("/api/qbittorrent/hardlink-missing")
def qbit_hardlink_missing():
    payload = request.get_json(silent=True) or {}
    dry_run = payload.get("dry_run", True) is not False
    category = _s(payload.get("category") or QBIT_CATEGORY).strip()
    qbit_filter = _s(payload.get("filter") or payload.get("qbit_filter") or QBIT_FILTER).strip()
    search = _s(payload.get("search") or payload.get("q") or "").strip()
    raw_hashes = payload.get("hashes") or []
    if isinstance(raw_hashes, str):
        hashes = [h.strip() for h in re.split(r"[\s,|]+", raw_hashes) if h.strip()]
    elif isinstance(raw_hashes, list):
        hashes = [_s(h).strip() for h in raw_hashes if _s(h).strip()]
    else:
        hashes = []
    limit = max(0, min(int(payload.get("limit") or 0), 10000))
    recheck = payload.get("recheck", True) is not False
    if not QBIT_URL:
        return jsonify({
            "ok": False,
            "error": (
                "qBittorrent is not configured. Set QBITTORRENT_URL or QBIT_URL "
                "for the Beets container."
            ),
            "status": _qbit_status_payload(),
        }), 400

    if dry_run:
        log: List[str] = []
        try:
            result = _qbit_hardlink_missing_impl(
                dry_run=True,
                category=category,
                qbit_filter=qbit_filter,
                search=search,
                hashes=hashes,
                limit=limit,
                recheck=False,
                log=log,
                cancel_event=None,
            )
        except Exception as ex:
            return jsonify({"ok": False, "error": str(ex), "log": log}), 500
        return jsonify({
            "ok": True,
            "dry_run": True,
            "result": result,
            "log": log,
        })

    def _do(log, cancel_event=None):
        return _qbit_hardlink_missing_impl(
            dry_run=False,
            category=category,
            qbit_filter=qbit_filter,
            search=search,
            hashes=hashes,
            limit=limit,
            recheck=recheck,
            log=log,
            cancel_event=cancel_event,
        )

    label = "qBittorrent hardlink dry run" if dry_run else "qBittorrent hardlink repair"
    job = jobs.start_python(
        _do,
        label=label,
        metadata={
            "type": "qbit-hardlink-repair",
            "dry_run": dry_run,
            "category": category,
            "filter": qbit_filter,
            "search": search,
            "hash_count": len(hashes),
        },
    )
    return jsonify({"ok": True, "job_id": job.job_id, "dry_run": dry_run})


def _unique_dest(path: Path) -> Path:
    if not path.exists():
        return path
    base = path.with_suffix("")
    suffix = path.suffix
    n = 1
    while True:
        cand = Path(f"{base}.{n}{suffix}")
        if not cand.exists():
            return cand
        n += 1


def _album_item_abs_paths(album_id: int) -> List[Path]:
    try:
        aid = int(album_id or 0)
    except Exception:
        aid = 0
    if aid <= 0:
        return []
    paths: List[Path] = []
    try:
        with _db(text_factory=bytes) as con:
            rows = con.execute(
                "SELECT path FROM items WHERE album_id=?",
                (aid,),
            ).fetchall()
        for (raw_path,) in rows:
            raw = _s(raw_path).strip()
            if not raw:
                continue
            p = Path(raw)
            if not p.is_absolute():
                p = MUSIC_ROOT / raw
            paths.append(p)
    except Exception:
        return []
    return paths


def _clean_template_token_stem(stem: str) -> str:
    cleaned = _UNRESOLVED_TEMPLATE_TOKEN_RE.sub("", _s(stem))
    cleaned = re.sub(r"(\s*-\s*){2,}", " - ", cleaned)
    cleaned = re.sub(r"\s+", " ", cleaned)
    return cleaned.strip(" -_")


def _clean_malformed_release_group_stamps(value: str) -> str:
    return _MALFORMED_RELEASE_GROUP_STAMP_RE.sub(r"{\1}", _s(value))


def _safe_path_component(value: Any, fallback: str = "untitled") -> str:
    text = _s(value).strip() or fallback
    text = text.replace("/", "_").replace("\\", "_")
    text = re.sub(r'[\x00-\x1f<>:"?*|]', "_", text)
    text = re.sub(r"\s+", " ", text).strip()
    text = text.rstrip(". ")
    return text or fallback


def _track_filename_row_target(row: sqlite3.Row, current_path: Path) -> Optional[Path]:
    title = _safe_path_component(_strip_track_filename_id_suffix(row["title"]), "")
    if not title:
        return None
    album = _safe_path_component(row["album"], "Unknown Album")
    artist = _safe_path_component(row["albumartist"] or row["artist"], "Unknown Artist")
    try:
        track = int(row["track"] or 0)
    except Exception:
        track = 0
    track_part = f"{track:02d}" if track > 0 else "00"
    target_parent = Path(_clean_malformed_release_group_stamps(str(current_path.parent)))
    target_name = f"{artist} - {album} - {track_part} - {title}{current_path.suffix}"
    return target_parent / target_name


def _template_token_row_target(row: sqlite3.Row, current_path: Path) -> Optional[Path]:
    target = _track_filename_row_target(row, current_path)
    return _unique_dest(target) if target else None


def _resolve_existing_template_token_file(path: Path) -> Path:
    if path.exists():
        return path
    try:
        parent = path.parent
        if not parent.exists() or not parent.is_dir():
            return path
        matches = [
            p for p in parent.iterdir()
            if p.is_file()
            and p.suffix.lower() == path.suffix.lower()
            and _UNRESOLVED_TEMPLATE_TOKEN_RE.search(p.stem)
        ]
        if len(matches) == 1:
            return matches[0]
    except Exception:
        return path
    return path


def _same_resolved_path(left: Path, right: Path) -> bool:
    try:
        return left.resolve(strict=False) == right.resolve(strict=False)
    except Exception:
        return str(left) == str(right)


def _cleanup_filename_conflict(source: Path, target: Path) -> bool:
    try:
        return target.exists() and not _same_resolved_path(source, target)
    except Exception:
        return False


def _album_template_token_cleanup_candidates(album_id: int) -> List[Dict[str, Any]]:
    try:
        aid = int(album_id or 0)
    except Exception:
        aid = 0
    if aid <= 0:
        return []
    candidates: List[Dict[str, Any]] = []
    seen: set[str] = set()
    try:
        with _db(text_factory=bytes, row_factory=sqlite3.Row) as con:
            rows = con.execute(
                "SELECT id, path, title, artist, album, albumartist, track, disc "
                "FROM items WHERE album_id=?",
                (aid,),
            ).fetchall()
    except Exception:
        return []
    for row in rows:
        raw_path = _s(row["path"]).strip()
        if not raw_path:
            continue
        current = Path(raw_path)
        if not current.is_absolute():
            current = MUSIC_ROOT / raw_path
        try:
            if not _path_under(current, MUSIC_ROOT):
                continue
        except Exception:
            continue
        has_template_token = bool(
            _UNRESOLVED_TEMPLATE_TOKEN_RE.search(raw_path)
            or _UNRESOLVED_TEMPLATE_TOKEN_RE.search(current.name)
        )
        has_malformed_stamp = _clean_malformed_release_group_stamps(str(current)) != str(current)
        has_source_id = bool(
            _track_filename_has_source_id_suffix(Path(raw_path).stem)
            or _track_filename_has_source_id_suffix(current.stem)
        )
        if not (has_template_token or has_malformed_stamp or has_source_id):
            continue
        key = str(current.resolve(strict=False))
        if key in seen:
            continue
        seen.add(key)
        actual_current = _resolve_existing_template_token_file(current)
        has_source_id = has_source_id or _track_filename_has_source_id_suffix(actual_current.stem)
        target = (
            _track_filename_row_target(row, actual_current)
            if has_source_id
            else _template_token_row_target(row, actual_current)
        )
        if not target or _same_resolved_path(target, actual_current):
            continue
        conflict = _cleanup_filename_conflict(actual_current, target)
        issue_type = "Lidarr ID in track filename" if has_source_id else "Unresolved path-template token"
        candidates.append({
            "item_id": int(row["id"] or 0),
            "path": str(actual_current),
            "db_path": str(current),
            "new_path": str(target),
            "filename": actual_current.name,
            "new_filename": target.name,
            "issue_type": issue_type,
            "action": "Fix filename" if has_source_id else "Fix template-token filename",
            "proposed_repair": "Rename to clean MusicBrainz title" if has_source_id else "Remove unresolved template token",
            "conflict": conflict,
            "duplicate_check_required": conflict,
        })
    return candidates

def _update_item_path_after_rename(old_path: Path, new_path: Path) -> int:
    old_abs = str(old_path)
    new_abs = str(new_path)
    old_rel = _db_path_value(old_path)
    new_rel = _db_path_value(new_path)
    changed = 0
    with _db() as con:
        cur = con.execute(
            "UPDATE items SET path=? WHERE path=? OR path=?",
            (new_rel, old_rel, old_abs),
        )
        changed += int(cur.rowcount or 0)
        cur = con.execute(
            "UPDATE items SET path=? WHERE path=? OR path=?",
            (new_rel.encode(), old_rel.encode(), old_abs.encode()),
        )
        changed += int(cur.rowcount or 0)
        con.commit()
    return changed


def _force_item_path_after_rename(item_id: int, new_path: Path) -> int:
    try:
        iid = int(item_id or 0)
    except Exception:
        iid = 0
    if iid <= 0:
        return 0
    new_rel = _db_path_value(new_path)
    with _db() as con:
        cur = con.execute("UPDATE items SET path=? WHERE id=?", (new_rel, iid))
        con.commit()
        return int(cur.rowcount or 0)


def _template_token_cleanup_candidates(paths: Iterable[Path],
                                       *,
                                       recursive: bool) -> List[Dict[str, Any]]:
    seen: set[str] = set()
    candidates: List[Dict[str, Any]] = []
    for raw_path in paths:
        roots = []
        try:
            p = Path(raw_path)
            if p.is_file():
                roots = [p]
            elif p.is_dir():
                roots = list(p.rglob("*") if recursive else p.iterdir())
        except Exception:
            continue
        for f in roots:
            try:
                if not f.is_file() or f.suffix.lower() not in AUDIO_EXT:
                    continue
                if not _path_under(f, MUSIC_ROOT):
                    continue
            except Exception:
                continue
            has_template_token = bool(_UNRESOLVED_TEMPLATE_TOKEN_RE.search(f.stem))
            has_source_id = _track_filename_has_source_id_suffix(f.stem)
            if not (has_template_token or has_source_id):
                continue
            key = str(f.resolve(strict=False))
            if key in seen:
                continue
            seen.add(key)
            cleaned_stem = _clean_template_token_stem(f.stem) if has_template_token else f.stem
            new_stem = _strip_track_filename_id_suffix(cleaned_stem) if has_source_id else cleaned_stem
            if not new_stem:
                continue
            target_base = f.parent / f"{new_stem}{f.suffix}"
            target = target_base if has_source_id else _unique_dest(target_base)
            if _same_resolved_path(target, f):
                continue
            conflict = _cleanup_filename_conflict(f, target)
            issue_type = "Lidarr ID in track filename" if has_source_id else "Unresolved path-template token"
            candidates.append({
                "path": str(f),
                "new_path": str(target),
                "filename": f.name,
                "new_filename": target.name,
                "issue_type": issue_type,
                "action": "Fix filename" if has_source_id else "Fix template-token filename",
                "proposed_repair": "Rename to clean MusicBrainz title" if has_source_id else "Remove unresolved template token",
                "conflict": conflict,
                "duplicate_check_required": conflict,
            })
    return candidates

def _delete_item_path_after_quarantine(item_id: int, old_path: Path) -> int:
    try:
        iid = int(item_id or 0)
    except Exception:
        iid = 0
    old_abs = str(old_path)
    old_rel = _db_path_value(old_path)
    with _db() as con:
        if iid > 0:
            cur = con.execute("DELETE FROM items WHERE id=?", (iid,))
        else:
            cur = con.execute(
                "DELETE FROM items WHERE path=? OR path=? OR path=? OR path=?",
                (old_rel, old_abs, old_rel.encode(), old_abs.encode()),
            )
        con.commit()
        return int(cur.rowcount or 0)


def _filename_cleanup_duplicate_quarantine_path(old_path: Path) -> Path:
    return _unique_import_review_cleanup_path(
        _import_review_cleanup_destination(
            Path("filename_cleanup") / uuid.uuid4().hex[:8] / old_path.name
        )
    )


def _apply_filename_cleanup_candidate(rec: Dict[str, Any], *,
                                      dry_run: bool,
                                      log: List[str]) -> Dict[str, int]:
    old_path = Path(rec["path"])
    new_path = Path(rec["new_path"])
    issue = _s(rec.get("issue_type") or "filename cleanup")
    if dry_run:
        action = "would verify duplicate" if rec.get("conflict") else "would rename"
        log.append(f"  {action}: {old_path.name!r} -> {new_path.name!r} ({issue})")
        return {"renamed": 0, "quarantined": 0, "db_updates": 0, "db_deletes": 0, "skipped": 0}
    if not old_path.exists() or not old_path.is_file():
        log.append(f"  WARN skipping missing file: {old_path.name}")
        return {"renamed": 0, "quarantined": 0, "db_updates": 0, "db_deletes": 0, "skipped": 1}
    try:
        if _cleanup_filename_conflict(old_path, new_path):
            if _maintenance_same_file_hash(old_path, new_path):
                dest = _filename_cleanup_duplicate_quarantine_path(old_path)
                dest.parent.mkdir(parents=True, exist_ok=True)
                shutil.move(str(old_path), str(dest))
                if not dest.exists() or old_path.exists():
                    raise RuntimeError("quarantine verification failed")
                db_deletes = _delete_item_path_after_quarantine(int(rec.get("item_id") or 0), old_path)
                log.append(
                    f"  Quarantined duplicate Lidarr-ID filename: {old_path.name!r} -> {dest}"
                )
                return {"renamed": 0, "quarantined": 1, "db_updates": 0, "db_deletes": db_deletes, "skipped": 0}
            log.append(
                f"  WARN target exists and differs; review required: {old_path.name!r} -> {new_path.name!r}"
            )
            return {"renamed": 0, "quarantined": 0, "db_updates": 0, "db_deletes": 0, "skipped": 1}
        new_path.parent.mkdir(parents=True, exist_ok=True)
        old_path.rename(new_path)
        db_updates = _update_item_path_after_rename(old_path, new_path)
        db_updates += _force_item_path_after_rename(int(rec.get("item_id") or 0), new_path)
        label = "filename cleanup file" if issue == "Lidarr ID in track filename" else "template-token file"
        log.append(f"  Renamed {label}: {old_path.name!r} -> {new_path.name!r}")
        return {"renamed": 1, "quarantined": 0, "db_updates": db_updates, "db_deletes": 0, "skipped": 0}
    except Exception as ex:
        log.append(f"  WARN renaming {old_path.name}: {ex}")
        return {"renamed": 0, "quarantined": 0, "db_updates": 0, "db_deletes": 0, "skipped": 1}


def _cleanup_template_token_files(paths: Iterable[Path], *,
                                  recursive: bool,
                                  dry_run: bool,
                                  log: List[str]) -> Dict[str, Any]:
    candidates = _template_token_cleanup_candidates(paths, recursive=recursive)
    renamed = 0
    quarantined = 0
    db_updates = 0
    db_deletes = 0
    skipped = 0
    for rec in candidates:
        result = _apply_filename_cleanup_candidate(rec, dry_run=dry_run, log=log)
        renamed += int(result.get("renamed") or 0)
        quarantined += int(result.get("quarantined") or 0)
        db_updates += int(result.get("db_updates") or 0)
        db_deletes += int(result.get("db_deletes") or 0)
        skipped += int(result.get("skipped") or 0)
    return {
        "candidates": len(candidates),
        "renamed": renamed,
        "quarantined": quarantined,
        "db_updates": db_updates,
        "db_deletes": db_deletes,
        "skipped": skipped,
        "dry_run": dry_run,
        "items": candidates[:200],
    }


def _cleanup_template_tokens_for_album(album_id: int, log: List[str],
                                       *,
                                       dry_run: bool = False) -> Dict[str, Any]:
    candidates = _album_template_token_cleanup_candidates(album_id)
    if not candidates:
        roots = sorted({p.parent for p in _album_item_abs_paths(album_id) if p.parent})
        if not roots:
            return {
                "candidates": 0,
                "renamed": 0,
                "quarantined": 0,
                "db_updates": 0,
                "db_deletes": 0,
                "skipped": 0,
                "items": [],
            }
        return _cleanup_template_token_files(
            roots,
            recursive=False,
            dry_run=dry_run,
            log=log,
        )
    renamed = 0
    quarantined = 0
    db_updates = 0
    db_deletes = 0
    skipped = 0
    for rec in candidates:
        result = _apply_filename_cleanup_candidate(rec, dry_run=dry_run, log=log)
        renamed += int(result.get("renamed") or 0)
        quarantined += int(result.get("quarantined") or 0)
        db_updates += int(result.get("db_updates") or 0)
        db_deletes += int(result.get("db_deletes") or 0)
        skipped += int(result.get("skipped") or 0)
    result = {
        "candidates": len(candidates),
        "renamed": renamed,
        "quarantined": quarantined,
        "db_updates": db_updates,
        "db_deletes": db_deletes,
        "skipped": skipped,
        "dry_run": dry_run,
        "items": candidates[:200],
    }
    if result.get("renamed") or result.get("quarantined"):
        log.append(
            f"  -> {result['renamed']} filename(s) renamed, "
            f"{result['quarantined']} duplicate filename(s) quarantined; "
            f"DB path updates: {result['db_updates']}; DB rows removed: {result['db_deletes']}"
        )
    return result

@app.post("/api/library/template-token-cleanup")
def library_template_token_cleanup():
    payload = request.get_json(silent=True) or {}
    dry_run = payload.get("dry_run", True) is not False
    album_id = int(payload.get("album_id") or 0)

    def _do(log, cancel_event=None):
        if album_id:
            log.append(f"Scanning album_id {album_id} for unresolved Beets path-template tokens...")
            result = _cleanup_template_tokens_for_album(album_id, log, dry_run=dry_run)
        else:
            roots = [MUSIC_ROOT]
            log.append("Scanning full music library for unresolved Beets path-template tokens...")
            result = _cleanup_template_token_files(
                roots,
                recursive=True,
                dry_run=dry_run,
                log=log,
            )
        action = "would rename" if dry_run else "renamed"
        log.append(
            f"Done - {action} {result['renamed'] if not dry_run else result['candidates']} "
            f"file(s); quarantined: {result.get('quarantined', 0)}; DB path updates: {result['db_updates']}; skipped: {result['skipped']}."
        )
        if not dry_run and (result.get("renamed") or result.get("quarantined")):
            _invalidate_lib_cache()
            _trigger_plex_refresh(log)
        return result

    job = jobs.start_python(
        _do,
        label="Library template-token cleanup",
        metadata={
            "type": "template-token-cleanup",
            "dry_run": dry_run,
            "album_id": album_id,
        },
    )
    return jsonify({"ok": True, "job_id": job.job_id})


def _try_resolve_leaked_path(current: Path) -> Optional[Path]:
    """Strip template-token-only directory components from a path that has leaked tokens.

    Handles the common '$disc_subfolder' case: removes any path component that is
    entirely an unresolved template token, returning the shortened path.
    Returns None if no stripping is possible or the result equals the input.
    """
    parts = current.parts
    if not parts:
        return None
    filename = parts[-1]
    dir_parts = list(parts[:-1])
    cleaned: list = []
    stripped_any = False
    for part in dir_parts:
        if not part:
            continue
        remainder = _UNRESOLVED_TEMPLATE_TOKEN_RE.sub("", part).strip()
        if remainder:
            cleaned.append(part)
        else:
            stripped_any = True
    if not stripped_any or not cleaned:
        return None
    try:
        candidate = Path(cleaned[0]).joinpath(*cleaned[1:]) / filename
    except Exception:
        return None
    if not candidate.is_absolute():
        return None
    return candidate if candidate != current else None


def _leaked_db_paths_summary(rows: List[Dict[str, Any]],
                             *,
                             total_scanned: Optional[int] = None) -> Dict[str, Any]:
    safe = [r for r in rows if r.get("safe")]
    unsafe = [r for r in rows if not r.get("safe")]
    source_missing = [
        r for r in rows
        if not r.get("file_exists_at_db_path") and not r.get("file_exists_at_resolved")
    ]
    target_exists = [r for r in rows if r.get("file_exists_at_resolved")]
    return {
        "total_db_rows_scanned": int(total_scanned if total_scanned is not None else len(rows)),
        "leaked_paths_found": len(rows),
        "safe_repair_candidates": len(safe),
        "needs_review": len(unsafe),
        "source_missing": len(source_missing),
        "target_exists": len(target_exists),
        "skipped_unsafe": len(unsafe),
    }


def _scan_leaked_db_paths(progress: Optional[Any] = None,
                          cancel_event: Optional[Any] = None,
                          scan_meta: Optional[Dict[str, Any]] = None) -> List[Dict[str, Any]]:
    """Scan the beets DB for item rows whose paths contain unresolved template tokens.

    Returns one dict per affected row with:
        item_id, album_id, db_path (as stored), abs_path (absolute),
        resolved_path (proposed fix), file_exists_at_db_path,
        file_exists_at_resolved, safe (bool), skip_reason (str).
    """
    results: List[Dict[str, Any]] = []
    try:
        with _db(text_factory=bytes, row_factory=sqlite3.Row) as con:
            rows = con.execute(
                "SELECT id, album_id, path FROM items"
            ).fetchall()
    except Exception as ex:
        return [{"error": str(ex)}]

    _mroot = str(MUSIC_ROOT)
    total_rows = len(rows)
    if scan_meta is not None:
        scan_meta["total_db_rows_scanned"] = total_rows
    if progress:
        progress({
            "category": "Cleanup",
            "current_task": "Scanning DB rows for leaked path-template tokens",
            "scanned_count": 0,
            "total_count": total_rows,
            "affected_count": 0,
            "safe_count": 0,
            "needs_review_count": 0,
        })
    safe_count = 0
    needs_review_count = 0
    source_missing_count = 0
    target_exists_count = 0
    for idx, row in enumerate(rows, start=1):
        if cancel_event and cancel_event.is_set():
            raise RuntimeError("cancelled")
        raw = row["path"]
        if isinstance(raw, bytes):
            try:
                raw_str = raw.decode("utf-8")
            except Exception:
                raw_str = raw.decode("latin-1", errors="replace")
        else:
            raw_str = _s(raw)
        if not raw_str:
            if progress and (idx == 1 or idx % 500 == 0 or idx == total_rows):
                progress({
                    "category": "Cleanup",
                    "current_task": "Scanning DB rows for leaked path-template tokens",
                    "scanned_count": idx,
                    "total_count": total_rows,
                    "remaining_count": max(0, total_rows - idx),
                    "affected_count": len(results),
                    "safe_count": safe_count,
                    "needs_review_count": needs_review_count,
                    "source_missing_count": source_missing_count,
                    "target_exists_count": target_exists_count,
                })
            continue
        if not _UNRESOLVED_TEMPLATE_TOKEN_RE.search(raw_str):
            if progress and (idx == 1 or idx % 500 == 0 or idx == total_rows):
                progress({
                    "category": "Cleanup",
                    "current_task": "Scanning DB rows for leaked path-template tokens",
                    "current_item": f"item {int(row['id'] or 0)}",
                    "scanned_count": idx,
                    "total_count": total_rows,
                    "remaining_count": max(0, total_rows - idx),
                    "affected_count": len(results),
                    "safe_count": safe_count,
                    "needs_review_count": needs_review_count,
                    "source_missing_count": source_missing_count,
                    "target_exists_count": target_exists_count,
                })
            continue

        # Resolve to absolute path
        if raw_str.startswith("/"):
            abs_path = Path(raw_str)
        else:
            abs_path = MUSIC_ROOT / raw_str

        try:
            file_at_db = abs_path.exists() and abs_path.is_file()
        except Exception:
            file_at_db = False

        resolved: Optional[Path] = _try_resolve_leaked_path(abs_path)
        file_at_resolved = False
        safe = False
        skip_reason = ""

        if file_at_db:
            # File literally exists at path with template token in it (e.g. dir named "$disc_subfolder")
            skip_reason = "File exists at leaked path — manual review needed"
        elif resolved is None:
            skip_reason = "Cannot determine target (complex or nested tokens)"
        else:
            try:
                file_at_resolved = resolved.exists() and resolved.is_file()
            except Exception:
                file_at_resolved = False
            if file_at_resolved:
                safe = True
            else:
                skip_reason = "File not found at either path"

        if safe:
            safe_count += 1
        else:
            needs_review_count += 1
        if file_at_resolved:
            target_exists_count += 1
        if not file_at_db and not file_at_resolved:
            source_missing_count += 1

        rec = {
            "item_id": int(row["id"] or 0),
            "album_id": int(row["album_id"] or 0),
            "db_path": raw_str,
            "abs_path": str(abs_path),
            "resolved_path": str(resolved) if resolved else None,
            "file_exists_at_db_path": file_at_db,
            "file_exists_at_resolved": file_at_resolved,
            "safe": safe,
            "skip_reason": skip_reason,
        }
        results.append(rec)
        if progress:
            progress({
                "category": "Cleanup",
                "current_task": "Scanning DB rows for leaked path-template tokens",
                "current_item": f"item {rec['item_id']}",
                "current_path": raw_str,
                "scanned_count": idx,
                "total_count": total_rows,
                "remaining_count": max(0, total_rows - idx),
                "affected_count": len(results),
                "safe_count": safe_count,
                "needs_review_count": needs_review_count,
                "source_missing_count": source_missing_count,
                "target_exists_count": target_exists_count,
                "skipped_count": needs_review_count,
                "current_result": (
                    "Safe repair candidate found" if safe
                    else "Leaked DB path needs review"
                ),
            })
    if progress:
        progress({
            "category": "Cleanup",
            "current_task": "Leaked DB Paths scan complete",
            "current_item": None,
            "current_path": None,
            "scanned_count": total_rows,
            "total_count": total_rows,
            "remaining_count": 0,
            "affected_count": len(results),
            "safe_count": safe_count,
            "needs_review_count": needs_review_count,
            "source_missing_count": source_missing_count,
            "target_exists_count": target_exists_count,
            "skipped_count": needs_review_count,
            "current_result": (
                f"{len(results)} leaked row(s): "
                f"{safe_count} safe, {needs_review_count} need review"
            ),
            "final_summary": _leaked_db_paths_summary(results, total_scanned=total_rows),
        })
    return results


@app.post("/api/library/leaked-db-paths/scan")
def scan_leaked_db_paths_job():
    """Start a background scan for DB rows with leaked template-token paths.

    Returns job_id. Poll /api/jobs/<job_id> for status; result has rows.
    """
    def _do(log, cancel_event=None, update_state=None):
        log.append("Scanning DB for items with unresolved path-template tokens...")
        scan_meta: Dict[str, Any] = {}
        rows = _scan_leaked_db_paths(progress=update_state, cancel_event=cancel_event, scan_meta=scan_meta)
        safe = [r for r in rows if r.get("safe")]
        unsafe = [r for r in rows if not r.get("safe")]
        final_summary = _leaked_db_paths_summary(
            rows,
            total_scanned=scan_meta.get("total_db_rows_scanned"),
        )
        if update_state:
            update_state({
                "category": "Cleanup",
                "current_task": "Leaked DB Paths scan complete",
                "current_item": None,
                "current_path": None,
                "affected_count": len(rows),
                "safe_count": len(safe),
                "needs_review_count": len(unsafe),
                "skipped_count": len(unsafe),
                "current_result": (
                    f"{len(rows)} leaked row(s): "
                    f"{len(safe)} safe, {len(unsafe)} need review"
                ),
                "final_summary": final_summary,
            })
        log.append(
            f"Found {len(rows)} leaked-path row(s): "
            f"{len(safe)} safe to fix, {len(unsafe)} need manual review."
        )
        for r in unsafe[:20]:
            log.append(f"  Skipped item {r['item_id']}: {r.get('skip_reason','?')} — {r['db_path'][:80]}")
        return {
            "ok": True,
            "total": len(rows),
            "safe_count": len(safe),
            "unsafe_count": len(unsafe),
            "rows": rows,
            "final_summary": final_summary,
        }
    job = jobs.start_python(
        _do,
        label="Leaked DB path scan",
        metadata={"type": "leaked-db-path-scan"},
    )
    return jsonify({"ok": True, "job_id": job.job_id})


@app.post("/api/library/leaked-db-paths/fix")
def fix_leaked_db_paths():
    """Fix leaked path DB rows (DB-only update — no files are moved).

    Body: { "dry_run": bool (default true), "item_ids": [int] (optional — all safe if omitted) }
    """
    payload = request.get_json(silent=True) or {}
    dry_run = payload.get("dry_run", True) is not False
    if not dry_run and payload.get("confirmed") is not True:
        return jsonify({"ok": False, "error": "Confirmation is required before repairing DB paths"}), 400
    requested_ids: set = set()
    for x in (payload.get("item_ids") or []):
        try:
            requested_ids.add(int(x))
        except Exception:
            pass

    def _do(log, cancel_event=None, update_state=None):
        log.append("Scanning DB for leaked path-template rows...")
        scan_meta: Dict[str, Any] = {}
        all_rows = _scan_leaked_db_paths(progress=update_state, cancel_event=cancel_event, scan_meta=scan_meta)
        safe_rows = [r for r in all_rows if r.get("safe")]
        target_rows = [r for r in safe_rows if r["item_id"] in requested_ids] if requested_ids else safe_rows

        unsafe_rows = [r for r in all_rows if not r.get("safe")]
        if requested_ids:
            unsafe_rows = [r for r in unsafe_rows if r["item_id"] in requested_ids]

        log.append(
            f"Found {len(all_rows)} leaked-path row(s) total; "
            f"{len(safe_rows)} safe to fix; "
            f"{len(all_rows) - len(safe_rows)} skipped."
        )

        fixed = 0
        errors = 0

        for r in target_rows:
            if cancel_event and cancel_event.is_set():
                log.append("Cancelled.")
                break
            item_id = r["item_id"]
            old_path = r["db_path"]
            new_path_str = r["resolved_path"]
            if not new_path_str:
                errors += 1
                continue
            new_path = Path(new_path_str)
            db_val = _db_path_value(new_path)
            if dry_run:
                log.append(
                    f"  [dry-run] item {item_id} (album {r['album_id']}):\n"
                    f"    old: {old_path}\n"
                    f"    new: {new_path_str}"
                )
                fixed += 1
            else:
                try:
                    with _db() as con:
                        cur = con.execute("UPDATE items SET path=? WHERE id=?", (db_val, item_id))
                        con.commit()
                    if int(cur.rowcount or 0) > 0:
                        fixed += 1
                        log.append(
                            f"  Fixed item {item_id}: {Path(old_path).name!r} -> {Path(new_path_str).name!r}"
                        )
                    else:
                        errors += 1
                        log.append(f"  WARN: no row updated for item {item_id}")
                except Exception as ex:
                    errors += 1
                    log.append(f"  ERROR item {item_id}: {ex}")
            if update_state:
                update_state({
                    "category": "Cleanup",
                    "current_task": "Previewing leaked DB path repairs" if dry_run else "Repairing leaked DB path rows",
                    "current_item": f"item {item_id}",
                    "changed_count": fixed,
                    "error_count": errors,
                    "skipped_count": len(unsafe_rows),
                    "current_result": f"{fixed} row(s) {'would be fixed' if dry_run else 'fixed'}",
                })

        for r in unsafe_rows:
            reason = r.get("skip_reason") or "unsafe"
            log.append(
                f"  Skipped item {r['item_id']} (album {r['album_id']}): {reason}\n"
                f"    path: {r['db_path']}"
            )

        action = "would fix" if dry_run else "fixed"
        log.append(
            f"Done — {action} {fixed} row(s); "
            f"skipped {len(unsafe_rows)} unsafe; "
            f"errors {errors}."
        )
        if not dry_run and fixed:
            _invalidate_lib_cache()

        final_summary = {
            "total_db_rows_scanned": int(scan_meta.get("total_db_rows_scanned") or len(all_rows)),
            "safe_repair_candidates": len(safe_rows),
            "selected_rows": len(target_rows),
            "changed_count": fixed,
            "skipped_unsafe": len(unsafe_rows),
            "errors": errors,
            "dry_run": dry_run,
        }
        if update_state:
            update_state({
                "category": "Cleanup",
                "current_task": "Leaked DB path repair preview complete" if dry_run else "Leaked DB path repair complete",
                "current_item": None,
                "current_path": None,
                "changed_count": fixed,
                "skipped_count": len(unsafe_rows),
                "error_count": errors,
                "current_result": (
                    f"{fixed} row(s) {'would be fixed' if dry_run else 'fixed'}; "
                    f"{len(unsafe_rows)} skipped"
                ),
                "final_summary": final_summary,
            })
        return {
            "fixed": fixed,
            "skipped": len(unsafe_rows),
            "errors": errors,
            "dry_run": dry_run,
            "total_scanned": len(all_rows),
            "safe_found": len(safe_rows),
            "rows": all_rows,
            "final_summary": final_summary,
        }

    job = jobs.start_python(
        _do,
        label=f"Leaked DB path fix ({'dry-run' if dry_run else 'apply'})",
        metadata={
            "type": "leaked-db-path-fix",
            "dry_run": dry_run,
        },
    )
    return jsonify({"ok": True, "job_id": job.job_id})


def _folder_placeholder_summary(rows: List[Dict[str, Any]],
                                *,
                                total_scanned: Optional[int] = None) -> Dict[str, Any]:
    safe = [r for r in rows if r.get("safe")]
    unsafe = [r for r in rows if not r.get("safe")]
    return {
        "total_folders_scanned": int(total_scanned if total_scanned is not None else len(rows)),
        "placeholder_folders_found": len(rows),
        "safe_to_fix": len(safe),
        "needs_review": len(unsafe),
        "target_exists": sum(1 for r in rows if r.get("target_exists")),
        "db_tracked": sum(1 for r in rows if int(r.get("db_item_count") or 0) > 0),
        "empty_folders": sum(1 for r in rows if r.get("is_empty")),
        "skipped_unsafe": len(unsafe),
    }


def _scan_folder_name_placeholders(progress: Optional[Any] = None,
                                   cancel_event: Optional[Any] = None,
                                   scan_meta: Optional[Dict[str, Any]] = None) -> List[Dict[str, Any]]:
    """Scan MUSIC_ROOT album-level folders for unresolved template placeholders in their names.

    Detects patterns like {Album MbId}, {Album Mbid}, $disc_subfolder in folder names.
    Returns one dict per found folder with enough info for a safe preview/review workflow.
    Does NOT modify anything.
    """
    root = Path(MUSIC_ROOT)
    if not root.exists():
        return []

    # Build folder -> DB info map from items table
    folder_db: Dict[str, Dict[str, Any]] = {}
    try:
        with _db(row_factory=sqlite3.Row) as con:
            rows = con.execute(
                "SELECT id AS item_id, album_id, path FROM items WHERE COALESCE(path, '') != ''"
            ).fetchall()
        for row in rows:
            p = _s(row["path"])
            d = os.path.dirname(p) if p else ""
            if not d:
                continue
            if d not in folder_db:
                folder_db[d] = {"album_ids": set(), "item_count": 0}
            if row["album_id"]:
                folder_db[d]["album_ids"].add(int(row["album_id"]))
            folder_db[d]["item_count"] += 1
    except Exception:
        pass

    results: List[Dict[str, Any]] = []
    seen: set = set()

    try:
        artist_dirs = [
            artist_dir for artist_dir in sorted(root.iterdir())
            if artist_dir.is_dir() and not artist_dir.name.startswith(".")
        ]
    except PermissionError:
        artist_dirs = []

    album_dirs: List[Path] = []
    skipped_count = 0
    for artist_dir in artist_dirs:
        try:
            album_dirs.extend([
                album_dir for album_dir in sorted(artist_dir.iterdir())
                if album_dir.is_dir() and not album_dir.name.startswith(".")
            ])
        except PermissionError:
            skipped_count += 1
            continue

    total_album_dirs = len(album_dirs)
    if scan_meta is not None:
        scan_meta["total_folders_scanned"] = total_album_dirs
    if progress:
        progress({
            "category": "Cleanup",
            "current_task": "Scanning folder names for unresolved placeholders",
            "scan_path": str(root),
            "scanned_count": 0,
            "total_count": total_album_dirs,
            "placeholder_count": 0,
            "safe_count": 0,
            "needs_review_count": 0,
            "skipped_count": skipped_count,
        })

    safe_count = 0
    needs_review_count = 0
    target_exists_count = 0
    db_tracked_count = 0
    empty_folder_count = 0

    for idx, album_dir in enumerate(album_dirs, start=1):
        if cancel_event and cancel_event.is_set():
            raise RuntimeError("cancelled")
        name = album_dir.name
        folder_str = str(album_dir)

        if progress and (idx == 1 or idx % 50 == 0 or idx == total_album_dirs):
            progress({
                "category": "Cleanup",
                "current_task": "Scanning folder names for unresolved placeholders",
                "current_path": folder_str,
                "scanned_count": idx,
                "total_count": total_album_dirs,
                "remaining_count": max(0, total_album_dirs - idx),
                "placeholder_count": len(results),
                "safe_count": safe_count,
                "needs_review_count": needs_review_count,
                "target_exists_count": target_exists_count,
                "db_tracked_count": db_tracked_count,
                "empty_folder_count": empty_folder_count,
                "skipped_count": skipped_count,
            })

        # Check for any unresolved placeholder in folder name
        has_literal = bool(_LITERAL_PLACEHOLDER_RE.search(name))
        has_token = bool(_UNRESOLVED_TEMPLATE_TOKEN_RE.search(name))
        if not (has_literal or has_token):
            continue

        key = folder_str.lower()
        if key in seen:
            continue
        seen.add(key)

        if has_literal:
            placeholder_type = "literal_placeholder"
            placeholder_desc = "{Album MbId} or {Track ArtistMbId} text was never replaced"
        else:
            placeholder_type = "template_token"
            placeholder_desc = "$variable or %func{} was never expanded"

        # Propose clean name by stripping placeholders
        clean_name = _LITERAL_PLACEHOLDER_RE.sub("", name)
        clean_name = _UNRESOLVED_TEMPLATE_TOKEN_RE.sub("", clean_name)
        clean_name = re.sub(r"\s+", " ", clean_name).strip().strip(" -_")

        proposed_folder = str(album_dir.parent / clean_name) if clean_name and clean_name != name else None
        target_exists = bool(proposed_folder and Path(proposed_folder).exists())

        # Inspect contents
        try:
            contents = list(album_dir.iterdir())
            file_count = sum(1 for f in contents if f.is_file())
            audio_count = sum(1 for f in contents if f.is_file() and f.suffix.lower() in AUDIO_EXT)
            is_empty = len(contents) == 0
        except Exception:
            file_count = -1
            audio_count = -1
            is_empty = False

        db_info = folder_db.get(folder_str, {})
        db_album_ids = sorted(db_info.get("album_ids", set()))
        db_item_count = db_info.get("item_count", 0)

        # Safety classification
        skip_reason = ""
        safe = False

        if not clean_name:
            skip_reason = "Placeholder removal results in an empty folder name"
        elif target_exists:
            skip_reason = f"Target already exists: {proposed_folder}"
        elif db_item_count > 0:
            # DB-tracked files require beet move, not just a folder rename
            skip_reason = (
                f"{db_item_count} DB-tracked item(s) — rename requires beet move, "
                "not a simple folder rename. Run beet move after fixing DB paths."
            )
        elif audio_count > 0 and db_item_count == 0:
            # Untracked audio — folder rename is possible
            safe = True
        elif is_empty:
            safe = True
        else:
            # Only non-audio files, no DB items
            safe = True

        if safe:
            safe_count += 1
        else:
            needs_review_count += 1
        if target_exists:
            target_exists_count += 1
        if db_item_count > 0:
            db_tracked_count += 1
        if is_empty:
            empty_folder_count += 1

        results.append({
            "folder": folder_str,
            "artist": album_dir.parent.name,
            "name": name,
            "clean_name": clean_name or None,
            "proposed_folder": proposed_folder,
            "placeholder_type": placeholder_type,
            "placeholder_desc": placeholder_desc,
            "is_empty": is_empty,
            "file_count": file_count,
            "audio_count": audio_count,
            "db_album_ids": db_album_ids,
            "db_item_count": db_item_count,
            "target_exists": target_exists,
            "safe": safe,
            "skip_reason": skip_reason,
        })
        if progress:
            progress({
                "category": "Cleanup",
                "current_task": "Scanning folder names for unresolved placeholders",
                "current_path": folder_str,
                "scanned_count": idx,
                "total_count": total_album_dirs,
                "remaining_count": max(0, total_album_dirs - idx),
                "placeholder_count": len(results),
                "safe_count": safe_count,
                "needs_review_count": needs_review_count,
                "target_exists_count": target_exists_count,
                "db_tracked_count": db_tracked_count,
                "empty_folder_count": empty_folder_count,
                "skipped_count": skipped_count + needs_review_count,
                "current_result": (
                    "Safe placeholder folder candidate found" if safe
                    else "Placeholder folder needs review"
                ),
            })

    sorted_results = sorted(results, key=lambda r: (r["artist"].casefold(), r["name"].casefold()))
    if progress:
        progress({
            "category": "Cleanup",
            "current_task": "Folder Names scan complete",
            "current_item": None,
            "current_path": None,
            "scanned_count": total_album_dirs,
            "total_count": total_album_dirs,
            "remaining_count": 0,
            "placeholder_count": len(sorted_results),
            "safe_count": safe_count,
            "needs_review_count": needs_review_count,
            "target_exists_count": target_exists_count,
            "db_tracked_count": db_tracked_count,
            "empty_folder_count": empty_folder_count,
            "skipped_count": skipped_count + needs_review_count,
            "current_result": (
                f"{len(sorted_results)} placeholder folder(s): "
                f"{safe_count} safe, {needs_review_count} need review"
            ),
            "final_summary": _folder_placeholder_summary(sorted_results, total_scanned=total_album_dirs),
        })
    return sorted_results


@app.post("/api/library/folder-placeholders/scan")
def scan_folder_placeholders_job():
    """Start a background scan for album folders with unresolved placeholder names."""
    def _do(log, cancel_event=None, update_state=None):
        log.append(f"Scanning {MUSIC_ROOT} for folder names with unresolved placeholders...")
        scan_meta: Dict[str, Any] = {}
        rows = _scan_folder_name_placeholders(progress=update_state, cancel_event=cancel_event, scan_meta=scan_meta)
        safe = [r for r in rows if r.get("safe")]
        unsafe = [r for r in rows if not r.get("safe")]
        final_summary = _folder_placeholder_summary(
            rows,
            total_scanned=scan_meta.get("total_folders_scanned"),
        )
        if update_state:
            update_state({
                "category": "Cleanup",
                "current_task": "Folder Names scan complete",
                "current_item": None,
                "current_path": None,
                "placeholder_count": len(rows),
                "safe_count": len(safe),
                "needs_review_count": len(unsafe),
                "target_exists_count": sum(1 for r in rows if r.get("target_exists")),
                "db_tracked_count": sum(1 for r in rows if int(r.get("db_item_count") or 0) > 0),
                "empty_folder_count": sum(1 for r in rows if r.get("is_empty")),
                "skipped_count": len(unsafe),
                "current_result": (
                    f"{len(rows)} placeholder folder(s): "
                    f"{len(safe)} safe, {len(unsafe)} need review"
                ),
                "final_summary": final_summary,
            })
        log.append(
            f"Found {len(rows)} folder(s) with placeholders: "
            f"{len(safe)} safe to rename, {len(unsafe)} need review."
        )
        for r in rows[:40]:
            tag = "[safe]" if r["safe"] else "[review]"
            log.append(f"  {tag} {r['folder']}")
            if r.get("proposed_folder"):
                log.append(f"    → {r['proposed_folder']}")
            if r.get("skip_reason"):
                log.append(f"    skip: {r['skip_reason']}")
        return {
            "ok": True,
            "total": len(rows),
            "safe_count": len(safe),
            "unsafe_count": len(unsafe),
            "rows": rows,
            "final_summary": final_summary,
        }

    job = jobs.start_python(
        _do,
        label="Scan folder placeholder names",
        metadata={"type": "folder-placeholder-scan"},
    )
    return jsonify({"ok": True, "job_id": job.job_id})


def _maintenance_safe_folder_renames(rows: List[Dict[str, Any]], log: List[str],
                                     cancel_event=None) -> Dict[str, Any]:
    """Apply only safe_rename folder placeholder rows.

    This intentionally excludes target_exists, DB-tracked, merge/delete, and
    conflict cases. It never overwrites an existing folder and never deletes
    media files.
    """
    renamed = 0
    skipped = 0
    errors = 0
    examples: List[Dict[str, str]] = []
    for row in rows:
        if cancel_event and cancel_event.is_set():
            raise RuntimeError("cancelled")
        source_raw = _s(row.get("folder")).strip()
        target_raw = _s(row.get("proposed_folder")).strip()
        safe = bool(row.get("safe"))
        if (
            not safe
            or row.get("target_exists")
            or int(row.get("db_item_count") or 0) > 0
            or not source_raw
            or not target_raw
        ):
            skipped += 1
            continue
        try:
            source = Path(source_raw).resolve(strict=False)
            target = Path(target_raw).resolve(strict=False)
            if not _path_under(source, MUSIC_ROOT) or not _path_under(target, MUSIC_ROOT):
                skipped += 1
                log.append(f"  [folder-safe-rename] skipped outside library root: {source_raw}")
                continue
            if source == target:
                skipped += 1
                continue
            if not source.exists() or not source.is_dir():
                skipped += 1
                log.append(f"  [folder-safe-rename] skipped missing source: {source}")
                continue
            if target.exists():
                skipped += 1
                log.append(f"  [folder-safe-rename] skipped existing target: {target}")
                continue
            target.parent.mkdir(parents=True, exist_ok=True)
            source.rename(target)
            renamed += 1
            if len(examples) < 20:
                examples.append({"source": str(source), "target": str(target)})
            log.append(f"  [folder-safe-rename] renamed: {source.name!r} -> {target.name!r}")
        except Exception as exc:
            errors += 1
            log.append(f"  [folder-safe-rename] error for {source_raw}: {exc}")
    if renamed:
        _invalidate_lib_cache()
    return {
        "renamed": renamed,
        "skipped": skipped,
        "errors": errors,
        "examples": examples,
    }


